import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const AccordionOrientation = S.Union([
  S.Literal('horizontal'),
  S.Literal('vertical'),
])
export type AccordionOrientation = typeof AccordionOrientation.Type

export const AccordionTransitionStatus = S.Union([
  S.Literal('idle'),
  S.Literal('starting'),
  S.Literal('ending'),
])
export type AccordionTransitionStatus = typeof AccordionTransitionStatus.Type

export const AccordionChangeReason = S.Union([
  S.Literal('trigger-press'),
  S.Literal('none'),
])
export type AccordionChangeReason = typeof AccordionChangeReason.Type

export const AccordionValueChange = S.Struct({
  value: S.Array(S.String),
  reason: AccordionChangeReason,
})
export type AccordionValueChange = typeof AccordionValueChange.Type

export const AccordionPanelGeometry = S.Struct({
  height: S.optional(S.Number),
  width: S.optional(S.Number),
})
export type AccordionPanelGeometry = typeof AccordionPanelGeometry.Type

export const AccordionPanelDescriptor = S.Struct({
  id: S.optional(S.String),
  label: S.optional(S.String),
  keepMounted: S.optional(S.Boolean),
  hiddenUntilFound: S.optional(S.Boolean),
  geometry: S.optional(AccordionPanelGeometry),
})
export type AccordionPanelDescriptor = typeof AccordionPanelDescriptor.Type

export const AccordionItemDescriptor = S.Struct({
  id: S.optional(S.String),
  value: S.String,
  label: S.optional(S.String),
  triggerId: S.optional(S.String),
  headerId: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  transitionStatus: S.optional(AccordionTransitionStatus),
  panel: S.optional(AccordionPanelDescriptor),
})
export type AccordionItemDescriptor = typeof AccordionItemDescriptor.Type

export const AccordionOptions = S.Struct({
  id: S.optional(S.String),
  value: S.Array(S.String),
  multiple: S.optional(S.Boolean),
  isDisabled: S.optional(S.Boolean),
  orientation: S.optional(AccordionOrientation),
  dir: S.optional(S.String),
  loopFocus: S.optional(S.Boolean),
  keepMounted: S.optional(S.Boolean),
  hiddenUntilFound: S.optional(S.Boolean),
  items: S.Array(AccordionItemDescriptor),
})
export type AccordionOptions = typeof AccordionOptions.Type

// UPDATE

export const isOpen = (
  value: ReadonlyArray<string>,
  item: Pick<AccordionItemDescriptor, 'value'>,
): boolean => value.includes(item.value)

export const triggerId = (
  item: Pick<AccordionItemDescriptor, 'id' | 'triggerId' | 'value'>,
): string => item.triggerId ?? `${item.id ?? item.value}-trigger`

export const panelId = (
  item: Pick<AccordionItemDescriptor, 'id' | 'panel' | 'value'>,
): string => item.panel?.id ?? `${item.id ?? item.value}-panel`

export const toggleValue = (
  value: ReadonlyArray<string>,
  item: Pick<AccordionItemDescriptor, 'value'>,
  multiple = false,
): ReadonlyArray<string> => {
  if (!multiple) {
    return isOpen(value, item) ? [] : [item.value]
  }

  return isOpen(value, item)
    ? value.filter(openValue => openValue !== item.value)
    : [...value, item.value]
}

export const valueChange = (
  value: ReadonlyArray<string>,
  reason: AccordionChangeReason,
): AccordionValueChange => ({
  value: [...value],
  reason,
})

// VIEW

export type AccordionItemAttributes<Message> = Readonly<{
  item: AccordionItemDescriptor
  root: ReadonlyArray<Attribute<Message>>
  header: ReadonlyArray<Attribute<Message>>
  trigger: ReadonlyArray<Attribute<Message>>
  panel: AccordionPanelAttributes<Message>
  isDisabled: boolean
  isOpen: boolean
}>

export type AccordionPanelAttributes<Message> = Readonly<{
  panel: AccordionPanelDescriptor
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type AccordionAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  items: ReadonlyArray<AccordionItemAttributes<Message>>
}>

export type ViewConfig<Message> = AccordionOptions &
  Readonly<{
    toView: (attributes: AccordionAttributes<Message>) => Html
    onValueChange?: (change: AccordionValueChange) => Message
  }>

const defaultOrientation = 'vertical'
const defaultPanel: AccordionPanelDescriptor = {}

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const transitionDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  transitionStatus: AccordionTransitionStatus | undefined,
): ReadonlyArray<Attribute<Message>> => {
  if (transitionStatus === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (transitionStatus === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const openStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  open: boolean,
): ReadonlyArray<Attribute<Message>> =>
  open ? [h.DataAttribute('open', '')] : [h.DataAttribute('closed', '')]

const canActivateItem = (
  config: Pick<ViewConfig<unknown>, 'isDisabled' | 'onValueChange'>,
  item: Pick<AccordionItemDescriptor, 'isDisabled'>,
): boolean =>
  config.isDisabled !== true &&
  item.isDisabled !== true &&
  Predicate.isNotUndefined(config.onValueChange)

const selectionMessage = <Message>(
  config: ViewConfig<Message>,
  item: AccordionItemDescriptor,
): Option.Option<Message> =>
  canActivateItem(config, item) && config.onValueChange !== undefined
    ? Option.some(
        config.onValueChange(
          valueChange(
            toggleValue(config.value, item, config.multiple),
            'trigger-press',
          ),
        ),
      )
    : Option.none()

const keyActivationMessage = <Message>(
  config: ViewConfig<Message>,
  item: AccordionItemDescriptor,
  key: string,
): Option.Option<Message> =>
  key === ' ' || key === 'Enter'
    ? selectionMessage(config, item)
    : Option.none()

const clickAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: AccordionItemDescriptor,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(selectionMessage(config, item), {
    onNone: () => [],
    onSome: message => [h.OnClick(message)],
  })

const keyboardAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: AccordionItemDescriptor,
): ReadonlyArray<Attribute<Message>> => {
  if (config.isDisabled === true || item.isDisabled === true) {
    return []
  }

  return [
    h.OnKeyDownPreventDefault(key => keyActivationMessage(config, item, key)),
  ]
}

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  h.DataAttribute('orientation', config.orientation ?? defaultOrientation),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
]

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: AccordionItemDescriptor,
  index: number,
): ReadonlyArray<Attribute<Message>> => {
  const itemIsOpen = isOpen(config.value, item)
  const itemIsDisabled = config.isDisabled === true || item.isDisabled === true

  return [
    ...optionalAttribute<Message>(item.id, value => h.Id(value)),
    h.Attribute('data-index', String(index)),
    ...openStateDataAttributes(h, itemIsOpen),
    ...booleanDataAttribute(h, 'disabled', itemIsDisabled),
  ]
}

const headerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: AccordionItemDescriptor,
  index: number,
): ReadonlyArray<Attribute<Message>> => {
  const itemIsOpen = isOpen(config.value, item)
  const itemIsDisabled = config.isDisabled === true || item.isDisabled === true

  return [
    ...optionalAttribute<Message>(item.headerId, value => h.Id(value)),
    h.Attribute('data-index', String(index)),
    ...openStateDataAttributes(h, itemIsOpen),
    ...booleanDataAttribute(h, 'disabled', itemIsDisabled),
  ]
}

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: AccordionItemDescriptor,
): ReadonlyArray<Attribute<Message>> => {
  const itemIsOpen = isOpen(config.value, item)
  const itemIsDisabled = config.isDisabled === true || item.isDisabled === true

  return [
    h.Type('button'),
    h.Id(triggerId(item)),
    h.AriaExpanded(itemIsOpen),
    ...optionalAttribute<Message>(
      itemIsOpen ? panelId(item) : undefined,
      value => h.AriaControls(value),
    ),
    ...booleanDataAttribute(h, 'panel-open', itemIsOpen),
    ...booleanDataAttribute(h, 'disabled', itemIsDisabled),
    ...(itemIsDisabled ? [h.AriaDisabled(true)] : []),
    ...clickAttributes(h, config, item),
    ...keyboardAttributes(h, config, item),
  ]
}

const panelStyle = (
  geometry: AccordionPanelGeometry | undefined,
): Record<string, string> => ({
  '--accordion-panel-height':
    geometry?.height === undefined ? 'auto' : `${geometry.height}px`,
  '--accordion-panel-width':
    geometry?.width === undefined ? 'auto' : `${geometry.width}px`,
})

const effectivePanel = (
  config: Pick<AccordionOptions, 'hiddenUntilFound' | 'keepMounted'>,
  item: AccordionItemDescriptor,
): AccordionPanelDescriptor => {
  const panel = item.panel ?? defaultPanel

  return {
    ...panel,
    keepMounted: panel.keepMounted ?? config.keepMounted,
    hiddenUntilFound: panel.hiddenUntilFound ?? config.hiddenUntilFound,
  }
}

const hiddenAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  panel: AccordionPanelDescriptor,
  open: boolean,
): ReadonlyArray<Attribute<Message>> => {
  if (open) {
    return []
  }

  return panel.hiddenUntilFound === true
    ? [h.Attribute('hidden', 'until-found')]
    : [h.Hidden(true)]
}

const panelAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: AccordionItemDescriptor,
  index: number,
): AccordionPanelAttributes<Message> => {
  const panel = effectivePanel(config, item)
  const itemIsOpen = isOpen(config.value, item)
  const itemIsDisabled = config.isDisabled === true || item.isDisabled === true
  const isMounted =
    itemIsOpen || panel.keepMounted === true || panel.hiddenUntilFound === true
  const attrs: ReadonlyArray<Attribute<Message>> = [
    h.Role('region'),
    h.Id(panelId(item)),
    h.AriaLabelledBy(triggerId(item)),
    h.Attribute('data-index', String(index)),
    ...hiddenAttributes(h, panel, itemIsOpen),
    ...(itemIsOpen ? [] : [h.Inert(true)]),
    h.DataAttribute('orientation', config.orientation ?? defaultOrientation),
    h.Style(panelStyle(panel.geometry)),
    ...openStateDataAttributes(h, itemIsOpen),
    ...booleanDataAttribute(h, 'disabled', itemIsDisabled),
    ...transitionDataAttributes(h, item.transitionStatus),
  ]

  return {
    panel,
    root: isMounted ? attrs : [],
    isMounted,
    isOpen: itemIsOpen,
  }
}

const accordionItemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: AccordionItemDescriptor,
  index: number,
): AccordionItemAttributes<Message> => ({
  item,
  root: itemAttributes(h, config, item, index),
  header: headerAttributes(h, config, item, index),
  trigger: triggerAttributes(h, config, item),
  panel: panelAttributes(h, config, item, index),
  isDisabled: config.isDisabled === true || item.isDisabled === true,
  isOpen: isOpen(config.value, item),
})

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()

  return config.toView({
    root: rootAttributes(h, config),
    items: config.items.map((item, index) =>
      accordionItemAttributes(h, config, item, index),
    ),
  })
}

import { Schema as S } from 'effect'
import type * as Command from 'foldkit/command'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import * as Dialog from './dialog'

// MODEL

export type AlertDialogModalMode = true

export const AlertDialogChangeReason = Dialog.DialogChangeReason
export type AlertDialogChangeReason = typeof AlertDialogChangeReason.Type
export const AlertDialogOpenChange = Dialog.DialogOpenChange
export type AlertDialogOpenChange = typeof AlertDialogOpenChange.Type
export const AlertDialogTransitionStatus = Dialog.DialogTransitionStatus
export type AlertDialogTransitionStatus =
  typeof AlertDialogTransitionStatus.Type

export const AlertDialogOptions = S.Struct({
  id: S.String,
  open: S.Boolean,
  isDisabled: S.optional(S.Boolean),
  isNested: S.optional(S.Boolean),
  hasNestedDialogOpen: S.optional(S.Boolean),
  transitionStatus: S.optional(Dialog.DialogTransitionStatus),
  titleId: S.optional(S.String),
  descriptionId: S.optional(S.String),
  focusSelector: S.optional(S.String),
  forceMount: S.optional(S.Boolean),
})
export type AlertDialogOptions = typeof AlertDialogOptions.Type

// MESSAGE

export const { CompletedCloseDialog, CompletedShowDialog } = Dialog

export const { CommandMessage } = Dialog
export type CommandMessage = Dialog.CommandMessage

// UPDATE

export const {
  CloseDialog,
  ShowDialog,
  closeOpenChange,
  descriptionId,
  escapeOpenChange,
  openChange,
  panelId,
  titleId,
  triggerOpenChange,
} = Dialog

export const modal: AlertDialogModalMode = true

export const commandForOpenChange = (
  config: Pick<AlertDialogOptions, 'focusSelector' | 'id'>,
  change: AlertDialogOpenChange,
): Command.Command<CommandMessage> =>
  Dialog.commandForOpenChange(
    {
      ...config,
      modal,
    },
    change,
  )

// VIEW

export type AlertDialogAttributes<Message> = Dialog.DialogAttributes<Message> &
  Readonly<{
    action: ReadonlyArray<Attribute<Message>>
    cancel: ReadonlyArray<Attribute<Message>>
  }>

export type AlertDialogPartAttributes<Message> =
  Dialog.DialogPartAttributes<Message>

export type ViewConfig<Message> = AlertDialogOptions &
  Readonly<{
    toView: (attributes: AlertDialogAttributes<Message>) => Html
    onOpenChange?: (change: AlertDialogOpenChange) => Message
    onAction?: () => Message
  }>

const disabledAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<AlertDialogOptions, 'isDisabled'>,
): ReadonlyArray<Attribute<Message>> =>
  config.isDisabled === true
    ? [h.AriaDisabled(true), h.DataAttribute('disabled', '')]
    : []

const actionAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('button'),
  ...disabledAttributes(h, config),
  ...(config.isDisabled === true || config.onAction === undefined
    ? []
    : [h.OnClick(config.onAction())]),
]

const alertDialogAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: Dialog.DialogAttributes<Message>,
): AlertDialogAttributes<Message> => ({
  ...attributes,
  popup: {
    ...attributes.popup,
    root:
      attributes.popup.root.length > 0
        ? [...attributes.popup.root, h.Role('alertdialog')]
        : attributes.popup.root,
  },
  cancel: attributes.close,
  action: actionAttributes(h, config),
})

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()

  return Dialog.view<Message>({
    ...config,
    modal,
    disableOutsidePress: true,
    toView: attributes =>
      config.toView(alertDialogAttributes(h, config, attributes)),
  })
}

import { Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import * as Combobox from './combobox'

// MODEL

export const AutocompleteSide = Combobox.ComboboxSide
export type AutocompleteSide = Combobox.ComboboxSide

export const AutocompleteAlign = Combobox.ComboboxAlign
export type AutocompleteAlign = Combobox.ComboboxAlign

export const AutocompleteTransitionStatus = Combobox.ComboboxTransitionStatus
export type AutocompleteTransitionStatus = Combobox.ComboboxTransitionStatus

export const AutocompleteMode = S.Union([
  S.Literal('list'),
  S.Literal('both'),
  S.Literal('inline'),
  S.Literal('none'),
])
export type AutocompleteMode = typeof AutocompleteMode.Type

export const AutocompleteAutoHighlight = S.Boolean
export type AutocompleteAutoHighlight = typeof AutocompleteAutoHighlight.Type

export const AutocompleteOpenChangeReason = S.Union([
  S.Literal('trigger-press'),
  S.Literal('input-press'),
  S.Literal('input-change'),
  S.Literal('input-clear'),
  S.Literal('outside-press'),
  S.Literal('escape-key'),
  S.Literal('keyboard-open'),
  S.Literal('list-navigation'),
  S.Literal('none'),
])
export type AutocompleteOpenChangeReason =
  typeof AutocompleteOpenChangeReason.Type

export const AutocompleteValueChangeReason = S.Union([
  S.Literal('input-change'),
  S.Literal('input-clear'),
  S.Literal('item-press'),
  S.Literal('keyboard-select'),
  S.Literal('clear-press'),
  S.Literal('none'),
])
export type AutocompleteValueChangeReason =
  typeof AutocompleteValueChangeReason.Type

export const AutocompleteHighlightChangeReason =
  Combobox.ComboboxHighlightChangeReason
export type AutocompleteHighlightChangeReason =
  Combobox.ComboboxHighlightChangeReason

export const AutocompleteOpenChange = S.Struct({
  open: S.Boolean,
  reason: AutocompleteOpenChangeReason,
})
export type AutocompleteOpenChange = typeof AutocompleteOpenChange.Type

export const AutocompleteValueChange = S.Struct({
  value: S.String,
  label: S.optional(S.String),
  itemValue: S.optional(S.String),
  reason: AutocompleteValueChangeReason,
})
export type AutocompleteValueChange = typeof AutocompleteValueChange.Type

export const AutocompleteHighlightChange = Combobox.ComboboxHighlightChange
export type AutocompleteHighlightChange = Combobox.ComboboxHighlightChange

export const AutocompleteItemDescriptor = Combobox.ComboboxItemDescriptor
export type AutocompleteItemDescriptor = Combobox.ComboboxItemDescriptor

export const AutocompleteOptions = S.Struct({
  id: S.String,
  open: S.Boolean,
  value: S.String,
  items: S.Array(AutocompleteItemDescriptor),
  highlightedValue: S.optional(S.String),
  placeholder: S.optional(S.String),
  name: S.optional(S.String),
  form: S.optional(S.String),
  forceMount: S.optional(S.Boolean),
  transitionStatus: S.optional(AutocompleteTransitionStatus),
  isDisabled: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
  isRequired: S.optional(S.Boolean),
  isReadOnly: S.optional(S.Boolean),
  mode: S.optional(AutocompleteMode),
  autoHighlight: S.optional(AutocompleteAutoHighlight),
  openOnInputClick: S.optional(S.Boolean),
  side: S.optional(AutocompleteSide),
  align: S.optional(AutocompleteAlign),
  sideOffset: S.optional(S.Number),
  alignOffset: S.optional(S.Number),
  collisionAvoidance: S.optional(S.Boolean),
  collisionPadding: S.optional(S.Number),
})
export type AutocompleteOptions = typeof AutocompleteOptions.Type

// UPDATE

const defaultSide: AutocompleteSide = 'bottom'
const defaultMode: AutocompleteMode = 'list'

export const {
  FocusCombobox: FocusAutocomplete,
  RestoreComboboxFocus: RestoreAutocompleteFocus,
  rootId,
  inputId,
  inputGroupId,
  triggerId,
  popupId,
  listId,
  positionerId,
  arrowId,
  valueId,
  clearId,
  collectionId,
  emptyId,
  itemId,
  itemFocusSelector,
  enabledItems,
  highlightedItem,
  highlightChange,
  clearHighlightChange,
} = Combobox

export const resolvedMode = (
  config: Pick<AutocompleteOptions, 'mode'>,
): AutocompleteMode => config.mode ?? defaultMode

export const filtersItems = (
  config: Pick<AutocompleteOptions, 'mode'>,
): boolean => {
  const mode = resolvedMode(config)

  return mode === 'list' || mode === 'both'
}

export const completesInline = (
  config: Pick<AutocompleteOptions, 'mode'>,
): boolean => {
  const mode = resolvedMode(config)

  return mode === 'inline' || mode === 'both'
}

export const filterValue = (
  config: Pick<AutocompleteOptions, 'mode' | 'value'>,
): string => (filtersItems(config) ? config.value : '')

export const displayValue = (
  config: Pick<
    AutocompleteOptions,
    'highlightedValue' | 'items' | 'mode' | 'value'
  >,
): string => {
  if (!completesInline(config)) {
    return config.value
  }

  return highlightedItem(config)?.label ?? config.value
}

export const filteredItems = (
  config: Pick<AutocompleteOptions, 'isDisabled' | 'items' | 'mode' | 'value'>,
): ReadonlyArray<AutocompleteItemDescriptor> =>
  Combobox.filteredItems({
    inputValue: config.value,
    filterValue: filterValue(config),
    isDisabled: config.isDisabled,
    items: config.items,
  })

export const firstFilteredItem = (
  config: Pick<AutocompleteOptions, 'isDisabled' | 'items' | 'mode' | 'value'>,
): AutocompleteItemDescriptor | undefined => filteredItems(config)[0]

export const nextHighlightedItem = (
  config: Pick<
    AutocompleteOptions,
    'highlightedValue' | 'isDisabled' | 'items' | 'mode' | 'value'
  >,
  direction: 'first' | 'last' | 'next' | 'previous',
): AutocompleteItemDescriptor | undefined =>
  Combobox.nextHighlightedItem(
    {
      highlightedValue: config.highlightedValue,
      inputValue: config.value,
      filterValue: filterValue(config),
      isDisabled: config.isDisabled,
      items: config.items,
    },
    direction,
  )

export const openChange = (
  open: boolean,
  reason: AutocompleteOpenChangeReason = 'none',
): AutocompleteOpenChange => ({
  open,
  reason,
})

export const valueChange = (
  value: string,
  reason: AutocompleteValueChangeReason = 'none',
): AutocompleteValueChange => ({
  value,
  reason,
})

export const itemValueChange = (
  item: AutocompleteItemDescriptor,
  reason: Extract<
    AutocompleteValueChangeReason,
    'item-press' | 'keyboard-select'
  > = 'item-press',
): AutocompleteValueChange => ({
  value: item.label,
  label: item.label,
  itemValue: item.value,
  reason,
})

export const clearValueChange = (
  reason: Extract<
    AutocompleteValueChangeReason,
    'clear-press' | 'input-clear'
  > = 'input-clear',
): AutocompleteValueChange => ({
  value: '',
  reason,
})

const comboboxOpenChange = (
  change: Combobox.ComboboxOpenChange,
): AutocompleteOpenChange => ({
  open: change.open,
  reason: change.reason,
})

const valueReasonFromCombobox = (
  reason: Combobox.ComboboxValueChangeReason,
): AutocompleteValueChangeReason => {
  if (reason === 'item-press' || reason === 'keyboard-select') {
    return reason
  }

  if (reason === 'input-clear' || reason === 'clear-press') {
    return reason
  }

  return 'none'
}

const valueChangeFromCombobox = (
  change: Combobox.ComboboxValueChange,
): AutocompleteValueChange => {
  if (change.reason === 'input-clear' || change.reason === 'clear-press') {
    return clearValueChange(change.reason)
  }

  return {
    value: change.label ?? change.value ?? '',
    label: change.label,
    itemValue: change.changedValue ?? change.value,
    reason: valueReasonFromCombobox(change.reason),
  }
}

const valueChangeFromInput = (
  change: Combobox.ComboboxInputValueChange,
): AutocompleteValueChange => ({
  value: change.value,
  reason: change.reason,
})

export const commandForOpenChange = (
  config: Pick<AutocompleteOptions, 'id'>,
  change: AutocompleteOpenChange,
) =>
  Combobox.commandForOpenChange(
    config,
    Combobox.openChange(
      change.open,
      change.reason === 'input-press' ? 'trigger-press' : change.reason,
    ),
  )

// VIEW

export type AutocompletePartAttributes<Message> =
  Combobox.ComboboxPartAttributes<Message>

export type AutocompleteItemAttributes<Message> =
  Combobox.ComboboxItemAttributes<Message>

export type AutocompleteAttributes<Message> = Omit<
  Combobox.ComboboxAttributes<Message>,
  'chipInput' | 'chipItems' | 'chips' | 'hiddenInputs' | 'selectedItems'
> &
  Readonly<{
    valueText: string
  }>

export type ViewConfig<Message> = AutocompleteOptions &
  Readonly<{
    toView: (attributes: AutocompleteAttributes<Message>) => Html
    onOpenChange?: (change: AutocompleteOpenChange) => Message
    onValueChange?: (change: AutocompleteValueChange) => Message
    onHighlightChange?: (change: AutocompleteHighlightChange) => Message
    onFocus?: Message
    onBlur?: Message
  }>

const resolvedSide = (
  config: Pick<AutocompleteOptions, 'side'>,
): AutocompleteSide => config.side ?? defaultSide

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<AutocompleteOptions, 'form' | 'name'>,
): ReadonlyArray<Attribute<Message>> => [
  ...(Predicate.isNotUndefined(config.name) ? [h.Name(config.name)] : []),
  ...(Predicate.isNotUndefined(config.form)
    ? [h.Attribute('form', config.form)]
    : []),
]

const inputClickAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> =>
  config.openOnInputClick === true &&
  config.open !== true &&
  config.isDisabled !== true &&
  config.isReadOnly !== true &&
  Predicate.isNotUndefined(config.onOpenChange)
    ? [h.OnClick(config.onOpenChange(openChange(true, 'input-press')))]
    : []

const inputGroupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isEmpty: boolean,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('popup-side', config.open ? resolvedSide(config) : ''),
  ...(isEmpty ? [h.DataAttribute('list-empty', '')] : []),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
]

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...(config.value === '' ? [] : [h.DataAttribute('filled', '')]),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'invalid', config.isInvalid),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
]

const optionalComboboxOptions = <Message>(
  config: ViewConfig<Message>,
): Partial<Combobox.ViewConfig<Message>> => {
  const {
    align,
    alignOffset,
    autoHighlight,
    collisionAvoidance,
    collisionPadding,
    forceMount,
    highlightedValue,
    isDisabled,
    isInvalid,
    isReadOnly,
    isRequired,
    placeholder,
    side,
    sideOffset,
    transitionStatus,
  } = config

  return {
    ...(highlightedValue === undefined ? {} : { highlightedValue }),
    ...(placeholder === undefined ? {} : { placeholder }),
    ...(forceMount === undefined ? {} : { forceMount }),
    ...(transitionStatus === undefined ? {} : { transitionStatus }),
    ...(isDisabled === undefined ? {} : { isDisabled }),
    ...(isInvalid === undefined ? {} : { isInvalid }),
    ...(isRequired === undefined ? {} : { isRequired }),
    ...(isReadOnly === undefined ? {} : { isReadOnly }),
    ...(autoHighlight === undefined ? {} : { autoHighlight }),
    ...(side === undefined ? {} : { side }),
    ...(align === undefined ? {} : { align }),
    ...(sideOffset === undefined ? {} : { sideOffset }),
    ...(alignOffset === undefined ? {} : { alignOffset }),
    ...(collisionAvoidance === undefined ? {} : { collisionAvoidance }),
    ...(collisionPadding === undefined ? {} : { collisionPadding }),
  }
}

const optionalComboboxCallbacks = <Message>(
  config: ViewConfig<Message>,
): Partial<Combobox.ViewConfig<Message>> => {
  const { onBlur, onFocus, onHighlightChange, onOpenChange, onValueChange } =
    config

  return {
    ...(onOpenChange === undefined
      ? {}
      : {
          onOpenChange: (change: Combobox.ComboboxOpenChange) =>
            onOpenChange(comboboxOpenChange(change)),
        }),
    ...(onValueChange === undefined
      ? {}
      : {
          onInputValueChange: (change: Combobox.ComboboxInputValueChange) =>
            onValueChange(valueChangeFromInput(change)),
          onValueChange: (change: Combobox.ComboboxValueChange) =>
            onValueChange(valueChangeFromCombobox(change)),
        }),
    ...(onHighlightChange === undefined ? {} : { onHighlightChange }),
    ...(onFocus === undefined ? {} : { onFocus }),
    ...(onBlur === undefined ? {} : { onBlur }),
  }
}

const comboboxConfig = <Message>(
  config: ViewConfig<Message>,
): Combobox.ViewConfig<Message> => {
  const { id, items, open, value } = config

  return {
    id,
    open,
    inputValue: value,
    displayInputValue: displayValue(config),
    filterValue: filterValue(config),
    items,
    values: [],
    showTriggerPlaceholder: false,
    ...optionalComboboxOptions(config),
    ...optionalComboboxCallbacks(config),
    toView: attributes => {
      const h = html<Message>()

      return config.toView({
        root: attributes.root,
        inputGroup: [
          ...attributes.inputGroup,
          ...inputGroupAttributes(h, config, attributes.isEmpty),
        ],
        input: [
          ...attributes.input,
          ...formOwnerAttributes(h, config),
          ...inputClickAttributes(h, config),
        ],
        trigger: [...attributes.trigger, ...triggerAttributes(h, config)],
        value: attributes.value,
        clear: attributes.clear,
        portal: attributes.portal,
        positioner: attributes.positioner,
        backdrop: attributes.backdrop,
        popup: attributes.popup,
        list: attributes.list,
        arrow: attributes.arrow,
        collection: attributes.collection,
        group: attributes.group,
        groupLabel: attributes.groupLabel,
        empty: attributes.empty,
        separator: attributes.separator,
        items: attributes.items,
        filteredItems: attributes.filteredItems,
        isMounted: attributes.isMounted,
        isOpen: attributes.isOpen,
        isEmpty: attributes.isEmpty,
        valueText: config.value,
      })
    },
  }
}

export const view = <Message>(config: ViewConfig<Message>): Html =>
  Combobox.view(comboboxConfig(config))

import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const ImageLoadingStatus = S.Union([
  S.Literal('idle'),
  S.Literal('loading'),
  S.Literal('loaded'),
  S.Literal('error'),
])
export type ImageLoadingStatus = typeof ImageLoadingStatus.Type

export const AvatarTransitionStatus = S.Union([
  S.Literal('idle'),
  S.Literal('starting'),
  S.Literal('ending'),
])
export type AvatarTransitionStatus = typeof AvatarTransitionStatus.Type

export const AvatarFallbackDelayStatus = S.Union([
  S.Literal('waiting'),
  S.Literal('elapsed'),
])
export type AvatarFallbackDelayStatus = typeof AvatarFallbackDelayStatus.Type

export const AvatarImageOptions = S.Struct({
  src: S.optional(S.String),
  srcSet: S.optional(S.String),
  sizes: S.optional(S.String),
  alt: S.optional(S.String),
  width: S.optional(S.String),
  height: S.optional(S.String),
  crossOrigin: S.optional(S.String),
  referrerPolicy: S.optional(S.String),
  transitionStatus: S.optional(AvatarTransitionStatus),
})
export type AvatarImageOptions = typeof AvatarImageOptions.Type

export const AvatarFallbackOptions = S.Struct({
  delayStatus: S.optional(AvatarFallbackDelayStatus),
})
export type AvatarFallbackOptions = typeof AvatarFallbackOptions.Type

export const AvatarOptions = S.Struct({
  imageLoadingStatus: ImageLoadingStatus,
  image: S.optional(AvatarImageOptions),
  fallback: S.optional(AvatarFallbackOptions),
})
export type AvatarOptions = typeof AvatarOptions.Type

export const AvatarPart = S.Union([
  S.Literal('root'),
  S.Literal('image'),
  S.Literal('fallback'),
])
export type AvatarPart = typeof AvatarPart.Type

export type AvatarState = Readonly<{
  imageLoadingStatus: ImageLoadingStatus
  transitionStatus: AvatarTransitionStatus
  shouldRenderImage: boolean
  shouldRenderFallback: boolean
}>

// UPDATE

const defaultTransitionStatus: AvatarTransitionStatus = 'idle'

export const avatarState = (options: AvatarOptions): AvatarState => {
  const transitionStatus =
    options.image?.transitionStatus ?? defaultTransitionStatus
  const shouldRenderImage =
    options.imageLoadingStatus === 'loaded' || transitionStatus === 'ending'
  const shouldRenderFallback =
    options.imageLoadingStatus !== 'loaded' &&
    options.fallback?.delayStatus !== 'waiting'

  return {
    imageLoadingStatus: options.imageLoadingStatus,
    transitionStatus,
    shouldRenderImage,
    shouldRenderFallback,
  }
}

// VIEW

export type AvatarAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  image: ReadonlyArray<Attribute<Message>>
  fallback: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = AvatarOptions &
  Readonly<{
    onImageLoaded?: Message
    onImageErrored?: Message
    toView: (attributes: AvatarAttributes<Message>, state: AvatarState) => Html
  }>

const statusAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  status: ImageLoadingStatus,
): ReadonlyArray<Attribute<Message>> => {
  if (status === 'loading') {
    return [h.DataAttribute('loading', '')]
  }

  if (status === 'loaded') {
    return [h.DataAttribute('loaded', '')]
  }

  if (status === 'error') {
    return [h.DataAttribute('error', '')]
  }

  return []
}

const transitionAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  status: AvatarTransitionStatus,
): ReadonlyArray<Attribute<Message>> => {
  if (status === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (status === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const optionalAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === undefined ? [] : [h.Attribute(name, value)]

const onErrorAttribute = <Message>(message: Message): Attribute<Message> => ({
  _tag: 'OnError',
  message,
})

const imageAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: AvatarState,
): ReadonlyArray<Attribute<Message>> => {
  const image = config.image ?? {}

  return [
    ...optionalAttribute(h, 'src', image.src),
    ...optionalAttribute(h, 'srcset', image.srcSet),
    ...optionalAttribute(h, 'sizes', image.sizes),
    ...optionalAttribute(h, 'alt', image.alt),
    ...optionalAttribute(h, 'width', image.width),
    ...optionalAttribute(h, 'height', image.height),
    ...optionalAttribute(h, 'crossorigin', image.crossOrigin),
    ...optionalAttribute(h, 'referrerpolicy', image.referrerPolicy),
    ...(config.onImageLoaded === undefined
      ? []
      : [h.OnLoad(config.onImageLoaded)]),
    ...(config.onImageErrored === undefined
      ? []
      : [onErrorAttribute(config.onImageErrored)]),
    ...statusAttributes(h, state.imageLoadingStatus),
    ...transitionAttributes(h, state.transitionStatus),
  ]
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const state = avatarState(config)
  const rootAndFallbackStatusAttributes = statusAttributes(
    h,
    state.imageLoadingStatus,
  )

  return config.toView(
    {
      root: [...rootAndFallbackStatusAttributes],
      image: imageAttributes(h, config, state),
      fallback: [...rootAndFallbackStatusAttributes],
    },
    state,
  )
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const ButtonType = S.Union([
  S.Literal('button'),
  S.Literal('submit'),
  S.Literal('reset'),
])
export type ButtonType = typeof ButtonType.Type

export const ButtonOptions = S.Struct({
  isDisabled: S.optional(S.Boolean),
  isFocusableWhenDisabled: S.optional(S.Boolean),
  isNativeButton: S.optional(S.Boolean),
  type: S.optional(ButtonType),
  isAutofocus: S.optional(S.Boolean),
})
export type ButtonOptions = typeof ButtonOptions.Type

// VIEW

export type ButtonAttributes<Message> = Readonly<{
  button: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = ButtonOptions &
  Readonly<{
    toView: (attributes: ButtonAttributes<Message>) => Html
    onClick?: Message
    onMouseDown?: Message
    onPointerDown?: Message
    onPointerUp?: Message
  }>

const activationKeys = new Set(['Enter', ' '])

const toSome = <Message>(message: Message): Option.Option<Message> =>
  Option.some(message)

const nativeDisabledAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  isFocusableWhenDisabled: boolean,
): ReadonlyArray<Attribute<Message>> =>
  isFocusableWhenDisabled
    ? [h.AriaDisabled(true), h.Tabindex(0), h.DataAttribute('disabled', '')]
    : [h.Disabled(true), h.Tabindex(0), h.DataAttribute('disabled', '')]

const nonNativeDisabledAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  isFocusableWhenDisabled: boolean,
): ReadonlyArray<Attribute<Message>> => [
  h.AriaDisabled(true),
  h.Tabindex(isFocusableWhenDisabled ? 0 : -1),
  h.DataAttribute('disabled', ''),
]

const disabledAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  isDisabled: boolean,
  isFocusableWhenDisabled: boolean,
  isNativeButton: boolean,
): ReadonlyArray<Attribute<Message>> => {
  if (!isDisabled) {
    return []
  }

  return isNativeButton
    ? nativeDisabledAttributes(h, isFocusableWhenDisabled)
    : nonNativeDisabledAttributes(h, isFocusableWhenDisabled)
}

const buttonKindAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  isNativeButton: boolean,
  type: ButtonType,
): ReadonlyArray<Attribute<Message>> =>
  isNativeButton
    ? [h.Type(type), h.Tabindex(0)]
    : [h.Role('button'), h.Tabindex(0)]

const clickAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  onClick: Message | undefined,
  isDisabled: boolean,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(onClick) && !isDisabled ? [h.OnClick(onClick)] : []

const mouseAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  onMouseDown: Message | undefined,
  isDisabled: boolean,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(onMouseDown) && !isDisabled
    ? [h.OnMouseDown(onMouseDown)]
    : []

const pointerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  onPointerDown: Message | undefined,
  onPointerUp: Message | undefined,
  isDisabled: boolean,
): ReadonlyArray<Attribute<Message>> => {
  if (isDisabled) {
    return []
  }

  const pointerDownAttributes = Predicate.isNotUndefined(onPointerDown)
    ? [h.OnPointerDown(() => toSome(onPointerDown))]
    : []
  const pointerUpAttributes = Predicate.isNotUndefined(onPointerUp)
    ? [h.OnPointerUp(() => toSome(onPointerUp))]
    : []

  return [...pointerDownAttributes, ...pointerUpAttributes]
}

const keyboardAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  onClick: Message | undefined,
  isDisabled: boolean,
  isNativeButton: boolean,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(onClick) && !isDisabled && !isNativeButton
    ? [
        h.OnKeyDownPreventDefault(key =>
          activationKeys.has(key) ? toSome(onClick) : Option.none(),
        ),
      ]
    : []

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()

  const {
    toView,
    onClick,
    onMouseDown,
    onPointerDown,
    onPointerUp,
    isDisabled = false,
    isFocusableWhenDisabled = false,
    isNativeButton = true,
    type = 'button',
    isAutofocus = false,
  } = config
  const autofocusAttributes = isAutofocus ? [h.Autofocus(true)] : []

  return toView({
    button: [
      ...buttonKindAttributes(h, isNativeButton, type),
      ...disabledAttributes(
        h,
        isDisabled,
        isFocusableWhenDisabled,
        isNativeButton,
      ),
      ...clickAttributes(h, onClick, isDisabled),
      ...mouseAttributes(h, onMouseDown, isDisabled),
      ...pointerAttributes(h, onPointerDown, onPointerUp, isDisabled),
      ...keyboardAttributes(h, onClick, isDisabled, isNativeButton),
      ...autofocusAttributes,
    ],
  })
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const CheckboxCheckedState = S.Union([
  S.Literal('checked'),
  S.Literal('unchecked'),
  S.Literal('indeterminate'),
])
export type CheckboxCheckedState = typeof CheckboxCheckedState.Type

export const CheckboxChangeReason = S.Literal('none')
export type CheckboxChangeReason = typeof CheckboxChangeReason.Type

export const CheckboxCheckedChange = S.Struct({
  checkedState: CheckboxCheckedState,
  reason: CheckboxChangeReason,
})
export type CheckboxCheckedChange = typeof CheckboxCheckedChange.Type

export const CheckboxOptions = S.Struct({
  id: S.optional(S.String),
  name: S.optional(S.String),
  form: S.optional(S.String),
  value: S.optional(S.String),
  uncheckedValue: S.optional(S.String),
  checkedState: CheckboxCheckedState,
  isDisabled: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
  isRequired: S.optional(S.Boolean),
  isReadOnly: S.optional(S.Boolean),
  isValid: S.optional(S.Boolean),
  isFieldInvalid: S.optional(S.Boolean),
  isDirty: S.optional(S.Boolean),
  isTouched: S.optional(S.Boolean),
  isFilled: S.optional(S.Boolean),
  isFocused: S.optional(S.Boolean),
})
export type CheckboxOptions = typeof CheckboxOptions.Type

// UPDATE

export const isChecked = (checkedState: CheckboxCheckedState): boolean =>
  checkedState === 'checked'

export const isIndeterminate = (checkedState: CheckboxCheckedState): boolean =>
  checkedState === 'indeterminate'

export const nextCheckedState = (
  checkedState: CheckboxCheckedState,
): CheckboxCheckedState =>
  checkedState === 'checked' ? 'unchecked' : 'checked'

export const checkedChange = (
  checkedState: CheckboxCheckedState,
): CheckboxCheckedChange => ({
  checkedState,
  reason: 'none',
})

// VIEW

export type CheckboxAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
  input: ReadonlyArray<Attribute<Message>>
  uncheckedInput: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = CheckboxOptions &
  Readonly<{
    toView: (attributes: CheckboxAttributes<Message>) => Html
    onCheckedChange?: (change: CheckboxCheckedChange) => Message
    onFocus?: Message
    onBlur?: Message
    keepIndicatorMounted?: boolean
  }>

const activationKeys = new Set([' '])

const visuallyHiddenInputStyle =
  'clip-path: inset(50%); overflow: hidden; white-space: nowrap; border: 0px; padding: 0px; width: 1px; height: 1px; margin: -1px; position: fixed; top: 0px; left: 0px;'

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const checkedStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  checkedState: CheckboxCheckedState,
): ReadonlyArray<Attribute<Message>> =>
  isIndeterminate(checkedState)
    ? [h.DataAttribute('indeterminate', '')]
    : [h.DataAttribute(checkedState, '')]

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ViewConfig<Message>,
    | 'checkedState'
    | 'isDirty'
    | 'isDisabled'
    | 'isFieldInvalid'
    | 'isFilled'
    | 'isFocused'
    | 'isReadOnly'
    | 'isRequired'
    | 'isTouched'
    | 'isValid'
  >,
): ReadonlyArray<Attribute<Message>> => [
  ...checkedStateDataAttributes(h, config.checkedState),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'valid', config.isValid),
  ...booleanDataAttribute(h, 'invalid', config.isFieldInvalid),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'filled', config.isFilled),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
]

const canActivate = (
  config: Pick<
    ViewConfig<unknown>,
    'checkedState' | 'isDisabled' | 'isReadOnly'
  >,
): boolean =>
  config.isDisabled !== true &&
  config.isReadOnly !== true &&
  !isIndeterminate(config.checkedState)

const activationMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'checkedState' | 'isDisabled' | 'isReadOnly' | 'onCheckedChange'
  >,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onCheckedChange) && canActivate(config)
    ? Option.some(
        config.onCheckedChange(
          checkedChange(nextCheckedState(config.checkedState)),
        ),
      )
    : Option.none()

const eventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(activationMessage(config), {
    onNone: () => [],
    onSome: message => [
      h.OnClick(message),
      h.OnKeyDownPreventDefault(key =>
        activationKeys.has(key) ? Option.some(message) : Option.none(),
      ),
    ],
  })

const focusAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'onBlur' | 'onFocus'>,
): ReadonlyArray<Attribute<Message>> => [
  ...(Predicate.isNotUndefined(config.onFocus)
    ? [h.OnFocus(config.onFocus)]
    : []),
  ...(Predicate.isNotUndefined(config.onBlur) ? [h.OnBlur(config.onBlur)] : []),
]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('checkbox'),
  h.AriaChecked(
    isIndeterminate(config.checkedState)
      ? 'mixed'
      : isChecked(config.checkedState),
  ),
  h.Tabindex(config.isDisabled === true ? -1 : 0),
  ...(config.isDisabled === true ? [h.AriaDisabled(true)] : []),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.AriaReadonly(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.AriaRequired(value),
  ),
  ...(config.isInvalid === true ? [h.AriaInvalid(true)] : []),
  ...stateDataAttributes(h, config),
  ...eventAttributes(h, config),
  ...focusAttributes(h, config),
]

const inputValueAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  value: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [h.Value(value)] : []

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  form: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(form) ? [h.Attribute('form', form)] : []

const inputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('checkbox'),
  h.AriaHidden(true),
  h.Tabindex(-1),
  h.Checked(isChecked(config.checkedState)),
  h.Attribute('style', visuallyHiddenInputStyle),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...optionalAttribute<Message>(config.name, value => h.Name(value)),
  ...formOwnerAttributes(h, config.form),
  ...inputValueAttributes(h, config.value),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.Disabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.Required(value),
  ),
  ...Option.match(activationMessage(config), {
    onNone: () => [],
    onSome: message => [h.OnClick(message)],
  }),
]

const uncheckedInputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => {
  if (
    isChecked(config.checkedState) ||
    config.isDisabled === true ||
    config.name === undefined ||
    config.uncheckedValue === undefined
  ) {
    return []
  }

  return [
    h.Type('hidden'),
    h.Name(config.name),
    h.Value(config.uncheckedValue),
    ...formOwnerAttributes(h, config.form),
  ]
}

const indicatorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> =>
  config.keepIndicatorMounted === true || config.checkedState !== 'unchecked'
    ? stateDataAttributes(h, config)
    : []

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()

  return config.toView({
    root: rootAttributes(h, config),
    indicator: indicatorAttributes(h, config),
    input: inputAttributes(h, config),
    uncheckedInput: uncheckedInputAttributes(h, config),
  })
}

import {
  Array as EffectArray,
  Option,
  Order,
  Predicate,
  Schema as S,
} from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import * as Checkbox from './checkbox'

// MODEL

export const CheckboxGroupChangeReason = S.Literal('none')
export type CheckboxGroupChangeReason = typeof CheckboxGroupChangeReason.Type

export const CheckboxGroupValueChange = S.Struct({
  value: S.Array(S.String),
  checkedState: Checkbox.CheckboxCheckedState,
  reason: CheckboxGroupChangeReason,
  changedValue: S.optional(S.String),
})
export type CheckboxGroupValueChange = typeof CheckboxGroupValueChange.Type

export const CheckboxGroupItemDescriptor = S.Struct({
  id: S.optional(S.String),
  value: S.String,
  name: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
  isRequired: S.optional(S.Boolean),
  isReadOnly: S.optional(S.Boolean),
})
export type CheckboxGroupItemDescriptor =
  typeof CheckboxGroupItemDescriptor.Type

export const CheckboxGroupOptions = S.Struct({
  id: S.optional(S.String),
  ariaLabelledBy: S.optional(S.String),
  ariaDescribedBy: S.optional(S.String),
  name: S.optional(S.String),
  form: S.optional(S.String),
  value: S.Array(S.String),
  allValues: S.optional(S.Array(S.String)),
  items: S.Array(CheckboxGroupItemDescriptor),
  hasParent: S.optional(S.Boolean),
  parentId: S.optional(S.String),
  parentName: S.optional(S.String),
  parentValue: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
  isRequired: S.optional(S.Boolean),
  isReadOnly: S.optional(S.Boolean),
  isValid: S.optional(S.Boolean),
  isFieldInvalid: S.optional(S.Boolean),
  isDirty: S.optional(S.Boolean),
  isTouched: S.optional(S.Boolean),
  isFilled: S.optional(S.Boolean),
  isFocused: S.optional(S.Boolean),
})
export type CheckboxGroupOptions = typeof CheckboxGroupOptions.Type

// UPDATE

export const canonicalValue = (
  value: ReadonlyArray<string>,
  allValues?: ReadonlyArray<string>,
): ReadonlyArray<string> => {
  const unique = [...new Set(value)]

  if (allValues === undefined) {
    return EffectArray.sort(unique, Order.String)
  }

  const allValueSet = new Set(allValues)
  const orderedKnownValues = allValues.filter(entry => unique.includes(entry))
  const orderedExtraValues = EffectArray.sort(
    unique.filter(entry => !allValueSet.has(entry)),
    Order.String,
  )

  return [...orderedKnownValues, ...orderedExtraValues]
}

export const valuesAreEqual = (
  left: ReadonlyArray<string>,
  right: ReadonlyArray<string>,
  allValues?: ReadonlyArray<string>,
): boolean => {
  const canonicalLeft = canonicalValue(left, allValues)
  const canonicalRight = canonicalValue(right, allValues)

  return (
    canonicalLeft.length === canonicalRight.length &&
    canonicalLeft.every((entry, index) => entry === canonicalRight[index])
  )
}

export const isChecked = (
  groupValue: ReadonlyArray<string>,
  item: Pick<CheckboxGroupItemDescriptor, 'value'>,
): boolean => groupValue.includes(item.value)

export const checkedState = (
  groupValue: ReadonlyArray<string>,
  item: Pick<CheckboxGroupItemDescriptor, 'value'>,
): Checkbox.CheckboxCheckedState =>
  isChecked(groupValue, item) ? 'checked' : 'unchecked'

const resolvedAllValues = (
  config: Pick<CheckboxGroupOptions, 'allValues' | 'items'>,
): ReadonlyArray<string> =>
  config.allValues === undefined
    ? config.items.map(item => item.value)
    : config.allValues

export const parentCheckedState = (
  groupValue: ReadonlyArray<string>,
  allValues: ReadonlyArray<string>,
): Checkbox.CheckboxCheckedState => {
  const selectedValueCount = canonicalValue(groupValue, allValues).filter(
    entry => allValues.includes(entry),
  ).length

  if (selectedValueCount === 0) {
    return 'unchecked'
  }

  return selectedValueCount === allValues.length ? 'checked' : 'indeterminate'
}

export const valueChange = (
  value: ReadonlyArray<string>,
  checkedStateValue: Checkbox.CheckboxCheckedState,
  changedValue?: string,
): CheckboxGroupValueChange => ({
  value: [...value],
  checkedState: checkedStateValue,
  reason: 'none',
  ...(changedValue === undefined ? {} : { changedValue }),
})

export const itemValueChange = (
  groupValue: ReadonlyArray<string>,
  allValues: ReadonlyArray<string>,
  item: Pick<CheckboxGroupItemDescriptor, 'value'>,
  nextCheckedState: Checkbox.CheckboxCheckedState,
): CheckboxGroupValueChange => {
  const nextValue =
    nextCheckedState === 'checked'
      ? canonicalValue([...groupValue, item.value], allValues)
      : canonicalValue(
          groupValue.filter(entry => entry !== item.value),
          allValues,
        )

  return valueChange(nextValue, nextCheckedState, item.value)
}

export const parentValueChange = (
  groupValue: ReadonlyArray<string>,
  allValues: ReadonlyArray<string>,
  items: ReadonlyArray<CheckboxGroupItemDescriptor>,
): CheckboxGroupValueChange => {
  const selectedValue = canonicalValue(groupValue, allValues)
  const selectedValueSet = new Set(selectedValue)
  const disabledValueSet = new Set(
    items.filter(item => item.isDisabled === true).map(item => item.value),
  )
  const none = allValues.filter(
    valueEntry =>
      disabledValueSet.has(valueEntry) && selectedValueSet.has(valueEntry),
  )
  const all = allValues.filter(
    valueEntry =>
      !disabledValueSet.has(valueEntry) || selectedValueSet.has(valueEntry),
  )
  const nextValue = valuesAreEqual(selectedValue, all, allValues) ? none : all

  return valueChange(
    canonicalValue(nextValue, allValues),
    parentCheckedState(nextValue, allValues),
  )
}

// VIEW

export type CheckboxGroupItemAttributes<Message> = Readonly<{
  item: CheckboxGroupItemDescriptor
  root: ReadonlyArray<Attribute<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
  input: ReadonlyArray<Attribute<Message>>
}>

export type CheckboxGroupParentAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
  input: ReadonlyArray<Attribute<Message>>
}>

export type CheckboxGroupAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  parent: Option.Option<CheckboxGroupParentAttributes<Message>>
  items: ReadonlyArray<CheckboxGroupItemAttributes<Message>>
}>

export type ViewConfig<Message> = CheckboxGroupOptions &
  Readonly<{
    toView: (attributes: CheckboxGroupAttributes<Message>) => Html
    onValueChange?: (change: CheckboxGroupValueChange) => Message
    onFocus?: Message
    onBlur?: Message
    keepIndicatorMounted?: boolean
  }>

const activationKeys = new Set([' '])

const visuallyHiddenInputStyle =
  'clip-path: inset(50%); overflow: hidden; white-space: nowrap; border: 0px; padding: 0px; width: 1px; height: 1px; margin: -1px; position: fixed; top: 0px; left: 0px;'

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const checkedStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: Checkbox.CheckboxCheckedState,
): ReadonlyArray<Attribute<Message>> =>
  Checkbox.isIndeterminate(state)
    ? [h.DataAttribute('indeterminate', '')]
    : [h.DataAttribute(state, '')]

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    CheckboxGroupOptions,
    | 'isDirty'
    | 'isDisabled'
    | 'isFieldInvalid'
    | 'isFilled'
    | 'isFocused'
    | 'isReadOnly'
    | 'isRequired'
    | 'isTouched'
    | 'isValid'
  >,
): ReadonlyArray<Attribute<Message>> => [
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'valid', config.isValid),
  ...booleanDataAttribute(h, 'invalid', config.isFieldInvalid),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'filled', config.isFilled),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
]

const checkboxStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    CheckboxGroupOptions,
    | 'isDirty'
    | 'isDisabled'
    | 'isFieldInvalid'
    | 'isFilled'
    | 'isFocused'
    | 'isReadOnly'
    | 'isRequired'
    | 'isTouched'
    | 'isValid'
  >,
  state: Checkbox.CheckboxCheckedState,
  item?: Pick<
    CheckboxGroupItemDescriptor,
    'isDisabled' | 'isInvalid' | 'isReadOnly' | 'isRequired'
  >,
): ReadonlyArray<Attribute<Message>> => [
  ...checkedStateDataAttributes(h, state),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled || item?.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly || item?.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired || item?.isRequired),
  ...booleanDataAttribute(h, 'valid', config.isValid),
  ...booleanDataAttribute(
    h,
    'invalid',
    config.isFieldInvalid || item?.isInvalid,
  ),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'filled', config.isFilled),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
]

const focusAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'onBlur' | 'onFocus'>,
): ReadonlyArray<Attribute<Message>> => [
  ...(Predicate.isNotUndefined(config.onFocus)
    ? [h.OnFocus(config.onFocus)]
    : []),
  ...(Predicate.isNotUndefined(config.onBlur) ? [h.OnBlur(config.onBlur)] : []),
]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('group'),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...optionalAttribute<Message>(config.ariaLabelledBy, value =>
    h.AriaLabelledBy(value),
  ),
  ...optionalAttribute<Message>(config.ariaDescribedBy, value =>
    h.AriaDescribedBy(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.AriaReadonly(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.AriaRequired(value),
  ),
  ...(config.isInvalid === true ? [h.AriaInvalid(true)] : []),
  ...stateDataAttributes(h, config),
  ...focusAttributes(h, config),
]

const parentId = (
  config: Pick<CheckboxGroupOptions, 'id' | 'parentId'>,
): string | undefined =>
  config.parentId ??
  (config.id === undefined ? undefined : `${config.id}-parent`)

const childRootId = (
  config: Pick<CheckboxGroupOptions, 'id' | 'parentId'>,
  item: Pick<CheckboxGroupItemDescriptor, 'id' | 'value'>,
): string | undefined => {
  const id = parentId(config)

  return item.id ?? (id === undefined ? undefined : `${id}-${item.value}`)
}

const checkboxAriaChecked = (
  state: Checkbox.CheckboxCheckedState,
): boolean | 'mixed' =>
  Checkbox.isIndeterminate(state) ? 'mixed' : Checkbox.isChecked(state)

const canActivateItem = (
  config: Pick<CheckboxGroupOptions, 'isDisabled' | 'isReadOnly'>,
  item?: Pick<CheckboxGroupItemDescriptor, 'isDisabled' | 'isReadOnly'>,
): boolean =>
  config.isDisabled !== true &&
  config.isReadOnly !== true &&
  item?.isDisabled !== true &&
  item?.isReadOnly !== true

const itemActivationMessage = <Message>(
  config: ViewConfig<Message>,
  item: CheckboxGroupItemDescriptor,
  nextCheckedState: Checkbox.CheckboxCheckedState,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onValueChange) &&
  canActivateItem(config, item)
    ? Option.some(
        config.onValueChange(
          itemValueChange(
            config.value,
            resolvedAllValues(config),
            item,
            nextCheckedState,
          ),
        ),
      )
    : Option.none()

const parentActivationMessage = <Message>(
  config: ViewConfig<Message>,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onValueChange) && canActivateItem(config)
    ? Option.some(
        config.onValueChange(
          parentValueChange(
            config.value,
            resolvedAllValues(config),
            config.items,
          ),
        ),
      )
    : Option.none()

const checkboxEventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  maybeMessage: Option.Option<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(maybeMessage, {
    onNone: () => [],
    onSome: message => [
      h.OnClick(message),
      h.OnKeyDownPreventDefault(key =>
        activationKeys.has(key) ? Option.some(message) : Option.none(),
      ),
    ],
  })

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: CheckboxGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> => {
  const state = checkedState(config.value, item)

  return [
    h.Role('checkbox'),
    h.AriaChecked(checkboxAriaChecked(state)),
    h.Tabindex(canActivateItem(config, item) ? 0 : -1),
    ...optionalAttribute<Message>(childRootId(config, item), value =>
      h.Id(value),
    ),
    ...optionalBooleanAttribute<Message>(
      config.isDisabled === true || item.isDisabled === true ? true : undefined,
      value => h.AriaDisabled(value),
    ),
    ...optionalBooleanAttribute<Message>(
      config.isReadOnly === true || item.isReadOnly === true ? true : undefined,
      value => h.AriaReadonly(value),
    ),
    ...optionalBooleanAttribute<Message>(
      config.isRequired === true || item.isRequired === true ? true : undefined,
      value => h.AriaRequired(value),
    ),
    ...(config.isInvalid === true || item.isInvalid === true
      ? [h.AriaInvalid(true)]
      : []),
    ...checkboxStateDataAttributes(h, config, state, item),
    ...checkboxEventAttributes(
      h,
      itemActivationMessage(config, item, Checkbox.nextCheckedState(state)),
    ),
  ]
}

const inputName = (
  config: Pick<CheckboxGroupOptions, 'name'>,
  item: Pick<CheckboxGroupItemDescriptor, 'name'>,
): string | undefined => item.name ?? config.name

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  form: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(form) ? [h.Attribute('form', form)] : []

const inputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: CheckboxGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> => {
  const state = checkedState(config.value, item)
  const maybeMessage = itemActivationMessage(
    config,
    item,
    Checkbox.nextCheckedState(state),
  )

  return [
    h.Type('checkbox'),
    h.AriaHidden(true),
    h.Tabindex(-1),
    h.Checked(Checkbox.isChecked(state)),
    h.Value(item.value),
    h.Attribute('style', visuallyHiddenInputStyle),
    ...optionalAttribute<Message>(childRootId(config, item), value =>
      h.Id(`${value}-input`),
    ),
    ...optionalAttribute<Message>(inputName(config, item), value =>
      h.Name(value),
    ),
    ...formOwnerAttributes(h, config.form),
    ...optionalBooleanAttribute<Message>(
      config.isDisabled === true || item.isDisabled === true ? true : undefined,
      value => h.Disabled(value),
    ),
    ...optionalBooleanAttribute<Message>(
      config.isReadOnly === true || item.isReadOnly === true ? true : undefined,
      value => h.Readonly(value),
    ),
    ...optionalBooleanAttribute<Message>(
      config.isRequired === true || item.isRequired === true ? true : undefined,
      value => h.Required(value),
    ),
    ...Option.match(maybeMessage, {
      onNone: () => [],
      onSome: message => [h.OnClick(message)],
    }),
  ]
}

const indicatorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: Checkbox.CheckboxCheckedState,
  item?: CheckboxGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> =>
  config.keepIndicatorMounted === true || state !== 'unchecked'
    ? checkboxStateDataAttributes(h, config, state, item)
    : []

const parentControls = (
  config: Pick<CheckboxGroupOptions, 'id' | 'items' | 'parentId'>,
): string | undefined => {
  const ids = config.items
    .map(item => childRootId(config, item))
    .filter(Predicate.isNotUndefined)

  return ids.length === 0 ? undefined : ids.join(' ')
}

const parentRootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => {
  const state = parentCheckedState(config.value, resolvedAllValues(config))

  return [
    h.Role('checkbox'),
    h.AriaChecked(checkboxAriaChecked(state)),
    h.Tabindex(canActivateItem(config) ? 0 : -1),
    h.DataAttribute('parent', ''),
    ...optionalAttribute<Message>(parentId(config), value => h.Id(value)),
    ...optionalAttribute<Message>(parentControls(config), value =>
      h.AriaControls(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
      h.AriaDisabled(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
      h.AriaReadonly(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isRequired, value =>
      h.AriaRequired(value),
    ),
    ...(config.isInvalid === true ? [h.AriaInvalid(true)] : []),
    ...checkboxStateDataAttributes(h, config, state),
    ...checkboxEventAttributes(h, parentActivationMessage(config)),
  ]
}

const parentInputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => {
  const state = parentCheckedState(config.value, resolvedAllValues(config))
  const maybeMessage = parentActivationMessage(config)

  return [
    h.Type('checkbox'),
    h.AriaHidden(true),
    h.Tabindex(-1),
    h.Checked(Checkbox.isChecked(state)),
    h.Attribute('style', visuallyHiddenInputStyle),
    ...optionalAttribute<Message>(parentId(config), value =>
      h.Id(`${value}-input`),
    ),
    ...optionalAttribute<Message>(config.parentName, value => h.Name(value)),
    ...optionalAttribute<Message>(config.parentValue, value => h.Value(value)),
    ...formOwnerAttributes(h, config.form),
    ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
      h.Disabled(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
      h.Readonly(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isRequired, value =>
      h.Required(value),
    ),
    ...Option.match(maybeMessage, {
      onNone: () => [],
      onSome: message => [h.OnClick(message)],
    }),
  ]
}

const parentAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): Option.Option<CheckboxGroupParentAttributes<Message>> =>
  config.hasParent === true
    ? Option.some({
        root: parentRootAttributes(h, config),
        indicator: indicatorAttributes(
          h,
          config,
          parentCheckedState(config.value, resolvedAllValues(config)),
        ),
        input: parentInputAttributes(h, config),
      })
    : Option.none()

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()

  return config.toView({
    root: rootAttributes(h, config),
    parent: parentAttributes(h, config),
    items: config.items.map(item => ({
      item,
      root: itemAttributes(h, config, item),
      indicator: indicatorAttributes(
        h,
        config,
        checkedState(config.value, item),
        item,
      ),
      input: inputAttributes(h, config, item),
    })),
  })
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const CollapsibleTransitionStatus = S.Union([
  S.Literal('idle'),
  S.Literal('starting'),
  S.Literal('ending'),
])
export type CollapsibleTransitionStatus =
  typeof CollapsibleTransitionStatus.Type

export const CollapsibleChangeReason = S.Union([
  S.Literal('trigger-press'),
  S.Literal('none'),
])
export type CollapsibleChangeReason = typeof CollapsibleChangeReason.Type

export const CollapsibleOpenChange = S.Struct({
  open: S.Boolean,
  reason: CollapsibleChangeReason,
})
export type CollapsibleOpenChange = typeof CollapsibleOpenChange.Type

export const CollapsiblePanelGeometry = S.Struct({
  height: S.optional(S.Number),
  width: S.optional(S.Number),
})
export type CollapsiblePanelGeometry = typeof CollapsiblePanelGeometry.Type

export const CollapsiblePanelDescriptor = S.Struct({
  id: S.optional(S.String),
  label: S.optional(S.String),
  keepMounted: S.optional(S.Boolean),
  hiddenUntilFound: S.optional(S.Boolean),
  geometry: S.optional(CollapsiblePanelGeometry),
})
export type CollapsiblePanelDescriptor = typeof CollapsiblePanelDescriptor.Type

export const CollapsibleOptions = S.Struct({
  id: S.optional(S.String),
  open: S.Boolean,
  isDisabled: S.optional(S.Boolean),
  transitionStatus: S.optional(CollapsibleTransitionStatus),
  panel: S.optional(CollapsiblePanelDescriptor),
})
export type CollapsibleOptions = typeof CollapsibleOptions.Type

// UPDATE

export const openChange = (
  open: boolean,
  reason: CollapsibleChangeReason = 'none',
): CollapsibleOpenChange => ({
  open,
  reason,
})

export const triggerOpenChange = (open: boolean): CollapsibleOpenChange =>
  openChange(!open, 'trigger-press')

// VIEW

export type CollapsiblePanelAttributes<Message> = Readonly<{
  panel: CollapsiblePanelDescriptor
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type CollapsibleAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  trigger: ReadonlyArray<Attribute<Message>>
  panel: CollapsiblePanelAttributes<Message>
}>

export type ViewConfig<Message> = CollapsibleOptions &
  Readonly<{
    toView: (attributes: CollapsibleAttributes<Message>) => Html
    onOpenChange?: (change: CollapsibleOpenChange) => Message
  }>

const activationKeys = new Set([' ', 'Enter'])
const defaultPanel: CollapsiblePanelDescriptor = {}

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const transitionDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  transitionStatus: CollapsibleTransitionStatus | undefined,
): ReadonlyArray<Attribute<Message>> => {
  if (transitionStatus === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (transitionStatus === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const openStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  open: boolean,
): ReadonlyArray<Attribute<Message>> =>
  open ? [h.DataAttribute('open', '')] : [h.DataAttribute('closed', '')]

const panelId = (
  config: Pick<CollapsibleOptions, 'id' | 'panel'>,
): string | undefined => config.panel?.id ?? config.id

const canActivate = (
  config: Pick<ViewConfig<unknown>, 'isDisabled' | 'onOpenChange'>,
): boolean =>
  config.isDisabled !== true && Predicate.isNotUndefined(config.onOpenChange)

const activationMessage = <Message>(
  config: ViewConfig<Message>,
): Option.Option<Message> => {
  if (!canActivate(config) || config.onOpenChange === undefined) {
    return Option.none()
  }

  return Option.some(config.onOpenChange(triggerOpenChange(config.open)))
}

const eventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(activationMessage(config), {
    onNone: () => [],
    onSome: message => [
      h.OnClick(message),
      h.OnKeyDownPreventDefault(key =>
        activationKeys.has(key) ? Option.some(message) : Option.none(),
      ),
    ],
  })

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...openStateDataAttributes(h, config.open),
  ...transitionDataAttributes(h, config.transitionStatus),
]

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('button'),
  h.AriaExpanded(config.open),
  ...optionalAttribute<Message>(
    config.open ? panelId(config) : undefined,
    value => h.AriaControls(value),
  ),
  ...booleanDataAttribute(h, 'panel-open', config.open),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...(config.isDisabled === true ? [h.AriaDisabled(true)] : []),
  ...transitionDataAttributes(h, config.transitionStatus),
  ...eventAttributes(h, config),
]

const panelStyle = (
  geometry: CollapsiblePanelGeometry | undefined,
): Record<string, string> => ({
  '--collapsible-panel-height':
    geometry?.height === undefined ? 'auto' : `${geometry.height}px`,
  '--collapsible-panel-width':
    geometry?.width === undefined ? 'auto' : `${geometry.width}px`,
})

const hiddenAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  panel: CollapsiblePanelDescriptor,
  open: boolean,
): ReadonlyArray<Attribute<Message>> => {
  if (open) {
    return []
  }

  return panel.hiddenUntilFound === true
    ? [h.Attribute('hidden', 'until-found')]
    : [h.Hidden(true)]
}

const panelAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): CollapsiblePanelAttributes<Message> => {
  const panel = config.panel ?? defaultPanel
  const isMounted =
    config.open || panel.keepMounted === true || panel.hiddenUntilFound === true
  const attrs: ReadonlyArray<Attribute<Message>> = [
    ...optionalAttribute<Message>(panelId(config), value => h.Id(value)),
    ...hiddenAttributes(h, panel, config.open),
    h.Style(panelStyle(panel.geometry)),
    ...openStateDataAttributes(h, config.open),
    ...transitionDataAttributes(h, config.transitionStatus),
  ]

  return {
    panel,
    root: isMounted ? attrs : [],
    isMounted,
    isOpen: config.open,
  }
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()

  return config.toView({
    root: rootAttributes(h, config),
    trigger: triggerAttributes(h, config),
    panel: panelAttributes(h, config),
  })
}

