// UPDATE

const defaultSide: ComboboxSide = 'bottom'
const defaultAlign: ComboboxAlign = 'center'
const defaultSideOffset = 0
const defaultAlignOffset = 0
const defaultCollisionAvoidance = true
const defaultCollisionPadding = 0

const activationKeys = new Set(['Enter', ' '])

const keyboardDirection = (
  key: string,
): 'first' | 'last' | 'next' | 'previous' | undefined => {
  if (key === 'ArrowDown') {
    return 'next'
  }

  if (key === 'ArrowUp') {
    return 'previous'
  }

  if (key === 'Home') {
    return 'first'
  }

  if (key === 'End') {
    return 'last'
  }

  return undefined
}

export const {
  FocusPopover: FocusCombobox,
  RestorePopoverFocus: RestoreComboboxFocus,
} = Popover

export const resolvedSelectionMode = (
  config: Pick<ComboboxOptions, 'selectionMode'>,
): ComboboxSelectionMode => config.selectionMode ?? 'single'

export const isMultiple = (
  config: Pick<ComboboxOptions, 'selectionMode'>,
): boolean => resolvedSelectionMode(config) === 'multiple'

export const rootId = (config: Pick<ComboboxOptions, 'id'>): string => config.id

export const inputId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-input`

export const inputGroupId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-input-group`

export const triggerId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-trigger`

export const popupId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-popup`

export const listId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-list`

export const positionerId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-positioner`

export const arrowId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-arrow`

export const valueId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-value`

export const clearId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-clear`

export const chipsId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-chips`

export const emptyId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-empty`

export const collectionId = (config: Pick<ComboboxOptions, 'id'>): string =>
  `${config.id}-collection`

export const itemId = (
  config: Pick<ComboboxOptions, 'id'>,
  item: Pick<ComboboxItemDescriptor, 'id' | 'value'>,
): string => item.id ?? `${config.id}-item-${item.value}`

export const chipId = (
  config: Pick<ComboboxOptions, 'id'>,
  item: Pick<ComboboxItemDescriptor, 'value'>,
): string => `${config.id}-chip-${item.value}`

export const chipRemoveId = (
  config: Pick<ComboboxOptions, 'id'>,
  item: Pick<ComboboxItemDescriptor, 'value'>,
): string => `${config.id}-chip-${item.value}-remove`

export const itemFocusSelector = (
  config: Pick<ComboboxOptions, 'id'>,
  item: Pick<ComboboxItemDescriptor, 'id' | 'value'>,
): string => `#${itemId(config, item)}`

export const chipFocusSelector = (
  config: Pick<ComboboxOptions, 'id'>,
  item: Pick<ComboboxItemDescriptor, 'value'>,
): string => `#${chipId(config, item)}`

export const selectedValues = (
  config: Pick<ComboboxOptions, 'selectionMode' | 'value' | 'values'>,
): ReadonlyArray<string> => {
  if (isMultiple(config)) {
    return config.values ?? []
  }

  if (config.value === undefined) {
    return []
  }

  return [config.value]
}

export const selectedItems = (
  config: Pick<ComboboxOptions, 'items' | 'selectionMode' | 'value' | 'values'>,
): ReadonlyArray<ComboboxItemDescriptor> => {
  const values = new Set(selectedValues(config))

  return config.items.filter(item => values.has(item.value))
}

export const selectedItem = (
  config: Pick<ComboboxOptions, 'items' | 'value'>,
): ComboboxItemDescriptor | undefined =>
  config.items.find(item => item.value === config.value)

export const displayValue = (
  config: Pick<
    ComboboxOptions,
    'items' | 'placeholder' | 'selectionMode' | 'value' | 'values'
  >,
): string =>
  isMultiple(config)
    ? selectedItems(config)
        .map(item => item.label)
        .join(', ')
    : (selectedItem(config)?.label ?? config.placeholder ?? '')

export const inputDisplayValue = (
  config: Pick<
    ComboboxOptions,
    'displayInputValue' | 'inputValue' | 'items' | 'selectionMode' | 'value'
  >,
): string => {
  if (config.displayInputValue !== undefined) {
    return config.displayInputValue
  }

  if (isMultiple(config)) {
    return config.inputValue
  }

  if (config.inputValue === '') {
    return selectedItem(config)?.label ?? ''
  }

  return config.inputValue
}

export const hasSelectedValue = (
  config: Pick<ComboboxOptions, 'selectionMode' | 'value' | 'values'>,
): boolean => selectedValues(config).length > 0

export const enabledItems = (
  config: Pick<ComboboxOptions, 'isDisabled' | 'items'>,
): ReadonlyArray<ComboboxItemDescriptor> =>
  config.isDisabled === true
    ? []
    : config.items.filter(item => item.isDisabled !== true)

export const filteredItems = (
  config: Pick<
    ComboboxOptions,
    'filterValue' | 'inputValue' | 'isDisabled' | 'items'
  >,
): ReadonlyArray<ComboboxItemDescriptor> => {
  const normalizedInputValue = (config.filterValue ?? config.inputValue)
    .trim()
    .toLocaleLowerCase()
  const items = enabledItems(config)

  if (normalizedInputValue === '') {
    return items
  }

  return items.filter(item =>
    (item.textValue ?? item.label)
      .toLocaleLowerCase()
      .includes(normalizedInputValue),
  )
}

export const highlightedItem = (
  config: Pick<ComboboxOptions, 'highlightedValue' | 'items'>,
): ComboboxItemDescriptor | undefined =>
  config.items.find(item => item.value === config.highlightedValue)

export const firstFilteredItem = (
  config: Pick<
    ComboboxOptions,
    'filterValue' | 'inputValue' | 'isDisabled' | 'items'
  >,
): ComboboxItemDescriptor | undefined => filteredItems(config)[0]

export const visibleSelectedItems = (
  config: Pick<ComboboxOptions, 'items' | 'selectionMode' | 'value' | 'values'>,
): ReadonlyArray<ComboboxItemDescriptor> => selectedItems(config)

export const openChange = (
  open: boolean,
  reason: ComboboxOpenChangeReason = 'none',
): ComboboxOpenChange => ({
  open,
  reason,
})

export const inputValueChange = (
  value: string,
  reason: ComboboxInputValueChangeReason = 'none',
): ComboboxInputValueChange => ({
  value,
  reason,
})

const nextValuesForItem = (
  config: Pick<ComboboxOptions, 'selectionMode' | 'value' | 'values'>,
  item: Pick<ComboboxItemDescriptor, 'value'>,
): ReadonlyArray<string> => {
  if (!isMultiple(config)) {
    return [item.value]
  }

  const currentValues = selectedValues(config)

  return currentValues.includes(item.value)
    ? currentValues.filter(value => value !== item.value)
    : [...currentValues, item.value]
}

export const valueChange = (
  config: Pick<ComboboxOptions, 'selectionMode' | 'value' | 'values'>,
  item: ComboboxItemDescriptor,
  reason: ComboboxValueChangeReason = 'none',
): ComboboxValueChange => {
  const values = nextValuesForItem(config, item)
  const base = {
    values,
    label: item.label,
    changedValue: item.value,
    reason,
  }

  return isMultiple(config) ? base : { ...base, value: item.value }
}

export const clearValueChange = (
  reason: ComboboxValueChangeReason = 'none',
): ComboboxValueChange => ({
  values: [],
  reason,
})

export const removeValueChange = (
  config: Pick<ComboboxOptions, 'selectionMode' | 'value' | 'values'>,
  item: ComboboxItemDescriptor,
  reason: ComboboxValueChangeReason = 'none',
): ComboboxValueChange => ({
  values: selectedValues(config).filter(value => value !== item.value),
  changedValue: item.value,
  label: item.label,
  reason,
})

export const highlightChange = (
  config: Pick<ComboboxOptions, 'id'>,
  item: ComboboxItemDescriptor,
  reason: ComboboxHighlightChangeReason = 'none',
): ComboboxHighlightChange => ({
  value: item.value,
  reason,
  focusSelector: itemFocusSelector(config, item),
})

export const clearHighlightChange = (
  reason: ComboboxHighlightChangeReason = 'none',
): ComboboxHighlightChange => ({
  reason,
})

export const chipHighlightChange = (
  config: Pick<ComboboxOptions, 'id'>,
  item: ComboboxItemDescriptor,
  reason: ComboboxChipHighlightChangeReason = 'none',
): ComboboxChipHighlightChange => ({
  value: item.value,
  reason,
  focusSelector: chipFocusSelector(config, item),
})

export const clearChipHighlightChange = (
  reason: ComboboxChipHighlightChangeReason = 'none',
): ComboboxChipHighlightChange => ({
  reason,
})

const popoverChangeReason = (
  change: ComboboxOpenChange,
): Popover.PopoverChangeReason => {
  if (change.reason === 'outside-press') {
    return 'outside-press'
  }

  if (change.reason === 'escape-key') {
    return 'escape-key'
  }

  return change.open ? 'trigger-press' : 'close-press'
}

export const commandForOpenChange = (
  config: Pick<ComboboxOptions, 'id'>,
  change: ComboboxOpenChange,
): Command.Command<Popover.CommandMessage> =>
  Popover.commandForOpenChange(
    {
      id: config.id,
      triggerId: inputId(config),
      triggerSelector: `#${inputId(config)}`,
      focusSelector: `#${inputId(config)}`,
    },
    Popover.openChange(change.open, popoverChangeReason(change)),
  )

const indexOffset = (
  currentIndex: number,
  direction: 'next' | 'previous',
): number => currentIndex + (direction === 'next' ? 1 : -1)

export const nextHighlightedItem = (
  config: Pick<
    ComboboxOptions,
    'filterValue' | 'highlightedValue' | 'inputValue' | 'isDisabled' | 'items'
  >,
  direction: 'first' | 'last' | 'next' | 'previous',
): ComboboxItemDescriptor | undefined => {
  const items = filteredItems(config)

  if (direction === 'first') {
    return items[0]
  }

  if (direction === 'last') {
    return items.at(-1)
  }

  const currentIndex = items.findIndex(
    item => item.value === config.highlightedValue,
  )
  const resolvedCurrentIndex = currentIndex === -1 ? 0 : currentIndex
  const candidateIndex = indexOffset(resolvedCurrentIndex, direction)

  if (candidateIndex >= 0 && candidateIndex < items.length) {
    return items[candidateIndex]
  }

  return items[resolvedCurrentIndex]
}

export const nextHighlightedChip = (
  config: Pick<
    ComboboxOptions,
    'highlightedChipValue' | 'items' | 'selectionMode' | 'value' | 'values'
  >,
  direction: 'next' | 'previous',
): ComboboxItemDescriptor | undefined => {
  const chips = visibleSelectedItems(config)
  const currentIndex = chips.findIndex(
    item => item.value === config.highlightedChipValue,
  )
  const resolvedCurrentIndex = currentIndex === -1 ? 0 : currentIndex
  const candidateIndex = indexOffset(resolvedCurrentIndex, direction)

  if (candidateIndex >= 0 && candidateIndex < chips.length) {
    return chips[candidateIndex]
  }

  return undefined
}

// VIEW

export type ComboboxPartAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type ComboboxItemAttributes<Message> = Readonly<{
  item: ComboboxItemDescriptor
  root: ReadonlyArray<Attribute<Message>>
  text: ReadonlyArray<Attribute<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
}>

export type ComboboxChipAttributes<Message> = Readonly<{
  item: ComboboxItemDescriptor
  root: ReadonlyArray<Attribute<Message>>
  remove: ReadonlyArray<Attribute<Message>>
}>

export type ComboboxAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  inputGroup: ReadonlyArray<Attribute<Message>>
  input: ReadonlyArray<Attribute<Message>>
  trigger: ReadonlyArray<Attribute<Message>>
  value: ReadonlyArray<Attribute<Message>>
  clear: ReadonlyArray<Attribute<Message>>
  portal: ReadonlyArray<Attribute<Message>>
  positioner: ComboboxPartAttributes<Message>
  backdrop: ComboboxPartAttributes<Message>
  popup: ComboboxPartAttributes<Message>
  list: ComboboxPartAttributes<Message>
  arrow: ComboboxPartAttributes<Message>
  collection: ReadonlyArray<Attribute<Message>>
  group: ReadonlyArray<Attribute<Message>>
  groupLabel: ReadonlyArray<Attribute<Message>>
  empty: ReadonlyArray<Attribute<Message>>
  separator: ReadonlyArray<Attribute<Message>>
  items: ReadonlyArray<ComboboxItemAttributes<Message>>
  chips: ReadonlyArray<Attribute<Message>>
  chipInput: ReadonlyArray<Attribute<Message>>
  chipItems: ReadonlyArray<ComboboxChipAttributes<Message>>
  hiddenInputs: ReadonlyArray<ReadonlyArray<Attribute<Message>>>
  filteredItems: ReadonlyArray<ComboboxItemDescriptor>
  selectedItems: ReadonlyArray<ComboboxItemDescriptor>
  isMounted: boolean
  isOpen: boolean
  isEmpty: boolean
}>

export type ViewConfig<Message> = ComboboxOptions &
  Readonly<{
    toView: (attributes: ComboboxAttributes<Message>) => Html
    onOpenChange?: (change: ComboboxOpenChange) => Message
    onInputValueChange?: (change: ComboboxInputValueChange) => Message
    onValueChange?: (change: ComboboxValueChange) => Message
    onHighlightChange?: (change: ComboboxHighlightChange) => Message
    onChipHighlightChange?: (change: ComboboxChipHighlightChange) => Message
    onFocus?: Message
    onBlur?: Message
  }>

const resolvedSide = (config: Pick<ComboboxOptions, 'side'>): ComboboxSide =>
  config.side ?? defaultSide

const resolvedAlign = (config: Pick<ComboboxOptions, 'align'>): ComboboxAlign =>
  config.align ?? defaultAlign

const isMounted = (
  config: Pick<ComboboxOptions, 'forceMount' | 'open' | 'transitionStatus'>,
): boolean =>
  config.open ||
  config.forceMount === true ||
  config.transitionStatus === 'ending'

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const optionalMessageAttribute = <Message>(
  message: Option.Option<Message>,
  toAttribute: (message: Message) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(message, {
    onNone: () => [],
    onSome: value => [toAttribute(value)],
  })

const openMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onOpenChange'>,
  change: ComboboxOpenChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onOpenChange)
    ? Option.some(config.onOpenChange(change))
    : Option.none()

const valueMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    | 'isDisabled'
    | 'isReadOnly'
    | 'onValueChange'
    | 'selectionMode'
    | 'value'
    | 'values'
  >,
  item: ComboboxItemDescriptor,
  reason: ComboboxValueChangeReason,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onValueChange) &&
  config.isDisabled !== true &&
  config.isReadOnly !== true &&
  item.isDisabled !== true
    ? Option.some(config.onValueChange(valueChange(config, item, reason)))
    : Option.none()

const clearValueMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'isDisabled' | 'isReadOnly' | 'onValueChange'
  >,
  reason: ComboboxValueChangeReason,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onValueChange) &&
  config.isDisabled !== true &&
  config.isReadOnly !== true
    ? Option.some(config.onValueChange(clearValueChange(reason)))
    : Option.none()

const removeValueMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    | 'isDisabled'
    | 'isReadOnly'
    | 'onValueChange'
    | 'selectionMode'
    | 'value'
    | 'values'
  >,
  item: ComboboxItemDescriptor,
  reason: ComboboxValueChangeReason,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onValueChange) &&
  config.isDisabled !== true &&
  config.isReadOnly !== true
    ? Option.some(config.onValueChange(removeValueChange(config, item, reason)))
    : Option.none()

const highlightMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'id' | 'isDisabled' | 'onHighlightChange'>,
  item: ComboboxItemDescriptor,
  reason: ComboboxHighlightChangeReason,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onHighlightChange) &&
  config.isDisabled !== true
    ? Option.some(
        config.onHighlightChange(highlightChange(config, item, reason)),
      )
    : Option.none()

const chipHighlightMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'id' | 'isDisabled' | 'onChipHighlightChange'
  >,
  item: ComboboxItemDescriptor,
  reason: ComboboxChipHighlightChangeReason,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onChipHighlightChange) &&
  config.isDisabled !== true
    ? Option.some(
        config.onChipHighlightChange(chipHighlightChange(config, item, reason)),
      )
    : Option.none()

const clearChipHighlightMessageOption = <Message>(
  config: Pick<ViewConfig<Message>, 'isDisabled' | 'onChipHighlightChange'>,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onChipHighlightChange) &&
  config.isDisabled !== true
    ? Option.some(config.onChipHighlightChange(clearChipHighlightChange()))
    : Option.none()

const openStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  open: boolean,
): ReadonlyArray<Attribute<Message>> =>
  open ? [h.DataAttribute('open', '')] : [h.DataAttribute('closed', '')]

const transitionDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  transitionStatus: ComboboxTransitionStatus | undefined,
): ReadonlyArray<Attribute<Message>> => {
  if (transitionStatus === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (transitionStatus === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const placementAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('side', resolvedSide(config)),
  h.DataAttribute('align', resolvedAlign(config)),
  h.DataAttribute(
    'side-offset',
    String(config.sideOffset ?? defaultSideOffset),
  ),
  h.DataAttribute(
    'align-offset',
    String(config.alignOffset ?? defaultAlignOffset),
  ),
  h.DataAttribute(
    'collision-avoidance',
    String(config.collisionAvoidance ?? defaultCollisionAvoidance),
  ),
  h.DataAttribute(
    'collision-padding',
    String(config.collisionPadding ?? defaultCollisionPadding),
  ),
]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(rootId(config)),
  h.DataAttribute('side', resolvedSide(config)),
  h.DataAttribute('align', resolvedAlign(config)),
  h.DataAttribute('selection-mode', resolvedSelectionMode(config)),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'invalid', config.isInvalid),
]

const inputGroupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(inputGroupId(config)),
  h.Role('group'),
  ...(config.open ? [h.DataAttribute('popup-open', '')] : []),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'invalid', config.isInvalid),
]

const inputKeyboardMessage = <Message>(
  config: ViewConfig<Message>,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (
    modifiers.shiftKey ||
    modifiers.ctrlKey ||
    modifiers.altKey ||
    modifiers.metaKey ||
    config.isDisabled === true ||
    config.isReadOnly === true
  ) {
    return Option.none()
  }

  if (key === 'Escape') {
    return config.open
      ? openMessage(config, openChange(false, 'escape-key'))
      : clearValueMessage(config, 'input-clear')
  }

  const direction = keyboardDirection(key)

  if (direction !== undefined) {
    const item = nextHighlightedItem(config, direction)

    return item === undefined
      ? Option.none()
      : highlightMessage(config, item, 'keyboard-navigation')
  }

  if (key === 'Enter' && config.highlightedValue !== undefined) {
    const item = highlightedItem(config)

    return item === undefined
      ? Option.none()
      : valueMessage(config, item, 'keyboard-select')
  }

  if (key === 'Backspace' && config.inputValue === '' && isMultiple(config)) {
    const chips = visibleSelectedItems(config)
    const item = chips.at(-1)

    return item === undefined
      ? Option.none()
      : removeValueMessage(config, item, 'chip-keyboard-remove')
  }

  return Option.none()
}

const inputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  items: ReadonlyArray<ComboboxItemDescriptor>,
): ReadonlyArray<Attribute<Message>> => {
  const { onInputValueChange } = config

  return [
    h.Id(inputId(config)),
    h.Type('text'),
    h.Role('combobox'),
    h.Value(inputDisplayValue(config)),
    h.AriaHasPopup('listbox'),
    h.AriaExpanded(config.open),
    h.AriaControls(listId(config)),
    h.Attribute('aria-autocomplete', 'list'),
    ...(config.highlightedValue === undefined
      ? []
      : [
          h.AriaActiveDescendant(
            itemId(config, { value: config.highlightedValue }),
          ),
        ]),
    ...(config.placeholder === undefined
      ? []
      : [h.Placeholder(config.placeholder)]),
    ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
      h.Disabled(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
      h.Readonly(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isRequired, value =>
      h.Required(value),
    ),
    ...(config.isInvalid === true ? [h.AriaInvalid(true)] : []),
    ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
      h.AriaDisabled(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
      h.AriaReadonly(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isRequired, value =>
      h.AriaRequired(value),
    ),
    ...(config.open ? [h.DataAttribute('popup-open', '')] : []),
    h.DataAttribute('popup-side', config.open ? resolvedSide(config) : ''),
    ...(items.length === 0 ? [h.DataAttribute('list-empty', '')] : []),
    ...booleanDataAttribute(h, 'disabled', config.isDisabled),
    ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
    ...booleanDataAttribute(h, 'required', config.isRequired),
    ...booleanDataAttribute(h, 'invalid', config.isInvalid),
    ...(inputDisplayValue(config) === ''
      ? []
      : [h.DataAttribute('filled', '')]),
    ...(Predicate.isNotUndefined(onInputValueChange) &&
    config.isDisabled !== true &&
    config.isReadOnly !== true
      ? [
          h.OnInput(value =>
            onInputValueChange(
              inputValueChange(
                value,
                value === '' ? 'input-clear' : 'input-change',
              ),
            ),
          ),
        ]
      : []),
    h.OnKeyDownPreventDefault((key, modifiers) =>
      inputKeyboardMessage(config, key, modifiers),
    ),
    ...(Predicate.isNotUndefined(config.onFocus)
      ? [h.OnFocus(config.onFocus)]
      : []),
    ...(Predicate.isNotUndefined(config.onBlur)
      ? [h.OnBlur(config.onBlur)]
      : []),
  ]
}

const triggerKeyboardMessage = <Message>(
  config: ViewConfig<Message>,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (
    modifiers.shiftKey ||
    config.isDisabled === true ||
    config.isReadOnly === true
  ) {
    return Option.none()
  }

  if (activationKeys.has(key) || key === 'ArrowDown' || key === 'ArrowUp') {
    return openMessage(config, openChange(true, 'keyboard-open'))
  }

  return Option.none()
}

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  items: ReadonlyArray<ComboboxItemDescriptor>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(triggerId(config)),
  h.Type('button'),
  h.AriaHasPopup('listbox'),
  h.AriaExpanded(config.open),
  h.AriaControls(listId(config)),
  ...(config.open ? [h.DataAttribute('popup-open', '')] : []),
  h.DataAttribute('popup-side', config.open ? resolvedSide(config) : ''),
  ...(items.length === 0 ? [h.DataAttribute('list-empty', '')] : []),
  ...(hasSelectedValue(config) || config.showTriggerPlaceholder === false
    ? []
    : [h.DataAttribute('placeholder', '')]),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.AriaReadonly(value),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true || config.isReadOnly === true
      ? Option.none()
      : openMessage(config, openChange(!config.open, 'trigger-press')),
    message => h.OnClick(message),
  ),
  h.OnKeyDownPreventDefault((key, modifiers) =>
    triggerKeyboardMessage(config, key, modifiers),
  ),
]

const valueAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(valueId(config)),
  ...(hasSelectedValue(config) ? [] : [h.DataAttribute('placeholder', '')]),
]

const clearAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(clearId(config)),
  h.Type('button'),
  h.Tabindex(-1),
  ...(config.open ? [h.DataAttribute('popup-open', '')] : []),
  ...(hasSelectedValue(config) || config.inputValue !== ''
    ? [h.DataAttribute('visible', '')]
    : []),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...optionalMessageAttribute(
    hasSelectedValue(config) || config.inputValue !== ''
      ? clearValueMessage(config, 'clear-press')
      : Option.none(),
    message => h.OnClick(message),
  ),
]

const portalAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
): ReadonlyArray<Attribute<Message>> => [h.DataAttribute('portal', '')]

const positionerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  mounted: boolean,
  isEmpty: boolean,
): ComboboxPartAttributes<Message> => ({
  root: mounted
    ? [
        h.Id(positionerId(config)),
        ...(config.open ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, config.open),
        ...placementAttributes(h, config),
        ...(isEmpty ? [h.DataAttribute('empty', '')] : []),
        h.Style({
          position: 'absolute',
          inset: 'auto',
          margin: '0',
        }),
      ]
    : [],
  isMounted: mounted,
  isOpen: config.open,
})

const backdropAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  mounted: boolean,
): ComboboxPartAttributes<Message> => ({
  root: mounted
    ? [
        h.Role('presentation'),
        ...(config.open ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, config.open),
        ...transitionDataAttributes(h, config.transitionStatus),
        ...optionalMessageAttribute(
          openMessage(config, openChange(false, 'outside-press')),
          message => h.OnClick(message),
        ),
      ]
    : [],
  isMounted: mounted,
  isOpen: config.open,
})

const popupKeyboardMessage = <Message>(
  config: ViewConfig<Message>,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (modifiers.shiftKey) {
    return Option.none()
  }

  if (key === 'Escape') {
    return openMessage(config, openChange(false, 'escape-key'))
  }

  return Option.none()
}

const popupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  mounted: boolean,
  isEmpty: boolean,
): ComboboxPartAttributes<Message> => ({
  root: mounted
    ? [
        h.Id(popupId(config)),
        h.Popover('manual'),
        h.Role('presentation'),
        h.Tabindex(-1),
        ...(config.open ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, config.open),
        ...transitionDataAttributes(h, config.transitionStatus),
        ...placementAttributes(h, config),
        ...(isEmpty ? [h.DataAttribute('empty', '')] : []),
        ...booleanDataAttribute(h, 'chips', config.anchorToChips),
        h.OnKeyDownPreventDefault((key, modifiers) =>
          popupKeyboardMessage(config, key, modifiers),
        ),
      ]
    : [],
  isMounted: mounted,
  isOpen: config.open,
})

const listKeyboardMessage = <Message>(
  config: ViewConfig<Message>,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => inputKeyboardMessage(config, key, modifiers)

const listAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  mounted: boolean,
  isEmpty: boolean,
): ComboboxPartAttributes<Message> => ({
  root: mounted
    ? [
        h.Id(listId(config)),
        h.Role('listbox'),
        h.Tabindex(-1),
        ...(isMultiple(config)
          ? [h.Attribute('aria-multiselectable', 'true')]
          : []),
        ...(isEmpty ? [h.DataAttribute('empty', '')] : []),
        h.OnKeyDownPreventDefault((key, modifiers) =>
          listKeyboardMessage(config, key, modifiers),
        ),
      ]
    : [],
  isMounted: mounted,
  isOpen: config.open,
})

const arrowAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  mounted: boolean,
): ComboboxPartAttributes<Message> => ({
  root: mounted
    ? [
        h.Id(arrowId(config)),
        h.AriaHidden(true),
        ...openStateDataAttributes(h, config.open),
        ...placementAttributes(h, config),
      ]
    : [],
  isMounted: mounted,
  isOpen: config.open,
})

const itemStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ComboboxItemDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  ...(selectedValues(config).includes(item.value)
    ? [h.DataAttribute('selected', '')]
    : []),
  ...(config.highlightedValue === item.value
    ? [h.DataAttribute('highlighted', '')]
    : []),
  ...booleanDataAttribute(h, 'disabled', item.isDisabled),
]

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ComboboxItemDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(itemId(config, item)),
  h.Role('option'),
  h.Tabindex(config.highlightedValue === item.value ? 0 : -1),
  h.AriaSelected(selectedValues(config).includes(item.value)),
  ...optionalBooleanAttribute<Message>(item.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...itemStateDataAttributes(h, config, item),
  ...optionalMessageAttribute(
    valueMessage(config, item, 'item-press'),
    message => h.OnClick(message),
  ),
  ...optionalMessageAttribute(
    highlightMessage(config, item, 'item-hover'),
    message => h.OnMouseEnter(message),
  ),
  ...optionalMessageAttribute(
    valueMessage(config, item, 'keyboard-select'),
    message =>
      h.OnKeyDownPreventDefault(key =>
        activationKeys.has(key) ? Option.some(message) : Option.none(),
      ),
  ),
]

const itemTextAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ComboboxItemDescriptor,
): ReadonlyArray<Attribute<Message>> => itemStateDataAttributes(h, config, item)

const itemIndicatorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ComboboxItemDescriptor,
): ReadonlyArray<Attribute<Message>> =>
  selectedValues(config).includes(item.value)
    ? itemStateDataAttributes(h, config, item)
    : []

const chipKeyboardMessage = <Message>(
  config: ViewConfig<Message>,
  item: ComboboxItemDescriptor,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (
    modifiers.shiftKey ||
    modifiers.ctrlKey ||
    modifiers.altKey ||
    modifiers.metaKey
  ) {
    return Option.none()
  }

  if (key === 'Backspace' || key === 'Delete') {
    return removeValueMessage(config, item, 'chip-keyboard-remove')
  }

  if (key === 'ArrowLeft') {
    const previous = nextHighlightedChip(config, 'previous')

    return previous === undefined
      ? clearChipHighlightMessageOption(config)
      : chipHighlightMessage(config, previous, 'keyboard-navigation')
  }

  if (key === 'ArrowRight') {
    const next = nextHighlightedChip(config, 'next')

    return next === undefined
      ? clearChipHighlightMessageOption(config)
      : chipHighlightMessage(config, next, 'keyboard-navigation')
  }

  return Option.none()
}

const chipAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ComboboxItemDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(chipId(config, item)),
  h.Tabindex(config.highlightedChipValue === item.value ? 0 : -1),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.AriaReadonly(value),
  ),
  ...(config.highlightedChipValue === item.value
    ? [h.DataAttribute('highlighted', '')]
    : []),
  h.OnKeyDownPreventDefault((key, modifiers) =>
    chipKeyboardMessage(config, item, key, modifiers),
  ),
]

const chipRemoveAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ComboboxItemDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(chipRemoveId(config, item)),
  h.Type('button'),
  h.Tabindex(-1),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...optionalMessageAttribute(
    removeValueMessage(config, item, 'chip-remove-press'),
    message => h.OnClick(message),
  ),
]

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  form: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(form) ? [h.Attribute('form', form)] : []

const hiddenInputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<ReadonlyArray<Attribute<Message>>> => {
  if (config.name === undefined) {
    return []
  }

  const values = isMultiple(config)
    ? selectedValues(config)
    : [config.value ?? '']

  return values.map(value => [
    h.Type('hidden'),
    h.Name(config.name ?? ''),
    h.Value(value),
    ...formOwnerAttributes(h, config.form),
    ...optionalBooleanAttribute<Message>(config.isDisabled, disabled =>
      h.Disabled(disabled),
    ),
    ...optionalBooleanAttribute<Message>(config.isRequired, required =>
      h.Required(required),
    ),
  ])
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const mounted = isMounted(config)
  const visibleItems = filteredItems(config)
  const selected = visibleSelectedItems(config)
  const empty = visibleItems.length === 0

  return config.toView({
    root: rootAttributes(h, config),
    inputGroup: inputGroupAttributes(h, config),
    input: inputAttributes(h, config, visibleItems),
    trigger: triggerAttributes(h, config, visibleItems),
    value: valueAttributes(h, config),
    clear: clearAttributes(h, config),
    portal: portalAttributes(h),
    positioner: positionerAttributes(h, config, mounted, empty),
    backdrop: backdropAttributes(h, config, mounted),
    popup: popupAttributes(h, config, mounted, empty),
    list: listAttributes(h, config, mounted, empty),
    arrow: arrowAttributes(h, config, mounted),
    collection: [h.Id(collectionId(config)), h.DataAttribute('collection', '')],
    group: [h.Role('group')],
    groupLabel: [],
    empty: [
      h.Id(emptyId(config)),
      h.Role('status'),
      h.Attribute('aria-live', 'polite'),
      h.Attribute('aria-atomic', 'true'),
    ],
    separator: [h.Role('separator'), h.AriaOrientation('horizontal')],
    items: visibleItems.map(item => ({
      item,
      root: itemAttributes(h, config, item),
      text: itemTextAttributes(h, config, item),
      indicator: itemIndicatorAttributes(h, config, item),
    })),
    chips: [
      h.Id(chipsId(config)),
      ...(selected.length > 0 ? [h.Role('toolbar')] : []),
      ...booleanDataAttribute(h, 'disabled', config.isDisabled),
    ],
    chipInput: [
      ...inputAttributes(h, config, visibleItems),
      h.Id(`${inputId(config)}-chip`),
    ],
    chipItems: selected.map(item => ({
      item,
      root: chipAttributes(h, config, item),
      remove: chipRemoveAttributes(h, config, item),
    })),
    hiddenInputs: hiddenInputAttributes(h, config),
    filteredItems: visibleItems,
    selectedItems: selected,
    isMounted: mounted,
    isOpen: config.open,
    isEmpty: empty,
  })
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html, KeyboardModifiers } from 'foldkit/html'
import { html } from 'foldkit/html'

import * as Menu from './menu'

// MODEL

export const {
  MenuAlign,
  MenuHighlightChangeReason,
  MenuItemKind,
  MenuOpenChangeReason,
  MenuSide,
  MenuTransitionStatus,
} = Menu

export type MenuAlign = Menu.MenuAlign
export type MenuCheckedChange = Menu.MenuCheckedChange
export type MenuHighlightChange = Menu.MenuHighlightChange
export type MenuHighlightChangeReason = Menu.MenuHighlightChangeReason
export type MenuItemDescriptor = Menu.MenuItemDescriptor
export type MenuItemKind = Menu.MenuItemKind
export type MenuItemPress = Menu.MenuItemPress
export type MenuOpenChangeReason = Menu.MenuOpenChangeReason
export type MenuRadioValueChange = Menu.MenuRadioValueChange
export type MenuSide = Menu.MenuSide
export type MenuTransitionStatus = Menu.MenuTransitionStatus

export const ContextMenuPlatform = S.Union([
  S.Literal('mac'),
  S.Literal('non-mac'),
])
export type ContextMenuPlatform = typeof ContextMenuPlatform.Type

export const ContextMenuPoint = S.Struct({
  clientX: S.Number,
  clientY: S.Number,
  screenX: S.Number,
  screenY: S.Number,
  pointerType: S.String,
})
export type ContextMenuPoint = typeof ContextMenuPoint.Type

export const ContextMenuOpenChange = S.Struct({
  open: S.Boolean,
  reason: Menu.MenuOpenChangeReason,
  parentValue: S.optional(S.String),
  point: S.optional(ContextMenuPoint),
})
export type ContextMenuOpenChange = typeof ContextMenuOpenChange.Type

// UPDATE

const defaultPlatform: ContextMenuPlatform = 'mac'
const pointerMoveTolerance = 2

const keyboardPoint: ContextMenuPoint = {
  clientX: 0,
  clientY: 0,
  screenX: 0,
  screenY: 0,
  pointerType: 'keyboard',
}

export const {
  FocusMenu: FocusContextMenu,
  RestoreMenuFocus: RestoreContextMenuFocus,
  arrowId,
  checkedChange,
  enabledItems,
  groupLabelId,
  highlightChange,
  highlightedItem,
  itemFocusSelector,
  itemId,
  itemKind,
  itemPress,
  itemsForParent,
  nextHighlightedItem,
  popupId,
  positionerId,
  radioValueChange,
  triggerId,
  triggerSelector,
  typeaheadItem,
} = Menu

export const contextPoint = (
  clientX: number,
  clientY: number,
  screenX: number,
  screenY: number,
  pointerType: string,
): ContextMenuPoint => ({
  clientX,
  clientY,
  screenX,
  screenY,
  pointerType,
})

export const openChange = (
  open: boolean,
  reason: MenuOpenChangeReason = 'none',
  point?: ContextMenuPoint | undefined,
  parentValue?: string | undefined,
): ContextMenuOpenChange => ({ open, reason, point, parentValue })

export const commandForOpenChange = (
  config: Pick<Menu.MenuOptions, 'id' | 'triggerId' | 'triggerSelector'>,
  change: ContextMenuOpenChange,
): ReturnType<typeof Menu.commandForOpenChange> =>
  Menu.commandForOpenChange(
    config,
    Menu.openChange(change.open, change.reason, change.parentValue),
  )

// VIEW

export type MenuPartAttributes<Message> = Menu.MenuPartAttributes<Message>
export type MenuItemAttributes<Message> = Menu.MenuItemAttributes<Message>
export type MenuPopupAttributes<Message> = Omit<
  Menu.MenuPopupAttributes<Message>,
  'items'
> &
  Readonly<{
    items: ReadonlyArray<MenuItemAttributes<Message>>
  }>
export type MenuAttributes<Message> = Omit<
  Menu.MenuAttributes<Message>,
  'popup' | 'submenus' | 'trigger'
> &
  Readonly<{
    trigger: ReadonlyArray<Attribute<Message>>
    popup: MenuPopupAttributes<Message>
    submenus: ReadonlyArray<MenuPopupAttributes<Message>>
  }>

export type ViewConfig<Message> = Omit<
  Menu.ViewConfig<Message>,
  'onOpenChange' | 'toView'
> &
  Readonly<{
    contextPoint?: ContextMenuPoint | undefined
    platform?: ContextMenuPlatform | undefined
    onOpenChange?: (change: ContextMenuOpenChange) => Message
    onPointerChange?: (point: ContextMenuPoint) => Message
    toView: (attributes: MenuAttributes<Message>) => Html
  }>

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const optionalMessageAttribute = <Message>(
  message: Option.Option<Message>,
  toAttribute: (message: Message) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(message, {
    onNone: () => [],
    onSome: value => [toAttribute(value)],
  })

const currentPoint = <Message>(
  config: Pick<ViewConfig<Message>, 'contextPoint'>,
): ContextMenuPoint => config.contextPoint ?? keyboardPoint

const contextPositionStyle = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'alignOffset' | 'side' | 'sideOffset' | 'contextPoint'
  >,
): Readonly<Record<string, string>> => {
  const point = currentPoint(config)
  const alignOffset = config.alignOffset ?? 0
  const sideOffset = config.sideOffset ?? 0
  const side = config.side ?? 'bottom'

  if (side === 'left' || side === 'inline-start') {
    return {
      left: `${point.clientX - sideOffset}px`,
      top: `${point.clientY + alignOffset}px`,
    }
  }

  if (side === 'top') {
    return {
      left: `${point.clientX + alignOffset}px`,
      top: `${point.clientY - sideOffset}px`,
    }
  }

  if (side === 'right' || side === 'inline-end') {
    return {
      left: `${point.clientX + sideOffset}px`,
      top: `${point.clientY + alignOffset}px`,
    }
  }

  return {
    left: `${point.clientX + alignOffset}px`,
    top: `${point.clientY + sideOffset}px`,
  }
}

const contextContentTranslateStyle = <Message>(
  config: Pick<ViewConfig<Message>, 'side'>,
): Readonly<Record<string, string>> => {
  const side = config.side ?? 'bottom'

  if (side === 'left' || side === 'inline-start') {
    return { translate: '-100% 0' }
  }

  if (side === 'top') {
    return { translate: '0 -100%' }
  }

  return {}
}

const contextContentPositionStyle = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'alignOffset' | 'side' | 'sideOffset' | 'contextPoint'
  >,
): Readonly<Record<string, string>> => ({
  ...contextPositionStyle(config),
  ...contextContentTranslateStyle(config),
})

const openMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'contextPoint' | 'onOpenChange'>,
  change: ContextMenuOpenChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onOpenChange)
    ? Option.some(config.onOpenChange(change))
    : Option.none()

const pointerChangeMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'isDisabled' | 'onPointerChange'>,
  pointerType: string,
  button: number,
  screenX: number,
  screenY: number,
  clientX: number,
  clientY: number,
): Option.Option<Message> => {
  if (
    config.isDisabled === true ||
    button !== 2 ||
    Predicate.isUndefined(config.onPointerChange)
  ) {
    return Option.none()
  }

  return Option.some(
    config.onPointerChange(
      contextPoint(clientX, clientY, screenX, screenY, pointerType),
    ),
  )
}

const keyboardOpenMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'contextPoint' | 'isDisabled' | 'onOpenChange'
  >,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (config.isDisabled === true) {
    return Option.none()
  }

  if (key === 'ContextMenu' || (key === 'F10' && modifiers.shiftKey)) {
    return openMessage(
      config,
      openChange(true, 'keyboard-open', currentPoint(config)),
    )
  }

  return Option.none()
}

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(triggerId(config)),
  h.Tabindex(config.isDisabled === true ? -1 : 0),
  h.AriaHasPopup('menu'),
  h.AriaExpanded(config.open),
  h.AriaControls(popupId(config)),
  h.Style({ WebkitTouchCallout: 'none' }),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...(config.open ? [h.DataAttribute('popup-open', '')] : []),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...(config.isDisabled === true
    ? []
    : [
        h.OnPointerDown(
          (pointerType, button, screenX, screenY, _time, clientX, clientY) =>
            pointerChangeMessage(
              config,
              pointerType,
              button,
              screenX,
              screenY,
              clientX,
              clientY,
            ),
        ),
      ]),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(
          config,
          openChange(true, 'trigger-press', currentPoint(config)),
        ),
    message => h.OnContextMenu(message),
  ),
  h.OnKeyDownPreventDefault((key, modifiers) =>
    keyboardOpenMessage(config, key, modifiers),
  ),
  ...(Predicate.isNotUndefined(config.onFocus)
    ? [h.OnFocus(config.onFocus)]
    : []),
  ...(Predicate.isNotUndefined(config.onBlur) ? [h.OnBlur(config.onBlur)] : []),
]

const contextPositionerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ViewConfig<Message>,
    'alignOffset' | 'side' | 'sideOffset' | 'contextPoint'
  >,
  positioner: Menu.MenuPartAttributes<Message>,
): Menu.MenuPartAttributes<Message> => {
  if (!positioner.isMounted) {
    return positioner
  }

  const point = currentPoint(config)

  return {
    ...positioner,
    root: [
      ...positioner.root.filter(attribute => attribute._tag !== 'Style'),
      h.DataAttribute('anchor', 'context-point'),
      h.DataAttribute('anchor-x', String(point.clientX)),
      h.DataAttribute('anchor-y', String(point.clientY)),
      h.Style({
        position: 'fixed',
        inset: 'auto',
        margin: '0',
        ...contextPositionStyle(config),
      }),
    ],
  }
}

const movedAwayFromInitialPoint = <Message>(
  config: Pick<ViewConfig<Message>, 'contextPoint'>,
  screenX: number,
  screenY: number,
): boolean => {
  if (config.contextPoint === undefined) {
    return false
  }

  return (
    Math.abs(screenX - config.contextPoint.screenX) > pointerMoveTolerance ||
    Math.abs(screenY - config.contextPoint.screenY) > pointerMoveTolerance
  )
}

const itemActionMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    | 'contextPoint'
    | 'isDisabled'
    | 'onCheckedChange'
    | 'onItemPress'
    | 'onOpenChange'
    | 'onRadioValueChange'
  >,
  item: MenuItemDescriptor,
): Option.Option<Message> => {
  if (config.isDisabled === true || item.isDisabled === true) {
    return Option.none()
  }

  const kind = Menu.itemKind(item)

  if (kind === 'checkbox' && Predicate.isNotUndefined(config.onCheckedChange)) {
    return Option.some(config.onCheckedChange(Menu.checkedChange(item)))
  }

  if (kind === 'radio' && Predicate.isNotUndefined(config.onRadioValueChange)) {
    return Option.some(config.onRadioValueChange(Menu.radioValueChange(item)))
  }

  if (kind === 'submenu-trigger') {
    return openMessage(
      config,
      openChange(true, 'submenu-open', currentPoint(config), item.value),
    )
  }

  return Predicate.isNotUndefined(config.onItemPress)
    ? Option.some(config.onItemPress(Menu.itemPress(item)))
    : Option.none()
}

const pointerUpMessage = <Message>(
  config: ViewConfig<Message>,
  item: MenuItemDescriptor,
  screenX: number,
  screenY: number,
  pointerType: string,
): Option.Option<Message> => {
  if (
    (config.platform ?? defaultPlatform) !== 'mac' ||
    pointerType !== 'mouse'
  ) {
    return Option.none()
  }

  return movedAwayFromInitialPoint(config, screenX, screenY)
    ? itemActionMessage(config, item)
    : Option.none()
}

const contextItemAttributes = <Message>(
  config: ViewConfig<Message>,
  itemAttributes: Menu.MenuItemAttributes<Message>,
): MenuItemAttributes<Message> => ({
  ...itemAttributes,
  root: [
    ...itemAttributes.root,
    html<Message>().OnPointerUp((screenX, screenY, pointerType) =>
      pointerUpMessage(
        config,
        itemAttributes.item,
        screenX,
        screenY,
        pointerType,
      ),
    ),
  ],
})

const contextPopupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  popup: Menu.MenuPopupAttributes<Message>,
): MenuPopupAttributes<Message> => ({
  ...popup,
  positioner:
    popup.parentValue === undefined
      ? contextPositionerAttributes(h, config, popup.positioner)
      : popup.positioner,
  popup:
    popup.parentValue === undefined
      ? {
          ...popup.popup,
          root: [
            ...popup.popup.root.filter(
              attribute =>
                attribute._tag !== 'Style' && attribute._tag !== 'Popover',
            ),
            h.Style({
              position: 'fixed',
              inset: 'auto',
              margin: '0',
              ...contextContentPositionStyle(config),
            }),
          ],
        }
      : {
          ...popup.popup,
          root: popup.popup.root.filter(
            attribute => attribute._tag !== 'Popover',
          ),
        },
  items: popup.items.map(itemAttributes =>
    contextItemAttributes(config, itemAttributes),
  ),
})

const contextAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: Menu.MenuAttributes<Message>,
): MenuAttributes<Message> => ({
  ...attributes,
  root: [...attributes.root, h.DataAttribute('context-menu', '')],
  trigger: triggerAttributes(h, config),
  popup: contextPopupAttributes(h, config, attributes.popup),
  submenus: attributes.submenus.map(popup =>
    contextPopupAttributes(h, config, popup),
  ),
})

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { toView, onOpenChange, ...menuConfig } = config
  const toContextView = (attributes: Menu.MenuAttributes<Message>): Html =>
    toView(contextAttributes(h, config, attributes))

  return onOpenChange === undefined
    ? Menu.view<Message>({
        ...menuConfig,
        positioning: 'static',
        toView: toContextView,
      })
    : Menu.view<Message>({
        ...menuConfig,
        positioning: 'static',
        onOpenChange: change =>
          onOpenChange(
            openChange(
              change.open,
              change.reason,
              currentPoint(config),
              change.parentValue,
            ),
          ),
        toView: toContextView,
      })
}

import { Effect, Option, Predicate, Schema as S } from 'effect'
import * as Command from 'foldkit/command'
import * as Dom from 'foldkit/dom'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'
import { m } from 'foldkit/message'

// MODEL

export const DialogModalMode = S.Union([S.Boolean, S.Literal('trap-focus')])
export type DialogModalMode = typeof DialogModalMode.Type

export const DialogTransitionStatus = S.Union([
  S.Literal('idle'),
  S.Literal('starting'),
  S.Literal('ending'),
])
export type DialogTransitionStatus = typeof DialogTransitionStatus.Type

export const DialogChangeReason = S.Union([
  S.Literal('trigger-press'),
  S.Literal('close-press'),
  S.Literal('outside-press'),
  S.Literal('escape-key'),
  S.Literal('none'),
])
export type DialogChangeReason = typeof DialogChangeReason.Type

export const DialogOpenChange = S.Struct({
  open: S.Boolean,
  reason: DialogChangeReason,
})
export type DialogOpenChange = typeof DialogOpenChange.Type

export const DialogOptions = S.Struct({
  id: S.String,
  open: S.Boolean,
  modal: S.optional(DialogModalMode),
  isDisabled: S.optional(S.Boolean),
  isNested: S.optional(S.Boolean),
  hasNestedDialogOpen: S.optional(S.Boolean),
  transitionStatus: S.optional(DialogTransitionStatus),
  titleId: S.optional(S.String),
  descriptionId: S.optional(S.String),
  focusSelector: S.optional(S.String),
  forceMount: S.optional(S.Boolean),
  disableOutsidePress: S.optional(S.Boolean),
})
export type DialogOptions = typeof DialogOptions.Type

// MESSAGE

export const CompletedShowDialog = m('CompletedShowDialog')
export const CompletedCloseDialog = m('CompletedCloseDialog')

export const CommandMessage = S.Union([
  CompletedShowDialog,
  CompletedCloseDialog,
])
export type CommandMessage = typeof CommandMessage.Type

// UPDATE

const defaultModal: DialogModalMode = true

const dialogSelector = (id: string): string => `#${id}`

const maybeFocusSelectorSchema = S.Option(S.String)

export const ShowDialog = Command.define(
  'ShowDialog',
  {
    id: S.String,
    modal: DialogModalMode,
    maybeFocusSelector: maybeFocusSelectorSchema,
  },
  CompletedShowDialog,
)(({ id, modal, maybeFocusSelector }) => {
  const focusOptions = Option.match(maybeFocusSelector, {
    onNone: () => ({}),
    onSome: focusSelector => ({ focusSelector }),
  })
  const show = Dom.showDialog(dialogSelector(id), focusOptions)

  if (modal === true) {
    return Dom.lockScroll.pipe(
      Effect.andThen(() => show),
      Effect.ignore,
      Effect.as(CompletedShowDialog()),
    )
  }

  if (modal === 'trap-focus') {
    return show.pipe(Effect.ignore, Effect.as(CompletedShowDialog()))
  }

  return Effect.succeed(CompletedShowDialog())
})

export const CloseDialog = Command.define(
  'CloseDialog',
  { id: S.String, modal: DialogModalMode },
  CompletedCloseDialog,
)(({ id, modal }) => {
  const close = Dom.closeDialog(dialogSelector(id))

  if (modal === true) {
    return close.pipe(
      Effect.andThen(() => Dom.unlockScroll),
      Effect.ignore,
      Effect.as(CompletedCloseDialog()),
    )
  }

  if (modal === 'trap-focus') {
    return close.pipe(Effect.ignore, Effect.as(CompletedCloseDialog()))
  }

  return Effect.succeed(CompletedCloseDialog())
})

export const titleId = (
  config: Pick<DialogOptions, 'id' | 'titleId'>,
): string => config.titleId ?? `${config.id}-title`

export const descriptionId = (
  config: Pick<DialogOptions, 'descriptionId' | 'id'>,
): string => config.descriptionId ?? `${config.id}-description`

export const panelId = (config: Pick<DialogOptions, 'id'>): string =>
  `${config.id}-popup`

export const openChange = (
  open: boolean,
  reason: DialogChangeReason = 'none',
): DialogOpenChange => ({
  open,
  reason,
})

export const triggerOpenChange = (): DialogOpenChange =>
  openChange(true, 'trigger-press')

export const closeOpenChange = (): DialogOpenChange =>
  openChange(false, 'close-press')

export const outsideOpenChange = (): DialogOpenChange =>
  openChange(false, 'outside-press')

export const escapeOpenChange = (): DialogOpenChange =>
  openChange(false, 'escape-key')

export const commandForOpenChange = (
  config: Pick<DialogOptions, 'focusSelector' | 'id' | 'modal'>,
  change: DialogOpenChange,
): Command.Command<CommandMessage> =>
  change.open
    ? ShowDialog({
        id: config.id,
        modal: config.modal ?? defaultModal,
        maybeFocusSelector: Option.fromNullishOr(config.focusSelector),
      })
    : CloseDialog({ id: config.id, modal: config.modal ?? defaultModal })

// VIEW

export type DialogAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  trigger: ReadonlyArray<Attribute<Message>>
  dialog: ReadonlyArray<Attribute<Message>>
  portal: ReadonlyArray<Attribute<Message>>
  backdrop: DialogPartAttributes<Message>
  popup: DialogPartAttributes<Message>
  title: ReadonlyArray<Attribute<Message>>
  description: ReadonlyArray<Attribute<Message>>
  close: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type DialogPartAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type ViewConfig<Message> = DialogOptions &
  Readonly<{
    toView: (attributes: DialogAttributes<Message>) => Html
    onOpenChange?: (change: DialogOpenChange) => Message
  }>

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const openStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  open: boolean,
): ReadonlyArray<Attribute<Message>> =>
  open ? [h.DataAttribute('open', '')] : [h.DataAttribute('closed', '')]

const transitionDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  transitionStatus: DialogTransitionStatus | undefined,
): ReadonlyArray<Attribute<Message>> => {
  if (transitionStatus === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (transitionStatus === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const mounted = (
  config: Pick<DialogOptions, 'forceMount' | 'open' | 'transitionStatus'>,
): boolean =>
  config.open ||
  config.forceMount === true ||
  config.transitionStatus === 'ending'

const openMessage = <Message>(
  config: ViewConfig<Message>,
  change: DialogOpenChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onOpenChange)
    ? Option.some(config.onOpenChange(change))
    : Option.none()

const optionalMessageAttribute = <Message>(
  message: Option.Option<Message>,
  toAttribute: (message: Message) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(message, {
    onNone: () => [],
    onSome: value => [toAttribute(value)],
  })

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('modal', String(config.modal ?? defaultModal)),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
]

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('button'),
  h.AriaHasPopup('dialog'),
  h.AriaExpanded(config.open),
  h.AriaControls(panelId(config)),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...(config.open ? [h.DataAttribute('popup-open', '')] : []),
  ...(config.isDisabled === true ? [h.AriaDisabled(true)] : []),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, triggerOpenChange()),
    message => h.OnClick(message),
  ),
]

const dialogAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(config.id),
  h.Open(config.open),
  h.Role('dialog'),
  h.AriaModal(config.modal !== false),
  h.AriaLabelledBy(titleId(config)),
  h.Attribute('aria-describedby', descriptionId(config)),
  h.Style({ position: 'fixed', inset: '0' }),
  ...optionalMessageAttribute(
    openMessage(config, escapeOpenChange()),
    message => h.OnCancel(message),
  ),
]

const portalAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
): ReadonlyArray<Attribute<Message>> => [h.DataAttribute('portal', '')]

const backdropAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): DialogPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Role('presentation'),
        ...(config.open ? [] : [h.Hidden(true)]),
        h.Style({ userSelect: 'none', WebkitUserSelect: 'none' }),
        ...openStateDataAttributes(h, config.open),
        ...transitionDataAttributes(h, config.transitionStatus),
        ...optionalMessageAttribute(
          config.disableOutsidePress === true
            ? Option.none()
            : openMessage(config, outsideOpenChange()),
          message => h.OnClick(message),
        ),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const popupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): DialogPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(panelId(config)),
        h.Role('dialog'),
        h.Tabindex(-1),
        ...(config.open ? [] : [h.Hidden(true)]),
        h.AriaLabelledBy(titleId(config)),
        h.Attribute('aria-describedby', descriptionId(config)),
        ...openStateDataAttributes(h, config.open),
        ...transitionDataAttributes(h, config.transitionStatus),
        ...booleanDataAttribute(h, 'nested', config.isNested),
        ...booleanDataAttribute(
          h,
          'nested-dialog-open',
          config.hasNestedDialogOpen,
        ),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const closeAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('button'),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...(config.isDisabled === true ? [h.AriaDisabled(true)] : []),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, closeOpenChange()),
    message => h.OnClick(message),
  ),
]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const isMounted = mounted(config)

  return config.toView({
    root: rootAttributes(h, config),
    trigger: triggerAttributes(h, config),
    dialog: dialogAttributes(h, config),
    portal: portalAttributes(h),
    backdrop: backdropAttributes(h, config, isMounted),
    popup: popupAttributes(h, config, isMounted),
    title: [h.Id(titleId(config))],
    description: [h.Id(descriptionId(config))],
    close: closeAttributes(h, config),
    isMounted,
    isOpen: config.open,
  })
}

import { Schema as S } from 'effect'
import type * as Command from 'foldkit/command'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import * as Dialog from './dialog'

// MODEL

export const DrawerModalMode = Dialog.DialogModalMode
export type DrawerModalMode = Dialog.DialogModalMode

export const DrawerTransitionStatus = Dialog.DialogTransitionStatus
export type DrawerTransitionStatus = Dialog.DialogTransitionStatus

export const DrawerSwipeDirection = S.Union([
  S.Literal('up'),
  S.Literal('down'),
  S.Literal('left'),
  S.Literal('right'),
])
export type DrawerSwipeDirection = typeof DrawerSwipeDirection.Type

export const DrawerPlacement = S.Union([
  S.Literal('top'),
  S.Literal('right'),
  S.Literal('bottom'),
  S.Literal('left'),
])
export type DrawerPlacement = typeof DrawerPlacement.Type

export const DrawerChangeReason = S.Union([
  S.Literal('trigger-press'),
  S.Literal('close-press'),
  S.Literal('outside-press'),
  S.Literal('escape-key'),
  S.Literal('swipe'),
  S.Literal('none'),
])
export type DrawerChangeReason = typeof DrawerChangeReason.Type

export const DrawerOpenChange = S.Struct({
  open: S.Boolean,
  reason: DrawerChangeReason,
})
export type DrawerOpenChange = typeof DrawerOpenChange.Type

export const DrawerOptions = S.Struct({
  id: S.String,
  open: S.Boolean,
  modal: S.optional(DrawerModalMode),
  isDisabled: S.optional(S.Boolean),
  isNested: S.optional(S.Boolean),
  hasNestedDialogOpen: S.optional(S.Boolean),
  hasNestedDrawerOpen: S.optional(S.Boolean),
  hasNestedDrawerSwiping: S.optional(S.Boolean),
  hasActiveDrawer: S.optional(S.Boolean),
  isExpanded: S.optional(S.Boolean),
  isSwiping: S.optional(S.Boolean),
  transitionStatus: S.optional(DrawerTransitionStatus),
  titleId: S.optional(S.String),
  descriptionId: S.optional(S.String),
  focusSelector: S.optional(S.String),
  forceMount: S.optional(S.Boolean),
  disableOutsidePress: S.optional(S.Boolean),
  swipeDirection: S.optional(DrawerSwipeDirection),
  placement: S.optional(DrawerPlacement),
})
export type DrawerOptions = typeof DrawerOptions.Type

// MESSAGE

export const { CompletedCloseDialog, CompletedShowDialog } = Dialog

export const { CommandMessage } = Dialog
export type CommandMessage = Dialog.CommandMessage

// UPDATE

export const {
  CloseDialog,
  ShowDialog,
  closeOpenChange,
  descriptionId,
  escapeOpenChange,
  outsideOpenChange,
  panelId,
  titleId,
  triggerOpenChange,
} = Dialog

export const openChange = (
  open: boolean,
  reason: DrawerChangeReason = 'none',
): DrawerOpenChange => ({
  open,
  reason,
})

export const swipeOpenChange = (): DrawerOpenChange =>
  openChange(false, 'swipe')

const toDialogChange = (change: DrawerOpenChange): Dialog.DialogOpenChange =>
  Dialog.openChange(
    change.open,
    change.reason === 'swipe' ? 'none' : change.reason,
  )

export const commandForOpenChange = (
  config: Pick<DrawerOptions, 'focusSelector' | 'id' | 'modal'>,
  change: DrawerOpenChange,
): Command.Command<CommandMessage> =>
  Dialog.commandForOpenChange(config, toDialogChange(change))

// VIEW

export type DrawerAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  trigger: ReadonlyArray<Attribute<Message>>
  dialog: ReadonlyArray<Attribute<Message>>
  portal: ReadonlyArray<Attribute<Message>>
  backdrop: DrawerPopupPartAttributes<Message>
  popup: DrawerPopupPartAttributes<Message>
  content: ReadonlyArray<Attribute<Message>>
  title: ReadonlyArray<Attribute<Message>>
  description: ReadonlyArray<Attribute<Message>>
  close: ReadonlyArray<Attribute<Message>>
  indent: DrawerIndentPartAttributes<Message>
  indentBackground: DrawerIndentPartAttributes<Message>
  isMounted: boolean
  isOpen: boolean
}>

export type DrawerPopupPartAttributes<Message> =
  Dialog.DialogPartAttributes<Message>

export type DrawerIndentPartAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  isActive: boolean
}>

export type ViewConfig<Message> = DrawerOptions &
  Readonly<{
    toView: (attributes: DrawerAttributes<Message>) => Html
    onOpenChange?: (change: DrawerOpenChange) => Message
  }>

const defaultSwipeDirection: DrawerSwipeDirection = 'down'

export const placementFromSwipeDirection = (
  swipeDirection: DrawerSwipeDirection,
): DrawerPlacement => {
  if (swipeDirection === 'up') {
    return 'top'
  }

  if (swipeDirection === 'left') {
    return 'left'
  }

  if (swipeDirection === 'right') {
    return 'right'
  }

  return 'bottom'
}

const resolvedSwipeDirection = (
  config: Pick<DrawerOptions, 'swipeDirection'>,
): DrawerSwipeDirection => config.swipeDirection ?? defaultSwipeDirection

const resolvedPlacement = (
  config: Pick<DrawerOptions, 'placement' | 'swipeDirection'>,
): DrawerPlacement =>
  config.placement ??
  placementFromSwipeDirection(resolvedSwipeDirection(config))

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const activeDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  active: boolean,
): ReadonlyArray<Attribute<Message>> =>
  active ? [h.DataAttribute('active', '')] : [h.DataAttribute('inactive', '')]

const drawerOpenChange = (change: Dialog.DialogOpenChange): DrawerOpenChange =>
  openChange(change.open, change.reason)

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: Dialog.DialogAttributes<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...attributes.root,
  h.DataAttribute('swipe-direction', resolvedSwipeDirection(config)),
  h.DataAttribute('placement', resolvedPlacement(config)),
]

const popupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: Dialog.DialogAttributes<Message>,
): DrawerPopupPartAttributes<Message> => ({
  ...attributes.popup,
  root:
    attributes.popup.root.length > 0
      ? [
          ...attributes.popup.root,
          h.DataAttribute('swipe-direction', resolvedSwipeDirection(config)),
          h.DataAttribute('placement', resolvedPlacement(config)),
          h.Style({
            '--drawer-frontmost-height': '0px',
            '--drawer-height': 'auto',
            '--drawer-snap-point-offset': '0px',
            '--drawer-swipe-movement-x': '0px',
            '--drawer-swipe-movement-y': '0px',
            '--drawer-swipe-progress': '0',
            '--drawer-swipe-strength': '1',
            '--nested-drawers': config.hasNestedDrawerOpen === true ? '1' : '0',
          }),
          ...booleanDataAttribute(h, 'expanded', config.isExpanded),
          ...booleanDataAttribute(
            h,
            'nested-drawer-open',
            config.hasNestedDrawerOpen,
          ),
          ...booleanDataAttribute(
            h,
            'nested-drawer-swiping',
            config.hasNestedDrawerSwiping,
          ),
          ...booleanDataAttribute(h, 'swiping', config.isSwiping),
        ]
      : attributes.popup.root,
})

const contentAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
): ReadonlyArray<Attribute<Message>> => [h.DataAttribute('drawer-content', '')]

const indentAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  active: boolean,
): DrawerIndentPartAttributes<Message> => ({
  root: [
    ...activeDataAttributes(h, active),
    h.Style({ '--drawer-swipe-progress': '0' }),
  ],
  isActive: active,
})

const indentBackgroundAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  active: boolean,
): DrawerIndentPartAttributes<Message> => ({
  root: activeDataAttributes(h, active),
  isActive: active,
})

const drawerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: Dialog.DialogAttributes<Message>,
): DrawerAttributes<Message> => {
  const hasActiveDrawer = config.hasActiveDrawer ?? config.open

  return {
    ...attributes,
    root: rootAttributes(h, config, attributes),
    backdrop: attributes.backdrop,
    popup: popupAttributes(h, config, attributes),
    content: contentAttributes(h),
    indent: indentAttributes(h, hasActiveDrawer),
    indentBackground: indentBackgroundAttributes(h, hasActiveDrawer),
  }
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { onOpenChange, ...dialogConfig } = config
  const maybeOnOpenChange =
    onOpenChange === undefined
      ? {}
      : {
          onOpenChange: (change: Dialog.DialogOpenChange) =>
            onOpenChange(drawerOpenChange(change)),
        }

  return Dialog.view<Message>({
    ...dialogConfig,
    ...maybeOnOpenChange,
    toView: attributes =>
      config.toView(drawerAttributes(h, config, attributes)),
  })
}

import { Array, Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'
import { ts } from 'foldkit/schema'

// MODEL

export const FieldValidityIssue = S.Literals([
  'badInput',
  'customError',
  'patternMismatch',
  'rangeOverflow',
  'rangeUnderflow',
  'stepMismatch',
  'tooLong',
  'tooShort',
  'typeMismatch',
  'valueMissing',
])
export type FieldValidityIssue = typeof FieldValidityIssue.Type

export const UnknownFieldValidation = ts('UnknownFieldValidation')
export const ValidFieldValidation = ts('ValidFieldValidation', {
  value: S.optional(S.String),
})
export const InvalidFieldValidation = ts('InvalidFieldValidation', {
  error: S.String,
  errors: S.Array(S.String),
  issues: S.Array(FieldValidityIssue),
  value: S.optional(S.String),
})

export const FieldValidation = S.Union([
  UnknownFieldValidation,
  ValidFieldValidation,
  InvalidFieldValidation,
])
export type FieldValidation = typeof FieldValidation.Type

export const FieldOptions = S.Struct({
  id: S.optional(S.String),
  name: S.optional(S.String),
  controlId: S.optional(S.String),
  labelId: S.optional(S.String),
  descriptionId: S.optional(S.String),
  errorId: S.optional(S.String),
  type: S.optional(S.String),
  value: S.optional(S.Union([S.String, S.Number])),
  placeholder: S.optional(S.String),
  validation: S.optional(FieldValidation),
  isDisabled: S.optional(S.Boolean),
  isParentDisabled: S.optional(S.Boolean),
  isRequired: S.optional(S.Boolean),
  isReadOnly: S.optional(S.Boolean),
  isAutofocus: S.optional(S.Boolean),
  isTouched: S.optional(S.Boolean),
  isDirty: S.optional(S.Boolean),
  isFilled: S.optional(S.Boolean),
  isFocused: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
})
export type FieldOptions = typeof FieldOptions.Type

export const InputValueChange = S.Struct({
  value: S.String,
  reason: S.Literal('none'),
})
export type InputValueChange = typeof InputValueChange.Type

export type FieldValidityData = Readonly<{
  valid: boolean | null
  badInput: boolean
  customError: boolean
  patternMismatch: boolean
  rangeOverflow: boolean
  rangeUnderflow: boolean
  stepMismatch: boolean
  tooLong: boolean
  tooShort: boolean
  typeMismatch: boolean
  valueMissing: boolean
  error: string
  errors: ReadonlyArray<string>
  value: string | undefined
}>

export type FieldState = Readonly<{
  controlId: string | undefined
  descriptionId: string | undefined
  errorId: string | undefined
  labelId: string | undefined
  describedBy: string | undefined
  isDisabled: boolean
  isRequired: boolean
  isInvalid: boolean
  isValid: boolean | null
  isTouched: boolean
  isDirty: boolean
  isFilled: boolean
  isFocused: boolean
  isErrorVisible: boolean
  validityData: FieldValidityData
}>

// UPDATE

const emptyValidityData = (
  validation: FieldValidation | undefined,
): FieldValidityData => ({
  valid: null,
  badInput: false,
  customError: false,
  patternMismatch: false,
  rangeOverflow: false,
  rangeUnderflow: false,
  stepMismatch: false,
  tooLong: false,
  tooShort: false,
  typeMismatch: false,
  valueMissing: false,
  error: '',
  errors: [],
  value:
    validation?._tag === 'ValidFieldValidation' ? validation.value : undefined,
})

export const validityData = (
  validation: FieldValidation | undefined,
): FieldValidityData => {
  if (validation?._tag !== 'InvalidFieldValidation') {
    return validation?._tag === 'ValidFieldValidation'
      ? { ...emptyValidityData(validation), valid: true }
      : emptyValidityData(validation)
  }

  const hasIssue = (issue: FieldValidityIssue): boolean =>
    validation.issues.includes(issue)

  return {
    valid: false,
    badInput: hasIssue('badInput'),
    customError: hasIssue('customError'),
    patternMismatch: hasIssue('patternMismatch'),
    rangeOverflow: hasIssue('rangeOverflow'),
    rangeUnderflow: hasIssue('rangeUnderflow'),
    stepMismatch: hasIssue('stepMismatch'),
    tooLong: hasIssue('tooLong'),
    tooShort: hasIssue('tooShort'),
    typeMismatch: hasIssue('typeMismatch'),
    valueMissing: hasIssue('valueMissing'),
    error: validation.error,
    errors: validation.errors,
    value: validation.value,
  }
}

export const combinedValidityData = (
  validation: FieldValidation | undefined,
  isInvalid: boolean | undefined,
): FieldValidityData => {
  const data = validityData(validation)

  return isInvalid === true ? { ...data, valid: false } : data
}

const derivedId = (
  id: string | undefined,
  suffix: string,
): string | undefined => (id === undefined ? undefined : `${id}-${suffix}`)

const spacedIds = (
  ids: ReadonlyArray<string | undefined>,
): string | undefined => {
  const presentIds = ids.filter((id): id is string => id !== undefined)

  return Array.isReadonlyArrayNonEmpty(presentIds)
    ? presentIds.join(' ')
    : undefined
}

export const fieldState = (options: FieldOptions): FieldState => {
  const data = combinedValidityData(options.validation, options.isInvalid)
  const isDisabled =
    options.isDisabled === true || options.isParentDisabled === true
  const isInvalid = isDisabled ? false : data.valid === false
  const descriptionId =
    options.descriptionId ?? derivedId(options.id, 'description')
  const errorId = options.errorId ?? derivedId(options.id, 'error')
  const isErrorVisible = !isDisabled && isInvalid && errorId !== undefined
  const visibleErrorId = isErrorVisible ? errorId : undefined

  return {
    controlId: options.controlId ?? derivedId(options.id, 'control'),
    descriptionId,
    errorId,
    labelId: options.labelId ?? derivedId(options.id, 'label'),
    describedBy: spacedIds([descriptionId, visibleErrorId]),
    isDisabled,
    isRequired: options.isRequired === true,
    isInvalid,
    isValid: isDisabled ? null : data.valid,
    isTouched: options.isTouched === true,
    isDirty: options.isDirty === true,
    isFilled: options.isFilled === true,
    isFocused: options.isFocused === true,
    isErrorVisible,
    validityData: data,
  }
}

// VIEW

export type FieldAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  item: ReadonlyArray<Attribute<Message>>
  label: ReadonlyArray<Attribute<Message>>
  control: ReadonlyArray<Attribute<Message>>
  description: ReadonlyArray<Attribute<Message>>
  error: ReadonlyArray<Attribute<Message>>
  state: FieldState
}>

export type ViewConfig<Message> = FieldOptions &
  Readonly<{
    toView: (attributes: FieldAttributes<Message>) => Html
    onValueChange?: (change: InputValueChange) => Message
    onFocus?: Message
    onBlur?: Message
  }>

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean,
): ReadonlyArray<Attribute<Message>> =>
  value ? [h.DataAttribute(name, '')] : []

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> => (value ? [toAttribute(true)] : [])

const validityAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: FieldState,
): ReadonlyArray<Attribute<Message>> => [
  ...booleanDataAttribute(h, 'disabled', state.isDisabled),
  ...booleanDataAttribute(h, 'required', state.isRequired),
  ...booleanDataAttribute(h, 'invalid', state.isInvalid),
  ...booleanDataAttribute(h, 'valid', state.isValid === true),
  ...booleanDataAttribute(h, 'touched', state.isTouched),
  ...booleanDataAttribute(h, 'dirty', state.isDirty),
  ...booleanDataAttribute(h, 'filled', state.isFilled),
  ...booleanDataAttribute(h, 'focused', state.isFocused),
]

const controlEvents = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: FieldState,
): ReadonlyArray<Attribute<Message>> => {
  const { onValueChange } = config

  return [
    ...(Predicate.isNotUndefined(onValueChange) && !state.isDisabled
      ? [
          h.OnInput(value =>
            onValueChange({
              value,
              reason: 'none',
            }),
          ),
        ]
      : []),
    ...(Predicate.isNotUndefined(config.onFocus)
      ? [h.OnFocus(config.onFocus)]
      : []),
    ...(Predicate.isNotUndefined(config.onBlur)
      ? [h.OnBlur(config.onBlur)]
      : []),
  ]
}

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: FieldState,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('group'),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...validityAttributes(h, state),
]

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: FieldState,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('group'),
  ...validityAttributes(h, state),
]

const labelAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: FieldState,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(state.labelId, value => h.Id(value)),
  ...optionalAttribute<Message>(state.controlId, value =>
    h.Attribute('for', value),
  ),
  ...validityAttributes(h, state),
]

const controlAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: FieldState,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(state.controlId, value => h.Id(value)),
  ...optionalAttribute<Message>(config.name, value => h.Name(value)),
  ...optionalAttribute<Message>(config.type, value => h.Type(value)),
  ...optionalAttribute<Message>(config.placeholder, value =>
    h.Placeholder(value),
  ),
  ...(config.value === undefined ? [] : [h.Value(String(config.value))]),
  ...optionalAttribute<Message>(state.labelId, value =>
    h.AriaLabelledBy(value),
  ),
  ...optionalAttribute<Message>(state.describedBy, value =>
    h.AriaDescribedBy(value),
  ),
  ...optionalBooleanAttribute<Message>(state.isDisabled, value =>
    h.Disabled(value),
  ),
  ...optionalBooleanAttribute<Message>(state.isRequired, value =>
    h.Required(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly === true, value =>
    h.Readonly(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isAutofocus === true, value =>
    h.Autofocus(value),
  ),
  ...(state.isInvalid ? [h.AriaInvalid(true)] : []),
  ...validityAttributes(h, state),
  ...controlEvents(h, config, state),
]

const descriptionAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: FieldState,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(state.descriptionId, value => h.Id(value)),
  ...validityAttributes(h, state),
]

const errorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: FieldState,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(state.errorId, value => h.Id(value)),
  ...validityAttributes(h, state),
]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const state = fieldState(config)

  return config.toView({
    root: rootAttributes(h, config, state),
    item: itemAttributes(h, state),
    label: labelAttributes(h, state),
    control: controlAttributes(h, config, state),
    description: descriptionAttributes(h, state),
    error: errorAttributes(h, state),
    state,
  })
}

import { Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const FieldsetOptions = S.Struct({
  id: S.optional(S.String),
  name: S.optional(S.String),
  form: S.optional(S.String),
  legendId: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  isParentDisabled: S.optional(S.Boolean),
})
export type FieldsetOptions = typeof FieldsetOptions.Type

export const FieldsetPart = S.Union([S.Literal('root'), S.Literal('legend')])
export type FieldsetPart = typeof FieldsetPart.Type

export type FieldsetState = Readonly<{
  isDisabled: boolean
  legendId: string | undefined
}>

// UPDATE

const derivedLegendId = (id: string | undefined): string | undefined =>
  id === undefined ? undefined : `${id}-legend`

export const legendId = (
  options: Pick<FieldsetOptions, 'id' | 'legendId'>,
): string | undefined => options.legendId ?? derivedLegendId(options.id)

export const fieldsetState = (options: FieldsetOptions): FieldsetState => ({
  isDisabled: options.isDisabled === true || options.isParentDisabled === true,
  legendId: legendId(options),
})

// VIEW

export type FieldsetAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  legend: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = FieldsetOptions &
  Readonly<{
    toView: (attributes: FieldsetAttributes<Message>) => Html
  }>

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean,
): ReadonlyArray<Attribute<Message>> =>
  value ? [h.DataAttribute(name, '')] : []

const disabledAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  isDisabled: boolean,
): ReadonlyArray<Attribute<Message>> => (isDisabled ? [h.Disabled(true)] : [])

const ariaLabelledByAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  id: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  id === undefined ? [] : [h.AriaLabelledBy(id)]

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  form: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  form === undefined ? [] : [h.Attribute('form', form)]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: FieldsetState,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...optionalAttribute<Message>(config.name, value => h.Name(value)),
  ...formOwnerAttributes(h, config.form),
  ...ariaLabelledByAttribute(h, state.legendId),
  ...disabledAttribute(h, state.isDisabled),
  ...booleanDataAttribute(h, 'disabled', state.isDisabled),
]

const legendAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: FieldsetState,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(state.legendId, value => h.Id(value)),
  ...booleanDataAttribute(h, 'disabled', state.isDisabled),
]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const state = fieldsetState(config)

  return config.toView({
    root: rootAttributes(h, config, state),
    legend: legendAttributes(h, state),
  })
}

import { Array, Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import * as Field from './field'

// MODEL

export const FormValidationMode = S.Union([
  S.Literal('onSubmit'),
  S.Literal('onBlur'),
  S.Literal('onChange'),
])
export type FormValidationMode = typeof FormValidationMode.Type

export const FormMethod = S.Union([
  S.Literal('get'),
  S.Literal('post'),
  S.Literal('dialog'),
])
export type FormMethod = typeof FormMethod.Type

export const FormEncodingType = S.Union([
  S.Literal('application/x-www-form-urlencoded'),
  S.Literal('multipart/form-data'),
  S.Literal('text/plain'),
])
export type FormEncodingType = typeof FormEncodingType.Type

export const FormValue = S.Union([S.String, S.Number, S.Boolean])
export type FormValue = typeof FormValue.Type

export const FormFieldValue = S.Struct({
  name: S.String,
  value: FormValue,
  validation: S.optional(Field.FieldValidation),
  isDisabled: S.optional(S.Boolean),
})
export type FormFieldValue = typeof FormFieldValue.Type

export const FormSubmitPayload = S.Struct({
  reason: S.Literal('none'),
  validationMode: FormValidationMode,
  values: S.Array(FormFieldValue),
  invalidNames: S.Array(S.String),
  isValid: S.Boolean,
})
export type FormSubmitPayload = typeof FormSubmitPayload.Type

export const FormResetPayload = S.Struct({
  reason: S.Literal('none'),
  values: S.Array(FormFieldValue),
})
export type FormResetPayload = typeof FormResetPayload.Type

export const FormOptions = S.Struct({
  id: S.optional(S.String),
  name: S.optional(S.String),
  action: S.optional(S.String),
  method: S.optional(FormMethod),
  encType: S.optional(FormEncodingType),
  target: S.optional(S.String),
  autocomplete: S.optional(S.String),
  noValidate: S.optional(S.Boolean),
  validationMode: S.optional(FormValidationMode),
  fields: S.optional(S.Array(FormFieldValue)),
  isDisabled: S.optional(S.Boolean),
  isSubmitting: S.optional(S.Boolean),
  isSubmitted: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
})
export type FormOptions = typeof FormOptions.Type

export type FormState = Readonly<{
  validationMode: FormValidationMode
  values: ReadonlyArray<FormFieldValue>
  invalidNames: ReadonlyArray<string>
  isDisabled: boolean
  isSubmitting: boolean
  isSubmitted: boolean
  isInvalid: boolean
  isValid: boolean
}>

// UPDATE

const isFieldInvalid = (field: FormFieldValue): boolean =>
  Field.fieldState({
    name: field.name,
    validation: field.validation,
    isDisabled: field.isDisabled,
  }).isInvalid

export const submittableValues = (
  fields: ReadonlyArray<FormFieldValue> | undefined,
): ReadonlyArray<FormFieldValue> =>
  (fields ?? []).filter(field => field.isDisabled !== true)

export const invalidFieldNames = (
  fields: ReadonlyArray<FormFieldValue> | undefined,
): ReadonlyArray<string> =>
  submittableValues(fields).flatMap(field =>
    isFieldInvalid(field) ? [field.name] : [],
  )

export const valuesByName = (
  fields: ReadonlyArray<FormFieldValue>,
): Readonly<Record<string, FormValue>> =>
  Object.fromEntries(fields.map(field => [field.name, field.value]))

export const formState = (options: FormOptions): FormState => {
  const values = submittableValues(options.fields)
  const invalidNames = invalidFieldNames(options.fields)
  const isInvalid =
    options.isDisabled === true
      ? false
      : options.isInvalid === true ||
        Array.isReadonlyArrayNonEmpty(invalidNames)

  return {
    validationMode: options.validationMode ?? 'onSubmit',
    values,
    invalidNames,
    isDisabled: options.isDisabled === true,
    isSubmitting: options.isSubmitting === true,
    isSubmitted: options.isSubmitted === true,
    isInvalid,
    isValid: !isInvalid,
  }
}

export const submitPayload = (state: FormState): FormSubmitPayload => ({
  reason: 'none',
  validationMode: state.validationMode,
  values: state.values,
  invalidNames: state.invalidNames,
  isValid: state.isValid,
})

export const resetPayload = (state: FormState): FormResetPayload => ({
  reason: 'none',
  values: state.values,
})

// VIEW

export type FormAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  state: FormState
}>

export type ViewConfig<Message> = FormOptions &
  Readonly<{
    toView: (attributes: FormAttributes<Message>) => Html
    onSubmit?: (payload: FormSubmitPayload) => Message
    onReset?: (payload: FormResetPayload) => Message
  }>

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> => (value ? [toAttribute(true)] : [])

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean,
): ReadonlyArray<Attribute<Message>> =>
  value ? [h.DataAttribute(name, '')] : []

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ViewConfig<Message>,
    'action' | 'autocomplete' | 'encType' | 'method' | 'target'
  >,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(config.action, value => h.Action(value)),
  ...optionalAttribute<Message>(config.method, value => h.Method(value)),
  ...optionalAttribute<Message>(config.encType, value => h.Enctype(value)),
  ...optionalAttribute<Message>(config.target, value => h.Target(value)),
  ...optionalAttribute<Message>(config.autocomplete, value =>
    h.Autocomplete(value),
  ),
]

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: FormState,
): ReadonlyArray<Attribute<Message>> => [
  ...booleanDataAttribute(h, 'disabled', state.isDisabled),
  ...booleanDataAttribute(h, 'valid', state.isValid),
  ...booleanDataAttribute(h, 'invalid', state.isInvalid),
  ...booleanDataAttribute(h, 'submitting', state.isSubmitting),
  ...booleanDataAttribute(h, 'submitted', state.isSubmitted),
]

const eventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: FormState,
): ReadonlyArray<Attribute<Message>> => {
  if (state.isDisabled) {
    return []
  }

  return [
    ...(Predicate.isNotUndefined(config.onSubmit)
      ? [h.OnSubmit(config.onSubmit(submitPayload(state)))]
      : []),
    ...(Predicate.isNotUndefined(config.onReset)
      ? [h.OnReset(config.onReset(resetPayload(state)))]
      : []),
  ]
}

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: FormState,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...optionalAttribute<Message>(config.name, value => h.Name(value)),
  ...formOwnerAttributes(h, config),
  ...optionalBooleanAttribute<Message>(config.noValidate !== false, value =>
    h.Novalidate(value),
  ),
  ...stateDataAttributes(h, state),
  ...eventAttributes(h, config, state),
]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const state = formState(config)

  return config.toView({
    root: rootAttributes(h, config, state),
    state,
  })
}

import { Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const InputType = S.String
export type InputType = typeof InputType.Type

export const InputChangeReason = S.Literal('none')
export type InputChangeReason = typeof InputChangeReason.Type

export const InputValueChange = S.Struct({
  value: S.String,
  reason: InputChangeReason,
})
export type InputValueChange = typeof InputValueChange.Type

export const InputOptions = S.Struct({
  id: S.optional(S.String),
  name: S.optional(S.String),
  type: S.optional(InputType),
  value: S.optional(S.Union([S.String, S.Number])),
  placeholder: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
  isRequired: S.optional(S.Boolean),
  isReadOnly: S.optional(S.Boolean),
  isAutofocus: S.optional(S.Boolean),
  isValid: S.optional(S.Boolean),
  isFieldInvalid: S.optional(S.Boolean),
  isDirty: S.optional(S.Boolean),
  isTouched: S.optional(S.Boolean),
  isFilled: S.optional(S.Boolean),
  isFocused: S.optional(S.Boolean),
})
export type InputOptions = typeof InputOptions.Type

// VIEW

export type InputAttributes<Message> = Readonly<{
  input: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = InputOptions &
  Readonly<{
    toView: (attributes: InputAttributes<Message>) => Html
    onValueChange?: (change: InputValueChange) => Message
    onFocus?: Message
    onBlur?: Message
  }>

const booleanAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.Attribute(name, '')] : []

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const valueAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  value: string | number | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [h.Value(String(value))] : []

const dataStateAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ViewConfig<Message>,
    | 'isDirty'
    | 'isDisabled'
    | 'isFieldInvalid'
    | 'isFilled'
    | 'isFocused'
    | 'isTouched'
    | 'isValid'
  >,
): ReadonlyArray<Attribute<Message>> => [
  ...booleanAttribute(h, 'data-disabled', config.isDisabled),
  ...booleanAttribute(h, 'data-valid', config.isValid),
  ...booleanAttribute(h, 'data-invalid', config.isFieldInvalid),
  ...booleanAttribute(h, 'data-dirty', config.isDirty),
  ...booleanAttribute(h, 'data-touched', config.isTouched),
  ...booleanAttribute(h, 'data-filled', config.isFilled),
  ...booleanAttribute(h, 'data-focused', config.isFocused),
]

const eventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => {
  const { onValueChange } = config

  return [
    ...(Predicate.isNotUndefined(onValueChange) && !config.isDisabled
      ? [
          h.OnInput(value =>
            onValueChange({
              value,
              reason: 'none',
            }),
          ),
        ]
      : []),
    ...(Predicate.isNotUndefined(config.onFocus)
      ? [h.OnFocus(config.onFocus)]
      : []),
    ...(Predicate.isNotUndefined(config.onBlur)
      ? [h.OnBlur(config.onBlur)]
      : []),
  ]
}

const inputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(config.type, value => h.Type(value)),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...optionalAttribute<Message>(config.name, value => h.Name(value)),
  ...optionalAttribute<Message>(config.placeholder, value =>
    h.Placeholder(value),
  ),
  ...valueAttribute(h, config.value),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.Disabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.Required(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.Readonly(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isAutofocus, value =>
    h.Autofocus(value),
  ),
  ...(config.isInvalid === true ? [h.AriaInvalid(true)] : []),
  ...dataStateAttributes(h, config),
  ...eventAttributes(h, config),
]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()

  return config.toView({
    input: inputAttributes(h, config),
  })
}

import { Option, Predicate, Schema as S } from 'effect'
