// UPDATE

const defaultSide: MenuSide = 'bottom'
const defaultAlign: MenuAlign = 'start'
const defaultSubmenuSide: MenuSide = 'right'
const defaultSubmenuAlign: MenuAlign = 'start'
const defaultSideOffset = 0
const defaultAlignOffset = 0
const defaultCollisionAvoidance = true
const defaultCollisionPadding = 0

const activationKeys = new Set(['Enter', ' '])
const searchKeyPattern = /^[\p{Letter}\p{Number}]$/u

export const {
  FocusPopover: FocusMenu,
  RestorePopoverFocus: RestoreMenuFocus,
} = Popover

export const triggerId = (config: Pick<MenuOptions, 'id' | 'triggerId'>) =>
  config.triggerId ?? `${config.id}-trigger`

export const triggerSelector = (
  config: Pick<MenuOptions, 'id' | 'triggerId' | 'triggerSelector'>,
) => config.triggerSelector ?? `#${triggerId(config)}`

export const popupId = (
  config: Pick<MenuOptions, 'id'>,
  parentValue?: string | undefined,
): string =>
  parentValue === undefined
    ? `${config.id}-popup`
    : `${config.id}-submenu-${parentValue}-popup`

export const positionerId = (
  config: Pick<MenuOptions, 'id'>,
  parentValue?: string | undefined,
): string =>
  parentValue === undefined
    ? `${config.id}-positioner`
    : `${config.id}-submenu-${parentValue}-positioner`

export const arrowId = (
  config: Pick<MenuOptions, 'id'>,
  parentValue?: string | undefined,
): string =>
  parentValue === undefined
    ? `${config.id}-arrow`
    : `${config.id}-submenu-${parentValue}-arrow`

export const groupLabelId = (
  config: Pick<MenuOptions, 'id'>,
  parentValue?: string | undefined,
): string =>
  parentValue === undefined
    ? `${config.id}-group-label`
    : `${config.id}-submenu-${parentValue}-group-label`

export const itemKind = (item: MenuItemDescriptor): MenuItemKind =>
  item.kind ?? 'item'

export const itemId = (
  config: Pick<MenuOptions, 'id'>,
  item: MenuItemDescriptor,
): string => item.id ?? `${config.id}-item-${item.value}`

export const itemFocusSelector = (
  config: Pick<MenuOptions, 'id'>,
  item: MenuItemDescriptor,
): string => `#${itemId(config, item)}`

const rootAnchorName = (config: Pick<MenuOptions, 'id'>): string =>
  `--${config.id}-trigger`

const submenuAnchorName = (
  config: Pick<MenuOptions, 'id'>,
  value: string,
): string => `--${config.id}-item-${value.replaceAll(/[^A-Za-z0-9_-]/gu, '-')}`

export const itemsForParent = (
  config: Pick<MenuOptions, 'items'>,
  parentValue?: string | undefined,
): ReadonlyArray<MenuItemDescriptor> =>
  config.items.filter(item => item.parentValue === parentValue)

export const enabledItems = (
  config: Pick<MenuOptions, 'isDisabled' | 'items'>,
  parentValue?: string | undefined,
): ReadonlyArray<MenuItemDescriptor> =>
  config.isDisabled === true
    ? []
    : itemsForParent(config, parentValue).filter(
        item => item.isDisabled !== true,
      )

export const navigableItems = (
  config: Pick<MenuOptions, 'isDisabled' | 'items'>,
  parentValue?: string | undefined,
): ReadonlyArray<MenuItemDescriptor> =>
  config.isDisabled === true ? [] : itemsForParent(config, parentValue)

export const highlightedItem = (
  config: Pick<MenuOptions, 'highlightedValue' | 'items'>,
): MenuItemDescriptor | undefined =>
  config.items.find(item => item.value === config.highlightedValue)

export const openChange = (
  open: boolean,
  reason: MenuOpenChangeReason = 'none',
  parentValue?: string | undefined,
): MenuOpenChange => ({ open, reason, parentValue })

export const highlightChange = (
  config: Pick<MenuOptions, 'id'>,
  item: MenuItemDescriptor,
  reason: MenuHighlightChangeReason = 'none',
): MenuHighlightChange => ({
  value: item.value,
  reason,
  focusSelector: itemFocusSelector(config, item),
})

export const itemPress = (item: MenuItemDescriptor): MenuItemPress => ({
  value: item.value,
  kind: itemKind(item),
})

export const checkedChange = (item: MenuItemDescriptor): MenuCheckedChange => ({
  value: item.value,
  checked: item.isChecked !== true,
})

export const radioValueChange = (
  item: MenuItemDescriptor,
): MenuRadioValueChange => ({
  groupValue: item.radioGroupValue ?? 'default',
  value: item.value,
})

const keyboardDirection = (
  key: string,
): 'first' | 'last' | 'next' | 'previous' | undefined => {
  if (key === 'ArrowDown') {
    return 'next'
  }

  if (key === 'ArrowUp') {
    return 'previous'
  }

  if (key === 'Home') {
    return 'first'
  }

  if (key === 'End') {
    return 'last'
  }

  return undefined
}

const indexOffset = (
  currentIndex: number,
  direction: 'next' | 'previous',
): number => currentIndex + (direction === 'next' ? 1 : -1)

export const nextHighlightedItem = (
  config: Pick<MenuOptions, 'highlightedValue' | 'isDisabled' | 'items'>,
  direction: 'first' | 'last' | 'next' | 'previous',
  parentValue?: string | undefined,
): MenuItemDescriptor | undefined => {
  const items = navigableItems(config, parentValue)

  if (direction === 'first') {
    return items[0]
  }

  if (direction === 'last') {
    return items.at(-1)
  }

  const currentIndex = items.findIndex(
    item => item.value === config.highlightedValue,
  )
  const resolvedCurrentIndex = currentIndex === -1 ? 0 : currentIndex
  const candidateIndex = indexOffset(resolvedCurrentIndex, direction)

  if (candidateIndex >= 0 && candidateIndex < items.length) {
    return items[candidateIndex]
  }

  return items[resolvedCurrentIndex]
}

export const typeaheadItem = (
  config: Pick<MenuOptions, 'highlightedValue' | 'isDisabled' | 'items'>,
  search: string,
  parentValue?: string | undefined,
): MenuItemDescriptor | undefined => {
  const items = navigableItems(config, parentValue)
  const normalizedSearch = search.toLocaleLowerCase()
  const currentIndex = items.findIndex(
    item => item.value === config.highlightedValue,
  )
  const orderedItems =
    currentIndex === -1
      ? items
      : [...items.slice(currentIndex + 1), ...items.slice(0, currentIndex + 1)]

  return orderedItems.find(item =>
    (item.textValue ?? item.label)
      .toLocaleLowerCase()
      .startsWith(normalizedSearch),
  )
}

const popoverChangeReason = (
  change: MenuOpenChange,
): Popover.PopoverChangeReason => {
  if (change.reason === 'outside-press') {
    return 'outside-press'
  }

  if (change.reason === 'escape-key') {
    return 'escape-key'
  }

  return change.open ? 'trigger-press' : 'close-press'
}

export const commandForOpenChange = (
  config: Pick<MenuOptions, 'id' | 'triggerId' | 'triggerSelector'>,
  change: MenuOpenChange,
): Command.Command<Popover.CommandMessage> =>
  Popover.commandForOpenChange(
    {
      id: config.id,
      triggerId: triggerId(config),
      triggerSelector: triggerSelector(config),
      focusSelector: `#${popupId(config, change.parentValue)}`,
    },
    Popover.openChange(change.open, popoverChangeReason(change)),
  )

// VIEW

export type MenuPartAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type MenuItemAttributes<Message> = Readonly<{
  item: MenuItemDescriptor
  root: ReadonlyArray<Attribute<Message>>
  label: ReadonlyArray<Attribute<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
  submenuIndicator: ReadonlyArray<Attribute<Message>>
}>

export type MenuPopupAttributes<Message> = Readonly<{
  parentValue?: string | undefined
  positioner: MenuPartAttributes<Message>
  backdrop: MenuPartAttributes<Message>
  popup: MenuPartAttributes<Message>
  arrow: MenuPartAttributes<Message>
  group: ReadonlyArray<Attribute<Message>>
  groupLabel: ReadonlyArray<Attribute<Message>>
  separator: ReadonlyArray<Attribute<Message>>
  items: ReadonlyArray<MenuItemAttributes<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type MenuAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  trigger: ReadonlyArray<Attribute<Message>>
  portal: ReadonlyArray<Attribute<Message>>
  popup: MenuPopupAttributes<Message>
  submenus: ReadonlyArray<MenuPopupAttributes<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type ViewConfig<Message> = MenuOptions &
  Readonly<{
    toView: (attributes: MenuAttributes<Message>) => Html
    onOpenChange?: (change: MenuOpenChange) => Message
    onHighlightChange?: (change: MenuHighlightChange) => Message
    onItemPress?: (press: MenuItemPress) => Message
    onCheckedChange?: (change: MenuCheckedChange) => Message
    onRadioValueChange?: (change: MenuRadioValueChange) => Message
    onFocus?: Message
    onBlur?: Message
  }> &
  AnchorPositioningConfig<Message>

const resolvedSide = (
  config: Pick<MenuOptions, 'side'>,
  parentValue?: string | undefined,
): MenuSide =>
  parentValue === undefined ? (config.side ?? defaultSide) : defaultSubmenuSide

const resolvedAlign = (
  config: Pick<MenuOptions, 'align'>,
  parentValue?: string | undefined,
): MenuAlign =>
  parentValue === undefined
    ? (config.align ?? defaultAlign)
    : defaultSubmenuAlign

const positioningAnchorId = (
  config: Pick<MenuOptions, 'id' | 'items' | 'triggerId'>,
  parentValue?: string | undefined,
): string => {
  if (parentValue === undefined) {
    return triggerId(config)
  }

  const parentItem = config.items.find(item => item.value === parentValue)
  return parentItem === undefined
    ? triggerId(config)
    : itemId(config, parentItem)
}

const mounted = (
  config: Pick<MenuOptions, 'forceMount' | 'open' | 'transitionStatus'>,
  isOpen: boolean,
): boolean =>
  isOpen ||
  config.open ||
  config.forceMount === true ||
  config.transitionStatus === 'ending'

const submenuValues = (
  config: Pick<MenuOptions, 'openSubmenuValues'>,
): ReadonlyArray<string> => config.openSubmenuValues ?? []

const isSubmenuOpen = (
  config: Pick<MenuOptions, 'open' | 'openSubmenuValues'>,
  parentValue: string,
): boolean => config.open && submenuValues(config).includes(parentValue)

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const optionalMessageAttribute = <Message>(
  message: Option.Option<Message>,
  toAttribute: (message: Message) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(message, {
    onNone: () => [],
    onSome: value => [toAttribute(value)],
  })

const openMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onOpenChange'>,
  change: MenuOpenChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onOpenChange)
    ? Option.some(config.onOpenChange(change))
    : Option.none()

const highlightMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'id' | 'isDisabled' | 'onHighlightChange'>,
  item: MenuItemDescriptor,
  reason: MenuHighlightChangeReason,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onHighlightChange) &&
  config.isDisabled !== true &&
  (item.isDisabled !== true || reason !== 'item-hover')
    ? Option.some(
        config.onHighlightChange(highlightChange(config, item, reason)),
      )
    : Option.none()

const itemPressMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'isDisabled' | 'onItemPress'>,
  item: MenuItemDescriptor,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onItemPress) &&
  config.isDisabled !== true &&
  item.isDisabled !== true &&
  itemKind(item) === 'item'
    ? Option.some(config.onItemPress(itemPress(item)))
    : Option.none()

const checkedMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'isDisabled' | 'onCheckedChange'>,
  item: MenuItemDescriptor,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onCheckedChange) &&
  config.isDisabled !== true &&
  item.isDisabled !== true &&
  itemKind(item) === 'checkbox'
    ? Option.some(config.onCheckedChange(checkedChange(item)))
    : Option.none()

const radioMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'isDisabled' | 'onRadioValueChange'>,
  item: MenuItemDescriptor,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onRadioValueChange) &&
  config.isDisabled !== true &&
  item.isDisabled !== true &&
  itemKind(item) === 'radio'
    ? Option.some(config.onRadioValueChange(radioValueChange(item)))
    : Option.none()

const openStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  open: boolean,
): ReadonlyArray<Attribute<Message>> =>
  open ? [h.DataAttribute('open', '')] : [h.DataAttribute('closed', '')]

const transitionDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  transitionStatus: MenuTransitionStatus | undefined,
): ReadonlyArray<Attribute<Message>> => {
  if (transitionStatus === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (transitionStatus === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const placementAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  parentValue?: string | undefined,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('side', resolvedSide(config, parentValue)),
  h.DataAttribute('align', resolvedAlign(config, parentValue)),
  h.DataAttribute(
    'side-offset',
    String(
      parentValue === undefined ? (config.sideOffset ?? defaultSideOffset) : 0,
    ),
  ),
  h.DataAttribute(
    'align-offset',
    String(
      parentValue === undefined
        ? (config.alignOffset ?? defaultAlignOffset)
        : -3,
    ),
  ),
  h.DataAttribute(
    'collision-avoidance',
    String(config.collisionAvoidance ?? defaultCollisionAvoidance),
  ),
  h.DataAttribute(
    'collision-padding',
    String(config.collisionPadding ?? defaultCollisionPadding),
  ),
]

const horizontalAnchorStyle = (
  config: Pick<MenuOptions, 'align'>,
  parentValue?: string | undefined,
): Readonly<Record<string, string>> => {
  const align = resolvedAlign(config, parentValue)

  if (align === 'center') {
    return { left: 'anchor(center)', translate: '-50% 0' }
  }

  if (align === 'end') {
    return { left: 'anchor(right)', translate: '-100% 0' }
  }

  return { left: 'anchor(left)' }
}

const verticalAnchorStyle = (
  config: Pick<MenuOptions, 'align'>,
  parentValue?: string | undefined,
): Readonly<Record<string, string>> => {
  const align = resolvedAlign(config, parentValue)

  if (align === 'center') {
    return { top: 'anchor(center)', translate: '0 -50%' }
  }

  if (align === 'end') {
    return { top: 'anchor(bottom)', translate: '0 -100%' }
  }

  return { top: 'anchor(top)' }
}

const sideOffset = (
  config: Pick<MenuOptions, 'sideOffset'>,
  parentValue?: string | undefined,
): number =>
  parentValue === undefined ? (config.sideOffset ?? defaultSideOffset) : 0

const placementStyle = (
  config: Pick<MenuOptions, 'align' | 'side' | 'sideOffset'>,
  parentValue?: string | undefined,
): Readonly<Record<string, string>> => {
  const offset = `${sideOffset(config, parentValue)}px`
  const side = resolvedSide(config, parentValue)

  if (side === 'top') {
    return {
      ...horizontalAnchorStyle(config, parentValue),
      bottom: `calc(anchor(top) + ${offset})`,
    }
  }

  if (side === 'left' || side === 'inline-start') {
    return {
      ...verticalAnchorStyle(config, parentValue),
      right: `calc(anchor(left) + ${offset})`,
    }
  }

  if (side === 'right' || side === 'inline-end') {
    return {
      ...verticalAnchorStyle(config, parentValue),
      left: `calc(anchor(right) + ${offset})`,
    }
  }

  return {
    ...horizontalAnchorStyle(config, parentValue),
    top: `calc(anchor(bottom) + ${offset})`,
  }
}

const positionArea = (
  config: Pick<MenuOptions, 'align' | 'side'>,
  parentValue?: string | undefined,
): string => {
  const align = resolvedAlign(config, parentValue)
  const side = resolvedSide(config, parentValue)
  const inlineAlignments = {
    start: 'span-inline-start',
    center: 'center',
    end: 'span-inline-end',
  }
  const blockAlignments = {
    start: 'span-block-start',
    center: 'center',
    end: 'span-block-end',
  }

  if (side === 'top') {
    return `block-start ${inlineAlignments[align]}`
  }
  if (side === 'bottom') {
    return `block-end ${inlineAlignments[align]}`
  }
  if (side === 'left' || side === 'inline-start') {
    return `inline-start ${blockAlignments[align]}`
  }
  return `inline-end ${blockAlignments[align]}`
}

const popupAnchorName = (
  config: Pick<MenuOptions, 'id'>,
  parentValue?: string | undefined,
): string =>
  parentValue === undefined
    ? rootAnchorName(config)
    : submenuAnchorName(config, parentValue)

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('side', resolvedSide(config)),
  h.DataAttribute('align', resolvedAlign(config)),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
]

const triggerKeyboardMessage = <Message>(
  config: ViewConfig<Message>,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (modifiers.shiftKey || config.isDisabled === true) {
    return Option.none()
  }

  if (activationKeys.has(key) || key === 'ArrowDown' || key === 'ArrowUp') {
    return openMessage(config, openChange(true, 'keyboard-open'))
  }

  return Option.none()
}

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(triggerId(config)),
  h.Type('button'),
  h.AriaHasPopup('menu'),
  h.AriaExpanded(config.open),
  h.AriaControls(popupId(config)),
  h.Style({ anchorName: rootAnchorName(config) }),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...(config.open ? [h.DataAttribute('popup-open', '')] : []),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, openChange(!config.open, 'trigger-press')),
    message => h.OnClick(message),
  ),
  h.OnKeyDownPreventDefault((key, modifiers) =>
    triggerKeyboardMessage(config, key, modifiers),
  ),
  ...(Predicate.isNotUndefined(config.onFocus)
    ? [h.OnFocus(config.onFocus)]
    : []),
  ...(Predicate.isNotUndefined(config.onBlur) ? [h.OnBlur(config.onBlur)] : []),
]

const portalAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
): ReadonlyArray<Attribute<Message>> => [h.DataAttribute('portal', '')]

const positionerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isOpen: boolean,
  isMounted: boolean,
  parentValue?: string | undefined,
): MenuPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(positionerId(config, parentValue)),
        ...(isOpen ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, isOpen),
        ...placementAttributes(h, config, parentValue),
        h.Style({
          position: 'absolute',
          positionAnchor: popupAnchorName(config, parentValue),
          inset: 'auto',
          margin: '0',
          ...placementStyle(config, parentValue),
        }),
      ]
    : [],
  isMounted,
  isOpen,
})

const backdropAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isOpen: boolean,
  isMounted: boolean,
  parentValue?: string | undefined,
): MenuPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Role('presentation'),
        ...(isOpen ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, isOpen),
        ...transitionDataAttributes(h, config.transitionStatus),
        h.Style({
          position: 'fixed',
          inset: '0',
          zIndex: '49',
        }),
        ...optionalMessageAttribute(
          openMessage(config, openChange(false, 'outside-press', parentValue)),
          message => h.OnClick(message),
        ),
        ...optionalMessageAttribute(
          openMessage(config, openChange(false, 'outside-press', parentValue)),
          message => h.OnContextMenu(message),
        ),
      ]
    : [],
  isMounted,
  isOpen,
})

const popupKeyboardMessage = <Message>(
  config: ViewConfig<Message>,
  key: string,
  modifiers: KeyboardModifiers,
  parentValue?: string | undefined,
): Option.Option<Message> => {
  if (modifiers.shiftKey) {
    return Option.none()
  }

  if (key === 'Escape') {
    return openMessage(config, openChange(false, 'escape-key', parentValue))
  }

  if (key === 'ArrowLeft' && parentValue !== undefined) {
    return openMessage(config, openChange(false, 'submenu-close', parentValue))
  }

  if (key === 'ArrowRight') {
    const item = highlightedItem(config)

    if (item !== undefined && itemKind(item) === 'submenu-trigger') {
      return openMessage(config, openChange(true, 'submenu-open', item.value))
    }
  }

  const direction = keyboardDirection(key)

  if (direction !== undefined) {
    const item = nextHighlightedItem(config, direction, parentValue)

    return item === undefined
      ? Option.none()
      : highlightMessage(config, item, 'keyboard-navigation')
  }

  if (searchKeyPattern.test(key)) {
    const item = typeaheadItem(config, key, parentValue)

    return item === undefined
      ? Option.none()
      : highlightMessage(config, item, 'typeahead')
  }

  return Option.none()
}

const popupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isOpen: boolean,
  isMounted: boolean,
  parentValue?: string | undefined,
): MenuPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Key(`${popupId(config, parentValue)}-${isOpen ? 'open' : 'closed'}`),
        h.Id(popupId(config, parentValue)),
        h.Popover('manual'),
        h.Role('menu'),
        h.Tabindex(-1),
        ...(isOpen ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, isOpen),
        ...transitionDataAttributes(h, config.transitionStatus),
        ...placementAttributes(h, config, parentValue),
        ...(isOpen && config.onPositioned !== undefined
          ? [
              h.OnMount(
                Mount.mapMessage(
                  PositionAnchoredSurface({
                    id: popupId(config, parentValue),
                    anchorId: positioningAnchorId(config, parentValue),
                    placement: anchorPlacement(
                      resolvedSide(config, parentValue),
                      resolvedAlign(config, parentValue),
                    ),
                    gap: sideOffset(config, parentValue),
                    offset:
                      parentValue === undefined
                        ? (config.alignOffset ?? defaultAlignOffset)
                        : defaultAlignOffset,
                    padding: config.collisionPadding ?? defaultCollisionPadding,
                    collisionAvoidance:
                      config.collisionAvoidance ?? defaultCollisionAvoidance,
                  }),
                  config.onPositioned,
                ),
              ),
            ]
          : []),
        h.Style({
          display: 'block',
          position: config.onPositioned === undefined ? 'fixed' : 'absolute',
          margin: '0',
          ...(config.onPositioned === undefined
            ? {
                positionAnchor: popupAnchorName(config, parentValue),
                positionArea: positionArea(config, parentValue),
              }
            : { inset: 'auto' }),
          ...(config.onPositioned === undefined &&
          (config.collisionAvoidance ?? defaultCollisionAvoidance)
            ? { positionTryFallbacks: 'flip-inline, flip-block' }
            : {}),
        }),
        ...optionalMessageAttribute(
          openMessage(config, openChange(isOpen, 'none', parentValue)),
          message => h.OnContextMenu(message),
        ),
        h.OnKeyDownPreventDefault((key, modifiers) =>
          popupKeyboardMessage(config, key, modifiers, parentValue),
        ),
      ]
    : [],
  isMounted,
  isOpen,
})

const positionedPartAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isOpen: boolean,
  isMounted: boolean,
  id: string,
  parentValue?: string | undefined,
): MenuPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(id),
        ...(isOpen ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, isOpen),
        ...placementAttributes(h, config, parentValue),
      ]
    : [],
  isMounted,
  isOpen,
})

const itemRole = (item: MenuItemDescriptor): string => {
  const kind = itemKind(item)

  if (kind === 'checkbox') {
    return 'menuitemcheckbox'
  }

  if (kind === 'radio') {
    return 'menuitemradio'
  }

  return 'menuitem'
}

const itemStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: MenuItemDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  ...(config.highlightedValue === item.value
    ? [h.DataAttribute('highlighted', '')]
    : []),
  ...booleanDataAttribute(h, 'disabled', item.isDisabled),
  ...(itemKind(item) === 'checkbox' || itemKind(item) === 'radio'
    ? [
        item.isChecked === true
          ? h.DataAttribute('checked', '')
          : h.DataAttribute('unchecked', ''),
      ]
    : []),
  ...(itemKind(item) === 'submenu-trigger' && isSubmenuOpen(config, item.value)
    ? [h.DataAttribute('popup-open', ''), h.DataAttribute('open', '')]
    : []),
]

const itemClickMessage = <Message>(
  config: ViewConfig<Message>,
  item: MenuItemDescriptor,
): Option.Option<Message> => {
  if (config.isDisabled === true || item.isDisabled === true) {
    return Option.none()
  }

  if (itemKind(item) === 'checkbox') {
    return checkedMessage(config, item)
  }

  if (itemKind(item) === 'radio') {
    return radioMessage(config, item)
  }

  if (itemKind(item) === 'submenu-trigger') {
    return openMessage(config, openChange(true, 'submenu-open', item.value))
  }

  return itemPressMessage(config, item)
}

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: MenuItemDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(itemId(config, item)),
  h.Role(itemRole(item)),
  h.Tabindex(config.open && config.highlightedValue === item.value ? 0 : -1),
  ...(itemKind(item) === 'checkbox' || itemKind(item) === 'radio'
    ? [h.AriaChecked(item.isChecked === true)]
    : []),
  ...(itemKind(item) === 'submenu-trigger'
    ? [
        h.AriaHasPopup('menu'),
        h.AriaExpanded(isSubmenuOpen(config, item.value)),
        h.AriaControls(popupId(config, item.value)),
        h.Style({ anchorName: submenuAnchorName(config, item.value) }),
      ]
    : []),
  ...optionalBooleanAttribute<Message>(item.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...itemStateDataAttributes(h, config, item),
  ...optionalMessageAttribute(itemClickMessage(config, item), message =>
    h.OnClick(message),
  ),
  ...optionalMessageAttribute(
    itemKind(item) === 'submenu-trigger'
      ? openMessage(config, openChange(true, 'submenu-open', item.value))
      : highlightMessage(config, item, 'item-hover'),
    message => h.OnMouseEnter(message),
  ),
  ...optionalMessageAttribute(itemClickMessage(config, item), message =>
    h.OnKeyDownPreventDefault(key =>
      activationKeys.has(key) ? Option.some(message) : Option.none(),
    ),
  ),
]

const itemLabelAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: MenuItemDescriptor,
): ReadonlyArray<Attribute<Message>> => itemStateDataAttributes(h, config, item)

const itemIndicatorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: MenuItemDescriptor,
): ReadonlyArray<Attribute<Message>> =>
  itemKind(item) === 'checkbox' || itemKind(item) === 'radio'
    ? itemStateDataAttributes(h, config, item)
    : []

const submenuIndicatorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: MenuItemDescriptor,
): ReadonlyArray<Attribute<Message>> =>
  itemKind(item) === 'submenu-trigger'
    ? itemStateDataAttributes(h, config, item)
    : []

const menuItems = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  parentValue?: string | undefined,
): ReadonlyArray<MenuItemAttributes<Message>> =>
  itemsForParent(config, parentValue).map(item => ({
    item,
    root: itemAttributes(h, config, item),
    label: itemLabelAttributes(h, config, item),
    indicator: itemIndicatorAttributes(h, config, item),
    submenuIndicator: submenuIndicatorAttributes(h, config, item),
  }))

const popupParts = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  parentValue?: string | undefined,
): MenuPopupAttributes<Message> => {
  const isOpen =
    parentValue === undefined ? config.open : isSubmenuOpen(config, parentValue)
  const isMounted = mounted(config, isOpen)

  return {
    parentValue,
    positioner: positionerAttributes(h, config, isOpen, isMounted, parentValue),
    backdrop: backdropAttributes(h, config, isOpen, isMounted, parentValue),
    popup: popupAttributes(h, config, isOpen, isMounted, parentValue),
    arrow: positionedPartAttributes(
      h,
      config,
      isOpen,
      isMounted,
      arrowId(config, parentValue),
      parentValue,
    ),
    group: isMounted ? [h.Role('group')] : [],
    groupLabel: isMounted ? [h.Id(groupLabelId(config, parentValue))] : [],
    separator: isMounted
      ? [h.Role('separator'), h.AriaOrientation('horizontal')]
      : [],
    items: menuItems(h, config, parentValue),
    isMounted,
    isOpen,
  }
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  if (
    config.onOpenChange !== undefined &&
    config.onPositioned === undefined &&
    config.positioning !== 'static'
  ) {
    throw new Error(
      'Interactive Menu positioning requires an onPositioned Message mapper.',
    )
  }

  const h = html<Message>()
  const submenus = config.items
    .filter(item => itemKind(item) === 'submenu-trigger')
    .map(item => popupParts(h, config, item.value))

  return config.toView({
    root: rootAttributes(h, config),
    trigger: triggerAttributes(h, config),
    portal: portalAttributes(h),
    popup: popupParts(h, config),
    submenus,
    isMounted: mounted(config, config.open),
    isOpen: config.open,
  })
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html, KeyboardModifiers } from 'foldkit/html'
import { html } from 'foldkit/html'

import * as Menu from './menu'

// MODEL

export const MenubarOrientation = S.Union([
  S.Literal('horizontal'),
  S.Literal('vertical'),
])
export type MenubarOrientation = typeof MenubarOrientation.Type

export const MenubarTriggerChangeReason = S.Union([
  S.Literal('keyboard-navigation'),
  S.Literal('trigger-hover'),
  S.Literal('none'),
])
export type MenubarTriggerChangeReason = typeof MenubarTriggerChangeReason.Type

export const {
  MenuAlign,
  MenuHighlightChangeReason,
  MenuItemKind,
  MenuOpenChangeReason,
  MenuSide,
  MenuTransitionStatus,
} = Menu

export type MenuAlign = Menu.MenuAlign
export type MenuCheckedChange = Menu.MenuCheckedChange
export type MenuHighlightChangeReason = Menu.MenuHighlightChangeReason
export type MenuItemDescriptor = Menu.MenuItemDescriptor
export type MenuItemKind = Menu.MenuItemKind
export type MenuItemPress = Menu.MenuItemPress
export type MenuOpenChangeReason = Menu.MenuOpenChangeReason
export type MenuRadioValueChange = Menu.MenuRadioValueChange
export type MenuSide = Menu.MenuSide
export type MenuTransitionStatus = Menu.MenuTransitionStatus

export const MenubarMenuDescriptor = S.Struct({
  id: S.optional(S.String),
  value: S.String,
  label: S.String,
  items: S.Array(Menu.MenuItemDescriptor),
  open: S.Boolean,
  highlightedValue: S.optional(S.String),
  openSubmenuValues: S.optional(S.Array(S.String)),
  forceMount: S.optional(S.Boolean),
  transitionStatus: S.optional(Menu.MenuTransitionStatus),
  isDisabled: S.optional(S.Boolean),
  side: S.optional(Menu.MenuSide),
  align: S.optional(Menu.MenuAlign),
  sideOffset: S.optional(S.Number),
  alignOffset: S.optional(S.Number),
  collisionAvoidance: S.optional(S.Boolean),
  collisionPadding: S.optional(S.Number),
  triggerId: S.optional(S.String),
  triggerSelector: S.optional(S.String),
})
export type MenubarMenuDescriptor = typeof MenubarMenuDescriptor.Type

export const MenubarOptions = S.Struct({
  id: S.String,
  menus: S.Array(MenubarMenuDescriptor),
  focusedMenuValue: S.optional(S.String),
  orientation: S.optional(MenubarOrientation),
  loopFocus: S.optional(S.Boolean),
  modal: S.optional(S.Boolean),
  isDisabled: S.optional(S.Boolean),
})
export type MenubarOptions = typeof MenubarOptions.Type

export const MenubarMenuOpenChange = S.Struct({
  menuValue: S.String,
  open: S.Boolean,
  reason: Menu.MenuOpenChangeReason,
  parentValue: S.optional(S.String),
})
export type MenubarMenuOpenChange = typeof MenubarMenuOpenChange.Type

export const MenubarMenuHighlightChange = S.Struct({
  menuValue: S.String,
  value: S.String,
  reason: Menu.MenuHighlightChangeReason,
  focusSelector: S.optional(S.String),
})
export type MenubarMenuHighlightChange = typeof MenubarMenuHighlightChange.Type

export const MenubarMenuItemPress = S.Struct({
  menuValue: S.String,
  value: S.String,
  kind: Menu.MenuItemKind,
})
export type MenubarMenuItemPress = typeof MenubarMenuItemPress.Type

export const MenubarMenuCheckedChange = S.Struct({
  menuValue: S.String,
  value: S.String,
  checked: S.Boolean,
})
export type MenubarMenuCheckedChange = typeof MenubarMenuCheckedChange.Type

export const MenubarMenuRadioValueChange = S.Struct({
  menuValue: S.String,
  groupValue: S.String,
  value: S.String,
})
export type MenubarMenuRadioValueChange =
  typeof MenubarMenuRadioValueChange.Type

export const MenubarTriggerChange = S.Struct({
  value: S.String,
  previousValue: S.optional(S.String),
  reason: MenubarTriggerChangeReason,
  focusSelector: S.optional(S.String),
  open: S.Boolean,
})
export type MenubarTriggerChange = typeof MenubarTriggerChange.Type

// UPDATE

const activationKeys = new Set(['Enter', ' '])
const defaultOrientation: MenubarOrientation = 'horizontal'
const defaultLoopFocus = true
const defaultModal = true
const defaultMenuSide: MenuSide = 'bottom'
const defaultMenuAlign: MenuAlign = 'start'
const defaultMenuSideOffset = 4
const defaultMenuAlignOffset = 0

export const {
  FocusMenu: FocusMenubarMenu,
  RestoreMenuFocus: RestoreMenubarMenuFocus,
  arrowId,
  checkedChange,
  enabledItems,
  groupLabelId,
  highlightChange,
  highlightedItem,
  itemFocusSelector,
  itemId,
  itemKind,
  itemPress,
  itemsForParent,
  nextHighlightedItem,
  openChange,
  popupId,
  positionerId,
  radioValueChange,
  triggerId: menuTriggerId,
  triggerSelector: menuTriggerSelector,
  typeaheadItem,
} = Menu

export const menuId = (
  config: Pick<MenubarOptions, 'id'>,
  menu: Pick<MenubarMenuDescriptor, 'id' | 'value'>,
): string => menu.id ?? `${config.id}-${menu.value}`

export const triggerId = (
  config: Pick<MenubarOptions, 'id'>,
  menu: Pick<MenubarMenuDescriptor, 'id' | 'triggerId' | 'value'>,
): string => menu.triggerId ?? `${menuId(config, menu)}-trigger`

export const triggerSelector = (
  config: Pick<MenubarOptions, 'id'>,
  menu: Pick<
    MenubarMenuDescriptor,
    'id' | 'triggerId' | 'triggerSelector' | 'value'
  >,
): string => menu.triggerSelector ?? `#${triggerId(config, menu)}`

export const menuOptions = (
  config: Pick<MenubarOptions, 'id' | 'isDisabled'>,
  menu: MenubarMenuDescriptor,
): Menu.MenuOptions => ({
  id: menuId(config, menu),
  open: menu.open,
  items: menu.items,
  highlightedValue: menu.highlightedValue,
  openSubmenuValues: menu.openSubmenuValues,
  forceMount: menu.forceMount,
  transitionStatus: menu.transitionStatus,
  isDisabled: config.isDisabled === true || menu.isDisabled === true,
  side: menu.side ?? defaultMenuSide,
  align: menu.align ?? defaultMenuAlign,
  sideOffset: menu.sideOffset ?? defaultMenuSideOffset,
  alignOffset: menu.alignOffset ?? defaultMenuAlignOffset,
  collisionAvoidance: menu.collisionAvoidance,
  collisionPadding: menu.collisionPadding,
  triggerId: triggerId(config, menu),
  triggerSelector: triggerSelector(config, menu),
})

export const enabledMenus = (
  config: Pick<MenubarOptions, 'isDisabled' | 'menus'>,
): ReadonlyArray<MenubarMenuDescriptor> =>
  config.isDisabled === true
    ? []
    : config.menus.filter(menu => menu.isDisabled !== true)

export const hasOpenMenu = (config: Pick<MenubarOptions, 'menus'>): boolean =>
  config.menus.some(menu => menu.open)

export const activeMenuValue = (
  config: Pick<MenubarOptions, 'focusedMenuValue' | 'isDisabled' | 'menus'>,
): string | undefined =>
  config.focusedMenuValue ??
  config.menus.find(menu => menu.open)?.value ??
  enabledMenus(config).at(0)?.value

const indexOffset = (
  currentIndex: number,
  direction: 'next' | 'previous',
): number => currentIndex + (direction === 'next' ? 1 : -1)

export const nextEnabledMenu = (
  config: Pick<
    MenubarOptions,
    'focusedMenuValue' | 'isDisabled' | 'loopFocus' | 'menus'
  >,
  direction: 'first' | 'last' | 'next' | 'previous',
  currentValue?: string | undefined,
): MenubarMenuDescriptor | undefined => {
  const menus = enabledMenus(config)

  if (direction === 'first') {
    return menus[0]
  }

  if (direction === 'last') {
    return menus.at(-1)
  }

  const resolvedValue = currentValue ?? activeMenuValue(config)
  const currentIndex = menus.findIndex(menu => menu.value === resolvedValue)
  const resolvedCurrentIndex = currentIndex === -1 ? 0 : currentIndex
  const candidateIndex = indexOffset(resolvedCurrentIndex, direction)

  if (candidateIndex >= 0 && candidateIndex < menus.length) {
    return menus[candidateIndex]
  }

  if (config.loopFocus ?? defaultLoopFocus) {
    return direction === 'next' ? menus[0] : menus.at(-1)
  }

  return menus[resolvedCurrentIndex]
}

export const menuOpenChange = (
  menuValue: string,
  open: boolean,
  reason: MenuOpenChangeReason = 'none',
  parentValue?: string | undefined,
): MenubarMenuOpenChange => ({ menuValue, open, reason, parentValue })

export const menuHighlightChange = (
  menuValue: string,
  change: Menu.MenuHighlightChange,
): MenubarMenuHighlightChange => ({
  menuValue,
  value: change.value,
  reason: change.reason,
  focusSelector: change.focusSelector,
})

export const menuItemPress = (
  menuValue: string,
  press: Menu.MenuItemPress,
): MenubarMenuItemPress => ({
  menuValue,
  value: press.value,
  kind: press.kind,
})

export const menuCheckedChange = (
  menuValue: string,
  change: Menu.MenuCheckedChange,
): MenubarMenuCheckedChange => ({
  menuValue,
  value: change.value,
  checked: change.checked,
})

export const menuRadioValueChange = (
  menuValue: string,
  change: Menu.MenuRadioValueChange,
): MenubarMenuRadioValueChange => ({
  menuValue,
  groupValue: change.groupValue,
  value: change.value,
})

export const triggerChange = (
  value: string,
  reason: MenubarTriggerChangeReason = 'none',
  open = false,
  previousValue?: string | undefined,
  focusSelector?: string | undefined,
): MenubarTriggerChange => ({
  value,
  previousValue,
  reason,
  focusSelector,
  open,
})

export const commandForMenuOpenChange = (
  config: Pick<MenubarOptions, 'id' | 'menus'>,
  change: MenubarMenuOpenChange,
): ReturnType<typeof Menu.commandForOpenChange> => {
  const menu = config.menus.find(
    candidate => candidate.value === change.menuValue,
  )

  if (menu === undefined) {
    throw new Error(`Unknown menubar menu: ${change.menuValue}`)
  }

  return Menu.commandForOpenChange(
    menuOptions(config, menu),
    Menu.openChange(change.open, change.reason, change.parentValue),
  )
}

// VIEW

export type MenuPartAttributes<Message> = Menu.MenuPartAttributes<Message>
export type MenuItemAttributes<Message> = Menu.MenuItemAttributes<Message>
export type MenuPopupAttributes<Message> = Menu.MenuPopupAttributes<Message>

export type MenubarMenuAttributes<Message> = Omit<
  Menu.MenuAttributes<Message>,
  'root' | 'trigger'
> &
  Readonly<{
    menu: MenubarMenuDescriptor
    root: ReadonlyArray<Attribute<Message>>
    trigger: ReadonlyArray<Attribute<Message>>
  }>

export type MenubarAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  menus: ReadonlyArray<Html>
  isOpen: boolean
  orientation: MenubarOrientation
}>

export type ViewConfig<Message> = MenubarOptions &
  Readonly<{
    onMenuOpenChange?: (change: MenubarMenuOpenChange) => Message
    onMenuHighlightChange?: (change: MenubarMenuHighlightChange) => Message
    onMenuItemPress?: (press: MenubarMenuItemPress) => Message
    onMenuCheckedChange?: (change: MenubarMenuCheckedChange) => Message
    onMenuRadioValueChange?: (change: MenubarMenuRadioValueChange) => Message
    onTriggerChange?: (change: MenubarTriggerChange) => Message
    onFocus?: Message
    onBlur?: Message
    toMenuView?: (attributes: MenubarMenuAttributes<Message>) => Html
    toView?: (attributes: MenubarAttributes<Message>) => Html
  }>

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const optionalMessageAttribute = <Message>(
  message: Option.Option<Message>,
  toAttribute: (message: Message) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(message, {
    onNone: () => [],
    onSome: value => [toAttribute(value)],
  })

const orientation = (
  config: Pick<MenubarOptions, 'orientation'>,
): MenubarOrientation => config.orientation ?? defaultOrientation

const triggerFocusSelector = (
  config: Pick<MenubarOptions, 'id'>,
  menu: MenubarMenuDescriptor,
): string => `#${triggerId(config, menu)}`

const openMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onMenuOpenChange'>,
  menuValue: string,
  change: Menu.MenuOpenChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onMenuOpenChange)
    ? Option.some(
        config.onMenuOpenChange(
          menuOpenChange(
            menuValue,
            change.open,
            change.reason,
            change.parentValue,
          ),
        ),
      )
    : Option.none()

const triggerMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onTriggerChange'>,
  change: MenubarTriggerChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onTriggerChange)
    ? Option.some(config.onTriggerChange(change))
    : Option.none()

const navigationDirection = (
  config: Pick<MenubarOptions, 'orientation'>,
  key: string,
): 'first' | 'last' | 'next' | 'previous' | undefined => {
  if (key === 'Home') {
    return 'first'
  }

  if (key === 'End') {
    return 'last'
  }

  if (orientation(config) === 'horizontal') {
    if (key === 'ArrowRight') {
      return 'next'
    }

    if (key === 'ArrowLeft') {
      return 'previous'
    }
  }

  if (orientation(config) === 'vertical') {
    if (key === 'ArrowDown') {
      return 'next'
    }

    if (key === 'ArrowUp') {
      return 'previous'
    }
  }

  return undefined
}

const opensMenuFromTrigger = (
  config: Pick<MenubarOptions, 'orientation'>,
  key: string,
): boolean =>
  activationKeys.has(key) ||
  (orientation(config) === 'horizontal' &&
    (key === 'ArrowDown' || key === 'ArrowUp')) ||
  (orientation(config) === 'vertical' &&
    (key === 'ArrowRight' || key === 'ArrowLeft'))

const triggerKeyboardMessage = <Message>(
  config: ViewConfig<Message>,
  menu: MenubarMenuDescriptor,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (modifiers.shiftKey || config.isDisabled === true) {
    return Option.none()
  }

  const direction = navigationDirection(config, key)

  if (direction !== undefined) {
    const nextMenu = nextEnabledMenu(config, direction, menu.value)

    if (nextMenu === undefined || nextMenu.value === menu.value) {
      return Option.none()
    }

    return triggerMessage(
      config,
      triggerChange(
        nextMenu.value,
        'keyboard-navigation',
        hasOpenMenu(config),
        menu.value,
        triggerFocusSelector(config, nextMenu),
      ),
    )
  }

  if (opensMenuFromTrigger(config, key)) {
    return openMessage(
      config,
      menu.value,
      Menu.openChange(true, 'keyboard-open'),
    )
  }

  return Option.none()
}

const triggerHoverMessage = <Message>(
  config: ViewConfig<Message>,
  menu: MenubarMenuDescriptor,
): Option.Option<Message> =>
  hasOpenMenu(config) && !menu.open && menu.isDisabled !== true
    ? triggerMessage(
        config,
        triggerChange(
          menu.value,
          'trigger-hover',
          true,
          activeMenuValue(config),
          triggerFocusSelector(config, menu),
        ),
      )
    : Option.none()

const triggerTabindex = (
  config: Pick<MenubarOptions, 'focusedMenuValue' | 'isDisabled' | 'menus'>,
  menu: MenubarMenuDescriptor,
): number => {
  if (config.isDisabled === true || menu.isDisabled === true) {
    return -1
  }

  return activeMenuValue(config) === menu.value ? 0 : -1
}

const menubarRootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(config.id),
  h.Role('menubar'),
  h.AriaOrientation(orientation(config)),
  h.DataAttribute('orientation', orientation(config)),
  ...booleanDataAttribute(h, 'modal', config.modal ?? defaultModal),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'has-submenu-open', hasOpenMenu(config)),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...(Predicate.isNotUndefined(config.onFocus)
    ? [h.OnFocus(config.onFocus)]
    : []),
  ...(Predicate.isNotUndefined(config.onBlur) ? [h.OnBlur(config.onBlur)] : []),
]

const menubarTriggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  menu: MenubarMenuDescriptor,
  attributes: Menu.MenuAttributes<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...attributes.trigger.filter(
    attribute => attribute._tag !== 'OnKeyDownPreventDefault',
  ),
  h.Role('menuitem'),
  h.Tabindex(triggerTabindex(config, menu)),
  h.DataAttribute('menubar-trigger', ''),
  h.DataAttribute('orientation', orientation(config)),
  h.DataAttribute('value', menu.value),
  ...optionalMessageAttribute(triggerHoverMessage(config, menu), message =>
    h.OnMouseEnter(message),
  ),
  h.OnKeyDownPreventDefault((key, modifiers) =>
    triggerKeyboardMessage(config, menu, key, modifiers),
  ),
]

const menubarMenuAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  menu: MenubarMenuDescriptor,
  attributes: Menu.MenuAttributes<Message>,
): MenubarMenuAttributes<Message> => ({
  ...attributes,
  menu,
  root: [
    ...attributes.root,
    h.DataAttribute('menubar-menu', ''),
    h.DataAttribute('value', menu.value),
  ],
  trigger: menubarTriggerAttributes(h, config, menu, attributes),
})

const defaultPopupView = <Message>(
  popup: Menu.MenuPopupAttributes<Message>,
): ReadonlyArray<Html> => {
  const h = html<Message>()

  if (!popup.isMounted) {
    return []
  }

  return [
    h.div([...popup.backdrop.root], []),
    h.div(
      [...popup.positioner.root],
      [
        h.div(
          [...popup.popup.root],
          [
            h.div([...popup.arrow.root], []),
            h.div(
              [...popup.group],
              popup.items.map(itemAttributes =>
                h.div(
                  [...itemAttributes.root],
                  [
                    h.span(
                      [...itemAttributes.label],
                      [itemAttributes.item.label],
                    ),
                    h.span([...itemAttributes.indicator], []),
                    h.span([...itemAttributes.submenuIndicator], ['>']),
                  ],
                ),
              ),
            ),
            h.div([...popup.separator], []),
          ],
        ),
      ],
    ),
  ]
}

const defaultMenuView = <Message>(
  attributes: MenubarMenuAttributes<Message>,
): Html => {
  const h = html<Message>()

  return h.div(
    [...attributes.root],
    [
      h.button([...attributes.trigger], [attributes.menu.label]),
      h.div(
        [...attributes.portal],
        [
          ...defaultPopupView(attributes.popup),
          ...attributes.submenus.flatMap(defaultPopupView),
        ],
      ),
    ],
  )
}

const renderMenu = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  menu: MenubarMenuDescriptor,
): Html => {
  const {
    onMenuCheckedChange,
    onMenuHighlightChange,
    onMenuItemPress,
    onMenuOpenChange,
    onMenuRadioValueChange,
  } = config

  return Menu.view<Message>({
    positioning: 'static',
    ...menuOptions(config, menu),
    ...(onMenuOpenChange === undefined
      ? {}
      : {
          onOpenChange: (change: Menu.MenuOpenChange): Message =>
            onMenuOpenChange(
              menuOpenChange(
                menu.value,
                change.open,
                change.reason,
                change.parentValue,
              ),
            ),
        }),
    ...(onMenuHighlightChange === undefined
      ? {}
      : {
          onHighlightChange: (change: Menu.MenuHighlightChange): Message =>
            onMenuHighlightChange(menuHighlightChange(menu.value, change)),
        }),
    ...(onMenuItemPress === undefined
      ? {}
      : {
          onItemPress: (press: Menu.MenuItemPress): Message =>
            onMenuItemPress(menuItemPress(menu.value, press)),
        }),
    ...(onMenuCheckedChange === undefined
      ? {}
      : {
          onCheckedChange: (change: Menu.MenuCheckedChange): Message =>
            onMenuCheckedChange(menuCheckedChange(menu.value, change)),
        }),
    ...(onMenuRadioValueChange === undefined
      ? {}
      : {
          onRadioValueChange: (change: Menu.MenuRadioValueChange): Message =>
            onMenuRadioValueChange(menuRadioValueChange(menu.value, change)),
        }),
    toView: attributes => {
      const menubarAttributes = menubarMenuAttributes(
        h,
        config,
        menu,
        attributes,
      )

      return config.toMenuView === undefined
        ? defaultMenuView(menubarAttributes)
        : config.toMenuView(menubarAttributes)
    },
  })
}

const defaultView = <Message>(attributes: MenubarAttributes<Message>): Html => {
  const h = html<Message>()

  return h.div([...attributes.root], attributes.menus)
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const menus = config.menus.map(menu => renderMenu(h, config, menu))
  const attributes: MenubarAttributes<Message> = {
    root: menubarRootAttributes(h, config),
    menus,
    isOpen: hasOpenMenu(config),
    orientation: orientation(config),
  }

  return config.toView === undefined
    ? defaultView(attributes)
    : config.toView(attributes)
}

import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const MeterFormatStyle = S.Union([
  S.Literal('decimal'),
  S.Literal('percent'),
  S.Literal('currency'),
])
export type MeterFormatStyle = typeof MeterFormatStyle.Type

export const MeterFormatOptions = S.Struct({
  style: S.optional(MeterFormatStyle),
  currency: S.optional(S.String),
  minimumFractionDigits: S.optional(S.Number),
  maximumFractionDigits: S.optional(S.Number),
})
export type MeterFormatOptions = typeof MeterFormatOptions.Type

export const MeterOptions = S.Struct({
  value: S.Number,
  min: S.optional(S.Number),
  max: S.optional(S.Number),
  low: S.optional(S.Number),
  high: S.optional(S.Number),
  optimum: S.optional(S.Number),
  locale: S.optional(S.String),
  format: S.optional(MeterFormatOptions),
  labelId: S.optional(S.String),
})
export type MeterOptions = typeof MeterOptions.Type

export const MeterPart = S.Union([
  S.Literal('root'),
  S.Literal('label'),
  S.Literal('track'),
  S.Literal('indicator'),
  S.Literal('value'),
])
export type MeterPart = typeof MeterPart.Type

export type MeterState = Readonly<{
  value: number
  clampedValue: number
  percentage: number
  formattedValue: string
  ariaValueText: string
  min: number
  max: number
}>

// UPDATE

const defaultMin = 0
const defaultMax = 100

const clamp = (value: number, min: number, max: number): number =>
  Math.max(min, Math.min(value, max))

const percentageFromValue = (
  value: number,
  min: number,
  max: number,
): number => {
  const rawPercentage = ((value - min) * 100) / (max - min)

  return clamp(Number.isNaN(rawPercentage) ? 0 : rawPercentage, 0, 100)
}

const formatValue = (
  value: number,
  locale: string | undefined,
  format: MeterFormatOptions,
): string => new Intl.NumberFormat(locale, format).format(value)

export const meterState = (options: MeterOptions): MeterState => {
  const { value, min = defaultMin, max = defaultMax, locale, format } = options
  const safeValue = Number.isNaN(value) ? min : value
  const percentage = percentageFromValue(safeValue, min, max)
  const clampedValue = clamp(safeValue, min, max)
  const formattedValue =
    format === undefined
      ? formatValue(percentage / 100, locale, { style: 'percent' })
      : formatValue(value, locale, format)

  return {
    value,
    clampedValue,
    percentage,
    formattedValue,
    ariaValueText: formattedValue,
    min,
    max,
  }
}

// VIEW

export type MeterAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  label: ReadonlyArray<Attribute<Message>>
  track: ReadonlyArray<Attribute<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
  value: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = MeterOptions &
  Readonly<{
    toView: (attributes: MeterAttributes<Message>) => Html
  }>

export const indicatorStyle = (
  percentage: number,
): Readonly<Record<string, string>> => ({
  insetInlineStart: '0',
  height: 'inherit',
  width: `${percentage}%`,
})

export const valueText = (state: MeterState): string => state.formattedValue

const ariaLabelledByAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  labelId: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  labelId === undefined ? [] : [h.AriaLabelledBy(labelId)]

const labelIdAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  labelId: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  labelId === undefined ? [] : [h.Id(labelId)]

const numberAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: number | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === undefined ? [] : [h.Attribute(name, String(value))]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { labelId, low, high, optimum, toView } = config
  const state = meterState(config)

  return toView({
    root: [
      h.Role('meter'),
      h.AriaValuemin(state.min),
      h.AriaValuemax(state.max),
      h.AriaValuenow(state.clampedValue),
      h.AriaValuetext(state.ariaValueText),
      ...ariaLabelledByAttribute(h, labelId),
      ...numberAttribute(h, 'low', low),
      ...numberAttribute(h, 'high', high),
      ...numberAttribute(h, 'optimum', optimum),
    ],
    label: [h.Role('presentation'), ...labelIdAttribute(h, labelId)],
    track: [],
    indicator: [h.Style(indicatorStyle(state.percentage))],
    value: [h.AriaHidden(true)],
  })
}

import { Effect, Option, Predicate, Schema as S } from 'effect'
