// UPDATE

type NumberFormatOptionsWithRounding = Intl.NumberFormatOptions & {
  readonly roundingIncrement?: number | undefined
  readonly roundingMode?: string | undefined
  readonly roundingPriority?: string | undefined
}

const defaultMin = Number.MIN_SAFE_INTEGER
const defaultMax = Number.MAX_SAFE_INTEGER
const defaultStep = 1
const defaultSmallStep = 0.1
const defaultLargeStep = 10
const floatingPointCleanupFactor = 1e-10
const maxFloatingPointCleanupDelta = 1e-10

const hanNumerals = [
  '零',
  '〇',
  '一',
  '二',
  '三',
  '四',
  '五',
  '六',
  '七',
  '八',
  '九',
]
const hanNumeralToDigit: Readonly<Record<string, string>> = {
  零: '0',
  〇: '0',
  一: '1',
  二: '2',
  三: '3',
  四: '4',
  五: '5',
  六: '6',
  七: '7',
  八: '8',
  九: '9',
}
const arabicNumerals = ['٠', '١', '٢', '٣', '٤', '٥', '٦', '٧', '٨', '٩']
const persianNumerals = ['۰', '۱', '۲', '۳', '۴', '۵', '۶', '۷', '۸', '۹']
const fullwidthNumerals = [
  '０',
  '１',
  '２',
  '３',
  '４',
  '５',
  '６',
  '７',
  '８',
  '９',
]
const percentages = ['%', '٪', '％', '﹪']
const permille = ['‰', '؉']
const unicodeMinusSigns = ['−', '－', '‒', '–', '—', '﹣']
const unicodePlusSigns = ['＋', '﹢']
const baseNonNumericSymbols = ['.', ',', '．', '，', '٫', '٬']

const arabicRe = new RegExp(`[${arabicNumerals.join('')}]`, 'gu')
const persianRe = new RegExp(`[${persianNumerals.join('')}]`, 'gu')
const fullwidthRe = new RegExp(`[${fullwidthNumerals.join('')}]`, 'gu')
const hanRe = new RegExp(`[${hanNumerals.join('')}]`, 'gu')
const arabicDetectRe = new RegExp(`[${arabicNumerals.join('')}]`, 'u')
const persianDetectRe = new RegExp(`[${persianNumerals.join('')}]`, 'u')
const fullwidthDetectRe = new RegExp(`[${fullwidthNumerals.join('')}]`, 'u')
const hanDetectRe = new RegExp(`[${hanNumerals.join('')}]`, 'u')
const percentRe = new RegExp(`[${percentages.join('')}]`, 'u')
const percentGlobalRe = new RegExp(percentRe.source, 'gu')
const permilleRe = new RegExp(`[${permille.join('')}]`, 'u')
const permilleGlobalRe = new RegExp(permilleRe.source, 'gu')
const spaceSeparatorRe = /\p{Zs}/u

const escapeRegExp = (value: string): string =>
  value.replaceAll(/[.*+?^${}()|[\]\\]/gu, '\\$&')

const escapeClassChar = (value: string): string =>
  value.replaceAll(/[-\\\]^]/gu, match => `\\${match}`)

const charClassFrom = (chars: ReadonlyArray<string>): string =>
  `[${chars.map(escapeClassChar).join('')}]`

const anyMinusClass = charClassFrom(['-', ...unicodeMinusSigns])
const anyPlusClass = charClassFrom(['+', ...unicodePlusSigns])
const anyMinusRe = new RegExp(anyMinusClass, 'gu')
const anyPlusRe = new RegExp(anyPlusClass, 'gu')
const anyMinusDetectRe = new RegExp(anyMinusClass, 'u')
const anyPlusDetectRe = new RegExp(anyPlusClass, 'u')

const clamp = (value: number, min: number, max: number): number =>
  Math.max(min, Math.min(value, max))

const shiftDecimal = (value: number, exponentDelta: number): number => {
  const [coefficient, exponent = '0'] = String(value).split('e')

  return Number(`${coefficient}e${Number(exponent) + exponentDelta}`)
}

const getFormatter = (
  locale?: string,
  options?: NumberFormatOptionsWithRounding,
): Intl.NumberFormat => new Intl.NumberFormat(locale, options)

export const formatNumber = (
  value: number | null,
  locale?: string,
  options?: NumberFormatOptionsWithRounding,
): string => (value === null ? '' : getFormatter(locale, options).format(value))

export const getNumberLocaleDetails = (
  locale?: string,
  options?: NumberFormatOptionsWithRounding,
): Partial<Record<Intl.NumberFormatPartTypes, string | undefined>> => {
  const result: Partial<
    Record<Intl.NumberFormatPartTypes, string | undefined>
  > = {}

  getFormatter(locale, options)
    .formatToParts(11_111.1)
    .map(part => {
      result[part.type] = part.value

      return part
    })

  getFormatter(locale)
    .formatToParts(0.1)
    .map(part => {
      if (part.type === 'decimal') {
        result[part.type] = part.value
      }

      return part
    })

  return result
}

const isNumeralChar = (char: string): boolean =>
  (char >= '0' && char <= '9') ||
  arabicDetectRe.test(char) ||
  persianDetectRe.test(char) ||
  hanDetectRe.test(char) ||
  fullwidthDetectRe.test(char)

const unitRegex = (
  locale?: string,
  options?: NumberFormatOptionsWithRounding,
): RegExp | null => {
  const unitParts = getFormatter(locale, options)
    .formatToParts(1)
    .filter(part => part.type === 'unit')
    .map(part => escapeRegExp(part.value))

  return unitParts.length === 0 ? null : new RegExp(unitParts.join('|'), 'gu')
}

const groupRegex = (group: string | undefined): RegExp | null => {
  if (group === undefined) {
    return null
  }

  if (spaceSeparatorRe.test(group)) {
    return /\p{Zs}/gu
  }

  if (group === "'" || group === '’') {
    return /['’]/gu
  }

  return new RegExp(escapeRegExp(group), 'gu')
}

const localeFromInput = (
  input: string,
  locale: string | undefined,
): string | undefined => {
  if (locale !== undefined) {
    return locale
  }

  if (arabicDetectRe.test(input) || persianDetectRe.test(input)) {
    return 'ar'
  }

  if (hanDetectRe.test(input)) {
    return 'zh'
  }

  return undefined
}

const signedInput = (
  normalizedInput: string,
): Readonly<{ input: string; isNegative: boolean }> => {
  const trailing = normalizedInput.match(/(?<sign>[+-])\s*$/u)
  const withoutTrailing =
    trailing === null
      ? normalizedInput
      : normalizedInput.replace(/(?<sign>[+-])\s*$/u, '')
  const leading = withoutTrailing.match(/^\s*(?<sign>[+-])/u)
  const input =
    leading === null
      ? withoutTrailing
      : withoutTrailing.replace(/^\s*(?<sign>[+-])/u, '')

  return {
    input,
    isNegative: trailing?.groups?.sign === '-' || leading?.groups?.sign === '-',
  }
}

export const parseNumber = (
  formattedNumber: string,
  locale?: string,
  options?: NumberFormatOptionsWithRounding,
): number | null => {
  const normalizedInput = String(formattedNumber)
    .replaceAll(/\p{Cf}/gu, '')
    .trim()
    .replaceAll(anyMinusRe, '-')
    .replaceAll(anyPlusRe, '+')
  const { input, isNegative } = signedInput(normalizedInput)
  const computedLocale = localeFromInput(input, locale)
  const { group, decimal, currency, exponentSeparator } =
    getNumberLocaleDetails(computedLocale, options)
  const replacements: ReadonlyArray<
    Readonly<{
      regex: RegExp | null
      replacement: string | ((substring: string) => string)
    }>
  > = [
    { regex: groupRegex(group), replacement: '' },
    {
      regex:
        decimal === undefined ? null : new RegExp(escapeRegExp(decimal), 'gu'),
      replacement: '.',
    },
    { regex: /．/gu, replacement: '.' },
    { regex: /，/gu, replacement: '' },
    { regex: /٫/gu, replacement: '.' },
    { regex: /٬/gu, replacement: '' },
    {
      regex:
        currency === undefined
          ? null
          : new RegExp(escapeRegExp(currency), 'gu'),
      replacement: '',
    },
    { regex: unitRegex(computedLocale, options), replacement: '' },
    { regex: percentGlobalRe, replacement: '' },
    { regex: permilleGlobalRe, replacement: '' },
    {
      regex:
        exponentSeparator === undefined
          ? null
          : new RegExp(escapeRegExp(exponentSeparator), 'gu'),
      replacement: 'e',
    },
    {
      regex: arabicRe,
      replacement: char => String(arabicNumerals.indexOf(char)),
    },
    {
      regex: persianRe,
      replacement: char => String(persianNumerals.indexOf(char)),
    },
    {
      regex: fullwidthRe,
      replacement: char => String(fullwidthNumerals.indexOf(char)),
    },
    {
      regex: hanRe,
      replacement: char => hanNumeralToDigit[char] ?? char,
    },
  ]
  let unformatted = replacements.reduce((text, { regex, replacement }) => {
    if (regex === null) {
      return text
    }

    return typeof replacement === 'string'
      ? text.replace(regex, replacement)
      : text.replace(regex, replacement)
  }, input)
  const lastDot = unformatted.lastIndexOf('.')

  if (lastDot !== -1) {
    unformatted = `${unformatted.slice(0, lastDot).replaceAll('.', '')}.${unformatted
      .slice(lastDot + 1)
      .replaceAll('.', '')}`
  }

  if (/^[-+]?Infinity$/iu.test(input) || input.includes('∞')) {
    return null
  }

  let numberValue = Number.parseFloat(`${isNegative ? '-' : ''}${unformatted}`)
  const formatStyle = options?.style
  const isUnitPercent = formatStyle === 'unit' && options?.unit === 'percent'
  const hasPercentSymbol =
    percentRe.test(formattedNumber) || formatStyle === 'percent'
  const hasPermilleSymbol = permilleRe.test(formattedNumber)

  if (hasPermilleSymbol) {
    numberValue = shiftDecimal(numberValue, -3)
  } else if (!isUnitPercent && hasPercentSymbol) {
    numberValue = shiftDecimal(numberValue, -2)
  }

  return Number.isFinite(numberValue) ? numberValue : null
}

export const valueStateFromText = (
  textValue: string,
  locale?: string,
  format?: NumberFormatOptionsWithRounding,
): NumberFieldValueState => {
  if (textValue.trim() === '') {
    return NumberFieldEmpty({ textValue })
  }

  const value = parseNumber(textValue, locale, format)

  return value === null
    ? NumberFieldInvalid({ textValue })
    : NumberFieldParsed({ value, textValue })
}

const hasNumberFormatRoundingOptions = (
  format?: NumberFormatOptionsWithRounding,
): format is NumberFormatOptionsWithRounding =>
  format?.maximumFractionDigits !== undefined ||
  format?.minimumFractionDigits !== undefined ||
  format?.maximumSignificantDigits !== undefined ||
  format?.minimumSignificantDigits !== undefined ||
  format?.roundingIncrement !== undefined ||
  format?.roundingMode !== undefined ||
  format?.roundingPriority !== undefined

export const removeFloatingPointErrors = (
  value: number,
  format?: NumberFormatOptionsWithRounding,
): number => {
  if (!Number.isFinite(value)) {
    return value
  }

  if (!hasNumberFormatRoundingOptions(format)) {
    const roundedValue = Number.parseFloat(value.toPrecision(15))
    const cleanupDelta = Math.abs(roundedValue - value)
    const cleanupTolerance = Math.min(
      Number.EPSILON * Math.max(1, Math.abs(value)),
      maxFloatingPointCleanupDelta,
    )

    return cleanupDelta <= cleanupTolerance ? roundedValue : value
  }

  const formatter = getFormatter('en-US', {
    ...format,
    signDisplay: 'auto',
    currencySign: 'standard',
    notation: format.notation === 'compact' ? 'standard' : format.notation,
    useGrouping: false,
  })
  const roundedText = formatter.format(value)
  const roundedValue = parseNumber(roundedText, 'en-US', format)

  if (roundedValue === null) {
    return value
  }

  return formatter.format(roundedValue) === roundedText ? roundedValue : value
}

const snapToStep = (
  value: number,
  base: number,
  step: number,
  mode: 'directional' | 'nearest' = 'directional',
): number => {
  const stepSize = Math.abs(step)
  const direction = Math.sign(step)
  const tolerance = stepSize * floatingPointCleanupFactor * direction
  const rawSteps = value - base + tolerance

  if (mode === 'nearest') {
    return base + Math.round(rawSteps / step) * step
  }

  const snappedSteps =
    direction > 0
      ? Math.floor(rawSteps / stepSize)
      : Math.ceil(rawSteps / stepSize)

  return base + snappedSteps * stepSize
}

const toValidatedNumber = (
  value: number | null,
  config: Readonly<{
    step: number | undefined
    min: number
    max: number
    minWithZeroDefault: number
    format: NumberFormatOptionsWithRounding | undefined
    snapOnStep: boolean
    small: boolean
    clamp: boolean
  }>,
): number | null => {
  if (value === null) {
    return value
  }

  const { step, min, max, minWithZeroDefault, format, snapOnStep, small } =
    config
  let nextValue = value

  if (step !== undefined && snapOnStep && step !== 0) {
    const base = small || min === defaultMin ? minWithZeroDefault : min

    nextValue = snapToStep(
      nextValue,
      base,
      step,
      small ? 'nearest' : 'directional',
    )
  }

  if (config.clamp) {
    nextValue = clamp(nextValue, min, max)
  }

  if (step === undefined && !hasNumberFormatRoundingOptions(format)) {
    return nextValue
  }

  const roundedValue = removeFloatingPointErrors(nextValue, format)

  return config.clamp ? clamp(roundedValue, min, max) : roundedValue
}

const stepAmount = (
  state: Pick<NumberFieldState, 'largeStep' | 'smallStep' | 'step'>,
  modifiers?: KeyboardModifiers,
): number => {
  if (modifiers?.altKey === true) {
    return state.smallStep
  }

  return modifiers?.shiftKey === true ? state.largeStep : state.step
}

const valueChange = (
  valueState: NumberFieldValueState,
  reason: NumberFieldChangeReason,
): NumberFieldValueChange => {
  if (valueState._tag === 'Parsed') {
    return {
      value: valueState.value,
      textValue: valueState.textValue,
      state: valueState,
      reason,
    }
  }

  return {
    value: null,
    textValue: valueState.textValue,
    state: valueState,
    reason,
  }
}

export const numberFieldState = (
  config: NumberFieldOptions,
): NumberFieldState => {
  const value = config.value ?? null
  const textValue =
    config.textValue ?? formatNumber(value, config.locale, config.format)
  const valueState = valueStateFromText(textValue, config.locale, config.format)
  const min = config.min ?? defaultMin
  const max = config.max ?? defaultMax
  const step =
    config.step === 'any' ? defaultStep : (config.step ?? defaultStep)

  return {
    value,
    textValue,
    valueState,
    min,
    max,
    step,
    smallStep: config.smallStep ?? defaultSmallStep,
    largeStep: config.largeStep ?? defaultLargeStep,
    inputId: config.inputId ?? config.id ?? 'number-field-input',
    hiddenInputId: `${config.inputId ?? config.id ?? 'number-field'}-hidden-input`,
    isInputInvalid: config.isInvalid === true || config.isFieldInvalid === true,
    isIncrementDisabled:
      config.isDisabled === true || (value !== null && value >= max),
    isDecrementDisabled:
      config.isDisabled === true || (value !== null && value <= min),
  }
}

export const numberFieldInputChange = (
  textValue: string,
  config: NumberFieldOptions,
  reason: Extract<
    NumberFieldChangeReason,
    'input-blur' | 'input-change' | 'input-clear' | 'input-paste' | 'none'
  > = 'input-change',
): NumberFieldValueChange => {
  const valueState = valueStateFromText(textValue, config.locale, config.format)

  if (valueState._tag !== 'Parsed') {
    return valueChange(valueState, reason)
  }

  const nextValue = toValidatedNumber(valueState.value, {
    step: undefined,
    min: config.min ?? defaultMin,
    max: config.max ?? defaultMax,
    minWithZeroDefault: config.min ?? 0,
    format: config.format,
    snapOnStep: config.snapOnStep ?? false,
    small: false,
    clamp: config.allowOutOfRange !== true,
  })

  return valueChange(
    nextValue === null
      ? NumberFieldEmpty({ textValue })
      : NumberFieldParsed({ value: nextValue, textValue }),
    reason,
  )
}

export const numberFieldStepChange = (
  state: NumberFieldState,
  config: Pick<
    NumberFieldOptions,
    'allowOutOfRange' | 'format' | 'locale' | 'min' | 'max' | 'snapOnStep'
  >,
  direction: 1 | -1,
  reason: Extract<
    NumberFieldChangeReason,
    'decrement-press' | 'increment-press' | 'keyboard' | 'scrub' | 'wheel'
  >,
  modifiers?: KeyboardModifiers,
): NumberFieldValueChange => {
  const amount = stepAmount(state, modifiers)
  const seedValue = state.value ?? 0
  const nextValue = toValidatedNumber(seedValue + amount * direction, {
    step: amount * direction,
    min: config.min ?? state.min,
    max: config.max ?? state.max,
    minWithZeroDefault: config.min ?? 0,
    format: config.format,
    snapOnStep: config.snapOnStep ?? false,
    small: modifiers?.altKey === true,
    clamp: true,
  })
  const textValue = formatNumber(nextValue, config.locale, config.format)

  return valueChange(
    nextValue === null
      ? NumberFieldEmpty({ textValue })
      : NumberFieldParsed({ value: nextValue, textValue }),
    reason,
  )
}

export const numberFieldKeyboardChange = (
  state: NumberFieldState,
  config: NumberFieldOptions,
  key: string,
  modifiers?: KeyboardModifiers,
): Option.Option<NumberFieldValueChange> => {
  if (key === 'ArrowUp') {
    return Option.some(
      numberFieldStepChange(state, config, 1, 'keyboard', modifiers),
    )
  }

  if (key === 'ArrowDown') {
    return Option.some(
      numberFieldStepChange(state, config, -1, 'keyboard', modifiers),
    )
  }

  if (key === 'Home' && config.min !== undefined) {
    return Option.some(
      valueChange(
        NumberFieldParsed({
          value: config.min,
          textValue: formatNumber(config.min, config.locale, config.format),
        }),
        'keyboard',
      ),
    )
  }

  if (key === 'End' && config.max !== undefined) {
    return Option.some(
      valueChange(
        NumberFieldParsed({
          value: config.max,
          textValue: formatNumber(config.max, config.locale, config.format),
        }),
        'keyboard',
      ),
    )
  }

  return Option.none()
}

// VIEW

export type NumberFieldPartAttributes<Message> = ReadonlyArray<
  Attribute<Message>
>

export type NumberFieldAttributes<Message> = Readonly<{
  state: NumberFieldState
  root: NumberFieldPartAttributes<Message>
  scrubArea: NumberFieldPartAttributes<Message>
  scrubAreaCursor: NumberFieldPartAttributes<Message>
  group: NumberFieldPartAttributes<Message>
  decrement: NumberFieldPartAttributes<Message>
  input: NumberFieldPartAttributes<Message>
  increment: NumberFieldPartAttributes<Message>
  hiddenInput: NumberFieldPartAttributes<Message>
}>

export type ViewConfig<Message> = NumberFieldOptions &
  Readonly<{
    toView: (attributes: NumberFieldAttributes<Message>) => Html
    onValueChange?: (change: NumberFieldValueChange) => Message
    onFocus?: Message
    onBlur?: Message
  }>

const visuallyHiddenInputStyle =
  'clip-path: inset(50%); overflow: hidden; white-space: nowrap; border: 0px; padding: 0px; width: 1px; height: 1px; margin: -1px; position: absolute;'

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  form: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(form) ? [h.Attribute('form', form)] : []

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ViewConfig<Message>,
    | 'isDirty'
    | 'isDisabled'
    | 'isFieldInvalid'
    | 'isFilled'
    | 'isFocused'
    | 'isReadOnly'
    | 'isRequired'
    | 'isScrubbing'
    | 'isTouched'
    | 'isValid'
  >,
): ReadonlyArray<Attribute<Message>> => [
  ...booleanDataAttribute(h, 'scrubbing', config.isScrubbing),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'valid', config.isValid),
  ...booleanDataAttribute(h, 'invalid', config.isFieldInvalid),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'filled', config.isFilled),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
]

const focusAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'onBlur' | 'onFocus'>,
): ReadonlyArray<Attribute<Message>> => [
  ...(Predicate.isNotUndefined(config.onFocus)
    ? [h.OnFocus(config.onFocus)]
    : []),
  ...(Predicate.isNotUndefined(config.onBlur) ? [h.OnBlur(config.onBlur)] : []),
]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...stateDataAttributes(h, config),
]

const scrubAreaAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Attribute('style', 'touch-action: none; user-select: none;'),
  ...stateDataAttributes(h, config),
]

const scrubAreaCursorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('presentation'),
  h.Attribute(
    'style',
    'position: fixed; top: 0; left: 0; pointer-events: none;',
  ),
  ...stateDataAttributes(h, config),
]

const groupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('group'),
  ...stateDataAttributes(h, config),
]

const stepperAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: NumberFieldState,
  direction: 1 | -1,
): ReadonlyArray<Attribute<Message>> => {
  const isIncrement = direction === 1
  const isDisabled = isIncrement
    ? state.isIncrementDisabled
    : state.isDecrementDisabled

  return [
    h.AriaLabel(isIncrement ? 'Increase' : 'Decrease'),
    h.AriaControls(state.inputId),
    h.Tabindex(-1),
    ...optionalBooleanAttribute<Message>(
      isDisabled || config.isReadOnly === true,
      value => h.Disabled(value),
    ),
    ...stateDataAttributes(h, { ...config, isDisabled }),
    ...(Predicate.isNotUndefined(config.onValueChange) &&
    !isDisabled &&
    config.isReadOnly !== true
      ? [
          h.OnClick(
            config.onValueChange(
              numberFieldStepChange(
                state,
                config,
                direction,
                isIncrement ? 'increment-press' : 'decrement-press',
              ),
            ),
          ),
        ]
      : []),
  ]
}

const inputEventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: NumberFieldState,
): ReadonlyArray<Attribute<Message>> => {
  const { onValueChange } = config

  if (config.isDisabled === true || onValueChange === undefined) {
    return []
  }

  return [
    ...(config.isReadOnly === true
      ? []
      : [
          h.OnInput(textValue =>
            onValueChange(
              numberFieldInputChange(textValue, config, 'input-change'),
            ),
          ),
          h.OnKeyDownPreventDefault((key, modifiers) =>
            Option.map(
              numberFieldKeyboardChange(state, config, key, modifiers),
              change => onValueChange(change),
            ),
          ),
        ]),
    ...focusAttributes(h, config),
  ]
}

const inputMode = (_state: NumberFieldState): string => 'numeric'

const inputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: NumberFieldState,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('text'),
  h.Id(state.inputId),
  h.Value(state.textValue),
  h.Attribute('inputmode', inputMode(state)),
  h.Attribute('autocomplete', 'off'),
  h.Attribute('autocorrect', 'off'),
  h.Attribute('spellcheck', 'false'),
  h.Attribute('aria-roledescription', 'Number field'),
  ...(state.isInputInvalid ? [h.AriaInvalid(true)] : []),
  ...optionalAttribute<Message>(config.labelId, value =>
    h.AriaLabelledBy(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.Disabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.Required(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.Readonly(value),
  ),
  ...stateDataAttributes(h, config),
  ...inputEventAttributes(h, config, state),
]

const hiddenInputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: NumberFieldState,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('number'),
  h.Id(state.hiddenInputId),
  h.AriaHidden(true),
  h.Tabindex(-1),
  h.Value(state.value === null ? '' : String(state.value)),
  h.Attribute('style', visuallyHiddenInputStyle),
  ...optionalAttribute<Message>(config.name, value => h.Name(value)),
  ...formOwnerAttributes(h, config.form),
  ...(config.min === undefined ? [] : [h.Min(String(config.min))]),
  ...(config.max === undefined ? [] : [h.Max(String(config.max))]),
  h.Step(config.step === undefined ? String(defaultStep) : String(config.step)),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.Disabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.Required(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.Readonly(value),
  ),
]

const addCharacters = (values: Set<string>, text: string): Set<string> =>
  [...text].reduce((nextValues, symbol) => {
    nextValues.add(symbol)

    return nextValues
  }, values)

export const allowedCharacters = (
  config: Pick<
    NumberFieldOptions,
    'allowOutOfRange' | 'format' | 'locale' | 'min'
  >,
): ReadonlySet<string> => {
  const { decimal, group, currency, literal } = getNumberLocaleDetails(
    config.locale,
    config.format,
  )
  const values = new Set<string>(baseNonNumericSymbols)

  if (decimal !== undefined) {
    values.add(decimal)
  }
  if (group !== undefined) {
    values.add(group)
    if (spaceSeparatorRe.test(group)) {
      values.add(' ')
    }
  }

  const formatStyle = config.format?.style
  const allowPercentSymbols =
    formatStyle === 'percent' ||
    (formatStyle === 'unit' && config.format?.unit === 'percent')
  const allowPermilleSymbols =
    formatStyle === 'percent' ||
    (formatStyle === 'unit' && config.format?.unit === 'permille')

  if (allowPercentSymbols) {
    percentages.map(symbol => values.add(symbol))
  }
  if (allowPermilleSymbols) {
    permille.map(symbol => values.add(symbol))
  }
  if (formatStyle === 'currency' && currency !== undefined) {
    values.add(currency)
  }
  if (literal !== undefined) {
    addCharacters(values, literal)
    if (spaceSeparatorRe.test(literal)) {
      values.add(' ')
    }
  }

  unicodePlusSigns.map(symbol => values.add(symbol))
  values.add('+')

  if ((config.min ?? defaultMin) < 0 || config.allowOutOfRange === true) {
    unicodeMinusSigns.map(symbol => values.add(symbol))
    values.add('-')
  }

  return values
}

export const isAllowedInputText = (
  textValue: string,
  config: Pick<
    NumberFieldOptions,
    'allowOutOfRange' | 'format' | 'locale' | 'min'
  >,
): boolean => {
  const allowed = allowedCharacters(config)

  return [...textValue].every(
    char =>
      isNumeralChar(char) ||
      anyMinusDetectRe.test(char) ||
      anyPlusDetectRe.test(char) ||
      allowed.has(char),
  )
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const state = numberFieldState(config)

  return config.toView({
    state,
    root: rootAttributes(h, config),
    scrubArea: scrubAreaAttributes(h, config),
    scrubAreaCursor: scrubAreaCursorAttributes(h, config),
    group: groupAttributes(h, config),
    decrement: stepperAttributes(h, config, state, -1),
    input: inputAttributes(h, config, state),
    increment: stepperAttributes(h, config, state, 1),
    hiddenInput: hiddenInputAttributes(h, config, state),
  })
}

import { Effect, Option, Predicate, Schema as S } from 'effect'
import * as Command from 'foldkit/command'
import * as Dom from 'foldkit/dom'
import type { Attribute, Html, KeyboardModifiers } from 'foldkit/html'
import { html } from 'foldkit/html'
import { m } from 'foldkit/message'

// MODEL

export const OTPFieldValidationType = S.Literals([
  'numeric',
  'alpha',
  'alphanumeric',
  'none',
])
export type OTPFieldValidationType = typeof OTPFieldValidationType.Type

export const OTPFieldChangeReason = S.Union([
  S.Literal('none'),
  S.Literal('input-change'),
  S.Literal('input-clear'),
  S.Literal('input-paste'),
  S.Literal('keyboard'),
])
export type OTPFieldChangeReason = typeof OTPFieldChangeReason.Type

export const OTPFieldValueChange = S.Struct({
  value: S.String,
  reason: OTPFieldChangeReason,
  index: S.Number,
  isComplete: S.Boolean,
  didRejectCharacters: S.Boolean,
  invalidValue: S.optional(S.String),
  focusSelector: S.optional(S.String),
})
export type OTPFieldValueChange = typeof OTPFieldValueChange.Type

export const OTPFieldFocusChange = S.Struct({
  focused: S.Boolean,
  index: S.Number,
  focusSelector: S.optional(S.String),
})
export type OTPFieldFocusChange = typeof OTPFieldFocusChange.Type

export const OTPFieldOptions = S.Struct({
  id: S.optional(S.String),
  name: S.optional(S.String),
  form: S.optional(S.String),
  length: S.Number,
  value: S.optional(S.String),
  autoComplete: S.optional(S.String),
  inputMode: S.optional(S.String),
  validationType: S.optional(OTPFieldValidationType),
  mask: S.optional(S.Boolean),
  isDisabled: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
  isRequired: S.optional(S.Boolean),
  isReadOnly: S.optional(S.Boolean),
  isValid: S.optional(S.Boolean),
  isFieldInvalid: S.optional(S.Boolean),
  isDirty: S.optional(S.Boolean),
  isTouched: S.optional(S.Boolean),
  isFilled: S.optional(S.Boolean),
  isFocused: S.optional(S.Boolean),
  focusedIndex: S.optional(S.Number),
  dir: S.optional(S.String),
  ariaLabel: S.optional(S.String),
  ariaLabelledBy: S.optional(S.String),
  ariaDescribedBy: S.optional(S.String),
})
export type OTPFieldOptions = typeof OTPFieldOptions.Type

export type OTPFieldState = Readonly<{
  value: string
  length: number
  activeIndex: number
  isComplete: boolean
  isFilled: boolean
  validationType: OTPFieldValidationType
  inputMode: string | undefined
  slotPattern: string | undefined
  hiddenInputPattern: string | undefined
}>

export type OTPFieldSlotState = Readonly<{
  index: number
  value: string
  id: string | undefined
  isActive: boolean
  isComplete: boolean
  isFilled: boolean
}>

type OTPValidationConfig = Readonly<{
  slotPattern: string
  getRootPattern: (length: number) => string
  regexp: RegExp
  inputMode: 'numeric' | 'text'
}>

// MESSAGE

export const CompletedFocusOTPFieldInput = m('CompletedFocusOTPFieldInput')

export const CommandMessage = S.Union([CompletedFocusOTPFieldInput])
export type CommandMessage = typeof CommandMessage.Type

// UPDATE

const validationConfig: Readonly<
  Record<Exclude<OTPFieldValidationType, 'none'>, OTPValidationConfig>
> = {
  numeric: {
    slotPattern: '\\d{1}',
    getRootPattern: length => `\\d{${length}}`,
    regexp: /[^\d]/gu,
    inputMode: 'numeric',
  },
  alpha: {
    slotPattern: '[a-zA-Z]{1}',
    getRootPattern: length => `[a-zA-Z]{${length}}`,
    regexp: /[^a-zA-Z]/gu,
    inputMode: 'text',
  },
  alphanumeric: {
    slotPattern: '[a-zA-Z0-9]{1}',
    getRootPattern: length => `[a-zA-Z0-9]{${length}}`,
    regexp: /[^a-zA-Z0-9]/gu,
    inputMode: 'text',
  },
}

const positiveLength = (length: number): number =>
  Number.isInteger(length) && length > 0 ? length : 0

const otpValueLength = (value: string): number => [...value].length

const getValidationConfig = (
  validationType: OTPFieldValidationType,
): OTPValidationConfig | undefined =>
  validationType === 'none' ? undefined : validationConfig[validationType]

export const stripOTPWhitespace = (value: string | null | undefined): string =>
  (value ?? '').replaceAll(/\s/gu, '')

const applyOTPValidation = (
  value: string,
  config: OTPValidationConfig | undefined,
): string =>
  config === undefined ? value : value.replaceAll(config.regexp, '')

const clampOTPValue = (
  value: string,
  length: number,
): Readonly<{ value: string; didClamp: boolean }> => {
  const maxLength = positiveLength(length)
  const characters = [...value]

  return {
    value: characters.slice(0, maxLength).join(''),
    didClamp: characters.length > maxLength,
  }
}

export const normalizeOTPValueWithDetails = (
  value: string | null | undefined,
  length: number,
  validationType: OTPFieldValidationType = 'numeric',
  normalizeValue?: ((value: string) => string) | undefined,
): readonly [value: string, didRejectCharacters: boolean] => {
  const strippedValue = stripOTPWhitespace(value)
  const config = getValidationConfig(validationType)
  const validatedValue = applyOTPValidation(strippedValue, config)

  if (normalizeValue === undefined) {
    const clampedValue = clampOTPValue(validatedValue, length)

    return [
      clampedValue.value,
      strippedValue.length > validatedValue.length || clampedValue.didClamp,
    ]
  }

  const customNormalizedValue = normalizeValue(validatedValue)
  const revalidatedValue = applyOTPValidation(customNormalizedValue, config)
  const clampedValue = clampOTPValue(revalidatedValue, length)

  return [
    clampedValue.value,
    strippedValue.length > validatedValue.length ||
      validatedValue.length > customNormalizedValue.length ||
      customNormalizedValue.length > revalidatedValue.length ||
      clampedValue.didClamp,
  ]
}

export const normalizeOTPValue = (
  value: string | null | undefined,
  length: number,
  validationType: OTPFieldValidationType = 'numeric',
  normalizeValue?: ((value: string) => string) | undefined,
): string =>
  normalizeOTPValueWithDetails(value, length, validationType, normalizeValue)[0]

export const replaceOTPValue = (
  currentValue: string,
  index: number,
  nextValue: string,
  length: number,
  validationType: OTPFieldValidationType = 'numeric',
  normalizeValue?: ((value: string) => string) | undefined,
): string => {
  const normalizedValue = normalizeOTPValue(
    nextValue,
    length,
    validationType,
    normalizeValue,
  )
  const currentCharacters = [...currentValue]
  const replacementLength = otpValueLength(normalizedValue)
  const prefix = currentCharacters.slice(0, index).join('')
  const suffix = currentCharacters.slice(index + replacementLength).join('')

  return normalizeOTPValue(
    `${prefix}${normalizedValue}${suffix}`,
    length,
    validationType,
    normalizeValue,
  )
}

export const removeOTPCharacter = (
  currentValue: string,
  index: number,
): string =>
  [...currentValue]
    .filter((_character, characterIndex) => characterIndex !== index)
    .join('')

export const inputId = (
  config: Pick<OTPFieldOptions, 'id'>,
  index: number,
): string | undefined => {
  if (config.id === undefined) {
    return undefined
  }

  if (index === 0) {
    return config.id
  }

  return `${config.id}-${index + 1}`
}

export const hiddenInputId = (
  config: Pick<OTPFieldOptions, 'id' | 'name'>,
): string | undefined =>
  config.id === undefined || config.name !== undefined
    ? undefined
    : `${config.id}-hidden-input`

export const inputFocusSelector = (
  config: Pick<OTPFieldOptions, 'id'>,
  index: number,
): string | undefined => {
  const id = inputId(config, index)

  return id === undefined ? undefined : `#${id}`
}

export const otpFieldState = (
  config: OTPFieldOptions &
    Readonly<{ normalizeValue?: ((value: string) => string) | undefined }>,
): OTPFieldState => {
  const length = positiveLength(config.length)
  const validationType = config.validationType ?? 'numeric'
  const value = normalizeOTPValue(
    config.value,
    length,
    validationType,
    config.normalizeValue,
  )
  const valueLength = otpValueLength(value)
  const lastIndex = Math.max(length - 1, 0)
  const activeIndex =
    config.isFocused === true && config.focusedIndex !== undefined
      ? Math.min(Math.max(config.focusedIndex, 0), lastIndex)
      : Math.min(valueLength, lastIndex)
  const configForValidation = getValidationConfig(validationType)

  return {
    value,
    length,
    activeIndex,
    isComplete: length > 0 && valueLength === length,
    isFilled: value !== '',
    validationType,
    inputMode: config.inputMode ?? configForValidation?.inputMode,
    slotPattern: configForValidation?.slotPattern,
    hiddenInputPattern: configForValidation?.getRootPattern(length),
  }
}

export const otpFieldSlots = (
  config: OTPFieldOptions &
    Readonly<{ normalizeValue?: ((value: string) => string) | undefined }>,
): ReadonlyArray<OTPFieldSlotState> => {
  const state = otpFieldState(config)
  const characters = [...state.value]

  return Array.from({ length: state.length }, (_item, index) => {
    const value = characters[index] ?? ''

    return {
      index,
      value,
      id: inputId(config, index),
      isActive: state.activeIndex === index,
      isComplete: state.isComplete,
      isFilled: value !== '',
    }
  })
}

const changeFromValue = (
  config: OTPFieldOptions &
    Readonly<{ normalizeValue?: ((value: string) => string) | undefined }>,
  index: number,
  value: string,
  reason: OTPFieldChangeReason,
  didRejectCharacters: boolean,
  invalidValue?: string | undefined,
): OTPFieldValueChange => {
  const state = otpFieldState(config)
  const nextValueLength = otpValueLength(value)
  const nextFocusIndex = Math.min(
    Math.max(
      index + Math.max(nextValueLength - otpValueLength(state.value), 1),
      0,
    ),
    Math.max(state.length - 1, 0),
  )

  return {
    value,
    reason,
    index,
    isComplete: state.length > 0 && otpValueLength(value) === state.length,
    didRejectCharacters,
    invalidValue,
    focusSelector:
      value === state.value
        ? undefined
        : inputFocusSelector(config, nextFocusIndex),
  }
}

const inputChangeValue = (
  config: OTPFieldOptions &
    Readonly<{ normalizeValue?: ((value: string) => string) | undefined }>,
  index: number,
  rawValue: string,
  nextCharacters: string,
  state: OTPFieldState,
): string => {
  if (nextCharacters === '') {
    if (rawValue === '') {
      return removeOTPCharacter(state.value, index)
    }

    return state.value
  }

  return replaceOTPValue(
    state.value,
    index,
    nextCharacters,
    state.length,
    state.validationType,
    config.normalizeValue,
  )
}

export const otpFieldInputChange = (
  config: OTPFieldOptions &
    Readonly<{ normalizeValue?: ((value: string) => string) | undefined }>,
  index: number,
  rawValue: string,
): OTPFieldValueChange => {
  const state = otpFieldState(config)
  const slotValue = [...state.value][index] ?? ''
  const [nextCharacters, didRejectCharacters] = normalizeOTPValueWithDetails(
    rawValue,
    state.length,
    state.validationType,
    config.normalizeValue,
  )
  const reason =
    nextCharacters === '' && rawValue === '' ? 'input-clear' : 'input-change'
  const nextValue = inputChangeValue(
    config,
    index,
    rawValue,
    nextCharacters,
    state,
  )

  return {
    ...changeFromValue(
      config,
      index,
      nextValue,
      reason,
      didRejectCharacters,
      didRejectCharacters ? rawValue : undefined,
    ),
    focusSelector:
      nextCharacters === '' || (nextValue === state.value && slotValue !== '')
        ? undefined
        : inputFocusSelector(
            config,
            Math.min(
              index + otpValueLength(nextCharacters),
              Math.max(state.length - 1, 0),
            ),
          ),
  }
}

export const otpFieldPasteChange = (
  config: OTPFieldOptions &
    Readonly<{ normalizeValue?: ((value: string) => string) | undefined }>,
  index: number,
  rawValue: string,
): OTPFieldValueChange => {
  const state = otpFieldState(config)
  const [nextCharacters, didRejectCharacters] = normalizeOTPValueWithDetails(
    rawValue,
    state.length,
    state.validationType,
    config.normalizeValue,
  )
  const nextValue =
    nextCharacters === ''
      ? state.value
      : replaceOTPValue(
          state.value,
          index,
          nextCharacters,
          state.length,
          state.validationType,
          config.normalizeValue,
        )

  return {
    ...changeFromValue(
      config,
      index,
      nextValue,
      'input-paste',
      didRejectCharacters,
      didRejectCharacters ? rawValue : undefined,
    ),
    focusSelector:
      nextCharacters === ''
        ? undefined
        : inputFocusSelector(
            config,
            Math.min(
              index + otpValueLength(nextCharacters),
              Math.max(state.length - 1, 0),
            ),
          ),
  }
}

export const otpFieldFocusChange = (
  config: OTPFieldOptions &
    Readonly<{ normalizeValue?: ((value: string) => string) | undefined }>,
  index: number,
  focused: boolean,
): OTPFieldFocusChange => {
  const state = otpFieldState(config)
  const targetIndex =
    focused && index > otpValueLength(state.value)
      ? Math.min(otpValueLength(state.value), Math.max(state.length - 1, 0))
      : Math.min(Math.max(index, 0), Math.max(state.length - 1, 0))

  return {
    focused,
    index: targetIndex,
    focusSelector:
      focused && targetIndex !== index
        ? inputFocusSelector(config, targetIndex)
        : undefined,
  }
}

export const otpFieldKeyboardFocusChange = (
  config: OTPFieldOptions &
    Readonly<{ normalizeValue?: ((value: string) => string) | undefined }>,
  index: number,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<OTPFieldFocusChange> => {
  const state = otpFieldState(config)
  const hasBoundaryModifier =
    (modifiers.ctrlKey || modifiers.metaKey) && !modifiers.altKey
  const isRtl = config.dir === 'rtl'
  const previousKey = isRtl ? 'ArrowRight' : 'ArrowLeft'
  const nextKey = isRtl ? 'ArrowLeft' : 'ArrowRight'
  const lastIndex = Math.max(state.length - 1, 0)
  const endTargetIndex = Math.min(otpValueLength(state.value), lastIndex)
  const slotValue = [...state.value][index] ?? ''

  if (key === previousKey) {
    return Option.some(
      otpFieldFocusChange(
        config,
        hasBoundaryModifier ? 0 : Math.max(0, index - 1),
        true,
      ),
    )
  }

  if (key === nextKey) {
    return Option.some(
      otpFieldFocusChange(
        config,
        hasBoundaryModifier ? endTargetIndex : Math.min(lastIndex, index + 1),
        true,
      ),
    )
  }

  if (key === 'Home' || key === 'ArrowUp') {
    return Option.some(otpFieldFocusChange(config, 0, true))
  }

  if (key === 'End' || key === 'ArrowDown') {
    return Option.some(otpFieldFocusChange(config, endTargetIndex, true))
  }

  if (key.length === 1 && slotValue === key && index < lastIndex) {
    return Option.some(otpFieldFocusChange(config, index + 1, true))
  }

  return Option.none()
}

export const otpFieldKeyboardValueChange = (
  config: OTPFieldOptions &
    Readonly<{ normalizeValue?: ((value: string) => string) | undefined }>,
  index: number,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<OTPFieldValueChange> => {
  const state = otpFieldState(config)
  const hasBoundaryModifier =
    (modifiers.ctrlKey || modifiers.metaKey) && !modifiers.altKey

  if (key === 'Backspace' && hasBoundaryModifier) {
    return Option.some(changeFromValue(config, 0, '', 'keyboard', false))
  }

  if (key === 'Delete') {
    return Option.some(
      changeFromValue(
        config,
        index,
        removeOTPCharacter(state.value, index),
        'keyboard',
        false,
      ),
    )
  }

  if (key === 'Backspace') {
    const targetIndex = Math.max(0, index - 1)
    const slotValue = [...state.value][index] ?? ''
    const deleteIndex = slotValue === '' ? targetIndex : index

    return Option.some({
      ...changeFromValue(
        config,
        index,
        removeOTPCharacter(state.value, deleteIndex),
        'keyboard',
        false,
      ),
      focusSelector: inputFocusSelector(config, targetIndex),
    })
  }

  return Option.none()
}

export const FocusOTPFieldInput = Command.define(
  'FocusOTPFieldInput',
  { selector: S.String },
  CompletedFocusOTPFieldInput,
)(({ selector }) =>
  Dom.focus(selector).pipe(
    Effect.ignore,
    Effect.catchCause(() => Effect.void),
    Effect.as(CompletedFocusOTPFieldInput()),
  ),
)

export const commandForValueChange = (
  change: Pick<OTPFieldValueChange, 'focusSelector'>,
): Option.Option<Command.Command<CommandMessage>> =>
  change.focusSelector === undefined
    ? Option.none()
    : Option.some(FocusOTPFieldInput({ selector: change.focusSelector }))

export const commandForFocusChange = (
  change: Pick<OTPFieldFocusChange, 'focusSelector'>,
): Option.Option<Command.Command<CommandMessage>> =>
  change.focusSelector === undefined
    ? Option.none()
    : Option.some(FocusOTPFieldInput({ selector: change.focusSelector }))

// VIEW

export type OTPFieldSlotAttributes<Message> = Readonly<{
  state: OTPFieldSlotState
  input: ReadonlyArray<Attribute<Message>>
}>

export type OTPFieldAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  slots: ReadonlyArray<OTPFieldSlotAttributes<Message>>
  hiddenInput: ReadonlyArray<Attribute<Message>>
  state: OTPFieldState
}>

export type ViewConfig<Message> = OTPFieldOptions &
  Readonly<{
    normalizeValue?: ((value: string) => string) | undefined
    toView: (attributes: OTPFieldAttributes<Message>) => Html
    onValueChange?: (change: OTPFieldValueChange) => Message
    onFocusChange?: (change: OTPFieldFocusChange) => Message
  }>

const visuallyHiddenInputStyle =
  'clip-path: inset(50%); overflow: hidden; white-space: nowrap; border: 0px; padding: 0px; width: 1px; height: 1px; margin: -1px; position: absolute;'

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  form: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  form === undefined ? [] : [h.Attribute('form', form)]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: OTPFieldState,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('group'),
  ...optionalAttribute<Message>(config.ariaLabelledBy, value =>
    h.AriaLabelledBy(value),
  ),
  ...optionalAttribute<Message>(config.ariaDescribedBy, value =>
    h.AriaDescribedBy(value),
  ),
  ...optionalAttribute<Message>(config.dir, value => h.Dir(value)),
  ...booleanDataAttribute(h, 'complete', state.isComplete),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'valid', config.isValid),
  ...booleanDataAttribute(h, 'invalid', config.isFieldInvalid),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'filled', config.isFilled ?? state.isFilled),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
]

const inputEventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  index: number,
): ReadonlyArray<Attribute<Message>> => {
  const { onValueChange } = config
  const { onFocusChange } = config

  if (config.isDisabled === true) {
    return []
  }

  return [
    ...(onFocusChange === undefined
      ? []
      : [
          h.OnFocus(onFocusChange(otpFieldFocusChange(config, index, true))),
          h.OnBlur(onFocusChange(otpFieldFocusChange(config, index, false))),
          h.OnMouseDown(
            onFocusChange(otpFieldFocusChange(config, index, true)),
          ),
        ]),
    ...(config.isReadOnly === true || onValueChange === undefined
      ? []
      : [
          h.OnInput(value =>
            onValueChange(otpFieldInputChange(config, index, value)),
          ),
          h.OnPastePreventDefault(text =>
            Option.some(
              onValueChange(otpFieldPasteChange(config, index, text)),
            ),
          ),
        ]),
    ...(onFocusChange === undefined && onValueChange === undefined
      ? []
      : [
          h.OnKeyDownPreventDefault((key, modifiers) =>
            Option.match(
              otpFieldKeyboardFocusChange(config, index, key, modifiers),
              {
                onNone: () =>
                  config.isReadOnly === true || onValueChange === undefined
                    ? Option.none()
                    : Option.map(
                        otpFieldKeyboardValueChange(
                          config,
                          index,
                          key,
                          modifiers,
                        ),
                        change => onValueChange(change),
                      ),
                onSome: change =>
                  onFocusChange === undefined
                    ? Option.none()
                    : Option.some(onFocusChange(change)),
              },
            ),
          ),
        ]),
  ]
}

const inputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: OTPFieldState,
  slot: OTPFieldSlotState,
): ReadonlyArray<Attribute<Message>> => [
  h.Type(config.mask === true ? 'password' : 'text'),
  h.Value(slot.value),
  h.InputMode(state.inputMode ?? 'text'),
  h.Autocomplete(
    slot.index === 0 ? (config.autoComplete ?? 'one-time-code') : 'off',
  ),
  h.Autocorrect('off'),
  h.Spellcheck(false),
  h.EnterKeyHint(slot.index === state.length - 1 ? 'done' : 'next'),
  h.Tabindex(slot.isActive ? 0 : -1),
  ...optionalAttribute<Message>(slot.id, value => h.Id(value)),
  ...optionalAttribute<Message>(state.slotPattern, value => h.Pattern(value)),
  ...(slot.index === 0 ? [h.Maxlength(state.length)] : []),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.Disabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.Required(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.Readonly(value),
  ),
  ...(config.isInvalid === true ? [h.AriaInvalid(true)] : []),
  ...(config.ariaLabel !== undefined && slot.index !== 0
    ? [h.AriaLabel(config.ariaLabel)]
    : []),
  ...optionalAttribute<Message>(
    config.ariaLabel === undefined ? config.ariaLabelledBy : undefined,
    value => h.AriaLabelledBy(value),
  ),
  ...formOwnerAttributes(h, config.form),
  ...booleanDataAttribute(h, 'complete', slot.isComplete),
  ...booleanDataAttribute(h, 'filled', slot.isFilled),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'valid', config.isValid),
  ...booleanDataAttribute(h, 'invalid', config.isFieldInvalid),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
  ...inputEventAttributes(h, config, slot.index),
]

const hiddenInputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: OTPFieldState,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('text'),
  h.Value(state.value),
  h.AriaHidden(true),
  h.Tabindex(-1),
  h.Minlength(state.length),
  h.Maxlength(state.length),
  h.Autocomplete(config.autoComplete ?? 'one-time-code'),
  h.InputMode(state.inputMode ?? 'text'),
  h.Attribute('style', visuallyHiddenInputStyle),
  ...optionalAttribute<Message>(hiddenInputId(config), value => h.Id(value)),
  ...optionalAttribute<Message>(config.name, value => h.Name(value)),
  ...optionalAttribute<Message>(state.hiddenInputPattern, value =>
    h.Pattern(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.Disabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.Required(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.Readonly(value),
  ),
  ...formOwnerAttributes(h, config.form),
]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const state = otpFieldState(config)
  const slots = otpFieldSlots(config)

  return config.toView({
    root: rootAttributes(h, config, state),
    slots: slots.map(slot => ({
      state: slot,
      input: inputAttributes(h, config, state, slot),
    })),
    hiddenInput: hiddenInputAttributes(h, config, state),
    state,
  })
}

import { Effect, Option, Predicate, Schema as S } from 'effect'
import * as Command from 'foldkit/command'
import * as Dom from 'foldkit/dom'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'
import { m } from 'foldkit/message'

// MODEL

export const PopoverSide = S.Union([
  S.Literal('bottom'),
  S.Literal('top'),
  S.Literal('right'),
  S.Literal('left'),
  S.Literal('inline-start'),
  S.Literal('inline-end'),
])
export type PopoverSide = typeof PopoverSide.Type

export const PopoverAlign = S.Union([
  S.Literal('start'),
  S.Literal('center'),
  S.Literal('end'),
])
export type PopoverAlign = typeof PopoverAlign.Type

export const PopoverModalMode = S.Union([S.Boolean, S.Literal('trap-focus')])
export type PopoverModalMode = typeof PopoverModalMode.Type

export const PopoverTransitionStatus = S.Union([
  S.Literal('idle'),
  S.Literal('starting'),
  S.Literal('ending'),
])
export type PopoverTransitionStatus = typeof PopoverTransitionStatus.Type

export const PopoverChangeReason = S.Union([
  S.Literal('trigger-press'),
  S.Literal('close-press'),
  S.Literal('outside-press'),
  S.Literal('escape-key'),
  S.Literal('none'),
])
export type PopoverChangeReason = typeof PopoverChangeReason.Type

export const PopoverOpenChange = S.Struct({
  open: S.Boolean,
  reason: PopoverChangeReason,
})
export type PopoverOpenChange = typeof PopoverOpenChange.Type

export const PopoverOptions = S.Struct({
  id: S.String,
  open: S.Boolean,
  modal: S.optional(PopoverModalMode),
  isDisabled: S.optional(S.Boolean),
  forceMount: S.optional(S.Boolean),
  transitionStatus: S.optional(PopoverTransitionStatus),
  titleId: S.optional(S.String),
  descriptionId: S.optional(S.String),
  focusSelector: S.optional(S.String),
  triggerId: S.optional(S.String),
  triggerSelector: S.optional(S.String),
  disableOutsidePress: S.optional(S.Boolean),
  side: S.optional(PopoverSide),
  align: S.optional(PopoverAlign),
  sideOffset: S.optional(S.Number),
  alignOffset: S.optional(S.Number),
  collisionAvoidance: S.optional(S.Boolean),
  collisionPadding: S.optional(S.Number),
  arrowWidth: S.optional(S.Number),
  arrowHeight: S.optional(S.Number),
  dir: S.optional(S.String),
})
export type PopoverOptions = typeof PopoverOptions.Type

// MESSAGE

export const CompletedFocusPopover = m('CompletedFocusPopover')
export const CompletedRestorePopoverFocus = m('CompletedRestorePopoverFocus')

export const CommandMessage = S.Union([
  CompletedFocusPopover,
  CompletedRestorePopoverFocus,
])
export type CommandMessage = typeof CommandMessage.Type

// UPDATE

const defaultSide: PopoverSide = 'bottom'
const defaultAlign: PopoverAlign = 'center'
const defaultModal: PopoverModalMode = false
const defaultSideOffset = 0
const defaultAlignOffset = 0
const defaultCollisionAvoidance = true
const defaultCollisionPadding = 0
const defaultArrowWidth = 10
const defaultArrowHeight = 5

const maybeFocusSelectorSchema = S.Option(S.String)

export const popupId = (config: Pick<PopoverOptions, 'id'>): string =>
  `${config.id}-popup`

export const positionerId = (config: Pick<PopoverOptions, 'id'>): string =>
  `${config.id}-positioner`

export const arrowId = (config: Pick<PopoverOptions, 'id'>): string =>
  `${config.id}-arrow`

export const titleId = (
  config: Pick<PopoverOptions, 'id' | 'titleId'>,
): string => config.titleId ?? `${config.id}-title`

export const descriptionId = (
  config: Pick<PopoverOptions, 'descriptionId' | 'id'>,
): string => config.descriptionId ?? `${config.id}-description`

export const popoverSelector = (id: string): string => `#${popupId({ id })}`

export const triggerId = (
  config: Pick<PopoverOptions, 'id' | 'triggerId'>,
): string => config.triggerId ?? `${config.id}-trigger`

export const triggerSelector = (
  config: Pick<PopoverOptions, 'id' | 'triggerId' | 'triggerSelector'>,
): string => config.triggerSelector ?? `#${triggerId(config)}`

const rootAnchorName = (config: Pick<PopoverOptions, 'id'>): string =>
  `--${config.id}-anchor`

export const openChange = (
  open: boolean,
  reason: PopoverChangeReason = 'none',
): PopoverOpenChange => ({
  open,
  reason,
})

export const triggerOpenChange = (): PopoverOpenChange =>
  openChange(true, 'trigger-press')

export const closeOpenChange = (): PopoverOpenChange =>
  openChange(false, 'close-press')

export const outsideOpenChange = (): PopoverOpenChange =>
  openChange(false, 'outside-press')

export const escapeOpenChange = (): PopoverOpenChange =>
  openChange(false, 'escape-key')

export const FocusPopover = Command.define(
  'FocusPopover',
  {
    id: S.String,
    modal: PopoverModalMode,
    maybeFocusSelector: maybeFocusSelectorSchema,
  },
  CompletedFocusPopover,
)(({ id, modal, maybeFocusSelector }) => {
  const selector = Option.getOrElse(maybeFocusSelector, () =>
    popoverSelector(id),
  )
  const focus = Dom.focus(selector, { makeFocusable: true }).pipe(
    Effect.ignore,
    Effect.catchCause(() => Effect.void),
    Effect.as(CompletedFocusPopover()),
  )

  return modal === true
    ? Dom.lockScroll.pipe(Effect.andThen(() => focus))
    : focus
})

export const RestorePopoverFocus = Command.define(
  'RestorePopoverFocus',
  { modal: PopoverModalMode, selector: S.String },
  CompletedRestorePopoverFocus,
)(({ modal, selector }) => {
  const restoreFocus = Dom.focus(selector).pipe(
    Effect.ignore,
    Effect.catchCause(() => Effect.void),
  )

  if (modal === true) {
    return restoreFocus.pipe(
      Effect.andThen(() => Dom.unlockScroll),
      Effect.as(CompletedRestorePopoverFocus()),
    )
  }

  return restoreFocus.pipe(Effect.as(CompletedRestorePopoverFocus()))
})

export const commandForOpenChange = (
  config: Pick<
    PopoverOptions,
    'focusSelector' | 'id' | 'modal' | 'triggerId' | 'triggerSelector'
  >,
  change: PopoverOpenChange,
): Command.Command<CommandMessage> =>
  change.open
    ? FocusPopover({
        id: config.id,
        modal: config.modal ?? defaultModal,
        maybeFocusSelector: Option.fromNullishOr(config.focusSelector),
      })
    : RestorePopoverFocus({
        modal: config.modal ?? defaultModal,
        selector: triggerSelector(config),
      })

// VIEW

export type PopoverAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  trigger: ReadonlyArray<Attribute<Message>>
  portal: ReadonlyArray<Attribute<Message>>
  positioner: PopoverPartAttributes<Message>
  backdrop: PopoverPartAttributes<Message>
  popup: PopoverPartAttributes<Message>
  arrow: PopoverPartAttributes<Message>
  title: ReadonlyArray<Attribute<Message>>
  description: ReadonlyArray<Attribute<Message>>
  close: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type PopoverPartAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type ViewConfig<Message> = PopoverOptions &
  Readonly<{
    toView: (attributes: PopoverAttributes<Message>) => Html
    onOpenChange?: (change: PopoverOpenChange) => Message
  }>

const resolvedSide = (config: Pick<PopoverOptions, 'side'>): PopoverSide =>
  config.side ?? defaultSide

const resolvedAlign = (config: Pick<PopoverOptions, 'align'>): PopoverAlign =>
  config.align ?? defaultAlign

const resolvedModal = (
  config: Pick<PopoverOptions, 'modal'>,
): PopoverModalMode => config.modal ?? defaultModal

const mounted = (
  config: Pick<PopoverOptions, 'forceMount' | 'open' | 'transitionStatus'>,
): boolean =>
  config.open ||
  config.forceMount === true ||
  config.transitionStatus === 'ending'

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const numberDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: number,
): Attribute<Message> => h.DataAttribute(name, String(value))

const openStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  open: boolean,
): ReadonlyArray<Attribute<Message>> =>
  open ? [h.DataAttribute('open', '')] : [h.DataAttribute('closed', '')]

const transitionDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  transitionStatus: PopoverTransitionStatus | undefined,
): ReadonlyArray<Attribute<Message>> => {
  if (transitionStatus === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (transitionStatus === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const openMessage = <Message>(
  config: ViewConfig<Message>,
  change: PopoverOpenChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onOpenChange)
    ? Option.some(config.onOpenChange(change))
    : Option.none()

const optionalMessageAttribute = <Message>(
  message: Option.Option<Message>,
  toAttribute: (message: Message) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(message, {
    onNone: () => [],
    onSome: value => [toAttribute(value)],
  })

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('modal', String(resolvedModal(config))),
  h.DataAttribute('side', resolvedSide(config)),
  h.DataAttribute('align', resolvedAlign(config)),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
]

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(triggerId(config)),
  h.Type('button'),
  h.AriaHasPopup('dialog'),
  h.AriaExpanded(config.open),
  h.AriaControls(popupId(config)),
  h.Style({ anchorName: rootAnchorName(config) }),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...(config.open ? [h.DataAttribute('popup-open', '')] : []),
  ...(config.isDisabled === true ? [h.AriaDisabled(true)] : []),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, triggerOpenChange()),
    message => h.OnClick(message),
  ),
]

const portalAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
): ReadonlyArray<Attribute<Message>> => [h.DataAttribute('portal', '')]

const placementAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('side', resolvedSide(config)),
  h.DataAttribute('align', resolvedAlign(config)),
  numberDataAttribute(h, 'side-offset', config.sideOffset ?? defaultSideOffset),
  numberDataAttribute(
    h,
    'align-offset',
    config.alignOffset ?? defaultAlignOffset,
  ),
  h.DataAttribute(
    'collision-avoidance',
    String(config.collisionAvoidance ?? defaultCollisionAvoidance),
  ),
  numberDataAttribute(
    h,
    'collision-padding',
    config.collisionPadding ?? defaultCollisionPadding,
  ),
]

const horizontalAnchorStyle = (
  config: Pick<PopoverOptions, 'align'>,
): Readonly<Record<string, string>> => {
  const align = resolvedAlign(config)

  if (align === 'center') {
    return { left: 'anchor(center)', translate: '-50% 0' }
  }

  if (align === 'end') {
    return { left: 'anchor(right)', translate: '-100% 0' }
  }

  return { left: 'anchor(left)' }
}

const verticalAnchorStyle = (
  config: Pick<PopoverOptions, 'align'>,
): Readonly<Record<string, string>> => {
  const align = resolvedAlign(config)

  if (align === 'center') {
    return { top: 'anchor(center)', translate: '0 -50%' }
  }

  if (align === 'end') {
    return { top: 'anchor(bottom)', translate: '0 -100%' }
  }

  return { top: 'anchor(top)' }
}

const positionerPlacementStyle = (
  config: Pick<PopoverOptions, 'align' | 'id' | 'side' | 'sideOffset'>,
): Readonly<Record<string, string>> => {
  const sideOffset = `${config.sideOffset ?? defaultSideOffset}px`
  const side = resolvedSide(config)

  if (side === 'top') {
    return {
      ...horizontalAnchorStyle(config),
      bottom: `calc(anchor(top) + ${sideOffset})`,
    }
  }

  if (side === 'left' || side === 'inline-start') {
    return {
      ...verticalAnchorStyle(config),
      right: `calc(anchor(left) + ${sideOffset})`,
    }
  }

  if (side === 'right' || side === 'inline-end') {
    return {
      ...verticalAnchorStyle(config),
      left: `calc(anchor(right) + ${sideOffset})`,
    }
  }

  return {
    ...horizontalAnchorStyle(config),
    top: `calc(anchor(bottom) + ${sideOffset})`,
  }
}

const positionArea = (
  config: Pick<PopoverOptions, 'align' | 'side'>,
): string => {
  const align = resolvedAlign(config)
  const side = resolvedSide(config)
  const inlineAlignments = {
    start: 'span-inline-start',
    center: 'center',
    end: 'span-inline-end',
  }
  const blockAlignments = {
    start: 'span-block-start',
    center: 'center',
    end: 'span-block-end',
  }

  if (side === 'top') {
    return `block-start ${inlineAlignments[align]}`
  }
  if (side === 'bottom') {
    return `block-end ${inlineAlignments[align]}`
  }
  if (side === 'left' || side === 'inline-start') {
    return `inline-start ${blockAlignments[align]}`
  }
  return `inline-end ${blockAlignments[align]}`
}

const positionerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): PopoverPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(positionerId(config)),
        ...(config.open ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, config.open),
        ...placementAttributes(h, config),
        h.Style({
          position: 'absolute',
          positionAnchor: rootAnchorName(config),
          inset: 'auto',
          margin: '0',
          ...positionerPlacementStyle(config),
        }),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const backdropAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): PopoverPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Role('presentation'),
        ...(config.open ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, config.open),
        ...transitionDataAttributes(h, config.transitionStatus),
        h.Style({
          position: 'fixed',
          inset: '0',
          zIndex: '49',
        }),
        ...optionalMessageAttribute(
          config.disableOutsidePress === true
            ? Option.none()
            : openMessage(config, outsideOpenChange()),
          message => h.OnClick(message),
        ),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const popupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): PopoverPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Key(`${popupId(config)}-${config.open ? 'open' : 'closed'}`),
        h.Id(popupId(config)),
        h.Popover('manual'),
        h.Role('dialog'),
        h.Tabindex(-1),
        ...(config.open ? [] : [h.Hidden(true)]),
        h.AriaModal(resolvedModal(config) !== false),
        h.AriaLabelledBy(titleId(config)),
        h.Attribute('aria-describedby', descriptionId(config)),
        ...openStateDataAttributes(h, config.open),
        ...transitionDataAttributes(h, config.transitionStatus),
        ...placementAttributes(h, config),
        h.Style({
          position: 'fixed',
          positionAnchor: rootAnchorName(config),
          positionArea: positionArea(config),
          margin: '0',
          ...((config.collisionAvoidance ?? defaultCollisionAvoidance)
            ? { positionTryFallbacks: 'flip-inline, flip-block' }
            : {}),
        }),
        ...optionalMessageAttribute(
          openMessage(config, escapeOpenChange()),
          message =>
            h.OnKeyDownPreventDefault(key =>
              key === 'Escape' ? Option.some(message) : Option.none(),
            ),
        ),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const arrowAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): PopoverPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(arrowId(config)),
        h.AriaHidden(true),
        ...openStateDataAttributes(h, config.open),
        ...placementAttributes(h, config),
        h.Style({
          width: `${config.arrowWidth ?? defaultArrowWidth}px`,
          height: `${config.arrowHeight ?? defaultArrowHeight}px`,
        }),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const closeAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('button'),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...(config.isDisabled === true ? [h.AriaDisabled(true)] : []),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, closeOpenChange()),
    message => h.OnClick(message),
  ),
]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const isMounted = mounted(config)

  return config.toView({
    root: rootAttributes(h, config),
    trigger: triggerAttributes(h, config),
    portal: portalAttributes(h),
    positioner: positionerAttributes(h, config, isMounted),
    backdrop: backdropAttributes(h, config, isMounted),
    popup: popupAttributes(h, config, isMounted),
    arrow: arrowAttributes(h, config, isMounted),
    title: [h.Id(titleId(config))],
    description: [h.Id(descriptionId(config))],
    close: closeAttributes(h, config),
    isMounted,
    isOpen: config.open,
  })
}

import { Effect, Option, Predicate, Schema as S } from 'effect'
import * as Command from 'foldkit/command'
import * as Dom from 'foldkit/dom'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'
import { m } from 'foldkit/message'

// MODEL

export const PreviewCardSide = S.Union([
  S.Literal('bottom'),
  S.Literal('top'),
  S.Literal('right'),
  S.Literal('left'),
  S.Literal('inline-start'),
  S.Literal('inline-end'),
])
export type PreviewCardSide = typeof PreviewCardSide.Type

export const PreviewCardAlign = S.Union([
  S.Literal('start'),
  S.Literal('center'),
  S.Literal('end'),
])
export type PreviewCardAlign = typeof PreviewCardAlign.Type

export const PreviewCardTransitionStatus = S.Union([
  S.Literal('idle'),
  S.Literal('starting'),
  S.Literal('ending'),
])
export type PreviewCardTransitionStatus =
  typeof PreviewCardTransitionStatus.Type

export const PreviewCardInstant = S.Union([
  S.Literal('dismiss'),
  S.Literal('focus'),
])
export type PreviewCardInstant = typeof PreviewCardInstant.Type

export const PreviewCardChangeReason = S.Union([
  S.Literal('trigger-hover'),
  S.Literal('trigger-focus'),
  S.Literal('trigger-press'),
  S.Literal('outside-press'),
  S.Literal('escape-key'),
  S.Literal('imperative-action'),
  S.Literal('disabled'),
  S.Literal('none'),
])
export type PreviewCardChangeReason = typeof PreviewCardChangeReason.Type

export const PreviewCardOpenChange = S.Struct({
  open: S.Boolean,
  reason: PreviewCardChangeReason,
  activeTriggerId: S.optional(S.String),
})
export type PreviewCardOpenChange = typeof PreviewCardOpenChange.Type

export const PreviewCardOptions = S.Struct({
  id: S.String,
  open: S.Boolean,
  activeTriggerId: S.optional(S.String),
  triggerId: S.optional(S.String),
  triggerSelector: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  forceMount: S.optional(S.Boolean),
  transitionStatus: S.optional(PreviewCardTransitionStatus),
  instant: S.optional(PreviewCardInstant),
  side: S.optional(PreviewCardSide),
  align: S.optional(PreviewCardAlign),
  sideOffset: S.optional(S.Number),
  alignOffset: S.optional(S.Number),
  collisionAvoidance: S.optional(S.Boolean),
  collisionPadding: S.optional(S.Number),
  arrowPadding: S.optional(S.Number),
  arrowWidth: S.optional(S.Number),
  arrowHeight: S.optional(S.Number),
  isAnchorHidden: S.optional(S.Boolean),
  isArrowUncentered: S.optional(S.Boolean),
  delay: S.optional(S.Number),
  closeDelay: S.optional(S.Number),
  disableOutsidePress: S.optional(S.Boolean),
  viewportActivationDirection: S.optional(S.String),
  isViewportTransitioning: S.optional(S.Boolean),
})
export type PreviewCardOptions = typeof PreviewCardOptions.Type

// MESSAGE

export const CompletedFocusPreviewCard = m('CompletedFocusPreviewCard')
export const CompletedRestorePreviewCardFocus = m(
  'CompletedRestorePreviewCardFocus',
)

export const CommandMessage = S.Union([
  CompletedFocusPreviewCard,
  CompletedRestorePreviewCardFocus,
])
export type CommandMessage = typeof CommandMessage.Type

// UPDATE

const defaultSide: PreviewCardSide = 'bottom'
const defaultAlign: PreviewCardAlign = 'center'
const defaultSideOffset = 0
const defaultAlignOffset = 0
const defaultCollisionAvoidance = true
const defaultCollisionPadding = 5
const defaultArrowPadding = 5
const defaultArrowWidth = 10
const defaultArrowHeight = 5
const defaultDelay = 600
const defaultCloseDelay = 300

export const popupId = (config: Pick<PreviewCardOptions, 'id'>): string =>
  `${config.id}-popup`

export const positionerId = (config: Pick<PreviewCardOptions, 'id'>): string =>
  `${config.id}-positioner`

export const arrowId = (config: Pick<PreviewCardOptions, 'id'>): string =>
  `${config.id}-arrow`

export const viewportId = (config: Pick<PreviewCardOptions, 'id'>): string =>
  `${config.id}-viewport`

const rootAnchorName = (config: Pick<PreviewCardOptions, 'id'>): string =>
  `--${config.id}-anchor`

export const previewCardSelector = (id: string): string => `#${popupId({ id })}`

export const triggerId = (
  config: Pick<PreviewCardOptions, 'id' | 'triggerId'>,
): string => config.triggerId ?? `${config.id}-trigger`

export const activeTriggerId = (
  config: Pick<PreviewCardOptions, 'activeTriggerId' | 'id' | 'triggerId'>,
): string => config.activeTriggerId ?? triggerId(config)

export const triggerSelector = (
  config: Pick<PreviewCardOptions, 'id' | 'triggerId' | 'triggerSelector'>,
): string => config.triggerSelector ?? `#${triggerId(config)}`

export const openChange = (
  open: boolean,
  reason: PreviewCardChangeReason = 'none',
  nextActiveTriggerId?: string | undefined,
): PreviewCardOpenChange => ({
  open,
  reason,
  ...(nextActiveTriggerId === undefined
    ? {}
    : { activeTriggerId: nextActiveTriggerId }),
})

export const hoverOpenChange = (
  nextActiveTriggerId?: string | undefined,
): PreviewCardOpenChange =>
  openChange(true, 'trigger-hover', nextActiveTriggerId)

export const focusOpenChange = (
  nextActiveTriggerId?: string | undefined,
): PreviewCardOpenChange =>
  openChange(true, 'trigger-focus', nextActiveTriggerId)

export const pressOpenChange = (
  nextActiveTriggerId?: string | undefined,
): PreviewCardOpenChange =>
  openChange(true, 'trigger-press', nextActiveTriggerId)

export const hoverCloseChange = (
  nextActiveTriggerId?: string | undefined,
): PreviewCardOpenChange =>
  openChange(false, 'trigger-hover', nextActiveTriggerId)

export const focusCloseChange = (
  nextActiveTriggerId?: string | undefined,
): PreviewCardOpenChange =>
  openChange(false, 'trigger-focus', nextActiveTriggerId)

export const pressCloseChange = (
  nextActiveTriggerId?: string | undefined,
): PreviewCardOpenChange =>
  openChange(false, 'trigger-press', nextActiveTriggerId)

export const outsideOpenChange = (): PreviewCardOpenChange =>
  openChange(false, 'outside-press')

export const escapeOpenChange = (): PreviewCardOpenChange =>
  openChange(false, 'escape-key')

export const imperativeOpenChange = (): PreviewCardOpenChange =>
  openChange(false, 'imperative-action')

export const disabledOpenChange = (): PreviewCardOpenChange =>
  openChange(false, 'disabled')

export const FocusPreviewCard = Command.define(
  'FocusPreviewCard',
  { selector: S.String },
  CompletedFocusPreviewCard,
)(({ selector }) =>
  Dom.focus(selector, { makeFocusable: true }).pipe(
    Effect.ignore,
    Effect.catchCause(() => Effect.void),
    Effect.as(CompletedFocusPreviewCard()),
  ),
)

export const RestorePreviewCardFocus = Command.define(
  'RestorePreviewCardFocus',
  { selector: S.String },
  CompletedRestorePreviewCardFocus,
)(({ selector }) =>
  Dom.focus(selector).pipe(
    Effect.ignore,
    Effect.catchCause(() => Effect.void),
    Effect.as(CompletedRestorePreviewCardFocus()),
  ),
)

export const commandForOpenChange = (
  config: Pick<PreviewCardOptions, 'id' | 'triggerId' | 'triggerSelector'>,
  change: PreviewCardOpenChange,
): Command.Command<CommandMessage> =>
  change.open
    ? FocusPreviewCard({ selector: previewCardSelector(config.id) })
    : RestorePreviewCardFocus({ selector: triggerSelector(config) })

// VIEW

export type PreviewCardAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  trigger: ReadonlyArray<Attribute<Message>>
  portal: ReadonlyArray<Attribute<Message>>
  positioner: PreviewCardPartAttributes<Message>
  backdrop: PreviewCardPartAttributes<Message>
  popup: PreviewCardPartAttributes<Message>
  viewport: PreviewCardPartAttributes<Message>
  arrow: PreviewCardPartAttributes<Message>
  isMounted: boolean
  isOpen: boolean
}>

export type PreviewCardPartAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type ViewConfig<Message> = PreviewCardOptions &
  Readonly<{
    toView: (attributes: PreviewCardAttributes<Message>) => Html
    onOpenChange?: (change: PreviewCardOpenChange) => Message
  }>

const resolvedSide = (
  config: Pick<PreviewCardOptions, 'side'>,
): PreviewCardSide => config.side ?? defaultSide

const resolvedAlign = (
  config: Pick<PreviewCardOptions, 'align'>,
): PreviewCardAlign => config.align ?? defaultAlign

const resolvedDelay = (config: Pick<PreviewCardOptions, 'delay'>): number =>
  config.delay ?? defaultDelay

const resolvedCloseDelay = (
  config: Pick<PreviewCardOptions, 'closeDelay'>,
): number => config.closeDelay ?? defaultCloseDelay

const mounted = (
  config: Pick<PreviewCardOptions, 'forceMount' | 'open' | 'transitionStatus'>,
): boolean =>
  config.open ||
  config.forceMount === true ||
  config.transitionStatus === 'ending'

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const numberDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: number,
): Attribute<Message> => h.DataAttribute(name, String(value))

const openStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  open: boolean,
): ReadonlyArray<Attribute<Message>> =>
  open ? [h.DataAttribute('open', '')] : [h.DataAttribute('closed', '')]

const transitionDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  transitionStatus: PreviewCardTransitionStatus | undefined,
): ReadonlyArray<Attribute<Message>> => {
  if (transitionStatus === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (transitionStatus === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const instantDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  instant: PreviewCardInstant | undefined,
): ReadonlyArray<Attribute<Message>> =>
  instant === undefined ? [] : [h.DataAttribute('instant', instant)]

const openMessage = <Message>(
  config: ViewConfig<Message>,
  change: PreviewCardOpenChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onOpenChange)
    ? Option.some(config.onOpenChange(change))
    : Option.none()

const optionalMessageAttribute = <Message>(
  message: Option.Option<Message>,
  toAttribute: (message: Message) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(message, {
    onNone: () => [],
    onSome: value => [toAttribute(value)],
  })

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('side', resolvedSide(config)),
  h.DataAttribute('align', resolvedAlign(config)),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
]

const triggerOpenChangeForClick = <Message>(
  config: ViewConfig<Message>,
): Option.Option<Message> => {
  const currentTriggerId = activeTriggerId(config)
  const shouldClose = config.open && currentTriggerId === triggerId(config)
  const change = shouldClose
    ? pressCloseChange(currentTriggerId)
    : pressOpenChange(currentTriggerId)

  return openMessage(config, change)
}

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(triggerId(config)),
  h.Attribute('aria-describedby', popupId(config)),
  h.Style({ anchorName: rootAnchorName(config) }),
  h.DataAttribute('delay', String(resolvedDelay(config))),
  h.DataAttribute('close-delay', String(resolvedCloseDelay(config))),
  ...(config.open && activeTriggerId(config) === triggerId(config)
    ? [h.DataAttribute('popup-open', '')]
    : []),
  ...(config.isDisabled === true
    ? [h.AriaDisabled(true), h.DataAttribute('trigger-disabled', '')]
    : [h.DataAttribute('base-ui-preview-card-trigger', '')]),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, hoverOpenChange(activeTriggerId(config))),
    message => h.OnMouseEnter(message),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, hoverCloseChange(activeTriggerId(config))),
    message => h.OnMouseLeave(message),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, focusOpenChange(activeTriggerId(config))),
    message => h.OnFocus(message),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, focusCloseChange(activeTriggerId(config))),
    message => h.OnBlur(message),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : triggerOpenChangeForClick(config),
    message => h.OnClick(message),
  ),
]

const portalAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
): ReadonlyArray<Attribute<Message>> => [h.DataAttribute('portal', '')]

const placementAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('side', resolvedSide(config)),
  h.DataAttribute('align', resolvedAlign(config)),
  numberDataAttribute(h, 'side-offset', config.sideOffset ?? defaultSideOffset),
  numberDataAttribute(
    h,
    'align-offset',
    config.alignOffset ?? defaultAlignOffset,
  ),
  h.DataAttribute(
    'collision-avoidance',
    String(config.collisionAvoidance ?? defaultCollisionAvoidance),
  ),
  numberDataAttribute(
    h,
    'collision-padding',
    config.collisionPadding ?? defaultCollisionPadding,
  ),
  numberDataAttribute(
    h,
    'arrow-padding',
    config.arrowPadding ?? defaultArrowPadding,
  ),
]

const horizontalAnchorStyle = (
  config: Pick<PreviewCardOptions, 'align'>,
): Readonly<Record<string, string>> => {
  const align = resolvedAlign(config)

  if (align === 'center') {
    return { left: 'anchor(center)', translate: '-50% 0' }
  }

  if (align === 'end') {
    return { left: 'anchor(right)', translate: '-100% 0' }
  }

  return { left: 'anchor(left)' }
}

const verticalAnchorStyle = (
  config: Pick<PreviewCardOptions, 'align'>,
): Readonly<Record<string, string>> => {
  const align = resolvedAlign(config)

  if (align === 'center') {
    return { top: 'anchor(center)', translate: '0 -50%' }
  }

  if (align === 'end') {
    return { top: 'anchor(bottom)', translate: '0 -100%' }
  }

  return { top: 'anchor(top)' }
}

const positionerPlacementStyle = (
  config: Pick<PreviewCardOptions, 'align' | 'side' | 'sideOffset'>,
): Readonly<Record<string, string>> => {
  const sideOffset = `${config.sideOffset ?? defaultSideOffset}px`
  const side = resolvedSide(config)

  if (side === 'top') {
    return {
      ...horizontalAnchorStyle(config),
      bottom: `calc(anchor(top) + ${sideOffset})`,
    }
  }

  if (side === 'left' || side === 'inline-start') {
    return {
      ...verticalAnchorStyle(config),
      right: `calc(anchor(left) + ${sideOffset})`,
    }
  }

  if (side === 'right' || side === 'inline-end') {
    return {
      ...verticalAnchorStyle(config),
      left: `calc(anchor(right) + ${sideOffset})`,
    }
  }

  return {
    ...horizontalAnchorStyle(config),
    top: `calc(anchor(bottom) + ${sideOffset})`,
  }
}

const positionerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): PreviewCardPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(positionerId(config)),
        ...(config.open ? [] : [h.Hidden(true), h.Inert(true)]),
        ...openStateDataAttributes(h, config.open),
        ...booleanDataAttribute(h, 'anchor-hidden', config.isAnchorHidden),
        ...instantDataAttribute(h, config.instant),
        ...placementAttributes(h, config),
        h.Style({
          position: 'absolute',
          positionAnchor: rootAnchorName(config),
          inset: 'auto',
          margin: '0',
          ...positionerPlacementStyle(config),
        }),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const backdropAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): PreviewCardPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Role('presentation'),
        ...(config.open ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, config.open),
        ...transitionDataAttributes(h, config.transitionStatus),
        h.Style({
          pointerEvents: 'none',
          userSelect: 'none',
          WebkitUserSelect: 'none',
        }),
        ...optionalMessageAttribute(
          config.disableOutsidePress === true
            ? Option.none()
            : openMessage(config, outsideOpenChange()),
          message => h.OnClick(message),
        ),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const popupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): PreviewCardPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(popupId(config)),
        h.Tabindex(-1),
        ...(config.open ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, config.open),
        ...transitionDataAttributes(h, config.transitionStatus),
        ...instantDataAttribute(h, config.instant),
        ...placementAttributes(h, config),
        ...optionalMessageAttribute(
          openMessage(config, hoverOpenChange(activeTriggerId(config))),
          message => h.OnMouseEnter(message),
        ),
        ...optionalMessageAttribute(
          openMessage(config, hoverCloseChange(activeTriggerId(config))),
          message => h.OnMouseLeave(message),
        ),
        ...optionalMessageAttribute(
          openMessage(config, escapeOpenChange()),
          message =>
            h.OnKeyDownPreventDefault(key =>
              key === 'Escape' ? Option.some(message) : Option.none(),
            ),
        ),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const viewportAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): PreviewCardPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(viewportId(config)),
        ...instantDataAttribute(h, config.instant),
        ...(config.viewportActivationDirection === undefined
          ? []
          : [
              h.DataAttribute(
                'activation-direction',
                config.viewportActivationDirection,
              ),
            ]),
        ...booleanDataAttribute(
          h,
          'transitioning',
          config.isViewportTransitioning,
        ),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const arrowAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): PreviewCardPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(arrowId(config)),
        h.AriaHidden(true),
        ...openStateDataAttributes(h, config.open),
        ...booleanDataAttribute(h, 'uncentered', config.isArrowUncentered),
        h.DataAttribute('side', resolvedSide(config)),
        h.DataAttribute('align', resolvedAlign(config)),
        h.Style({
          width: `${config.arrowWidth ?? defaultArrowWidth}px`,
          height: `${config.arrowHeight ?? defaultArrowHeight}px`,
        }),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const isMounted = mounted(config)

  return config.toView({
    root: rootAttributes(h, config),
    trigger: triggerAttributes(h, config),
    portal: portalAttributes(h),
    positioner: positionerAttributes(h, config, isMounted),
    backdrop: backdropAttributes(h, config, isMounted),
    popup: popupAttributes(h, config, isMounted),
    viewport: viewportAttributes(h, config, isMounted),
    arrow: arrowAttributes(h, config, isMounted),
    isMounted,
    isOpen: config.open,
  })
}

import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const ProgressStatus = S.Union([
  S.Literal('indeterminate'),
  S.Literal('progressing'),
  S.Literal('complete'),
])
export type ProgressStatus = typeof ProgressStatus.Type

export const ProgressFormatStyle = S.Union([
  S.Literal('decimal'),
  S.Literal('percent'),
  S.Literal('currency'),
])
export type ProgressFormatStyle = typeof ProgressFormatStyle.Type

export const ProgressFormatOptions = S.Struct({
  style: S.optional(ProgressFormatStyle),
  currency: S.optional(S.String),
  minimumFractionDigits: S.optional(S.Number),
  maximumFractionDigits: S.optional(S.Number),
})
export type ProgressFormatOptions = typeof ProgressFormatOptions.Type

export const ProgressOptions = S.Struct({
  value: S.Union([S.Number, S.Null]),
  min: S.optional(S.Number),
  max: S.optional(S.Number),
  locale: S.optional(S.String),
  format: S.optional(ProgressFormatOptions),
  labelId: S.optional(S.String),
})
export type ProgressOptions = typeof ProgressOptions.Type

export const ProgressPart = S.Union([
  S.Literal('root'),
  S.Literal('label'),
  S.Literal('track'),
  S.Literal('indicator'),
  S.Literal('value'),
])
export type ProgressPart = typeof ProgressPart.Type

export type ProgressState = Readonly<{
  status: ProgressStatus
  clampedValue: number | null
  percentage: number | null
  formattedValue: string
  ariaValueText: string
  min: number
  max: number
}>

// UPDATE

const defaultMin = 0
const defaultMax = 100

const clamp = (value: number, min: number, max: number): number =>
  Math.max(min, Math.min(value, max))

const percentageFromValue = (
  value: number,
  min: number,
  max: number,
): number => {
  const rawPercentage = ((value - min) * 100) / (max - min)

  return clamp(Number.isNaN(rawPercentage) ? 0 : rawPercentage, 0, 100)
}

const formatValue = (
  value: number,
  locale: string | undefined,
  format?: ProgressFormatOptions,
): string => {
  const options: Intl.NumberFormatOptions =
    format === undefined ? { style: 'percent' } : format

  return new Intl.NumberFormat(locale, options).format(value)
}

export const progressState = (options: ProgressOptions): ProgressState => {
  const { value, min = defaultMin, max = defaultMax, locale, format } = options

  if (value === null || !Number.isFinite(value)) {
    return {
      status: 'indeterminate',
      clampedValue: null,
      percentage: null,
      formattedValue: '',
      ariaValueText: 'indeterminate progress',
      min,
      max,
    }
  }

  const percentage = percentageFromValue(value, min, max)
  const clampedValue = clamp(value, min, max)
  const formattedValue =
    format === undefined
      ? formatValue(percentage / 100, locale)
      : formatValue(value, locale, format)
  const status = clampedValue === max ? 'complete' : 'progressing'

  return {
    status,
    clampedValue,
    percentage,
    formattedValue,
    ariaValueText: formattedValue,
    min,
    max,
  }
}

// VIEW

export type ProgressAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  label: ReadonlyArray<Attribute<Message>>
  track: ReadonlyArray<Attribute<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
  value: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = ProgressOptions &
  Readonly<{
    toView: (attributes: ProgressAttributes<Message>) => Html
  }>

export const progressStatusAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  status: ProgressStatus,
): ReadonlyArray<Attribute<Message>> => {
  if (status === 'progressing') {
    return [h.DataAttribute('progressing', '')]
  }

  if (status === 'complete') {
    return [h.DataAttribute('complete', '')]
  }

  return [h.DataAttribute('indeterminate', '')]
}

export const indicatorStyle = (
  percentage: number | null,
): Readonly<Record<string, string>> =>
  percentage === null
    ? {}
    : {
        insetInlineStart: '0',
        height: 'inherit',
        width: `${percentage}%`,
      }

export const valueText = (state: ProgressState): string => state.formattedValue

const ariaValueNowAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  value: number | null,
): ReadonlyArray<Attribute<Message>> =>
  value === null ? [] : [h.AriaValuenow(value)]

const ariaLabelledByAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  labelId: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  labelId === undefined ? [] : [h.AriaLabelledBy(labelId)]

const labelIdAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  labelId: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  labelId === undefined ? [] : [h.Id(labelId)]

const styleAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  style: Readonly<Record<string, string>>,
): ReadonlyArray<Attribute<Message>> =>
  Object.keys(style).length === 0 ? [] : [h.Style(style)]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { labelId, toView } = config
  const state = progressState(config)
  const statusAttributes = progressStatusAttributes(h, state.status)

  return toView({
    root: [
      h.Role('progressbar'),
      h.AriaValuemin(state.min),
      h.AriaValuemax(state.max),
      ...ariaValueNowAttribute(h, state.clampedValue),
      h.AriaValuetext(state.ariaValueText),
      ...ariaLabelledByAttribute(h, labelId),
      ...statusAttributes,
    ],
    label: [
      h.Role('presentation'),
      ...labelIdAttribute(h, labelId),
      ...statusAttributes,
    ],
    track: [...statusAttributes],
    indicator: [
      ...statusAttributes,
      ...styleAttribute(h, indicatorStyle(state.percentage)),
    ],
    value: [h.AriaHidden(true), ...statusAttributes],
  })
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html, KeyboardModifiers } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const RadioGroupOrientation = S.Union([
  S.Literal('horizontal'),
  S.Literal('vertical'),
])
export type RadioGroupOrientation = typeof RadioGroupOrientation.Type

export const RadioGroupChangeReason = S.Literal('none')
export type RadioGroupChangeReason = typeof RadioGroupChangeReason.Type

export const RadioGroupValueChange = S.Struct({
  value: S.String,
  reason: RadioGroupChangeReason,
  focusSelector: S.optional(S.String),
})
export type RadioGroupValueChange = typeof RadioGroupValueChange.Type

export const RadioGroupItemDescriptor = S.Struct({
  id: S.optional(S.String),
  value: S.String,
  isDisabled: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
})
export type RadioGroupItemDescriptor = typeof RadioGroupItemDescriptor.Type

export const RadioGroupOptions = S.Struct({
  id: S.optional(S.String),
  name: S.optional(S.String),
  form: S.optional(S.String),
  value: S.optional(S.String),
  orientation: S.optional(RadioGroupOrientation),
  loop: S.optional(S.Boolean),
  items: S.Array(RadioGroupItemDescriptor),
  isDisabled: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
  isRequired: S.optional(S.Boolean),
  isReadOnly: S.optional(S.Boolean),
  isValid: S.optional(S.Boolean),
  isFieldInvalid: S.optional(S.Boolean),
  isDirty: S.optional(S.Boolean),
  isTouched: S.optional(S.Boolean),
  isFilled: S.optional(S.Boolean),
  isFocused: S.optional(S.Boolean),
})
export type RadioGroupOptions = typeof RadioGroupOptions.Type

// UPDATE

export const isChecked = (
  groupValue: string | undefined,
  item: Pick<RadioGroupItemDescriptor, 'value'>,
): boolean => groupValue === item.value

export const checkedState = (
  groupValue: string | undefined,
  item: Pick<RadioGroupItemDescriptor, 'value'>,
): 'checked' | 'unchecked' =>
  isChecked(groupValue, item) ? 'checked' : 'unchecked'

export const valueChange = (
  value: string,
  focusSelector?: string,
): RadioGroupValueChange => ({
  value,
  reason: 'none',
  ...(focusSelector === undefined ? {} : { focusSelector }),
})

export const itemFocusSelector = (
  item: Pick<RadioGroupItemDescriptor, 'id'>,
): string | undefined => (item.id === undefined ? undefined : `#${item.id}`)

// VIEW

export type RadioGroupItemAttributes<Message> = Readonly<{
  item: RadioGroupItemDescriptor
  root: ReadonlyArray<Attribute<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
  input: ReadonlyArray<Attribute<Message>>
}>

export type RadioGroupAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  items: ReadonlyArray<RadioGroupItemAttributes<Message>>
}>

export type ViewConfig<Message> = RadioGroupOptions &
  Readonly<{
    toView: (attributes: RadioGroupAttributes<Message>) => Html
    onValueChange?: (change: RadioGroupValueChange) => Message
    onFocus?: Message
    onBlur?: Message
    keepIndicatorMounted?: boolean
  }>

const visuallyHiddenInputStyle =
  'clip-path: inset(50%); overflow: hidden; white-space: nowrap; border: 0px; padding: 0px; width: 1px; height: 1px; margin: -1px; position: fixed; top: 0px; left: 0px;'

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    RadioGroupOptions,
    | 'isDirty'
    | 'isDisabled'
    | 'isFieldInvalid'
    | 'isFilled'
    | 'isFocused'
    | 'isReadOnly'
    | 'isRequired'
    | 'isTouched'
    | 'isValid'
  >,
): ReadonlyArray<Attribute<Message>> => [
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'valid', config.isValid),
  ...booleanDataAttribute(h, 'invalid', config.isFieldInvalid),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'filled', config.isFilled),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
]

const itemStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    RadioGroupOptions,
    | 'isDirty'
    | 'isDisabled'
    | 'isFieldInvalid'
    | 'isFilled'
    | 'isFocused'
    | 'isReadOnly'
    | 'isRequired'
    | 'isTouched'
    | 'isValid'
    | 'value'
  >,
  item: RadioGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute(checkedState(config.value, item), ''),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled || item.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'valid', config.isValid),
  ...booleanDataAttribute(
    h,
    'invalid',
    config.isFieldInvalid || item.isInvalid,
  ),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'filled', config.isFilled),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
]

const enabledItems = (
  config: Pick<RadioGroupOptions, 'isDisabled' | 'items'>,
): ReadonlyArray<RadioGroupItemDescriptor> =>
  config.isDisabled === true
    ? []
    : config.items.filter(item => item.isDisabled !== true)

const tabbableValue = (
  config: Pick<RadioGroupOptions, 'isDisabled' | 'items' | 'value'>,
): string | undefined => {
  const enabled = enabledItems(config)
  const checkedEnabledItem = enabled.find(item => item.value === config.value)

  return checkedEnabledItem?.value ?? enabled[0]?.value
}

const canActivateItem = (
  config: Pick<RadioGroupOptions, 'isDisabled' | 'isReadOnly'>,
  item: RadioGroupItemDescriptor,
): boolean =>
  config.isDisabled !== true &&
  config.isReadOnly !== true &&
  item.isDisabled !== true

const activationMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'isDisabled' | 'isReadOnly' | 'onValueChange'
  >,
  item: RadioGroupItemDescriptor,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onValueChange) &&
  canActivateItem(config, item)
    ? Option.some(
        config.onValueChange(valueChange(item.value, itemFocusSelector(item))),
      )
    : Option.none()

const nextIndex = (
  currentIndex: number,
  enabled: ReadonlyArray<RadioGroupItemDescriptor>,
  direction: 'next' | 'previous',
  loop: boolean,
): number | undefined => {
  const offset = direction === 'next' ? 1 : -1
  const candidateIndex = currentIndex + offset

  if (candidateIndex >= 0 && candidateIndex < enabled.length) {
    return candidateIndex
  }

  if (!loop) {
    return undefined
  }

  return direction === 'next' ? 0 : enabled.length - 1
}

const rovingItem = (
  config: Pick<RadioGroupOptions, 'isDisabled' | 'items' | 'loop'>,
  item: RadioGroupItemDescriptor,
  direction: 'next' | 'previous',
): RadioGroupItemDescriptor | undefined => {
  const enabled = enabledItems(config)
  const currentIndex = enabled.findIndex(entry => entry.value === item.value)
  const targetIndex =
    currentIndex === -1
      ? undefined
      : nextIndex(currentIndex, enabled, direction, config.loop ?? true)

  return targetIndex === undefined ? undefined : enabled[targetIndex]
}

const horizontalDirection = (
  key: string,
  dir: string | undefined,
): 'next' | 'previous' | undefined => {
  if (key === 'ArrowRight') {
    return dir === 'rtl' ? 'previous' : 'next'
  }

  if (key === 'ArrowLeft') {
    return dir === 'rtl' ? 'next' : 'previous'
  }

  return undefined
}

const arrowDirection = (
  key: string,
  config: Pick<RadioGroupOptions, 'orientation'> & Readonly<{ dir?: string }>,
): 'next' | 'previous' | undefined => {
  if (key === 'ArrowDown') {
    return 'next'
  }

  if (key === 'ArrowUp') {
    return 'previous'
  }

  if (config.orientation === 'vertical') {
    return undefined
  }

  return horizontalDirection(key, config.dir)
}

const rovingMessage = <Message>(
  config: ViewConfig<Message>,
  item: RadioGroupItemDescriptor,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (modifiers.shiftKey) {
    return Option.none()
  }

  const direction = arrowDirection(key, config)

  if (
    direction === undefined ||
    Predicate.isUndefined(config.onValueChange) ||
    !canActivateItem(config, item)
  ) {
    return Option.none()
  }

  const targetItem = rovingItem(config, item, direction)

  return targetItem === undefined
    ? Option.none()
    : Option.some(
        config.onValueChange(
          valueChange(targetItem.value, itemFocusSelector(targetItem)),
        ),
      )
}

const eventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: RadioGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(activationMessage(config, item), {
    onNone: () => [],
    onSome: message => [
      h.OnClick(message),
      h.OnKeyUpPreventDefault(key =>
        key === ' ' ? Option.some(message) : Option.none(),
      ),
      h.OnKeyDownPreventDefault((key, modifiers) =>
        rovingMessage(config, item, key, modifiers),
      ),
    ],
  })

const focusAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'onBlur' | 'onFocus'>,
): ReadonlyArray<Attribute<Message>> => [
  ...(Predicate.isNotUndefined(config.onFocus)
    ? [h.OnFocus(config.onFocus)]
    : []),
  ...(Predicate.isNotUndefined(config.onBlur) ? [h.OnBlur(config.onBlur)] : []),
]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('radiogroup'),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...optionalAttribute<Message>(config.orientation, value =>
    h.AriaOrientation(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.AriaDisabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.AriaReadonly(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.AriaRequired(value),
  ),
  ...(config.isInvalid === true ? [h.AriaInvalid(true)] : []),
  ...stateDataAttributes(h, config),
  ...focusAttributes(h, config),
]

const itemTabIndex = (
  config: Pick<RadioGroupOptions, 'isDisabled' | 'items' | 'value'>,
  item: RadioGroupItemDescriptor,
): number => {
  if (item.isDisabled === true || config.isDisabled === true) {
    return -1
  }

  if (tabbableValue(config) === item.value) {
    return 0
  }

  return -1
}

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: RadioGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('radio'),
  h.AriaChecked(isChecked(config.value, item)),
  h.Tabindex(itemTabIndex(config, item)),
  ...optionalAttribute<Message>(item.id, value => h.Id(value)),
  ...optionalBooleanAttribute<Message>(
    config.isDisabled === true || item.isDisabled === true ? true : undefined,
    value => h.AriaDisabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.AriaReadonly(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.AriaRequired(value),
  ),
  ...(config.isInvalid === true || item.isInvalid === true
    ? [h.AriaInvalid(true)]
    : []),
  ...itemStateDataAttributes(h, config, item),
  ...eventAttributes(h, config, item),
]

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  form: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(form) ? [h.Attribute('form', form)] : []

const inputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: RadioGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('radio'),
  h.AriaHidden(true),
  h.Tabindex(-1),
  h.Checked(isChecked(config.value, item)),
  h.Value(item.value),
  h.Attribute('style', visuallyHiddenInputStyle),
  ...optionalAttribute<Message>(item.id, value =>
    h.Attribute('id', `${value}-input`),
  ),
  ...optionalAttribute<Message>(config.name, value => h.Name(value)),
  ...formOwnerAttributes(h, config.form),
  ...optionalBooleanAttribute<Message>(
    config.isDisabled === true || item.isDisabled === true ? true : undefined,
    value => h.Disabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.Readonly(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.Required(value),
  ),
  ...Option.match(activationMessage(config, item), {
    onNone: () => [],
    onSome: message => [h.OnClick(message)],
  }),
]

const indicatorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: RadioGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> =>
  config.keepIndicatorMounted === true || isChecked(config.value, item)
    ? itemStateDataAttributes(h, config, item)
    : []

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()

  return config.toView({
    root: rootAttributes(h, config),
    items: config.items.map(item => ({
      item,
      root: itemAttributes(h, config, item),
      indicator: indicatorAttributes(h, config, item),
      input: inputAttributes(h, config, item),
    })),
  })
}

import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const ScrollAreaOrientation = S.Union([
  S.Literal('horizontal'),
  S.Literal('vertical'),
])
export type ScrollAreaOrientation = typeof ScrollAreaOrientation.Type

export const ScrollAreaDirection = S.Union([S.Literal('ltr'), S.Literal('rtl')])
export type ScrollAreaDirection = typeof ScrollAreaDirection.Type

export const ScrollAreaSize = S.Struct({
  width: S.Number,
  height: S.Number,
})
export type ScrollAreaSize = typeof ScrollAreaSize.Type

export const ScrollAreaOverflowEdges = S.Struct({
  xStart: S.Boolean,
  xEnd: S.Boolean,
  yStart: S.Boolean,
  yEnd: S.Boolean,
})
export type ScrollAreaOverflowEdges = typeof ScrollAreaOverflowEdges.Type

export const ScrollAreaOverflowMetrics = S.Struct({
  xStart: S.Number,
  xEnd: S.Number,
  yStart: S.Number,
  yEnd: S.Number,
})
export type ScrollAreaOverflowMetrics = typeof ScrollAreaOverflowMetrics.Type

export const ScrollAreaOverflowEdgeThreshold = S.Union([
  S.Number,
  S.Struct({
    xStart: S.optional(S.Number),
    xEnd: S.optional(S.Number),
    yStart: S.optional(S.Number),
    yEnd: S.optional(S.Number),
  }),
])
export type ScrollAreaOverflowEdgeThreshold =
  typeof ScrollAreaOverflowEdgeThreshold.Type

export const ScrollAreaMetrics = S.Struct({
  viewportWidth: S.Number,
  viewportHeight: S.Number,
  contentWidth: S.Number,
  contentHeight: S.Number,
  scrollLeft: S.optional(S.Number),
  scrollTop: S.optional(S.Number),
  dir: S.optional(ScrollAreaDirection),
  overflowEdgeThreshold: S.optional(ScrollAreaOverflowEdgeThreshold),
  verticalTrackHeight: S.optional(S.Number),
  horizontalTrackWidth: S.optional(S.Number),
})
export type ScrollAreaMetrics = typeof ScrollAreaMetrics.Type

export const ScrollAreaStateOptions = S.Struct({
  scrollingX: S.optional(S.Boolean),
  scrollingY: S.optional(S.Boolean),
  isHovering: S.optional(S.Boolean),
  hasOverflowX: S.optional(S.Boolean),
  hasOverflowY: S.optional(S.Boolean),
  overflowXStart: S.optional(S.Boolean),
  overflowXEnd: S.optional(S.Boolean),
  overflowYStart: S.optional(S.Boolean),
  overflowYEnd: S.optional(S.Boolean),
  hasMeasuredScrollbar: S.optional(S.Boolean),
  cornerSize: S.optional(ScrollAreaSize),
  thumbSize: S.optional(ScrollAreaSize),
  overflowMetrics: S.optional(ScrollAreaOverflowMetrics),
})
export type ScrollAreaStateOptions = typeof ScrollAreaStateOptions.Type

export const ScrollAreaScrollbarDescriptor = S.Struct({
  orientation: S.optional(ScrollAreaOrientation),
  keepMounted: S.optional(S.Boolean),
})
export type ScrollAreaScrollbarDescriptor =
  typeof ScrollAreaScrollbarDescriptor.Type

export const ScrollAreaOptions = S.Struct({
  id: S.optional(S.String),
  rootId: S.optional(S.String),
  dir: S.optional(ScrollAreaDirection),
  state: S.optional(ScrollAreaStateOptions),
  scrollbars: S.optional(S.Array(ScrollAreaScrollbarDescriptor)),
})
export type ScrollAreaOptions = typeof ScrollAreaOptions.Type

export type ScrollAreaState = Readonly<{
  scrolling: boolean
  scrollingX: boolean
  scrollingY: boolean
  hovering: boolean
  hasOverflowX: boolean
  hasOverflowY: boolean
  overflowXStart: boolean
  overflowXEnd: boolean
  overflowYStart: boolean
  overflowYEnd: boolean
  cornerHidden: boolean
  hasMeasuredScrollbar: boolean
  cornerSize: ScrollAreaSize
  thumbSize: ScrollAreaSize
  overflowMetrics: ScrollAreaOverflowMetrics
}>

// UPDATE

export const minThumbSize = 16

const emptySize: ScrollAreaSize = { width: 0, height: 0 }
const emptyOverflowMetrics: ScrollAreaOverflowMetrics = {
  xStart: 0,
  xEnd: 0,
  yStart: 0,
  yEnd: 0,
}

const clamp = (value: number, min: number, max: number): number =>
  Math.max(min, Math.min(value, max))

const normalizedThreshold = (
  threshold: ScrollAreaOverflowEdgeThreshold | undefined,
): ScrollAreaOverflowMetrics => {
  if (typeof threshold === 'number') {
    const value = Math.max(0, threshold)

    return {
      xStart: value,
      xEnd: value,
      yStart: value,
      yEnd: value,
    }
  }

  return {
    xStart: Math.max(0, threshold?.xStart ?? 0),
    xEnd: Math.max(0, threshold?.xEnd ?? 0),
    yStart: Math.max(0, threshold?.yStart ?? 0),
    yEnd: Math.max(0, threshold?.yEnd ?? 0),
  }
}

const safeRatio = (viewportSize: number, contentSize: number): number =>
  contentSize <= 0 ? 0 : clamp(viewportSize / contentSize, 0, 1)

const thumbLength = (
  viewportSize: number,
  contentSize: number,
  trackSize: number,
): number =>
  contentSize <= viewportSize
    ? 0
    : Math.max(minThumbSize, trackSize * safeRatio(viewportSize, contentSize))

export const scrollAreaState = (
  options: ScrollAreaStateOptions = {},
): ScrollAreaState => {
  const scrollingX = options.scrollingX ?? false
  const scrollingY = options.scrollingY ?? false
  const hasOverflowX = options.hasOverflowX ?? false
  const hasOverflowY = options.hasOverflowY ?? false

  return {
    scrolling: scrollingX || scrollingY,
    scrollingX,
    scrollingY,
    hovering: options.isHovering ?? false,
    hasOverflowX,
    hasOverflowY,
    overflowXStart: options.overflowXStart ?? false,
    overflowXEnd: options.overflowXEnd ?? hasOverflowX,
    overflowYStart: options.overflowYStart ?? false,
    overflowYEnd: options.overflowYEnd ?? hasOverflowY,
    cornerHidden: !(hasOverflowX && hasOverflowY),
    hasMeasuredScrollbar: options.hasMeasuredScrollbar ?? true,
    cornerSize: options.cornerSize ?? emptySize,
    thumbSize: options.thumbSize ?? emptySize,
    overflowMetrics: options.overflowMetrics ?? emptyOverflowMetrics,
  }
}

export const scrollAreaStateFromMetrics = (
  metrics: ScrollAreaMetrics,
): ScrollAreaState => {
  const dir = metrics.dir ?? 'ltr'
  const scrollLeft = metrics.scrollLeft ?? 0
  const scrollTop = metrics.scrollTop ?? 0
  const maxScrollLeft = Math.max(
    0,
    metrics.contentWidth - metrics.viewportWidth,
  )
  const maxScrollTop = Math.max(
    0,
    metrics.contentHeight - metrics.viewportHeight,
  )
  const hasOverflowX = maxScrollLeft > 0
  const hasOverflowY = maxScrollTop > 0
  const scrollLeftFromStart = hasOverflowX
    ? clamp(dir === 'rtl' ? -scrollLeft : scrollLeft, 0, maxScrollLeft)
    : 0
  const scrollTopFromStart = hasOverflowY
    ? clamp(scrollTop, 0, maxScrollTop)
    : 0
  const overflowMetrics: ScrollAreaOverflowMetrics = {
    xStart: scrollLeftFromStart,
    xEnd: hasOverflowX ? maxScrollLeft - scrollLeftFromStart : 0,
    yStart: scrollTopFromStart,
    yEnd: hasOverflowY ? maxScrollTop - scrollTopFromStart : 0,
  }
  const threshold = normalizedThreshold(metrics.overflowEdgeThreshold)

  return scrollAreaState({
    hasOverflowX,
    hasOverflowY,
    overflowXStart: hasOverflowX && overflowMetrics.xStart > threshold.xStart,
    overflowXEnd: hasOverflowX && overflowMetrics.xEnd > threshold.xEnd,
    overflowYStart: hasOverflowY && overflowMetrics.yStart > threshold.yStart,
    overflowYEnd: hasOverflowY && overflowMetrics.yEnd > threshold.yEnd,
    cornerSize: hasOverflowX && hasOverflowY ? emptySize : emptySize,
    thumbSize: {
      width: thumbLength(
        metrics.viewportWidth,
        metrics.contentWidth,
        metrics.horizontalTrackWidth ?? metrics.viewportWidth,
      ),
      height: thumbLength(
        metrics.viewportHeight,
        metrics.contentHeight,
        metrics.verticalTrackHeight ?? metrics.viewportHeight,
      ),
    },
    overflowMetrics,
  })
}

export const trackPressScrollOffset = (config: {
  readonly orientation: ScrollAreaOrientation
  readonly pointerOffset: number
  readonly thumbSize: number
  readonly trackSize: number
  readonly viewportSize: number
  readonly contentSize: number
  readonly dir?: ScrollAreaDirection
}): number => {
  const maxScroll = Math.max(0, config.contentSize - config.viewportSize)
  const maxThumbOffset = Math.max(0, config.trackSize - config.thumbSize)
  const pointerOffset = clamp(
    config.pointerOffset - config.thumbSize / 2,
    0,
    maxThumbOffset,
  )
  const ratio = maxThumbOffset === 0 ? 0 : pointerOffset / maxThumbOffset
  const scrollOffset = ratio * maxScroll

  return config.orientation === 'horizontal' && config.dir === 'rtl'
    ? -scrollOffset
    : scrollOffset
}

export const thumbDragScrollOffset = (config: {
  readonly startScrollOffset: number
  readonly pointerDelta: number
  readonly thumbSize: number
  readonly trackSize: number
  readonly viewportSize: number
  readonly contentSize: number
  readonly dir?: ScrollAreaDirection
}): number => {
  const maxScroll = Math.max(0, config.contentSize - config.viewportSize)
  const maxThumbOffset = Math.max(0, config.trackSize - config.thumbSize)
  const ratio = maxThumbOffset === 0 ? 0 : config.pointerDelta / maxThumbOffset
  const directionMultiplier = config.dir === 'rtl' ? -1 : 1

  return clamp(
    config.startScrollOffset + ratio * maxScroll * directionMultiplier,
    config.dir === 'rtl' ? -maxScroll : 0,
    config.dir === 'rtl' ? 0 : maxScroll,
  )
}

// VIEW

export type ScrollAreaScrollbarAttributes<Message> = Readonly<{
  orientation: ScrollAreaOrientation
  root: ReadonlyArray<Attribute<Message>>
  thumb: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
}>

type ResolvedScrollAreaScrollbarDescriptor = Readonly<{
  orientation: ScrollAreaOrientation
  keepMounted: boolean
}>

export type ScrollAreaCornerAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
}>

export type ScrollAreaAttributes<Message> = Readonly<{
  state: ScrollAreaState
  root: ReadonlyArray<Attribute<Message>>
  viewport: ReadonlyArray<Attribute<Message>>
  content: ReadonlyArray<Attribute<Message>>
  scrollbars: ReadonlyArray<ScrollAreaScrollbarAttributes<Message>>
  corner: ScrollAreaCornerAttributes<Message>
}>

export type ViewConfig<Message> = ScrollAreaOptions &
  Readonly<{
    metrics?: ScrollAreaMetrics
    children?: ReadonlyArray<Html | string>
    toView: (attributes: ScrollAreaAttributes<Message>) => Html
  }>

const defaultScrollbars: ReadonlyArray<ScrollAreaScrollbarDescriptor> = [
  { orientation: 'vertical' },
]

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === undefined ? [] : [toAttribute(value)]

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean,
): ReadonlyArray<Attribute<Message>> =>
  value ? [h.DataAttribute(name, '')] : []

const overflowDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: ScrollAreaState,
): ReadonlyArray<Attribute<Message>> => [
  ...booleanDataAttribute(h, 'has-overflow-x', state.hasOverflowX),
  ...booleanDataAttribute(h, 'has-overflow-y', state.hasOverflowY),
  ...booleanDataAttribute(h, 'overflow-x-start', state.overflowXStart),
  ...booleanDataAttribute(h, 'overflow-x-end', state.overflowXEnd),
  ...booleanDataAttribute(h, 'overflow-y-start', state.overflowYStart),
  ...booleanDataAttribute(h, 'overflow-y-end', state.overflowYEnd),
]

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: ScrollAreaState,
): ReadonlyArray<Attribute<Message>> => [
  ...booleanDataAttribute(h, 'scrolling', state.scrolling),
  ...overflowDataAttributes(h, state),
]

const scrollDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: ScrollAreaState,
  orientation: ScrollAreaOrientation,
): ReadonlyArray<Attribute<Message>> =>
  booleanDataAttribute(
    h,
    'scrolling',
    orientation === 'horizontal' ? state.scrollingX : state.scrollingY,
  )

const rootStyle = (
  state: ScrollAreaState,
): Readonly<Record<string, string>> => ({
  position: 'relative',
  '--scroll-area-corner-height': `${state.cornerSize.height}px`,
  '--scroll-area-corner-width': `${state.cornerSize.width}px`,
})

const viewportStyle = (
  state: ScrollAreaState,
): Readonly<Record<string, string>> => ({
  overflow: 'scroll',
  '--scroll-area-overflow-x-start': `${state.overflowMetrics.xStart}px`,
  '--scroll-area-overflow-x-end': `${state.overflowMetrics.xEnd}px`,
  '--scroll-area-overflow-y-start': `${state.overflowMetrics.yStart}px`,
  '--scroll-area-overflow-y-end': `${state.overflowMetrics.yEnd}px`,
})

const cssPropertyName = (property: string): string =>
  property.replaceAll(/[A-Z]/gu, match => `-${match.toLowerCase()}`)

const styleText = (style: Readonly<Record<string, string>>): string =>
  Object.entries(style)
    .map(([property, value]) => `${cssPropertyName(property)}: ${value};`)
    .join(' ')

const styleAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  style: Readonly<Record<string, string>>,
): Attribute<Message> => h.Attribute('style', styleText(style))

const scrollbarStyle = (
  state: ScrollAreaState,
  descriptor: ResolvedScrollAreaScrollbarDescriptor,
): Readonly<Record<string, string>> => {
  const visibility =
    state.hasMeasuredScrollbar || descriptor.keepMounted
      ? {}
      : { visibility: 'hidden' }

  if (descriptor.orientation === 'horizontal') {
    return {
      position: 'absolute',
      touchAction: 'none',
      userSelect: 'none',
      insetInlineStart: '0px',
      insetInlineEnd: 'var(--scroll-area-corner-width)',
      bottom: '0px',
      '--scroll-area-thumb-width': `${state.thumbSize.width}px`,
      ...visibility,
    }
  }

  return {
    position: 'absolute',
    touchAction: 'none',
    userSelect: 'none',
    top: '0px',
    bottom: 'var(--scroll-area-corner-height)',
    insetInlineEnd: '0px',
    '--scroll-area-thumb-height': `${state.thumbSize.height}px`,
    ...visibility,
  }
}

const thumbStyle = (
  state: ScrollAreaState,
  orientation: ScrollAreaOrientation,
): Readonly<Record<string, string>> => {
  const visibility = state.hasMeasuredScrollbar ? {} : { visibility: 'hidden' }

  return orientation === 'horizontal'
    ? {
        width: 'var(--scroll-area-thumb-width)',
        transform: 'translate3d(0px, 0px, 0px)',
        ...visibility,
      }
    : {
        height: 'var(--scroll-area-thumb-height)',
        transform: 'translate3d(0px, 0px, 0px)',
        ...visibility,
      }
}

const cornerStyle = (
  state: ScrollAreaState,
): Readonly<Record<string, string>> => ({
  position: 'absolute',
  bottom: '0',
  insetInlineEnd: '0',
  width: `${state.cornerSize.width}px`,
  height: `${state.cornerSize.height}px`,
})

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'id' | 'dir'>,
  state: ScrollAreaState,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('presentation'),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
  styleAttribute(h, rootStyle(state)),
  ...stateDataAttributes(h, state),
]

const viewportAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'rootId'>,
  state: ScrollAreaState,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('presentation'),
  ...(config.rootId === undefined
    ? []
    : [h.Attribute('data-id', `${config.rootId}-viewport`)]),
  h.Attribute(
    'tabindex',
    String(state.hasOverflowX || state.hasOverflowY ? 0 : -1),
  ),
  styleAttribute(h, viewportStyle(state)),
  ...stateDataAttributes(h, state),
]

const contentAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: ScrollAreaState,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('presentation'),
  styleAttribute(h, { minWidth: 'fit-content' }),
  ...stateDataAttributes(h, state),
]

const isScrollbarMounted = (
  state: ScrollAreaState,
  descriptor: ResolvedScrollAreaScrollbarDescriptor,
): boolean =>
  descriptor.keepMounted ||
  (descriptor.orientation === 'horizontal'
    ? state.hasOverflowX
    : state.hasOverflowY)

const scrollbarAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'rootId'>,
  state: ScrollAreaState,
  descriptor: ScrollAreaScrollbarDescriptor,
): ScrollAreaScrollbarAttributes<Message> => {
  const resolvedDescriptor: ResolvedScrollAreaScrollbarDescriptor = {
    orientation: descriptor.orientation ?? 'vertical',
    keepMounted: descriptor.keepMounted ?? false,
  }
  const isMounted = isScrollbarMounted(state, resolvedDescriptor)
  const root = isMounted
    ? [
        ...(config.rootId === undefined
          ? []
          : [h.Attribute('data-id', `${config.rootId}-scrollbar`)]),
        h.DataAttribute('orientation', resolvedDescriptor.orientation),
        ...booleanDataAttribute(h, 'hovering', state.hovering),
        ...scrollDataAttribute(h, state, resolvedDescriptor.orientation),
        ...overflowDataAttributes(h, state),
        styleAttribute(h, scrollbarStyle(state, resolvedDescriptor)),
      ]
    : []
  const thumb = isMounted
    ? [
        h.DataAttribute('orientation', resolvedDescriptor.orientation),
        ...scrollDataAttribute(h, state, resolvedDescriptor.orientation),
        styleAttribute(h, thumbStyle(state, resolvedDescriptor.orientation)),
      ]
    : []

  return {
    orientation: resolvedDescriptor.orientation,
    root,
    thumb,
    isMounted,
  }
}

const cornerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: ScrollAreaState,
): ScrollAreaCornerAttributes<Message> => {
  const isMounted = !state.cornerHidden

  return {
    root: isMounted ? [styleAttribute(h, cornerStyle(state))] : [],
    isMounted,
  }
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const state =
    config.metrics === undefined
      ? scrollAreaState(config.state)
      : scrollAreaStateFromMetrics(config.metrics)
  const scrollbars = (config.scrollbars ?? defaultScrollbars).map(descriptor =>
    scrollbarAttributes(h, config, state, descriptor),
  )

  return config.toView({
    state,
    root: rootAttributes(h, config, state),
    viewport: viewportAttributes(h, config, state),
    content: contentAttributes(h, state),
    scrollbars,
    corner: cornerAttributes(h, state),
  })
}

