// UPDATE

const defaultMin = 0
const defaultMax = 100
const defaultStep = 1
const defaultLargeStep = 10
const defaultMinStepsBetweenValues = 0
const defaultThumbSizePx = 12

const clamp = (value: number, min: number, max: number): number =>
  Math.max(min, Math.min(value, max))

const valueToPercent = (value: number, min: number, max: number): number => {
  const percentage = ((value - min) * 100) / (max - min)

  return clamp(Number.isNaN(percentage) ? 0 : percentage, 0, 100)
}

export const getDecimalPrecision = (value: number): number => {
  if (value === 0) {
    return 0
  }

  if (Math.abs(value) < 1) {
    const parts = value.toExponential().split('e-')
    const mantissaDecimalPart = parts[0]?.split('.')[1]

    return (
      (mantissaDecimalPart === undefined ? 0 : mantissaDecimalPart.length) +
      Number.parseInt(parts[1] ?? '0', 10)
    )
  }

  const [, decimalPart] = value.toString().split('.')

  return decimalPart === undefined ? 0 : decimalPart.length
}

export const roundValueToStep = (
  value: number,
  step: number,
  min: number,
): number => {
  const nearest = Math.round((value - min) / step) * step + min

  return Number(
    nearest.toFixed(
      Math.max(getDecimalPrecision(step), getDecimalPrecision(min)),
    ),
  )
}

const roundedClamp = (value: number, min: number, max: number): number =>
  Number(clamp(value, min, max).toFixed(12))

export const canonicalValues = (
  values: ReadonlyArray<number>,
  min = defaultMin,
  max = defaultMax,
): ReadonlyArray<number> => {
  const safeValues = values.length === 0 ? [min] : values

  return EffectArray.sort(
    safeValues.map(value =>
      Number.isFinite(value) ? clamp(value, min, max) : min,
    ),
    Order.Number,
  )
}

export const valueArrayToPercentages = (
  values: ReadonlyArray<number>,
  min: number,
  max: number,
): ReadonlyArray<number> => values.map(value => valueToPercent(value, min, max))

export const getSliderValue = (
  valueInput: number,
  index: number,
  min: number,
  max: number,
  range: boolean,
  values: ReadonlyArray<number>,
): number | ReadonlyArray<number> => {
  const clampedValue = clamp(valueInput, min, max)

  if (!range) {
    return clampedValue
  }

  return values.map((value, valueIndex) =>
    valueIndex === index
      ? clamp(
          clampedValue,
          values[valueIndex - 1] ?? -Infinity,
          values[valueIndex + 1] ?? Infinity,
        )
      : value,
  )
}

export const validateMinimumDistance = (
  values: number | ReadonlyArray<number>,
  step: number,
  minStepsBetweenValues: number,
): boolean => {
  if (!Array.isArray(values) || values.length < 2) {
    return true
  }

  const minValueDifference = step * minStepsBetweenValues

  return values.every((value, index) => {
    const nextValue = values[index + 1]

    return nextValue === undefined || nextValue - value >= minValueDifference
  })
}

export const getPushedThumbValues = (config: {
  readonly values: ReadonlyArray<number>
  readonly index: number
  readonly nextValue: number
  readonly min: number
  readonly max: number
  readonly step: number
  readonly minStepsBetweenValues: number
  readonly initialValues?: ReadonlyArray<number>
}): ReadonlyArray<number> => {
  const {
    values,
    index,
    nextValue,
    min,
    max,
    step,
    minStepsBetweenValues,
    initialValues,
  } = config

  if (values.length === 0) {
    return []
  }

  const minValueDifference = step * minStepsBetweenValues
  const lastIndex = values.length - 1
  const baseInitialValues = initialValues ?? values
  const firstPass = values.map((value, valueIndex) =>
    valueIndex === index
      ? clamp(
          nextValue,
          min + valueIndex * minValueDifference,
          max - (lastIndex - valueIndex) * minValueDifference,
        )
      : value,
  )
  const forwardPass = firstPass.reduce<ReadonlyArray<number>>(
    (nextValues, _value, valueIndex) => {
      if (valueIndex <= index) {
        return nextValues
      }

      const previousValue = nextValues[valueIndex - 1] ?? min
      const currentValue = nextValues[valueIndex] ?? min
      const minAllowed = previousValue + minValueDifference
      const maxAllowed = max - (lastIndex - valueIndex) * minValueDifference
      const initialValue = baseInitialValues[valueIndex] ?? currentValue
      const pushedCandidate = Math.max(currentValue, minAllowed)
      const candidate =
        initialValue < pushedCandidate
          ? Math.max(initialValue, minAllowed)
          : pushedCandidate

      return nextValues.map((entry, entryIndex) =>
        entryIndex === valueIndex
          ? clamp(candidate, minAllowed, maxAllowed)
          : entry,
      )
    },
    firstPass,
  )
  const backwardIndexes = EffectArray.reverse(
    forwardPass.map((_, valueIndex) => valueIndex),
  )

  return backwardIndexes
    .reduce<ReadonlyArray<number>>((nextValues, valueIndex) => {
      if (valueIndex >= index) {
        return nextValues
      }

      const nextValueAfter = nextValues[valueIndex + 1] ?? max
      const currentValue = nextValues[valueIndex] ?? min
      const maxAllowed = nextValueAfter - minValueDifference
      const minAllowed = min + valueIndex * minValueDifference
      const initialValue = baseInitialValues[valueIndex] ?? currentValue
      const pushedCandidate = Math.min(currentValue, maxAllowed)
      const candidate =
        initialValue > pushedCandidate
          ? Math.min(initialValue, maxAllowed)
          : pushedCandidate

      return nextValues.map((entry, entryIndex) =>
        entryIndex === valueIndex
          ? clamp(candidate, minAllowed, maxAllowed)
          : entry,
      )
    }, forwardPass)
    .map(value => Number(value.toFixed(12)))
}

interface ResolveThumbCollisionConfig {
  readonly behavior: SliderThumbCollisionBehavior
  readonly values: ReadonlyArray<number>
  readonly currentValues?: ReadonlyArray<number> | null
  readonly initialValues?: ReadonlyArray<number> | null
  readonly pressedIndex: number
  readonly nextValue: number
  readonly min: number
  readonly max: number
  readonly step: number
  readonly minStepsBetweenValues: number
}

type ResolveThumbCollisionResult = Readonly<{
  value: number | ReadonlyArray<number>
  thumbIndex: number
  didSwap: boolean
}>

const resolvePushCollision = (
  config: ResolveThumbCollisionConfig,
  activeValues: ReadonlyArray<number>,
): ResolveThumbCollisionResult => ({
  value: getPushedThumbValues({
    values: activeValues,
    index: config.pressedIndex,
    nextValue: config.nextValue,
    min: config.min,
    max: config.max,
    step: config.step,
    minStepsBetweenValues: config.minStepsBetweenValues,
  }),
  thumbIndex: config.pressedIndex,
  didSwap: false,
})

const resolveNoneCollision = (
  config: ResolveThumbCollisionConfig,
  activeValues: ReadonlyArray<number>,
  minValueDifference: number,
): ResolveThumbCollisionResult => {
  const { max, min, nextValue, pressedIndex } = config
  const previousNeighbor = activeValues[pressedIndex - 1]
  const nextNeighbor = activeValues[pressedIndex + 1]
  const lowerBound =
    previousNeighbor === undefined ? min : previousNeighbor + minValueDifference
  const upperBound =
    nextNeighbor === undefined ? max : nextNeighbor - minValueDifference

  return {
    value: activeValues.map((value, index) =>
      index === pressedIndex
        ? roundedClamp(nextValue, lowerBound, upperBound)
        : value,
    ),
    thumbIndex: pressedIndex,
    didSwap: false,
  }
}

const restoredSwapValues = (
  config: ResolveThumbCollisionConfig,
  pushedValues: ReadonlyArray<number>,
  neighborIndex: number,
  pressedValueAfterClamp: number,
  minValueDifference: number,
): ReadonlyArray<number> =>
  neighborIndex >= 0 && neighborIndex < pushedValues.length
    ? pushedValues.map((value, index) => {
        if (index !== neighborIndex) {
          return value
        }

        const previousValue = pushedValues[neighborIndex - 1]
        const nextValueAfter = pushedValues[neighborIndex + 1]
        const neighborLowerBound = Math.max(
          previousValue === undefined
            ? config.min
            : previousValue + minValueDifference,
          config.min + neighborIndex * minValueDifference,
        )
        const neighborUpperBound = Math.min(
          nextValueAfter === undefined
            ? config.max
            : nextValueAfter - minValueDifference,
          config.max -
            (pushedValues.length - 1 - neighborIndex) * minValueDifference,
        )

        return roundedClamp(
          pressedValueAfterClamp,
          neighborLowerBound,
          neighborUpperBound,
        )
      })
    : pushedValues

const resolveSwapCollision = (
  config: ResolveThumbCollisionConfig,
  activeValues: ReadonlyArray<number>,
  baselineValues: ReadonlyArray<number>,
  minValueDifference: number,
): ResolveThumbCollisionResult => {
  const { pressedIndex, nextValue, min, max, step, minStepsBetweenValues } =
    config
  const pressedInitialValue = activeValues[pressedIndex] ?? min
  const previousNeighbor = activeValues[pressedIndex - 1]
  const nextNeighbor = activeValues[pressedIndex + 1]
  const lowerBound =
    previousNeighbor === undefined ? min : previousNeighbor + minValueDifference
  const upperBound =
    nextNeighbor === undefined ? max : nextNeighbor - minValueDifference
  const pressedValueAfterClamp = roundedClamp(nextValue, lowerBound, upperBound)
  const candidateValues = activeValues.map((value, index) =>
    index === pressedIndex ? pressedValueAfterClamp : value,
  )
  const movingForward = nextValue > pressedInitialValue
  const movingBackward = nextValue < pressedInitialValue
  const epsilon = 1e-7
  const shouldSwapForward =
    movingForward &&
    nextNeighbor !== undefined &&
    nextValue >= nextNeighbor - epsilon
  const shouldSwapBackward =
    movingBackward &&
    previousNeighbor !== undefined &&
    nextValue <= previousNeighbor + epsilon

  if (!shouldSwapForward && !shouldSwapBackward) {
    return {
      value: candidateValues,
      thumbIndex: pressedIndex,
      didSwap: false,
    }
  }

  const targetIndex = shouldSwapForward ? pressedIndex + 1 : pressedIndex - 1
  const initialValuesForPush = candidateValues.map((_, index) =>
    index === pressedIndex
      ? pressedValueAfterClamp
      : (baselineValues[index] ?? activeValues[index] ?? min),
  )
  const nextValueForTarget = shouldSwapForward
    ? Math.max(nextValue, candidateValues[targetIndex] ?? min)
    : Math.min(nextValue, candidateValues[targetIndex] ?? max)
  const pushedValues = getPushedThumbValues({
    values: candidateValues,
    index: targetIndex,
    nextValue: nextValueForTarget,
    min,
    max,
    step,
    minStepsBetweenValues,
    initialValues: initialValuesForPush,
  })
  const neighborIndex = shouldSwapForward ? targetIndex - 1 : targetIndex + 1

  return {
    value: restoredSwapValues(
      config,
      pushedValues,
      neighborIndex,
      pressedValueAfterClamp,
      minValueDifference,
    ),
    thumbIndex: targetIndex,
    didSwap: true,
  }
}

export const resolveThumbCollision = (
  config: ResolveThumbCollisionConfig,
): ResolveThumbCollisionResult => {
  const activeValues = config.currentValues ?? config.values
  const baselineValues = config.initialValues ?? config.values

  if (activeValues.length < 2) {
    return { value: config.nextValue, thumbIndex: 0, didSwap: false }
  }

  const minValueDifference = config.step * config.minStepsBetweenValues

  if (config.behavior === 'push') {
    return resolvePushCollision(config, activeValues)
  }

  if (config.behavior === 'swap') {
    return resolveSwapCollision(
      config,
      activeValues,
      baselineValues,
      minValueDifference,
    )
  }

  return resolveNoneCollision(config, activeValues, minValueDifference)
}

const nextNumericValue = (
  thumbValue: number,
  increment: number,
  direction: 1 | -1,
  min: number,
  max: number,
): number => {
  const value =
    direction === 1 ? thumbValue + increment : thumbValue - increment

  return clamp(
    Number(
      value.toFixed(
        Math.max(
          getDecimalPrecision(thumbValue),
          getDecimalPrecision(increment),
          getDecimalPrecision(min),
        ),
      ),
    ),
    min,
    max,
  )
}

const valueChangeFromValue = (
  value: number | ReadonlyArray<number>,
  reason: SliderChangeReason,
  activeThumbIndex: number,
): SliderValueChange => ({
  values: Array.isArray(value) ? [...value] : [value],
  reason,
  activeThumbIndex,
})

const defaultKeyboardModifiers: KeyboardModifiers = {
  altKey: false,
  ctrlKey: false,
  metaKey: false,
  shiftKey: false,
}

export const keyboardValueChange = (
  state: SliderState,
  index: number,
  key: string,
  modifiers: KeyboardModifiers = defaultKeyboardModifiers,
): SliderValueChange | undefined => {
  const thumbValue = state.values[index]

  if (thumbValue === undefined) {
    return undefined
  }

  const roundedValue = roundValueToStep(thumbValue, state.step, state.min)
  const increment = modifiers.shiftKey ? state.largeStep : state.step
  const nextValue = M.value(key).pipe(
    M.when('ArrowUp', () =>
      nextNumericValue(roundedValue, increment, 1, state.min, state.max),
    ),
    M.when('ArrowRight', () =>
      nextNumericValue(
        roundedValue,
        increment,
        state.dir === 'rtl' ? -1 : 1,
        state.min,
        state.max,
      ),
    ),
    M.when('ArrowDown', () =>
      nextNumericValue(roundedValue, increment, -1, state.min, state.max),
    ),
    M.when('ArrowLeft', () =>
      nextNumericValue(
        roundedValue,
        increment,
        state.dir === 'rtl' ? 1 : -1,
        state.min,
        state.max,
      ),
    ),
    M.when('PageUp', () =>
      nextNumericValue(roundedValue, state.largeStep, 1, state.min, state.max),
    ),
    M.when('PageDown', () =>
      nextNumericValue(roundedValue, state.largeStep, -1, state.min, state.max),
    ),
    M.when('End', () =>
      state.isRange && state.values[index + 1] !== undefined
        ? (state.values[index + 1] ?? state.max) -
          state.step * state.minStepsBetweenValues
        : state.max,
    ),
    M.when('Home', () =>
      state.isRange && state.values[index - 1] !== undefined
        ? (state.values[index - 1] ?? state.min) +
          state.step * state.minStepsBetweenValues
        : state.min,
    ),
    M.orElse(() => Number.NaN),
  )

  if (Number.isNaN(nextValue)) {
    return undefined
  }

  const value = getSliderValue(
    nextValue,
    index,
    state.min,
    state.max,
    state.isRange,
    state.values,
  )

  return validateMinimumDistance(value, state.step, state.minStepsBetweenValues)
    ? valueChangeFromValue(value, 'keyboard', index)
    : undefined
}

export const pointerValue = (config: {
  readonly pointer: SliderPointer
  readonly rect: SliderControlRect
  readonly min: number
  readonly max: number
  readonly step: number
  readonly orientation: SliderOrientation
  readonly dir: SliderDirection
}): number => {
  const { pointer, rect, min, max, step, orientation, dir } = config
  const controlSize = orientation === 'vertical' ? rect.height : rect.width
  const valueSize = (() => {
    if (orientation === 'vertical') {
      return rect.bottom - pointer.clientY
    }

    if (dir === 'rtl') {
      return rect.right - pointer.clientX
    }

    return pointer.clientX - rect.left
  })()
  const valueRescaled = clamp(valueSize / controlSize, 0, 1)
  const rawValue = (max - min) * valueRescaled + min

  return clamp(roundValueToStep(rawValue, step, min), min, max)
}

export const closestThumbIndex = (
  values: ReadonlyArray<number>,
  nextValue: number,
): number =>
  values.reduce(
    (closest, value, index) => {
      const distance = Math.abs(value - nextValue)

      return distance <= closest.distance ? { index, distance } : closest
    },
    { index: 0, distance: Number.POSITIVE_INFINITY },
  ).index

export const pointerValueChange = (config: {
  readonly state: SliderState
  readonly pointer: SliderPointer
  readonly rect: SliderControlRect
  readonly activeThumbIndex?: number
  readonly behavior?: SliderThumbCollisionBehavior
  readonly reason?: Extract<SliderChangeReason, 'track-press' | 'drag'>
  readonly initialValues?: ReadonlyArray<number>
}): SliderValueChange => {
  const {
    state,
    pointer,
    rect,
    activeThumbIndex,
    behavior = 'push',
    reason = 'track-press',
    initialValues,
  } = config
  const nextValue = pointerValue({
    pointer,
    rect,
    min: state.min,
    max: state.max,
    step: state.step,
    orientation: state.orientation,
    dir: state.dir,
  })
  const index =
    activeThumbIndex === undefined
      ? closestThumbIndex(state.values, nextValue)
      : activeThumbIndex
  const collision = resolveThumbCollision({
    behavior,
    values: state.values,
    pressedIndex: index,
    nextValue,
    min: state.min,
    max: state.max,
    step: state.step,
    minStepsBetweenValues: state.minStepsBetweenValues,
    ...(initialValues === undefined ? {} : { initialValues }),
  })

  return valueChangeFromValue(collision.value, reason, collision.thumbIndex)
}

const formatValue = (
  value: number,
  locale: string | undefined,
  format: SliderFormatOptions | undefined,
): string => new Intl.NumberFormat(locale, format).format(value)

const inputId = (config: Pick<SliderOptions, 'id'>, index: number): string =>
  `${config.id ?? 'slider'}-input-${index}`

const thumbId = (config: Pick<SliderOptions, 'id'>, index: number): string =>
  `${config.id ?? 'slider'}-thumb-${index}`

const ariaValueText = (
  values: ReadonlyArray<number>,
  formattedValues: ReadonlyArray<string>,
  value: number,
  index: number,
  format: SliderFormatOptions | undefined,
): string | undefined => {
  if (values.length === 2) {
    return `${formattedValues[index] ?? value} ${index === 0 ? 'start' : 'end'} range`
  }

  if (format !== undefined) {
    return formattedValues[index] ?? String(value)
  }

  return undefined
}

export const sliderState = (options: SliderOptions): SliderState => {
  const {
    min = defaultMin,
    max = defaultMax,
    step = defaultStep,
    largeStep = defaultLargeStep,
    minStepsBetweenValues = defaultMinStepsBetweenValues,
    orientation = 'horizontal',
    dir = 'ltr',
    activeThumbIndex = -1,
  } = options
  const values = canonicalValues(options.values, min, max)
  const percentages = valueArrayToPercentages(values, min, max)
  const formattedValues = values.map(value =>
    formatValue(value, options.locale, options.format),
  )

  return {
    values,
    percentages,
    thumbs: values.map((value, index) => ({
      index,
      value,
      percentage: percentages[index] ?? 0,
      isActive: activeThumbIndex === index,
      inputId: inputId(options, index),
      thumbId: thumbId(options, index),
      ariaValueText: ariaValueText(
        values,
        formattedValues,
        value,
        index,
        options.format,
      ),
    })),
    min,
    max,
    step,
    largeStep,
    minStepsBetweenValues,
    orientation,
    dir,
    isRange: values.length > 1,
    activeThumbIndex,
    formattedValues,
    displayValue: formattedValues.join(' – '),
  }
}

// VIEW

export type SliderThumbAttributes<Message> = Readonly<{
  state: SliderThumbState
  root: ReadonlyArray<Attribute<Message>>
  input: ReadonlyArray<Attribute<Message>>
}>

export type SliderAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  label: ReadonlyArray<Attribute<Message>>
  control: ReadonlyArray<Attribute<Message>>
  track: ReadonlyArray<Attribute<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
  value: ReadonlyArray<Attribute<Message>>
  thumbs: ReadonlyArray<SliderThumbAttributes<Message>>
}>

export type ViewConfig<Message> = SliderOptions &
  Readonly<{
    toView: (attributes: SliderAttributes<Message>) => Html
    onValueChange?: (change: SliderValueChange) => Message
    onFocus?: Message
    onBlur?: Message
    controlRect?: SliderControlRect
    thumbCollisionBehavior?: SliderThumbCollisionBehavior
  }>

const visuallyHiddenInputStyle =
  'clip-path: inset(50%); overflow: hidden; white-space: nowrap; border: 0px; padding: 0px; width: 100%; height: 100%; margin: -1px; position: fixed; top: 0px; left: 0px;'

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ViewConfig<Message>,
    | 'isDirty'
    | 'isDisabled'
    | 'isFocused'
    | 'isDragging'
    | 'isTouched'
    | 'isValid'
    | 'orientation'
  >,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('orientation', config.orientation ?? 'horizontal'),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'dragging', config.isDragging),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
  ...(config.isValid === undefined
    ? []
    : [h.DataAttribute(config.isValid ? 'valid' : 'invalid', '')]),
]

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  form: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(form) ? [h.Attribute('form', form)] : []

const focusAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'onBlur' | 'onFocus'>,
): ReadonlyArray<Attribute<Message>> => [
  ...(Predicate.isNotUndefined(config.onFocus)
    ? [h.OnFocus(config.onFocus)]
    : []),
  ...(Predicate.isNotUndefined(config.onBlur) ? [h.OnBlur(config.onBlur)] : []),
]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('group'),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
  ...optionalAttribute<Message>(config.labelId, value =>
    h.AriaLabelledBy(value),
  ),
  ...stateDataAttributes(h, config),
]

const labelAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(config.labelId, value => h.Id(value)),
  ...stateDataAttributes(h, config),
]

const controlPointerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: SliderState,
): ReadonlyArray<Attribute<Message>> => {
  if (
    config.isDisabled === true ||
    config.controlRect === undefined ||
    config.onValueChange === undefined
  ) {
    return []
  }

  const { controlRect, onValueChange } = config

  return [
    h.OnPointerDown(
      (_pointerType, button, _screenX, _screenY, _time, clientX, clientY) =>
        button === 0
          ? Option.some(
              onValueChange(
                pointerValueChange({
                  state,
                  pointer: { clientX, clientY },
                  rect: controlRect,
                  ...(config.thumbCollisionBehavior === undefined
                    ? {}
                    : { behavior: config.thumbCollisionBehavior }),
                }),
              ),
            )
          : Option.none(),
    ),
  ]
}

const controlAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: SliderState,
): ReadonlyArray<Attribute<Message>> => [
  h.Attribute('data-base-ui-slider-control', ''),
  ...stateDataAttributes(h, config),
  ...controlPointerAttributes(h, config, state),
]

const trackAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Style({ position: 'relative' }),
  ...stateDataAttributes(h, config),
]

const cssNumber = (value: number): string => String(Number(value.toFixed(6)))

const edgePosition = (percentage: number, thumbSizePx: number): string =>
  `calc(${cssNumber(percentage)}% + ${cssNumber(
    thumbSizePx / 2 - (thumbSizePx * percentage) / 100,
  )}px)`

const edgeSize = (percentage: number, thumbSizePx: number): string =>
  `calc(${cssNumber(percentage)}% + ${cssNumber(
    -(thumbSizePx * percentage) / 100,
  )}px)`

const startPositionStyle = (
  percentage: number,
  config: Pick<SliderOptions, 'orientation' | 'thumbAlignment' | 'thumbSizePx'>,
): string => {
  if (config.thumbAlignment !== 'edge') {
    return `${percentage}%`
  }

  return edgePosition(percentage, config.thumbSizePx ?? defaultThumbSizePx)
}

export const indicatorStyle = (
  state: SliderState,
  config: Pick<SliderOptions, 'thumbAlignment' | 'thumbSizePx'> = {},
): Readonly<Record<string, string>> => {
  const start = state.percentages[0] ?? 0
  const end = state.percentages.at(-1) ?? start
  const size = state.isRange ? end - start : start
  const startEdge =
    state.orientation === 'vertical' ? 'bottom' : 'insetInlineStart'
  const mainSide = state.orientation === 'vertical' ? 'height' : 'width'
  const crossSide = state.orientation === 'vertical' ? 'width' : 'height'
  const startValue = state.isRange
    ? startPositionStyle(start, { ...config, orientation: state.orientation })
    : '0'
  const sizeValue = (() => {
    if (config.thumbAlignment !== 'edge') {
      return `${size}%`
    }

    if (state.isRange) {
      return edgeSize(size, config.thumbSizePx ?? defaultThumbSizePx)
    }

    return edgePosition(size, config.thumbSizePx ?? defaultThumbSizePx)
  })()

  return {
    position: state.orientation === 'vertical' ? 'absolute' : 'relative',
    [crossSide]: 'inherit',
    [startEdge]: startValue,
    [mainSide]: sizeValue,
  }
}

const indicatorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: SliderState,
): ReadonlyArray<Attribute<Message>> => [
  h.Attribute('data-base-ui-slider-indicator', ''),
  h.Style(indicatorStyle(state, config)),
  ...stateDataAttributes(h, config),
]

const outputForAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  state: SliderState,
): ReadonlyArray<Attribute<Message>> =>
  state.thumbs.length === 0
    ? []
    : [h.Attribute('for', state.thumbs.map(thumb => thumb.inputId).join(' '))]

const valueAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: SliderState,
): ReadonlyArray<Attribute<Message>> => [
  h.Attribute('aria-live', 'off'),
  ...outputForAttribute(h, state),
  ...stateDataAttributes(h, config),
]

const thumbStyle = (
  state: SliderState,
  thumb: SliderThumbState,
  config: Pick<SliderOptions, 'thumbAlignment' | 'thumbSizePx'>,
): Readonly<Record<string, string>> => {
  const startEdge =
    state.orientation === 'vertical' ? 'bottom' : 'insetInlineStart'
  const crossOffsetProperty = state.orientation === 'vertical' ? 'left' : 'top'
  const translateX =
    state.orientation === 'vertical' || state.dir !== 'rtl' ? -50 : 50
  const translateY = state.orientation === 'vertical' ? 50 : -50

  return {
    position: 'absolute',
    [startEdge]: startPositionStyle(thumb.percentage, {
      orientation: state.orientation,
      thumbAlignment: config.thumbAlignment,
      thumbSizePx: config.thumbSizePx,
    }),
    [crossOffsetProperty]: '50%',
    translate: `${translateX}% ${translateY}%`,
    ...(thumb.isActive ? { zIndex: state.isRange ? '2' : '1' } : {}),
  }
}

const inputChangeAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: SliderState,
  thumb: SliderThumbState,
): ReadonlyArray<Attribute<Message>> => {
  if (config.isDisabled === true || config.onValueChange === undefined) {
    return []
  }

  const { onValueChange } = config

  return [
    h.OnChange(value => {
      const valueAsNumber = Number(value)
      const nextValue = getSliderValue(
        valueAsNumber,
        thumb.index,
        state.min,
        state.max,
        state.isRange,
        state.values,
      )

      return onValueChange(
        valueChangeFromValue(nextValue, 'input-change', thumb.index),
      )
    }),
    h.OnKeyDownPreventDefault((key, modifiers) => {
      const change = keyboardValueChange(state, thumb.index, key, modifiers)

      return change === undefined
        ? Option.none()
        : Option.some(onValueChange(change))
    }),
  ]
}

const thumbAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  state: SliderState,
  thumb: SliderThumbState,
): SliderThumbAttributes<Message> => ({
  state: thumb,
  root: [
    h.Id(thumb.thumbId),
    h.DataAttribute('index', String(thumb.index)),
    h.Style(thumbStyle(state, thumb, config)),
    ...stateDataAttributes(h, config),
    ...focusAttributes(h, config),
  ],
  input: [
    h.Type('range'),
    h.Id(thumb.inputId),
    h.AriaOrientation(state.orientation),
    h.AriaValuenow(thumb.value),
    ...(thumb.ariaValueText === undefined
      ? []
      : [h.AriaValuetext(thumb.ariaValueText)]),
    ...optionalAttribute<Message>(config.labelId, value =>
      h.AriaLabelledBy(value),
    ),
    h.Min(String(state.min)),
    h.Max(String(state.max)),
    h.Step(String(state.step)),
    h.Value(String(thumb.value)),
    h.Attribute('style', visuallyHiddenInputStyle),
    ...optionalAttribute<Message>(config.name, value => h.Name(value)),
    ...formOwnerAttributes(h, config.form),
    ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
      h.Disabled(value),
    ),
    ...optionalBooleanAttribute<Message>(config.isRequired, value =>
      h.Required(value),
    ),
    ...(config.isInvalid === true ? [h.AriaInvalid(true)] : []),
    ...inputChangeAttributes(h, config, state, thumb),
  ],
})

export const valueText = (state: SliderState): string => state.displayValue

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const state = sliderState(config)

  return config.toView({
    root: rootAttributes(h, config),
    label: labelAttributes(h, config),
    control: controlAttributes(h, config, state),
    track: trackAttributes(h, config),
    indicator: indicatorAttributes(h, config, state),
    value: valueAttributes(h, config, state),
    thumbs: state.thumbs.map(thumb => thumbAttributes(h, config, state, thumb)),
  })
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const SwitchCheckedState = S.Union([
  S.Literal('checked'),
  S.Literal('unchecked'),
])
export type SwitchCheckedState = typeof SwitchCheckedState.Type

export const SwitchChangeReason = S.Literal('none')
export type SwitchChangeReason = typeof SwitchChangeReason.Type

export const SwitchCheckedChange = S.Struct({
  isChecked: S.Boolean,
  reason: SwitchChangeReason,
})
export type SwitchCheckedChange = typeof SwitchCheckedChange.Type

export const SwitchOptions = S.Struct({
  id: S.optional(S.String),
  name: S.optional(S.String),
  form: S.optional(S.String),
  value: S.optional(S.String),
  uncheckedValue: S.optional(S.String),
  isChecked: S.Boolean,
  isDisabled: S.optional(S.Boolean),
  isInvalid: S.optional(S.Boolean),
  isRequired: S.optional(S.Boolean),
  isReadOnly: S.optional(S.Boolean),
  isValid: S.optional(S.Boolean),
  isFieldInvalid: S.optional(S.Boolean),
  isDirty: S.optional(S.Boolean),
  isTouched: S.optional(S.Boolean),
  isFilled: S.optional(S.Boolean),
  isFocused: S.optional(S.Boolean),
})
export type SwitchOptions = typeof SwitchOptions.Type

// UPDATE

export const checkedState = (
  options: Pick<SwitchOptions, 'isChecked'>,
): SwitchCheckedState => (options.isChecked ? 'checked' : 'unchecked')

export const checkedChange = (isChecked: boolean): SwitchCheckedChange => ({
  isChecked,
  reason: 'none',
})

// VIEW

export type SwitchAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  thumb: ReadonlyArray<Attribute<Message>>
  input: ReadonlyArray<Attribute<Message>>
  uncheckedInput: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = SwitchOptions &
  Readonly<{
    toView: (attributes: SwitchAttributes<Message>) => Html
    onCheckedChange?: (change: SwitchCheckedChange) => Message
    onFocus?: Message
    onBlur?: Message
  }>

const activationKeys = new Set(['Enter', ' '])

const visuallyHiddenInputStyle =
  'clip-path: inset(50%); overflow: hidden; white-space: nowrap; border: 0px; padding: 0px; width: 1px; height: 1px; margin: -1px; position: fixed; top: 0px; left: 0px;'

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const optionalBooleanAttribute = <Message>(
  value: boolean | undefined,
  toAttribute: (value: boolean) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [toAttribute(true)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ViewConfig<Message>,
    | 'isChecked'
    | 'isDirty'
    | 'isDisabled'
    | 'isFieldInvalid'
    | 'isFilled'
    | 'isFocused'
    | 'isReadOnly'
    | 'isRequired'
    | 'isTouched'
    | 'isValid'
  >,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute(checkedState(config), ''),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(h, 'readonly', config.isReadOnly),
  ...booleanDataAttribute(h, 'required', config.isRequired),
  ...booleanDataAttribute(h, 'valid', config.isValid),
  ...booleanDataAttribute(h, 'invalid', config.isFieldInvalid),
  ...booleanDataAttribute(h, 'dirty', config.isDirty),
  ...booleanDataAttribute(h, 'touched', config.isTouched),
  ...booleanDataAttribute(h, 'filled', config.isFilled),
  ...booleanDataAttribute(h, 'focused', config.isFocused),
]

const canActivate = (
  config: Pick<ViewConfig<unknown>, 'isDisabled' | 'isReadOnly'>,
): boolean => config.isDisabled !== true && config.isReadOnly !== true

const activationMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'isChecked' | 'isDisabled' | 'isReadOnly' | 'onCheckedChange'
  >,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onCheckedChange) && canActivate(config)
    ? Option.some(config.onCheckedChange(checkedChange(!config.isChecked)))
    : Option.none()

const eventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(activationMessage(config), {
    onNone: () => [],
    onSome: message => [
      h.OnClick(message),
      h.OnKeyDownPreventDefault(key =>
        activationKeys.has(key) ? Option.some(message) : Option.none(),
      ),
    ],
  })

const focusAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'onBlur' | 'onFocus'>,
): ReadonlyArray<Attribute<Message>> => [
  ...(Predicate.isNotUndefined(config.onFocus)
    ? [h.OnFocus(config.onFocus)]
    : []),
  ...(Predicate.isNotUndefined(config.onBlur) ? [h.OnBlur(config.onBlur)] : []),
]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('switch'),
  h.AriaChecked(config.isChecked),
  h.Tabindex(config.isDisabled === true ? -1 : 0),
  ...(config.isDisabled === true ? [h.AriaDisabled(true)] : []),
  ...optionalBooleanAttribute<Message>(config.isReadOnly, value =>
    h.AriaReadonly(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.AriaRequired(value),
  ),
  ...(config.isInvalid === true ? [h.AriaInvalid(true)] : []),
  ...stateDataAttributes(h, config),
  ...eventAttributes(h, config),
  ...focusAttributes(h, config),
]

const inputValueAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  value: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [h.Value(value)] : []

const formOwnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  form: string | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(form) ? [h.Attribute('form', form)] : []

const inputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('checkbox'),
  h.AriaHidden(true),
  h.Tabindex(-1),
  h.Checked(config.isChecked),
  h.Attribute('style', visuallyHiddenInputStyle),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...optionalAttribute<Message>(config.name, value => h.Name(value)),
  ...formOwnerAttributes(h, config.form),
  ...inputValueAttributes(h, config.value),
  ...optionalBooleanAttribute<Message>(config.isDisabled, value =>
    h.Disabled(value),
  ),
  ...optionalBooleanAttribute<Message>(config.isRequired, value =>
    h.Required(value),
  ),
  ...Option.match(activationMessage(config), {
    onNone: () => [],
    onSome: message => [h.OnClick(message)],
  }),
]

const uncheckedInputAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => {
  if (
    config.isChecked ||
    config.isDisabled === true ||
    config.name === undefined ||
    config.uncheckedValue === undefined
  ) {
    return []
  }

  return [
    h.Type('hidden'),
    h.Name(config.name),
    h.Value(config.uncheckedValue),
    ...formOwnerAttributes(h, config.form),
  ]
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const attributes = stateDataAttributes(h, config)

  return config.toView({
    root: rootAttributes(h, config),
    thumb: attributes,
    input: inputAttributes(h, config),
    uncheckedInput: uncheckedInputAttributes(h, config),
  })
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html, KeyboardModifiers } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const TabsOrientation = S.Union([
  S.Literal('horizontal'),
  S.Literal('vertical'),
])
export type TabsOrientation = typeof TabsOrientation.Type

export const TabsActivationMode = S.Union([
  S.Literal('manual'),
  S.Literal('automatic'),
])
export type TabsActivationMode = typeof TabsActivationMode.Type

export const TabsActivationDirection = S.Union([
  S.Literal('left'),
  S.Literal('right'),
  S.Literal('up'),
  S.Literal('down'),
  S.Literal('none'),
])
export type TabsActivationDirection = typeof TabsActivationDirection.Type

export const TabsChangeReason = S.Literal('none')
export type TabsChangeReason = typeof TabsChangeReason.Type

export const TabsValueChange = S.Struct({
  value: S.String,
  reason: TabsChangeReason,
  activationDirection: TabsActivationDirection,
  focusSelector: S.optional(S.String),
})
export type TabsValueChange = typeof TabsValueChange.Type

export const TabsHighlightChange = S.Struct({
  value: S.String,
  focusSelector: S.optional(S.String),
})
export type TabsHighlightChange = typeof TabsHighlightChange.Type

export const TabsTabDescriptor = S.Struct({
  id: S.optional(S.String),
  value: S.String,
  label: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
})
export type TabsTabDescriptor = typeof TabsTabDescriptor.Type

export const TabsPanelDescriptor = S.Struct({
  id: S.optional(S.String),
  value: S.String,
  label: S.optional(S.String),
  keepMounted: S.optional(S.Boolean),
})
export type TabsPanelDescriptor = typeof TabsPanelDescriptor.Type

export const TabsIndicatorGeometry = S.Struct({
  left: S.Number,
  right: S.Number,
  top: S.Number,
  bottom: S.Number,
  width: S.Number,
  height: S.Number,
})
export type TabsIndicatorGeometry = typeof TabsIndicatorGeometry.Type

export const TabsOptions = S.Struct({
  id: S.optional(S.String),
  value: S.optional(S.String),
  highlightedValue: S.optional(S.String),
  orientation: S.optional(TabsOrientation),
  dir: S.optional(S.String),
  activationMode: S.optional(TabsActivationMode),
  loopFocus: S.optional(S.Boolean),
  activationDirection: S.optional(TabsActivationDirection),
  tabs: S.Array(TabsTabDescriptor),
  panels: S.optional(S.Array(TabsPanelDescriptor)),
  indicatorGeometry: S.optional(TabsIndicatorGeometry),
})
export type TabsOptions = typeof TabsOptions.Type

// UPDATE

export const isActive = (
  selectedValue: string | undefined,
  tab: Pick<TabsTabDescriptor, 'value'>,
): boolean => selectedValue === tab.value

export const valueChange = (
  value: string,
  activationDirection: TabsActivationDirection,
  focusSelector?: string,
): TabsValueChange => ({
  value,
  reason: 'none',
  activationDirection,
  ...(focusSelector === undefined ? {} : { focusSelector }),
})

export const highlightChange = (
  value: string,
  focusSelector?: string,
): TabsHighlightChange => ({
  value,
  ...(focusSelector === undefined ? {} : { focusSelector }),
})

export const tabFocusSelector = (
  tab: Pick<TabsTabDescriptor, 'id'>,
): string | undefined => (tab.id === undefined ? undefined : `#${tab.id}`)

// VIEW

export type TabsTabAttributes<Message> = Readonly<{
  tab: TabsTabDescriptor
  root: ReadonlyArray<Attribute<Message>>
}>

export type TabsPanelAttributes<Message> = Readonly<{
  panel: TabsPanelDescriptor
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isActive: boolean
}>

export type TabsAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  list: ReadonlyArray<Attribute<Message>>
  tabs: ReadonlyArray<TabsTabAttributes<Message>>
  panels: ReadonlyArray<TabsPanelAttributes<Message>>
  indicator: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = TabsOptions &
  Readonly<{
    toView: (attributes: TabsAttributes<Message>) => Html
    onValueChange?: (change: TabsValueChange) => Message
    onHighlightChange?: (change: TabsHighlightChange) => Message
  }>

const defaultOrientation = 'horizontal'
const defaultActivationMode = 'manual'
const defaultActivationDirection = 'none'

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'activationDirection' | 'orientation'>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('orientation', config.orientation ?? defaultOrientation),
  h.DataAttribute(
    'activation-direction',
    config.activationDirection ?? defaultActivationDirection,
  ),
]

const selectedTab = (
  config: Pick<TabsOptions, 'tabs' | 'value'>,
): TabsTabDescriptor | undefined =>
  config.tabs.find(tab => tab.value === config.value && tab.isDisabled !== true)

const firstEnabledTab = (
  config: Pick<TabsOptions, 'tabs'>,
): TabsTabDescriptor | undefined =>
  config.tabs.find(tab => tab.isDisabled !== true)

const tabbableValue = (
  config: Pick<TabsOptions, 'highlightedValue' | 'tabs' | 'value'>,
): string | undefined => {
  const highlightedTab = config.tabs.find(
    tab => tab.value === config.highlightedValue,
  )

  return (
    highlightedTab?.value ??
    selectedTab(config)?.value ??
    firstEnabledTab(config)?.value
  )
}

const panelId = (
  config: Pick<TabsOptions, 'panels' | 'value'>,
  value: string,
): string | undefined =>
  config.panels?.find(panel => panel.value === value)?.id ??
  (config.value === value ? `${value}-panel` : undefined)

const tabId = (
  config: Pick<TabsOptions, 'tabs'>,
  value: string,
): string | undefined => config.tabs.find(tab => tab.value === value)?.id

const activeIndex = (
  tabs: ReadonlyArray<TabsTabDescriptor>,
  value: string,
): number => tabs.findIndex(tab => tab.value === value)

const activationDirection = (
  config: Pick<TabsOptions, 'orientation' | 'tabs'>,
  from: TabsTabDescriptor,
  to: TabsTabDescriptor,
): TabsActivationDirection => {
  const fromIndex = activeIndex(config.tabs, from.value)
  const toIndex = activeIndex(config.tabs, to.value)

  if (fromIndex === -1 || toIndex === -1 || fromIndex === toIndex) {
    return 'none'
  }

  if ((config.orientation ?? defaultOrientation) === 'vertical') {
    return toIndex > fromIndex ? 'down' : 'up'
  }

  return toIndex > fromIndex ? 'right' : 'left'
}

const nextIndex = (
  currentIndex: number,
  tabs: ReadonlyArray<TabsTabDescriptor>,
  direction: 'next' | 'previous',
  loopFocus: boolean,
): number | undefined => {
  const offset = direction === 'next' ? 1 : -1
  const candidateIndex = currentIndex + offset

  if (candidateIndex >= 0 && candidateIndex < tabs.length) {
    return candidateIndex
  }

  if (!loopFocus) {
    return undefined
  }

  return direction === 'next' ? 0 : tabs.length - 1
}

const horizontalDirection = (
  key: string,
  dir: string | undefined,
): 'next' | 'previous' | undefined => {
  if (key === 'ArrowRight') {
    return dir === 'rtl' ? 'previous' : 'next'
  }

  if (key === 'ArrowLeft') {
    return dir === 'rtl' ? 'next' : 'previous'
  }

  return undefined
}

const verticalDirection = (key: string): 'next' | 'previous' | undefined => {
  if (key === 'ArrowDown') {
    return 'next'
  }

  if (key === 'ArrowUp') {
    return 'previous'
  }

  return undefined
}

const arrowDirection = (
  key: string,
  config: Pick<TabsOptions, 'dir' | 'orientation'>,
): 'next' | 'previous' | undefined =>
  (config.orientation ?? defaultOrientation) === 'vertical'
    ? verticalDirection(key)
    : horizontalDirection(key, config.dir)

const rovingTab = (
  config: Pick<TabsOptions, 'dir' | 'loopFocus' | 'orientation' | 'tabs'>,
  tab: TabsTabDescriptor,
  key: string,
): TabsTabDescriptor | undefined => {
  const currentIndex = config.tabs.findIndex(entry => entry.value === tab.value)

  if (key === 'Home') {
    return config.tabs[0]
  }

  if (key === 'End') {
    return config.tabs.at(-1)
  }

  const direction = arrowDirection(key, config)
  const targetIndex =
    direction === undefined || currentIndex === -1
      ? undefined
      : nextIndex(
          currentIndex,
          config.tabs,
          direction,
          config.loopFocus ?? true,
        )

  return targetIndex === undefined ? undefined : config.tabs[targetIndex]
}

const canActivateTab = (tab: TabsTabDescriptor): boolean =>
  tab.isDisabled !== true

const selectionMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'onValueChange' | 'orientation' | 'tabs' | 'value'
  >,
  from: TabsTabDescriptor,
  to: TabsTabDescriptor,
): Option.Option<Message> => {
  const fromTab = selectedTab(config) ?? from

  return Predicate.isNotUndefined(config.onValueChange) && canActivateTab(to)
    ? Option.some(
        config.onValueChange(
          valueChange(
            to.value,
            activationDirection(config, fromTab, to),
            tabFocusSelector(to),
          ),
        ),
      )
    : Option.none()
}

const highlightMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onHighlightChange'>,
  tab: TabsTabDescriptor,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onHighlightChange)
    ? Option.some(
        config.onHighlightChange(
          highlightChange(tab.value, tabFocusSelector(tab)),
        ),
      )
    : Option.none()

const hasKeyboardModifier = (modifiers: KeyboardModifiers): boolean =>
  modifiers.altKey ||
  modifiers.ctrlKey ||
  modifiers.metaKey ||
  modifiers.shiftKey

const rovingMessage = <Message>(
  config: ViewConfig<Message>,
  tab: TabsTabDescriptor,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (hasKeyboardModifier(modifiers)) {
    return Option.none()
  }

  const targetTab = rovingTab(config, tab, key)

  if (targetTab === undefined) {
    return Option.none()
  }

  return (config.activationMode ?? defaultActivationMode) === 'automatic' &&
    canActivateTab(targetTab)
    ? selectionMessage(config, tab, targetTab)
    : highlightMessage(config, targetTab)
}

const keyActivationMessage = <Message>(
  config: ViewConfig<Message>,
  tab: TabsTabDescriptor,
  key: string,
): Option.Option<Message> =>
  key === ' ' || key === 'Enter'
    ? selectionMessage(config, tab, tab)
    : Option.none()

const clickAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  tab: TabsTabDescriptor,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(selectionMessage(config, tab, tab), {
    onNone: () => [],
    onSome: message => [h.OnClick(message)],
  })

const keyboardAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  tab: TabsTabDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.OnKeyDownPreventDefault((key, modifiers) =>
    keyActivationMessage(config, tab, key).pipe(
      Option.orElse(() => rovingMessage(config, tab, key, modifiers)),
    ),
  ),
]

const focusAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  tab: TabsTabDescriptor,
): ReadonlyArray<Attribute<Message>> => {
  if (isActive(config.value, tab)) {
    return []
  }

  const maybeMessage =
    (config.activationMode ?? defaultActivationMode) === 'automatic' &&
    canActivateTab(tab)
      ? selectionMessage(config, tab, tab)
      : highlightMessage(config, tab)

  return Option.match(maybeMessage, {
    onNone: () => [],
    onSome: message => [h.OnFocus(message)],
  })
}

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...stateDataAttributes(h, config),
]

const listAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('tablist'),
  ...((config.orientation ?? defaultOrientation) === 'vertical'
    ? [h.AriaOrientation('vertical')]
    : []),
  ...stateDataAttributes(h, config),
]

const tabAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  tab: TabsTabDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('tab'),
  h.Type('button'),
  h.AriaSelected(isActive(config.value, tab)),
  h.Tabindex(tabbableValue(config) === tab.value ? 0 : -1),
  ...optionalAttribute<Message>(tab.id, value => h.Id(value)),
  ...optionalAttribute<Message>(panelId(config, tab.value), value =>
    h.AriaControls(value),
  ),
  ...booleanDataAttribute(h, 'active', isActive(config.value, tab)),
  ...booleanDataAttribute(h, 'disabled', tab.isDisabled),
  ...(tab.isDisabled === true ? [h.AriaDisabled(true)] : []),
  ...stateDataAttributes(h, config),
  ...clickAttributes(h, config, tab),
  ...keyboardAttributes(h, config, tab),
  ...focusAttributes(h, config, tab),
]

const panelAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  panel: TabsPanelDescriptor,
  index: number,
): TabsPanelAttributes<Message> => {
  const panelIsActive = config.value === panel.value
  const isMounted = panel.keepMounted === true || panelIsActive
  const attrs: ReadonlyArray<Attribute<Message>> = [
    h.Role('tabpanel'),
    h.Tabindex(panelIsActive ? 0 : -1),
    h.Attribute('data-index', String(index)),
    ...optionalAttribute<Message>(panel.id, value => h.Id(value)),
    ...optionalAttribute<Message>(tabId(config, panel.value), value =>
      h.AriaLabelledBy(value),
    ),
    ...(panelIsActive ? [] : [h.Hidden(true), h.Inert(true)]),
    ...booleanDataAttribute(h, 'hidden', panelIsActive ? undefined : true),
    ...stateDataAttributes(h, config),
  ]

  return {
    panel,
    root: isMounted ? attrs : [],
    isMounted,
    isActive: panelIsActive,
  }
}

const indicatorStyle = (
  geometry: TabsIndicatorGeometry | undefined,
): Record<string, string> =>
  geometry === undefined
    ? {}
    : {
        '--active-tab-left': `${geometry.left}px`,
        '--active-tab-right': `${geometry.right}px`,
        '--active-tab-top': `${geometry.top}px`,
        '--active-tab-bottom': `${geometry.bottom}px`,
        '--active-tab-width': `${geometry.width}px`,
        '--active-tab-height': `${geometry.height}px`,
      }

const indicatorAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> =>
  config.value === undefined
    ? []
    : [
        h.Role('presentation'),
        h.Hidden(config.indicatorGeometry === undefined),
        h.Style(indicatorStyle(config.indicatorGeometry)),
        ...stateDataAttributes(h, config),
      ]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const panels = config.panels ?? []

  return config.toView({
    root: rootAttributes(h, config),
    list: listAttributes(h, config),
    tabs: config.tabs.map(tab => ({
      tab,
      root: tabAttributes(h, config, tab),
    })),
    panels: panels.map((panel, index) =>
      panelAttributes(h, config, panel, index),
    ),
    indicator: indicatorAttributes(h, config),
  })
}

import {
  Array as EffectArray,
  Match as M,
  Option,
  Predicate,
  Schema as S,
} from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'
import { ts } from 'foldkit/schema'

// MODEL

export const ToastPriority = S.Union([S.Literal('low'), S.Literal('high')])
export type ToastPriority = typeof ToastPriority.Type

export const ToastTransitionStatus = S.Union([
  S.Literal('idle'),
  S.Literal('starting'),
  S.Literal('ending'),
])
export type ToastTransitionStatus = typeof ToastTransitionStatus.Type

export const ToastSide = S.Union([
  S.Literal('bottom'),
  S.Literal('top'),
  S.Literal('right'),
  S.Literal('left'),
  S.Literal('inline-start'),
  S.Literal('inline-end'),
])
export type ToastSide = typeof ToastSide.Type

export const ToastAlign = S.Union([
  S.Literal('start'),
  S.Literal('center'),
  S.Literal('end'),
])
export type ToastAlign = typeof ToastAlign.Type

export const ToastViewportPosition = S.Union([
  S.Literal('top-left'),
  S.Literal('top-center'),
  S.Literal('top-right'),
  S.Literal('bottom-left'),
  S.Literal('bottom-center'),
  S.Literal('bottom-right'),
])
export type ToastViewportPosition = typeof ToastViewportPosition.Type

export const ToastViewportPositioning = S.Union([
  S.Literal('fixed'),
  S.Literal('absolute'),
])
export type ToastViewportPositioning = typeof ToastViewportPositioning.Type

export const ToastSwipeDirection = S.Union([
  S.Literal('up'),
  S.Literal('down'),
  S.Literal('left'),
  S.Literal('right'),
])
export type ToastSwipeDirection = typeof ToastSwipeDirection.Type

export const ToastStackingStrategy = S.Union([
  S.Literal('base-ui-shuffle'),
  S.Literal('foldkit-push'),
])
export type ToastStackingStrategy = typeof ToastStackingStrategy.Type

export const ToastSwipeStatus = S.Union([
  S.Literal('idle'),
  S.Literal('swiping'),
  S.Literal('dismissed'),
