export type ToastUpdateOptions = Partial<
  Pick<
    ToastItem,
    | 'actionLabel'
    | 'description'
    | 'duration'
    | 'height'
    | 'position'
    | 'priority'
    | 'promiseState'
    | 'remainingDuration'
    | 'swipe'
    | 'timerStatus'
    | 'title'
