// UPDATE

const defaultDuration = 5000
const defaultLimit = 3
const defaultSide: ToastSide = 'top'
const defaultAlign: ToastAlign = 'center'
const defaultSideOffset = 0
const defaultAlignOffset = 0
const defaultCollisionAvoidance = true
const defaultCollisionPadding = 5
const defaultArrowPadding = 5
const defaultArrowWidth = 10
const defaultArrowHeight = 5
const defaultViewportPosition: ToastViewportPosition = 'bottom-right'

const activeToast = (toast: ToastItem): boolean =>
  toast.transitionStatus !== 'ending'

const activeCountBefore = (
  toasts: ReadonlyArray<ToastItem>,
  index: number,
): number => toasts.slice(0, index).filter(activeToast).length

const offsetBefore = (
  toasts: ReadonlyArray<ToastItem>,
  index: number,
): number =>
  toasts
    .slice(0, index)
    .reduce((offset, toast) => offset + (toast.height ?? 0), 0)

const applyLimited = (
  toasts: ReadonlyArray<ToastItem>,
  limit: number,
): ReadonlyArray<ToastItem> =>
  toasts.map((toast, index) => {
    if (!activeToast(toast)) {
      return toast
    }

    const limited = activeCountBefore(toasts, index) >= limit

    return toast.limited === limited ? toast : { ...toast, limited }
  })

const withToasts = (
  state: ToastState,
  toasts: ReadonlyArray<ToastItem>,
): ToastState => ({
  ...state,
  toasts: applyLimited(toasts, state.limit),
})

const generatedToastId = (state: Pick<ToastState, 'nextId'>): string =>
  `toast-${state.nextId}`

const resolvedTimeout = (
  options: Readonly<{
    duration?: number | undefined
    timeout?: number | undefined
  }>,
): number | undefined => options.timeout ?? options.duration

const timerStatusForToast = (
  state: Pick<
    ToastState,
    'isFocused' | 'isHovered' | 'isWindowFocused' | 'timersPaused'
  >,
  toast: Pick<ToastItem, 'duration' | 'type'>,
): ToastTimerStatus => {
  const duration = toast.duration ?? defaultDuration

  if (toast.type === 'loading' || duration <= 0) {
    return 'idle'
  }

  return state.timersPaused ||
    state.isHovered ||
    state.isFocused ||
    !state.isWindowFocused
    ? 'paused'
    : 'running'
}

const newToast = (
  state: ToastState,
  id: string,
  options: ToastAddOptions,
): ToastItem => {
  const duration = resolvedTimeout(options) ?? state.defaultDuration
  const timerStatus = timerStatusForToast(state, {
    duration,
    type: options.type,
  })

  return {
    id,
    ...(options.title === undefined ? {} : { title: options.title }),
    ...(options.description === undefined
      ? {}
      : { description: options.description }),
    ...(options.type === undefined ? {} : { type: options.type }),
    ...(options.priority === undefined ? {} : { priority: options.priority }),
    duration,
    remainingDuration: duration,
    ...(options.height === undefined ? {} : { height: options.height }),
    timerStatus,
    transitionStatus: 'starting',
    updateKey: 0,
    ...(options.actionLabel === undefined
      ? {}
      : { actionLabel: options.actionLabel }),
    ...(options.position === undefined ? {} : { position: options.position }),
    ...(options.promiseState === undefined
      ? {}
      : { promiseState: options.promiseState }),
  }
}

export const createToastState = (
  options: ToastStateOptions = {},
): ToastState => {
  const state = {
    toasts: options.toasts ?? [],
    limit: options.limit ?? defaultLimit,
    defaultDuration:
      options.timeout ?? options.defaultDuration ?? defaultDuration,
    isHovered: options.isHovered ?? false,
    isFocused: options.isFocused ?? false,
    isWindowFocused: options.isWindowFocused ?? true,
    timersPaused: options.timersPaused ?? false,
    nextId: options.nextId ?? 1,
  }

  return withToasts(state, state.toasts)
}

export const toastMetadata = (
  state: Pick<ToastState, 'toasts'>,
): ReadonlyArray<ToastMetadata> =>
  state.toasts.map((toast, domIndex) => ({
    id: toast.id,
    domIndex,
    visibleIndex: activeToast(toast)
      ? activeCountBefore(state.toasts, domIndex)
      : -1,
    offsetY: offsetBefore(state.toasts, domIndex),
  }))

export const metadataForToast = (
  state: Pick<ToastState, 'toasts'>,
  id: string,
): ToastMetadata | undefined =>
  toastMetadata(state).find(metadata => metadata.id === id)

export const isExpanded = (
  state: Pick<ToastState, 'isFocused' | 'isHovered'>,
): boolean => state.isHovered || state.isFocused

export const updateToast = (
  state: ToastState,
  id: string,
  updates: ToastUpdateOptions,
): ToastState => {
  const existing = state.toasts.find(toast => toast.id === id)

  if (existing === undefined || !activeToast(existing)) {
    return state
  }

  const { timeout: _timeout, ...toastUpdates } = updates
  const nextTimeout = resolvedTimeout(updates)
  const nextToast = {
    ...existing,
    ...toastUpdates,
    ...(nextTimeout === undefined
      ? {}
      : { duration: nextTimeout, remainingDuration: nextTimeout }),
    updateKey: (existing.updateKey ?? 0) + 1,
  }

  const nextTimerStatus = timerStatusForToast(state, nextToast)
  const withTimer = {
    ...nextToast,
    timerStatus: updates.timerStatus ?? nextTimerStatus,
  }

  return withToasts(
    state,
    state.toasts.map(toast => (toast.id === id ? withTimer : toast)),
  )
}

export const addToast = (
  state: ToastState,
  options: ToastAddOptions,
): ToastStateChange => {
  const id = options.id ?? generatedToastId(state)
  const existing = state.toasts.find(toast => toast.id === id)
  const nextId = options.id === undefined ? state.nextId + 1 : state.nextId

  if (existing !== undefined && activeToast(existing)) {
    const nextTimeout = resolvedTimeout(options)

    return {
      id,
      state: updateToast({ ...state, nextId }, id, {
        ...(options.title === undefined ? {} : { title: options.title }),
        ...(options.description === undefined
          ? {}
          : { description: options.description }),
        ...(options.type === undefined ? {} : { type: options.type }),
        ...(options.priority === undefined
          ? {}
          : { priority: options.priority }),
        ...(nextTimeout === undefined
          ? {}
          : {
              duration: nextTimeout,
              remainingDuration: nextTimeout,
            }),
        ...(options.actionLabel === undefined
          ? {}
          : { actionLabel: options.actionLabel }),
        ...(options.position === undefined
          ? {}
          : { position: options.position }),
        ...(options.promiseState === undefined
          ? {}
          : { promiseState: options.promiseState }),
      }),
    }
  }

  const withoutEndingDuplicate = state.toasts.filter(
    toast => toast.id !== id || activeToast(toast),
  )

  return {
    id,
    state: withToasts({ ...state, nextId }, [
      newToast(state, id, options),
      ...withoutEndingDuplicate,
    ]),
  }
}

export const closeRequest = (
  id: string | undefined,
  reason: ToastCloseReason,
): ToastCloseRequest => ({
  ...(id === undefined ? {} : { id }),
  reason,
})

export const closeToast = (
  state: ToastState,
  request: ToastCloseRequest,
): ToastState => {
  const closeAll = request.id === undefined
  const endingTransitionStatus: ToastTransitionStatus = 'ending'
  const idleTimerStatus: ToastTimerStatus = 'idle'
  const toasts = state.toasts.map(toast => {
    if (!closeAll && toast.id !== request.id) {
      return toast
    }

    if (!activeToast(toast)) {
      return toast
    }

    return {
      ...toast,
      transitionStatus: endingTransitionStatus,
      height: 0,
      timerStatus: idleTimerStatus,
    }
  })
  const hasActiveToasts = toasts.some(activeToast)

  return withToasts(
    {
      ...state,
      isHovered: hasActiveToasts ? state.isHovered : false,
      isFocused: hasActiveToasts ? state.isFocused : false,
      timersPaused: hasActiveToasts ? state.timersPaused : false,
    },
    toasts,
  )
}

export const timeoutToast = (state: ToastState, id: string): ToastState =>
  closeToast(state, closeRequest(id, 'timeout'))

export const removeToast = (state: ToastState, id: string): ToastState =>
  withToasts(
    state,
    state.toasts.filter(toast => toast.id !== id),
  )

export const pauseToasts = (state: ToastState): ToastState => ({
  ...state,
  timersPaused: true,
  toasts: state.toasts.map(toast =>
    activeToast(toast) && toast.timerStatus === 'running'
      ? { ...toast, timerStatus: 'paused' }
      : toast,
  ),
})

export const resumeToasts = (state: ToastState): ToastState => ({
  ...state,
  timersPaused: false,
  toasts: state.toasts.map(toast =>
    activeToast(toast) && toast.timerStatus === 'paused'
      ? {
          ...toast,
          timerStatus: timerStatusForToast(
            { ...state, timersPaused: false },
            toast,
          ),
        }
      : toast,
  ),
})

export const applyViewportInteraction = (
  state: ToastState,
  interaction: ToastViewportInteraction,
): ToastState =>
  M.value(interaction.type).pipe(
    M.when('hover-start', () => pauseToasts({ ...state, isHovered: true })),
    M.when('hover-end', () => resumeToasts({ ...state, isHovered: false })),
    M.when('focus-start', () => pauseToasts({ ...state, isFocused: true })),
    M.when('focus-end', () => resumeToasts({ ...state, isFocused: false })),
    M.when('touch-start', () => pauseToasts(state)),
    M.when('touch-end', () => resumeToasts(state)),
    M.when('window-blur', () =>
      pauseToasts({ ...state, isWindowFocused: false }),
    ),
    M.when('window-focus', () =>
      resumeToasts({ ...state, isWindowFocused: true }),
    ),
    M.exhaustive,
  )

export const startPromiseToast = (
  state: ToastState,
  options: Readonly<{
    id?: string
    loading: string
  }>,
): ToastStateChange =>
  addToast(state, {
    ...(options.id === undefined ? {} : { id: options.id }),
    description: options.loading,
    type: 'loading',
    timeout: 0,
    promiseState: ToastPromiseLoading({ label: options.loading }),
  })

const promiseUpdates = (result: ToastPromiseState): ToastUpdateOptions =>
  M.value(result).pipe(
    M.tagsExhaustive({
      ToastPromiseLoading: ({ label }) => ({
        description: label,
        timeout: 0,
        promiseState: result,
        type: 'loading',
      }),
      ToastPromiseSucceeded: ({ description, duration, timeout, title }) => {
        const nextTimeout = resolvedTimeout({ duration, timeout })

        return {
          ...(title === undefined ? {} : { title }),
          ...(description === undefined ? {} : { description }),
          ...(nextTimeout === undefined ? {} : { timeout: nextTimeout }),
          transitionStatus: undefined,
          promiseState: result,
          type: 'success',
        }
      },
      ToastPromiseFailed: ({ description, duration, timeout, title }) => {
        const nextTimeout = resolvedTimeout({ duration, timeout })

        return {
          ...(title === undefined ? {} : { title }),
          ...(description === undefined ? {} : { description }),
          ...(nextTimeout === undefined ? {} : { timeout: nextTimeout }),
          transitionStatus: undefined,
          promiseState: result,
          type: 'error',
        }
      },
    }),
  )

export const resolvePromiseToast = (
  state: ToastState,
  id: string,
  result: ToastPromiseState,
): ToastState => updateToast(state, id, promiseUpdates(result))

export const updateSwipe = (
  state: ToastState,
  change: ToastSwipeChange,
): ToastState => {
  const status: ToastSwipeStatus =
    change.phase === 'end' ? 'dismissed' : 'swiping'
  const swipe = {
    status,
    pointerType: change.pointerType,
    movementX: change.x,
    movementY: change.y,
  }

  return updateToast(state, change.id, {
    swipe,
  })
}

// VIEW

export type ToastPartAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
}>

export type ToastItemAttributes<Message> = Readonly<{
  toast: ToastItem
  metadata: ToastMetadata
  root: ReadonlyArray<Attribute<Message>>
  content: ReadonlyArray<Attribute<Message>>
  title: ReadonlyArray<Attribute<Message>>
  description: ReadonlyArray<Attribute<Message>>
  action: ReadonlyArray<Attribute<Message>>
  close: ReadonlyArray<Attribute<Message>>
  positioner: ToastPartAttributes<Message>
  arrow: ToastPartAttributes<Message>
  isOpen: boolean
  isMounted: boolean
}>

export type ToastAnnouncementAttributes<Message> = Readonly<{
  toast: ToastItem
  root: ReadonlyArray<Attribute<Message>>
  title: ReadonlyArray<Attribute<Message>>
  description: ReadonlyArray<Attribute<Message>>
}>

export type ToastAttributes<Message> = Readonly<{
  provider: ReadonlyArray<Attribute<Message>>
  portal: ReadonlyArray<Attribute<Message>>
  viewport: ToastPartAttributes<Message>
  toasts: ReadonlyArray<ToastItemAttributes<Message>>
  highPriorityAnnouncements: ReadonlyArray<ToastAnnouncementAttributes<Message>>
  isExpanded: boolean
  isEmpty: boolean
}>

export type ViewConfig<Message> = Readonly<{
  id: string
  state: ToastState
  label?: string
  forceMount?: boolean
  stackingStrategy?: ToastStackingStrategy
  viewportPosition?: ToastViewportPosition
  viewportPositioning?: ToastViewportPositioning
  swipeDirections?: ReadonlyArray<ToastSwipeDirection>
  toView: (attributes: ToastAttributes<Message>) => Html
  onAction?: (press: ToastActionPress) => Message
  onClose?: (request: ToastCloseRequest) => Message
  onSwipeChange?: (change: ToastSwipeChange) => Message
  onViewportInteraction?: (interaction: ToastViewportInteraction) => Message
}>

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const typeDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  toast: Pick<ToastItem, 'type'>,
): ReadonlyArray<Attribute<Message>> =>
  toast.type === undefined ? [] : [h.DataAttribute('type', toast.type)]

const optionalMessageAttribute = <Message>(
  message: Option.Option<Message>,
  toAttribute: (message: Message) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(message, {
    onNone: () => [],
    onSome: value => [toAttribute(value)],
  })

const viewportId = (config: Pick<ViewConfig<unknown>, 'id'>): string =>
  `${config.id}-viewport`

export const rootId = (
  config: Pick<ViewConfig<unknown>, 'id'>,
  toast: Pick<ToastItem, 'id'>,
): string => `${config.id}-${toast.id}`

export const contentId = (
  config: Pick<ViewConfig<unknown>, 'id'>,
  toast: Pick<ToastItem, 'id'>,
): string => `${rootId(config, toast)}-content`

export const titleId = (
  config: Pick<ViewConfig<unknown>, 'id'>,
  toast: Pick<ToastItem, 'id'>,
): string => `${rootId(config, toast)}-title`

export const descriptionId = (
  config: Pick<ViewConfig<unknown>, 'id'>,
  toast: Pick<ToastItem, 'id'>,
): string => `${rootId(config, toast)}-description`

export const positionerId = (
  config: Pick<ViewConfig<unknown>, 'id'>,
  toast: Pick<ToastItem, 'id'>,
): string => `${rootId(config, toast)}-positioner`

export const arrowId = (
  config: Pick<ViewConfig<unknown>, 'id'>,
  toast: Pick<ToastItem, 'id'>,
): string => `${rootId(config, toast)}-arrow`

const resolvedPosition = (toast: Pick<ToastItem, 'position'>): ToastPosition =>
  toast.position ?? {}

const resolvedSide = (toast: Pick<ToastItem, 'position'>): ToastSide =>
  resolvedPosition(toast).side ?? defaultSide

const resolvedAlign = (toast: Pick<ToastItem, 'position'>): ToastAlign =>
  resolvedPosition(toast).align ?? defaultAlign

const transitionDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  transitionStatus: ToastTransitionStatus | undefined,
): ReadonlyArray<Attribute<Message>> => {
  if (transitionStatus === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (transitionStatus === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const expandedDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  expanded: boolean,
): ReadonlyArray<Attribute<Message>> =>
  expanded ? [h.DataAttribute('expanded', '')] : []

const foldkitPushTransform = (
  position: ToastViewportPosition | undefined,
): string =>
  position === 'top-left' ||
  position === 'top-center' ||
  position === 'top-right'
    ? 'translateY(var(--toast-offset-y))'
    : 'translateY(calc(var(--toast-offset-y) * -1))'

const foldkitPushAnchorsFromTop = (
  position: ToastViewportPosition | undefined,
): boolean =>
  position === 'top-left' ||
  position === 'top-center' ||
  position === 'top-right'

const rootPlacementStyle = (
  config: Pick<ViewConfig<unknown>, 'stackingStrategy' | 'viewportPosition'>,
): Readonly<Record<'bottom' | 'top', string>> =>
  foldkitPushAnchorsFromTop(config.viewportPosition)
    ? { top: '0', bottom: 'auto' }
    : { top: 'auto', bottom: '0' }

const baseUiShuffleTransform = (
  position: ToastViewportPosition | undefined,
): string =>
  foldkitPushAnchorsFromTop(position)
    ? 'translateY(calc(var(--toast-index) * 20%)) scale(calc(1 - (var(--toast-index) * 0.05)))'
    : 'translateY(calc(var(--toast-index) * -20%)) scale(calc(1 - (var(--toast-index) * 0.05)))'

const providerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('provider', ''),
  h.DataAttribute('limit', String(config.state.limit)),
  h.DataAttribute('timeout', String(config.state.defaultDuration)),
  h.DataAttribute('paused', String(config.state.timersPaused)),
]

const portalAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
): ReadonlyArray<Attribute<Message>> => [h.DataAttribute('portal', '')]

const viewportPlacementStyle = (
  position: ToastViewportPosition,
): Record<string, string> => {
  if (position === 'top-left') {
    return {
      top: '1rem',
      right: 'auto',
      bottom: 'auto',
      left: '1rem',
      transform: 'none',
    }
  }

  if (position === 'top-center') {
    return {
      top: '1rem',
      right: 'auto',
      bottom: 'auto',
      left: '50%',
      transform: 'translateX(-50%)',
    }
  }

  if (position === 'top-right') {
    return {
      top: '1rem',
      right: '1rem',
      bottom: 'auto',
      left: 'auto',
      transform: 'none',
    }
  }

  if (position === 'bottom-left') {
    return {
      top: 'auto',
      right: 'auto',
      bottom: '1rem',
      left: '1rem',
      transform: 'none',
    }
  }

  if (position === 'bottom-center') {
    return {
      top: 'auto',
      right: 'auto',
      bottom: '1rem',
      left: '50%',
      transform: 'translateX(-50%)',
    }
  }

  return {
    top: 'auto',
    right: '1rem',
    bottom: '1rem',
    left: 'auto',
    transform: 'none',
  }
}

const viewportInteractionMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onViewportInteraction'>,
  type: ToastViewportInteractionType,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onViewportInteraction)
    ? Option.some(config.onViewportInteraction({ type }))
    : Option.none()

const viewportAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  expanded: boolean,
): ToastPartAttributes<Message> => ({
  root: [
    h.Id(viewportId(config)),
    h.Role('region'),
    h.Tabindex(-1),
    h.AriaLive('polite'),
    h.AriaAtomic(false),
    h.Attribute('aria-relevant', 'additions text'),
    h.AriaLabel(config.label ?? 'Notifications'),
    h.DataAttribute(
      'position',
      config.viewportPosition ?? defaultViewportPosition,
    ),
    ...expandedDataAttribute(h, expanded),
    h.Style({
      position: config.viewportPositioning ?? 'fixed',
      display: 'grid',
      gap: '0.5rem',
      zIndex: '2147483647',
      '--toast-frontmost-height': `${
        config.state.toasts.find(activeToast)?.height ?? 0
      }px`,
      ...viewportPlacementStyle(
        config.viewportPosition ?? defaultViewportPosition,
      ),
    }),
    ...optionalMessageAttribute(
      viewportInteractionMessage(config, 'hover-start'),
      message => h.OnMouseEnter(message),
    ),
    ...optionalMessageAttribute(
      viewportInteractionMessage(config, 'hover-end'),
      message => h.OnMouseLeave(message),
    ),
    ...optionalMessageAttribute(
      viewportInteractionMessage(config, 'focus-start'),
      message => h.OnFocus(message),
    ),
    ...optionalMessageAttribute(
      viewportInteractionMessage(config, 'focus-end'),
      message => h.OnBlur(message),
    ),
    ...(Predicate.isNotUndefined(config.onViewportInteraction)
      ? [
          h.OnPointerDown(pointerType => {
            const { onViewportInteraction } = config

            return pointerType === 'touch' &&
              Predicate.isNotUndefined(onViewportInteraction)
              ? Option.some(onViewportInteraction({ type: 'touch-start' }))
              : Option.none()
          }),
          h.OnPointerUp((_screenX, _screenY, pointerType) => {
            const { onViewportInteraction } = config

            return pointerType === 'touch' &&
              Predicate.isNotUndefined(onViewportInteraction)
              ? Option.some(onViewportInteraction({ type: 'touch-end' }))
              : Option.none()
          }),
        ]
      : []),
  ],
  isMounted:
    config.forceMount === true ||
    !EffectArray.isReadonlyArrayEmpty(config.state.toasts),
})

const closeMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onClose'>,
  request: ToastCloseRequest,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onClose)
    ? Option.some(config.onClose(request))
    : Option.none()

const actionMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onAction'>,
  press: ToastActionPress,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onAction)
    ? Option.some(config.onAction(press))
    : Option.none()

const swipeMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onSwipeChange'>,
  change: ToastSwipeChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onSwipeChange)
    ? Option.some(config.onSwipeChange(change))
    : Option.none()

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
  metadata: ToastMetadata,
  expanded: boolean,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(rootId(config, toast)),
  h.Role(toast.priority === 'high' ? 'alertdialog' : 'dialog'),
  h.Tabindex(0),
  h.AriaModal(false),
  ...(toast.title === undefined
    ? []
    : [h.AriaLabelledBy(titleId(config, toast))]),
  ...(toast.description === undefined
    ? []
    : [h.Attribute('aria-describedby', descriptionId(config, toast))]),
  ...(toast.priority === 'high' && !expanded ? [h.AriaHidden(true)] : []),
  ...expandedDataAttribute(h, expanded),
  ...booleanDataAttribute(h, 'limited', toast.limited),
  h.DataAttribute(
    'stacking-strategy',
    config.stackingStrategy ?? 'base-ui-shuffle',
  ),
  ...typeDataAttribute(h, toast),
  ...booleanDataAttribute(h, 'swiping', toast.swipe?.status === 'swiping'),
  ...(toast.swipe?.direction === undefined
    ? []
    : [h.DataAttribute('swipe-direction', toast.swipe.direction)]),
  ...transitionDataAttributes(h, toast.transitionStatus),
  ...(toast.limited === true ? [h.Inert(true)] : []),
  h.Style({
    '--toast-index': String(metadata.visibleIndex),
    '--toast-offset-y': `${metadata.offsetY}px`,
    '--toast-height': `${toast.height ?? 0}px`,
    '--toast-swipe-movement-x': `${toast.swipe?.movementX ?? 0}px`,
    '--toast-swipe-movement-y': `${toast.swipe?.movementY ?? 0}px`,
    zIndex: String(1000 - Math.max(metadata.visibleIndex, 0)),
    ...rootPlacementStyle(config),
    transform:
      config.stackingStrategy === 'foldkit-push' || expanded
        ? foldkitPushTransform(config.viewportPosition)
        : baseUiShuffleTransform(config.viewportPosition),
  }),
  ...optionalMessageAttribute(
    closeMessage(config, closeRequest(toast.id, 'escape-key')),
    message =>
      h.OnKeyDownPreventDefault(key =>
        key === 'Escape' ? Option.some(message) : Option.none(),
      ),
  ),
  ...(Predicate.isNotUndefined(config.onSwipeChange)
    ? [
        h.OnPointerDown(
          (
            pointerType,
            button,
            _screenX,
            _screenY,
            timeStamp,
            clientX,
            clientY,
          ) =>
            button === 0
              ? swipeMessage(config, {
                  id: toast.id,
                  phase: 'start',
                  pointerType,
                  x: clientX,
                  y: clientY,
                  timeStamp,
                })
              : Option.none(),
        ),
        h.OnPointerMove((screenX, screenY, pointerType) =>
          swipeMessage(config, {
            id: toast.id,
            phase: 'move',
            pointerType,
            x: screenX,
            y: screenY,
          }),
        ),
        h.OnPointerUp((screenX, screenY, pointerType, timeStamp) =>
          swipeMessage(config, {
            id: toast.id,
            phase: 'end',
            pointerType,
            x: screenX,
            y: screenY,
            timeStamp,
          }),
        ),
      ]
    : []),
]

const contentAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
  metadata: ToastMetadata,
  expanded: boolean,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(contentId(config, toast)),
  ...expandedDataAttribute(h, expanded),
  ...booleanDataAttribute(
    h,
    'behind',
    (config.stackingStrategy ?? 'base-ui-shuffle') === 'base-ui-shuffle' &&
      metadata.visibleIndex > 0,
  ),
]

const titleAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(titleId(config, toast)),
  ...typeDataAttribute(h, toast),
]

const descriptionAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(descriptionId(config, toast)),
  ...typeDataAttribute(h, toast),
]

const actionAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('button'),
  ...typeDataAttribute(h, toast),
  ...optionalMessageAttribute(
    actionMessage(config, { id: toast.id }),
    message => h.OnClick(message),
  ),
]

const closeAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
  _expanded: boolean,
): ReadonlyArray<Attribute<Message>> => [
  h.Type('button'),
  ...typeDataAttribute(h, toast),
  ...optionalMessageAttribute(
    closeMessage(config, closeRequest(toast.id, 'close-button')),
    message => h.OnClick(message),
  ),
]

const placementAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  toast: ToastItem,
): ReadonlyArray<Attribute<Message>> => {
  const position = resolvedPosition(toast)

  return [
    h.DataAttribute('side', resolvedSide(toast)),
    h.DataAttribute('align', resolvedAlign(toast)),
    h.DataAttribute(
      'side-offset',
      String(position.sideOffset ?? defaultSideOffset),
    ),
    h.DataAttribute(
      'align-offset',
      String(position.alignOffset ?? defaultAlignOffset),
    ),
    h.DataAttribute(
      'collision-avoidance',
      String(position.collisionAvoidance ?? defaultCollisionAvoidance),
    ),
    h.DataAttribute(
      'collision-padding',
      String(position.collisionPadding ?? defaultCollisionPadding),
    ),
    h.DataAttribute(
      'arrow-padding',
      String(position.arrowPadding ?? defaultArrowPadding),
    ),
  ]
}

const positionerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
  metadata: ToastMetadata,
): ToastPartAttributes<Message> => {
  const position = resolvedPosition(toast)

  return {
    root: [
      h.Id(positionerId(config, toast)),
      ...placementAttributes(h, toast),
      ...booleanDataAttribute(h, 'anchor-hidden', position.isAnchorHidden),
      h.Style({
        position: position.positionMethod ?? 'absolute',
        '--toast-index': String(metadata.visibleIndex),
      }),
    ],
    isMounted: true,
  }
}

const arrowAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
): ToastPartAttributes<Message> => {
  const position = resolvedPosition(toast)

  return {
    root: [
      h.Id(arrowId(config, toast)),
      h.AriaHidden(true),
      ...placementAttributes(h, toast),
      ...booleanDataAttribute(h, 'uncentered', position.isArrowUncentered),
      h.Style({
        width: `${position.arrowWidth ?? defaultArrowWidth}px`,
        height: `${position.arrowHeight ?? defaultArrowHeight}px`,
      }),
    ],
    isMounted: true,
  }
}

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
  metadata: ToastMetadata,
  expanded: boolean,
): ToastItemAttributes<Message> => ({
  toast,
  metadata,
  root: rootAttributes(h, config, toast, metadata, expanded),
  content: contentAttributes(h, config, toast, metadata, expanded),
  title: titleAttributes(h, config, toast),
  description: descriptionAttributes(h, config, toast),
  action: actionAttributes(h, config, toast),
  close: closeAttributes(h, config, toast, expanded),
  positioner: positionerAttributes(h, config, toast, metadata),
  arrow: arrowAttributes(h, config, toast),
  isOpen: activeToast(toast),
  isMounted: true,
})

const announcementAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  toast: ToastItem,
): ToastAnnouncementAttributes<Message> => ({
  toast,
  root: [h.Role('alert'), h.AriaAtomic(true)],
  title: [h.Id(`${rootId(config, toast)}-announcement-title`)],
  description: [h.Id(`${rootId(config, toast)}-announcement-description`)],
})

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const expanded = isExpanded(config.state)
  const metadata = toastMetadata(config.state)
  const metadataById = new Map(metadata.map(item => [item.id, item]))
  const toasts = config.state.toasts.flatMap(toast => {
    const itemMetadata = metadataById.get(toast.id)

    return itemMetadata === undefined
      ? []
      : [itemAttributes(h, config, toast, itemMetadata, expanded)]
  })
  const highPriorityAnnouncements = config.state.toasts
    .filter(toast => toast.priority === 'high')
    .map(toast => announcementAttributes(h, config, toast))

  return config.toView({
    provider: providerAttributes(h, config),
    portal: portalAttributes(h),
    viewport: viewportAttributes(h, config, expanded),
    toasts,
    highPriorityAnnouncements,
    isExpanded: expanded,
    isEmpty: EffectArray.isReadonlyArrayEmpty(config.state.toasts),
  })
}

import { Predicate, Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import * as Button from './button'

// MODEL

export const ToggleChangeReason = S.Literal('none')
export type ToggleChangeReason = typeof ToggleChangeReason.Type

export const TogglePressedChange = S.Struct({
  isPressed: S.Boolean,
  reason: ToggleChangeReason,
})
export type TogglePressedChange = typeof TogglePressedChange.Type

export const ToggleOptions = S.Struct({
  isPressed: S.Boolean,
  isDisabled: S.optional(S.Boolean),
  isNativeButton: S.optional(S.Boolean),
})
export type ToggleOptions = typeof ToggleOptions.Type

// UPDATE

export const pressedChange = (isPressed: boolean): TogglePressedChange => ({
  isPressed,
  reason: 'none',
})

// VIEW

export type ToggleAttributes<Message> = Button.ButtonAttributes<Message>

export type ViewConfig<Message> = ToggleOptions &
  Omit<Button.ViewConfig<Message>, 'onClick' | 'toView' | 'type'> &
  Readonly<{
    toView: (attributes: ToggleAttributes<Message>) => Html
    onPressedChange?: (change: TogglePressedChange) => Message
  }>

const pressedAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  isPressed: boolean,
): ReadonlyArray<Attribute<Message>> => [
  h.AriaPressed(String(isPressed)),
  ...(isPressed ? [h.DataAttribute('pressed', '')] : []),
]

const nextPressedMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'isPressed' | 'onPressedChange'>,
): Message | undefined =>
  Predicate.isNotUndefined(config.onPressedChange)
    ? config.onPressedChange(pressedChange(!config.isPressed))
    : undefined

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const {
    toView,
    isPressed,
    onPressedChange: _onPressedChange,
    ...buttonConfig
  } = config
  const onClick = nextPressedMessage(config)

  return Button.view<Message>({
    ...buttonConfig,
    type: 'button',
    ...(onClick === undefined ? {} : { onClick }),
    toView: attributes =>
      toView({
        button: [...attributes.button, ...pressedAttributes(h, isPressed)],
      }),
  })
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html, KeyboardModifiers } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const ToggleGroupOrientation = S.Union([
  S.Literal('horizontal'),
  S.Literal('vertical'),
])
export type ToggleGroupOrientation = typeof ToggleGroupOrientation.Type

export const ToggleGroupSelectionMode = S.Union([
  S.Literal('single'),
  S.Literal('multiple'),
])
export type ToggleGroupSelectionMode = typeof ToggleGroupSelectionMode.Type

export const ToggleGroupChangeReason = S.Literal('none')
export type ToggleGroupChangeReason = typeof ToggleGroupChangeReason.Type

export const ToggleGroupValueChange = S.Struct({
  value: S.Array(S.String),
  reason: ToggleGroupChangeReason,
  focusSelector: S.optional(S.String),
})
export type ToggleGroupValueChange = typeof ToggleGroupValueChange.Type

export const ToggleGroupHighlightChange = S.Struct({
  value: S.String,
  focusSelector: S.optional(S.String),
})
export type ToggleGroupHighlightChange = typeof ToggleGroupHighlightChange.Type

export const ToggleGroupItemDescriptor = S.Struct({
  id: S.optional(S.String),
  value: S.String,
  label: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  isNativeButton: S.optional(S.Boolean),
})
export type ToggleGroupItemDescriptor = typeof ToggleGroupItemDescriptor.Type

export const ToggleGroupOptions = S.Struct({
  id: S.optional(S.String),
  value: S.Array(S.String),
  highlightedValue: S.optional(S.String),
  selectionMode: S.optional(ToggleGroupSelectionMode),
  orientation: S.optional(ToggleGroupOrientation),
  loopFocus: S.optional(S.Boolean),
  isDisabled: S.optional(S.Boolean),
  items: S.Array(ToggleGroupItemDescriptor),
})
export type ToggleGroupOptions = typeof ToggleGroupOptions.Type

// UPDATE

export const isPressed = (
  groupValue: ReadonlyArray<string>,
  item: Pick<ToggleGroupItemDescriptor, 'value'>,
): boolean => groupValue.includes(item.value)

export const pressedState = (
  groupValue: ReadonlyArray<string>,
  item: Pick<ToggleGroupItemDescriptor, 'value'>,
): 'on' | 'off' => (isPressed(groupValue, item) ? 'on' : 'off')

export const valueChange = (
  value: ReadonlyArray<string>,
  focusSelector?: string,
): ToggleGroupValueChange => ({
  value,
  reason: 'none',
  ...(focusSelector === undefined ? {} : { focusSelector }),
})

export const highlightChange = (
  value: string,
  focusSelector?: string,
): ToggleGroupHighlightChange => ({
  value,
  ...(focusSelector === undefined ? {} : { focusSelector }),
})

export const itemFocusSelector = (
  item: Pick<ToggleGroupItemDescriptor, 'id'>,
): string | undefined => (item.id === undefined ? undefined : `#${item.id}`)

export const nextValue = (
  groupValue: ReadonlyArray<string>,
  selectionMode: ToggleGroupSelectionMode,
  item: Pick<ToggleGroupItemDescriptor, 'value'>,
): ReadonlyArray<string> => {
  const itemIsPressed = isPressed(groupValue, item)

  if (selectionMode === 'single') {
    return itemIsPressed ? [] : [item.value]
  }

  return itemIsPressed
    ? groupValue.filter(value => value !== item.value)
    : [...groupValue, item.value]
}

// VIEW

export type ToggleGroupItemAttributes<Message> = Readonly<{
  item: ToggleGroupItemDescriptor
  root: ReadonlyArray<Attribute<Message>>
}>

export type ToggleGroupAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  items: ReadonlyArray<ToggleGroupItemAttributes<Message>>
}>

export type ViewConfig<Message> = ToggleGroupOptions &
  Readonly<{
    toView: (attributes: ToggleGroupAttributes<Message>) => Html
    onValueChange?: (change: ToggleGroupValueChange) => Message
    onHighlightChange?: (change: ToggleGroupHighlightChange) => Message
  }>

const defaultOrientation = 'horizontal'
const defaultSelectionMode = 'single'

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const stateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<
    ToggleGroupOptions,
    'isDisabled' | 'orientation' | 'selectionMode'
  >,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('orientation', config.orientation ?? defaultOrientation),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(
    h,
    'multiple',
    (config.selectionMode ?? defaultSelectionMode) === 'multiple',
  ),
]

const enabledItems = (
  config: Pick<ToggleGroupOptions, 'isDisabled' | 'items'>,
): ReadonlyArray<ToggleGroupItemDescriptor> =>
  config.isDisabled === true
    ? []
    : config.items.filter(item => item.isDisabled !== true)

const firstEnabledItem = (
  config: Pick<ToggleGroupOptions, 'isDisabled' | 'items'>,
): ToggleGroupItemDescriptor | undefined => enabledItems(config)[0]

const firstPressedEnabledItem = (
  config: Pick<ToggleGroupOptions, 'isDisabled' | 'items' | 'value'>,
): ToggleGroupItemDescriptor | undefined =>
  enabledItems(config).find(item => isPressed(config.value, item))

const highlightedEnabledItem = (
  config: Pick<ToggleGroupOptions, 'highlightedValue' | 'isDisabled' | 'items'>,
): ToggleGroupItemDescriptor | undefined =>
  enabledItems(config).find(item => item.value === config.highlightedValue)

const tabbableValue = (
  config: Pick<
    ToggleGroupOptions,
    'highlightedValue' | 'isDisabled' | 'items' | 'value'
  >,
): string | undefined =>
  highlightedEnabledItem(config)?.value ??
  firstPressedEnabledItem(config)?.value ??
  firstEnabledItem(config)?.value

const canActivateItem = (
  config: Pick<ToggleGroupOptions, 'isDisabled'>,
  item: ToggleGroupItemDescriptor,
): boolean => config.isDisabled !== true && item.isDisabled !== true

const activationMessage = <Message>(
  config: Pick<
    ViewConfig<Message>,
    'isDisabled' | 'onValueChange' | 'selectionMode' | 'value'
  >,
  item: ToggleGroupItemDescriptor,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onValueChange) &&
  canActivateItem(config, item)
    ? Option.some(
        config.onValueChange(
          valueChange(
            nextValue(
              config.value,
              config.selectionMode ?? defaultSelectionMode,
              item,
            ),
            itemFocusSelector(item),
          ),
        ),
      )
    : Option.none()

const nextIndex = (
  currentIndex: number,
  enabled: ReadonlyArray<ToggleGroupItemDescriptor>,
  direction: 'next' | 'previous',
  loopFocus: boolean,
): number | undefined => {
  const offset = direction === 'next' ? 1 : -1
  const candidateIndex = currentIndex + offset

  if (candidateIndex >= 0 && candidateIndex < enabled.length) {
    return candidateIndex
  }

  if (!loopFocus) {
    return undefined
  }

  return direction === 'next' ? 0 : enabled.length - 1
}

const horizontalDirection = (
  key: string,
  dir: string | undefined,
): 'next' | 'previous' | undefined => {
  if (key === 'ArrowRight') {
    return dir === 'rtl' ? 'previous' : 'next'
  }

  if (key === 'ArrowLeft') {
    return dir === 'rtl' ? 'next' : 'previous'
  }

  return undefined
}

const verticalDirection = (key: string): 'next' | 'previous' | undefined => {
  if (key === 'ArrowDown') {
    return 'next'
  }

  if (key === 'ArrowUp') {
    return 'previous'
  }

  return undefined
}

const arrowDirection = (
  key: string,
  config: Pick<ToggleGroupOptions, 'orientation'> &
    Readonly<{ dir?: string | undefined }>,
): 'next' | 'previous' | undefined =>
  (config.orientation ?? defaultOrientation) === 'vertical'
    ? verticalDirection(key)
    : horizontalDirection(key, config.dir)

const rovingItem = (
  config: Pick<
    ToggleGroupOptions,
    'isDisabled' | 'items' | 'loopFocus' | 'orientation'
  > &
    Readonly<{ dir?: string | undefined }>,
  item: ToggleGroupItemDescriptor,
  key: string,
): ToggleGroupItemDescriptor | undefined => {
  const enabled = enabledItems(config)
  const currentIndex = enabled.findIndex(entry => entry.value === item.value)

  if (key === 'Home') {
    return enabled[0]
  }

  if (key === 'End') {
    return enabled.at(-1)
  }

  const direction = arrowDirection(key, config)
  const targetIndex =
    direction === undefined || currentIndex === -1
      ? undefined
      : nextIndex(currentIndex, enabled, direction, config.loopFocus ?? true)

  return targetIndex === undefined ? undefined : enabled[targetIndex]
}

const hasKeyboardModifier = (modifiers: KeyboardModifiers): boolean =>
  modifiers.altKey ||
  modifiers.ctrlKey ||
  modifiers.metaKey ||
  modifiers.shiftKey

const rovingMessage = <Message>(
  config: ViewConfig<Message> & Readonly<{ dir?: string | undefined }>,
  item: ToggleGroupItemDescriptor,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (
    hasKeyboardModifier(modifiers) ||
    Predicate.isUndefined(config.onHighlightChange)
  ) {
    return Option.none()
  }

  const targetItem = rovingItem(config, item, key)

  return targetItem === undefined
    ? Option.none()
    : Option.some(
        config.onHighlightChange(
          highlightChange(targetItem.value, itemFocusSelector(targetItem)),
        ),
      )
}

const keyboardMessage = <Message>(
  config: ViewConfig<Message> & Readonly<{ dir?: string | undefined }>,
  item: ToggleGroupItemDescriptor,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> =>
  rovingMessage(config, item, key, modifiers).pipe(
    Option.orElse(() =>
      key === ' ' || key === 'Enter'
        ? activationMessage(config, item)
        : Option.none(),
    ),
  )

const eventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message> & Readonly<{ dir?: string | undefined }>,
  item: ToggleGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> => {
  if (!canActivateItem(config, item)) {
    return []
  }

  const keyboardAttributes =
    Predicate.isNotUndefined(config.onValueChange) ||
    Predicate.isNotUndefined(config.onHighlightChange)
      ? [
          h.OnKeyDownPreventDefault((key, modifiers) =>
            keyboardMessage(config, item, key, modifiers),
          ),
        ]
      : []

  return Option.match(activationMessage(config, item), {
    onNone: () => keyboardAttributes,
    onSome: message => [h.OnClick(message), ...keyboardAttributes],
  })
}

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('group'),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...(config.isDisabled === true ? [h.AriaDisabled(true)] : []),
  ...stateDataAttributes(h, config),
]

const pressedAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  isItemPressed: boolean,
): ReadonlyArray<Attribute<Message>> => [
  h.AriaPressed(String(isItemPressed)),
  h.DataAttribute('state', isItemPressed ? 'on' : 'off'),
  ...(isItemPressed ? [h.DataAttribute('pressed', '')] : []),
]

const itemTabIndex = (
  config: Pick<
    ToggleGroupOptions,
    'highlightedValue' | 'isDisabled' | 'items' | 'value'
  >,
  item: ToggleGroupItemDescriptor,
): number => {
  if (config.isDisabled === true || item.isDisabled === true) {
    return -1
  }

  return tabbableValue(config) === item.value ? 0 : -1
}

const itemKindAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  item: Pick<ToggleGroupItemDescriptor, 'isNativeButton'>,
): ReadonlyArray<Attribute<Message>> =>
  item.isNativeButton === false ? [h.Role('button')] : [h.Type('button')]

const disabledAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ToggleGroupOptions, 'isDisabled'>,
  item: Pick<ToggleGroupItemDescriptor, 'isDisabled'>,
): ReadonlyArray<Attribute<Message>> =>
  config.isDisabled === true || item.isDisabled === true
    ? [h.AriaDisabled(true), h.DataAttribute('disabled', '')]
    : []

const itemOrientationAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ToggleGroupOptions, 'orientation'>,
): Attribute<Message> =>
  h.DataAttribute('orientation', config.orientation ?? defaultOrientation)

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message> & Readonly<{ dir?: string | undefined }>,
  item: ToggleGroupItemDescriptor,
): ReadonlyArray<Attribute<Message>> => {
  const itemIsPressed = isPressed(config.value, item)

  return [
    ...itemKindAttributes(h, item),
    h.Tabindex(itemTabIndex(config, item)),
    ...optionalAttribute<Message>(item.id, value => h.Id(value)),
    ...pressedAttributes(h, itemIsPressed),
    ...disabledAttributes(h, config, item),
    itemOrientationAttribute(h, config),
    ...eventAttributes(h, config, item),
  ]
}

export const view = <Message>(
  config: ViewConfig<Message> & Readonly<{ dir?: string | undefined }>,
): Html => {
  const h = html<Message>()

  return config.toView({
    root: rootAttributes(h, config),
    items: config.items.map(item => ({
      item,
      root: itemAttributes(h, config, item),
    })),
  })
}

import { Option, Predicate, Schema as S } from 'effect'
import type { Attribute, Html, KeyboardModifiers } from 'foldkit/html'
import { html } from 'foldkit/html'

// MODEL

export const ToolbarOrientation = S.Union([
  S.Literal('horizontal'),
  S.Literal('vertical'),
])
export type ToolbarOrientation = typeof ToolbarOrientation.Type

export const ToolbarItemKind = S.Union([
  S.Literal('button'),
  S.Literal('link'),
  S.Literal('input'),
])
export type ToolbarItemKind = typeof ToolbarItemKind.Type

export const ToolbarChildKind = S.Union([ToolbarItemKind, S.Literal('group')])
export type ToolbarChildKind = typeof ToolbarChildKind.Type

export const ToolbarHighlightChange = S.Struct({
  value: S.String,
  focusSelector: S.optional(S.String),
})
export type ToolbarHighlightChange = typeof ToolbarHighlightChange.Type

export const ToolbarItemPress = S.Struct({
  value: S.String,
  kind: ToolbarItemKind,
})
export type ToolbarItemPress = typeof ToolbarItemPress.Type

export const ToolbarInputChangeReason = S.Literal('none')
export type ToolbarInputChangeReason = typeof ToolbarInputChangeReason.Type

export const ToolbarInputValueChange = S.Struct({
  value: S.String,
  itemValue: S.String,
  reason: ToolbarInputChangeReason,
})
export type ToolbarInputValueChange = typeof ToolbarInputValueChange.Type

export const ToolbarItemDescriptor = S.Struct({
  id: S.optional(S.String),
  value: S.String,
  label: S.optional(S.String),
  kind: S.optional(ToolbarItemKind),
  href: S.optional(S.String),
  name: S.optional(S.String),
  type: S.optional(S.String),
  inputValue: S.optional(S.Union([S.String, S.Number])),
  placeholder: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  isFocusableWhenDisabled: S.optional(S.Boolean),
  isNativeButton: S.optional(S.Boolean),
})
export type ToolbarItemDescriptor = typeof ToolbarItemDescriptor.Type

export const ToolbarChildDescriptor = S.Struct({
  id: S.optional(S.String),
  value: S.String,
  label: S.optional(S.String),
  kind: S.optional(ToolbarChildKind),
  href: S.optional(S.String),
  name: S.optional(S.String),
  type: S.optional(S.String),
  inputValue: S.optional(S.Union([S.String, S.Number])),
  placeholder: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  isFocusableWhenDisabled: S.optional(S.Boolean),
  isNativeButton: S.optional(S.Boolean),
  items: S.optional(S.Array(ToolbarItemDescriptor)),
})
export type ToolbarChildDescriptor = typeof ToolbarChildDescriptor.Type

export const ToolbarOptions = S.Struct({
  id: S.optional(S.String),
  orientation: S.optional(ToolbarOrientation),
  highlightedValue: S.optional(S.String),
  loopFocus: S.optional(S.Boolean),
  isDisabled: S.optional(S.Boolean),
  dir: S.optional(S.String),
  children: S.Array(ToolbarChildDescriptor),
})
export type ToolbarOptions = typeof ToolbarOptions.Type

// UPDATE

type ToolbarItemSource = ToolbarItemDescriptor | ToolbarChildDescriptor

type ResolvedToolbarItem = Readonly<{
  group?: ToolbarChildDescriptor
  item: ToolbarItemSource
}>

const defaultOrientation: ToolbarOrientation = 'horizontal'
const defaultLoopFocus = true
const defaultItemKind: ToolbarItemKind = 'button'
const defaultFocusableWhenDisabled = true
const activationKeys = new Set(['Enter', ' '])

export const itemKind = (item: ToolbarItemSource): ToolbarItemKind => {
  if (item.kind === 'link' || item.kind === 'input') {
    return item.kind
  }

  return defaultItemKind
}

export const childKind = (child: ToolbarChildDescriptor): ToolbarChildKind =>
  child.kind ?? defaultItemKind

export const highlightChange = (
  value: string,
  focusSelector?: string | undefined,
): ToolbarHighlightChange => ({
  value,
  ...(focusSelector === undefined ? {} : { focusSelector }),
})

export const itemPress = (item: ToolbarItemSource): ToolbarItemPress => ({
  value: item.value,
  kind: itemKind(item),
})

export const inputValueChange = (
  item: ToolbarItemSource,
  value: string,
): ToolbarInputValueChange => ({
  value,
  itemValue: item.value,
  reason: 'none',
})

export const itemFocusSelector = (
  item: Pick<ToolbarItemSource, 'id'>,
): string | undefined => (item.id === undefined ? undefined : `#${item.id}`)

const resolvedChildItems = (
  child: ToolbarChildDescriptor,
): ReadonlyArray<ResolvedToolbarItem> =>
  childKind(child) === 'group'
    ? (child.items ?? []).map(item => ({ group: child, item }))
    : [{ item: child }]

const resolvedItems = (
  children: ReadonlyArray<ToolbarChildDescriptor>,
): ReadonlyArray<ResolvedToolbarItem> => children.flatMap(resolvedChildItems)

const isDisabledByContext = (
  config: Pick<ToolbarOptions, 'isDisabled'>,
  resolvedItem: ResolvedToolbarItem,
): boolean =>
  config.isDisabled === true ||
  resolvedItem.group?.isDisabled === true ||
  resolvedItem.item.isDisabled === true

const isItemDisabled = (
  config: Pick<ToolbarOptions, 'isDisabled'>,
  resolvedItem: ResolvedToolbarItem,
): boolean =>
  itemKind(resolvedItem.item) === 'link'
    ? false
    : isDisabledByContext(config, resolvedItem)

const focusableWhenDisabled = (item: ToolbarItemSource): boolean =>
  item.isFocusableWhenDisabled ?? defaultFocusableWhenDisabled

const isNavigableItem = (
  config: Pick<ToolbarOptions, 'isDisabled'>,
  resolvedItem: ResolvedToolbarItem,
): boolean =>
  !isItemDisabled(config, resolvedItem) ||
  itemKind(resolvedItem.item) === 'link' ||
  focusableWhenDisabled(resolvedItem.item)

const navigableItems = (
  config: Pick<ToolbarOptions, 'children' | 'isDisabled'>,
): ReadonlyArray<ResolvedToolbarItem> =>
  resolvedItems(config.children).filter(item => isNavigableItem(config, item))

const highlightedItem = (
  config: Pick<ToolbarOptions, 'children' | 'highlightedValue' | 'isDisabled'>,
): ResolvedToolbarItem | undefined =>
  navigableItems(config).find(
    item => item.item.value === config.highlightedValue,
  )

const tabbableValue = (
  config: Pick<ToolbarOptions, 'children' | 'highlightedValue' | 'isDisabled'>,
): string | undefined =>
  highlightedItem(config)?.item.value ?? navigableItems(config)[0]?.item.value

const itemTabIndex = (
  config: Pick<ToolbarOptions, 'children' | 'highlightedValue' | 'isDisabled'>,
  item: ToolbarItemSource,
): number => (tabbableValue(config) === item.value ? 0 : -1)

const nextIndex = (
  currentIndex: number,
  enabled: ReadonlyArray<ResolvedToolbarItem>,
  direction: 'next' | 'previous',
  loopFocus: boolean,
): number | undefined => {
  const offset = direction === 'next' ? 1 : -1
  const candidateIndex = currentIndex + offset

  if (candidateIndex >= 0 && candidateIndex < enabled.length) {
    return candidateIndex
  }

  if (!loopFocus) {
    return undefined
  }

  return direction === 'next' ? 0 : enabled.length - 1
}

const horizontalDirection = (
  key: string,
  dir: string | undefined,
): 'next' | 'previous' | undefined => {
  if (key === 'ArrowRight') {
    return dir === 'rtl' ? 'previous' : 'next'
  }

  if (key === 'ArrowLeft') {
    return dir === 'rtl' ? 'next' : 'previous'
  }

  return undefined
}

const verticalDirection = (key: string): 'next' | 'previous' | undefined => {
  if (key === 'ArrowDown') {
    return 'next'
  }

  if (key === 'ArrowUp') {
    return 'previous'
  }

  return undefined
}

const arrowDirection = (
  key: string,
  config: Pick<ToolbarOptions, 'dir' | 'orientation'>,
): 'next' | 'previous' | undefined =>
  (config.orientation ?? defaultOrientation) === 'vertical'
    ? verticalDirection(key)
    : horizontalDirection(key, config.dir)

const rovingItem = (
  config: Pick<
    ToolbarOptions,
    'children' | 'dir' | 'isDisabled' | 'loopFocus' | 'orientation'
  >,
  item: ToolbarItemSource,
  key: string,
): ResolvedToolbarItem | undefined => {
  const enabled = navigableItems(config)
  const currentIndex = enabled.findIndex(
    entry => entry.item.value === item.value,
  )

  if (key === 'Home') {
    return enabled[0]
  }

  if (key === 'End') {
    return enabled.at(-1)
  }

  const direction = arrowDirection(key, config)
  const targetIndex =
    direction === undefined || currentIndex === -1
      ? undefined
      : nextIndex(
          currentIndex,
          enabled,
          direction,
          config.loopFocus ?? defaultLoopFocus,
        )

  return targetIndex === undefined ? undefined : enabled[targetIndex]
}

const hasKeyboardModifier = (modifiers: KeyboardModifiers): boolean =>
  modifiers.altKey ||
  modifiers.ctrlKey ||
  modifiers.metaKey ||
  modifiers.shiftKey

// VIEW

export type ToolbarItemAttributes<Message> = Readonly<{
  kind: ToolbarItemKind
  item: ToolbarItemSource
  root: ReadonlyArray<Attribute<Message>>
}>

export type ToolbarGroupAttributes<Message> = Readonly<{
  group: ToolbarChildDescriptor
  items: ReadonlyArray<ToolbarItemAttributes<Message>>
  root: ReadonlyArray<Attribute<Message>>
}>

export type ToolbarChildAttributes<Message> =
  | Readonly<{
      _tag: 'Item'
      item: ToolbarItemAttributes<Message>
    }>
  | Readonly<{
      _tag: 'Group'
      group: ToolbarGroupAttributes<Message>
    }>

export type ToolbarAttributes<Message> = Readonly<{
  children: ReadonlyArray<ToolbarChildAttributes<Message>>
  root: ReadonlyArray<Attribute<Message>>
}>

export type ViewConfig<Message> = ToolbarOptions &
  Readonly<{
    toView: (attributes: ToolbarAttributes<Message>) => Html
    onHighlightChange?: (change: ToolbarHighlightChange) => Message
    onInputValueChange?: (change: ToolbarInputValueChange) => Message
    onItemPress?: (press: ToolbarItemPress) => Message
  }>

const optionalAttribute = <Message>(
  value: string | undefined,
  toAttribute: (value: string) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [toAttribute(value)] : []

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const valueAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  value: string | number | undefined,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(value) ? [h.Value(String(value))] : []

const nativeDisabledAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  item: ToolbarItemSource,
): ReadonlyArray<Attribute<Message>> =>
  focusableWhenDisabled(item)
    ? [h.AriaDisabled(true), h.DataAttribute('disabled', '')]
    : [h.Disabled(true), h.DataAttribute('disabled', '')]

const nonNativeButtonDisabledAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  item: ToolbarItemSource,
): ReadonlyArray<Attribute<Message>> => [
  h.AriaDisabled(true),
  ...(focusableWhenDisabled(item) ? [] : [h.Tabindex(-1)]),
  h.DataAttribute('disabled', ''),
]

const disabledAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  kind: ToolbarItemKind,
  item: ToolbarItemSource,
  isDisabled: boolean,
): ReadonlyArray<Attribute<Message>> => {
  if (!isDisabled || kind === 'link') {
    return []
  }

  if (kind === 'button' && item.isNativeButton === false) {
    return nonNativeButtonDisabledAttributes(h, item)
  }

  return nativeDisabledAttributes(h, item)
}

const focusableAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  kind: ToolbarItemKind,
  item: ToolbarItemSource,
): ReadonlyArray<Attribute<Message>> =>
  kind === 'button' || kind === 'input'
    ? booleanDataAttribute(h, 'focusable', focusableWhenDisabled(item))
    : []

const kindAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  kind: ToolbarItemKind,
  item: ToolbarItemSource,
): ReadonlyArray<Attribute<Message>> => {
  if (kind === 'link') {
    return optionalAttribute<Message>(item.href, value => h.Href(value))
  }

  if (kind === 'input') {
    return [
      ...optionalAttribute<Message>(item.type, value => h.Type(value)),
      ...optionalAttribute<Message>(item.name, value => h.Name(value)),
      ...optionalAttribute<Message>(item.placeholder, value =>
        h.Placeholder(value),
      ),
      ...valueAttribute(h, item.inputValue),
    ]
  }

  return item.isNativeButton === false ? [h.Role('button')] : [h.Type('button')]
}

const activationMessage = <Message>(
  config: Pick<ViewConfig<Message>, 'onItemPress'>,
  item: ToolbarItemSource,
  isDisabled: boolean,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onItemPress) && !isDisabled
    ? Option.some(config.onItemPress(itemPress(item)))
    : Option.none()

const rovingMessage = <Message>(
  config: ViewConfig<Message>,
  item: ToolbarItemSource,
  key: string,
  modifiers: KeyboardModifiers,
): Option.Option<Message> => {
  if (
    hasKeyboardModifier(modifiers) ||
    Predicate.isUndefined(config.onHighlightChange)
  ) {
    return Option.none()
  }

  const targetItem = rovingItem(config, item, key)

  return targetItem === undefined
    ? Option.none()
    : Option.some(
        config.onHighlightChange(
          highlightChange(
            targetItem.item.value,
            itemFocusSelector(targetItem.item),
          ),
        ),
      )
}

const keyboardMessage = <Message>(
  config: ViewConfig<Message>,
  item: ToolbarItemSource,
  key: string,
  modifiers: KeyboardModifiers,
  isDisabled: boolean,
): Option.Option<Message> =>
  rovingMessage(config, item, key, modifiers).pipe(
    Option.orElse(() =>
      activationKeys.has(key) && itemKind(item) === 'button'
        ? activationMessage(config, item, isDisabled)
        : Option.none(),
    ),
  )

const clickAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ToolbarItemSource,
  isDisabled: boolean,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(activationMessage(config, item, isDisabled), {
    onNone: () => [],
    onSome: message => [h.OnClick(message)],
  })

const keyboardAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ToolbarItemSource,
  isDisabled: boolean,
): ReadonlyArray<Attribute<Message>> =>
  Predicate.isNotUndefined(config.onHighlightChange) ||
  Predicate.isNotUndefined(config.onItemPress)
    ? [
        h.OnKeyDownPreventDefault((key, modifiers) =>
          keyboardMessage(config, item, key, modifiers, isDisabled),
        ),
      ]
    : []

const inputChangeAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ToolbarItemSource,
  isDisabled: boolean,
): ReadonlyArray<Attribute<Message>> => {
  const { onInputValueChange } = config

  return Predicate.isNotUndefined(onInputValueChange) && !isDisabled
    ? [h.OnInput(value => onInputValueChange(inputValueChange(item, value)))]
    : []
}

const eventAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  item: ToolbarItemSource,
  isDisabled: boolean,
): ReadonlyArray<Attribute<Message>> => {
  const kind = itemKind(item)
  const inputEvents =
    kind === 'input' ? inputChangeAttributes(h, config, item, isDisabled) : []

  return [
    ...clickAttributes(h, config, item, isDisabled),
    ...keyboardAttributes(h, config, item, isDisabled),
    ...inputEvents,
  ]
}

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('toolbar'),
  h.AriaOrientation(config.orientation ?? defaultOrientation),
  h.DataAttribute('orientation', config.orientation ?? defaultOrientation),
  ...optionalAttribute<Message>(config.id, value => h.Id(value)),
  ...optionalAttribute<Message>(config.dir, value => h.Attribute('dir', value)),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
]

const groupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  group: ToolbarChildDescriptor,
): ReadonlyArray<Attribute<Message>> => [
  h.Role('group'),
  ...optionalAttribute<Message>(group.id, value => h.Id(value)),
  h.DataAttribute('orientation', config.orientation ?? defaultOrientation),
  ...booleanDataAttribute(
    h,
    'disabled',
    config.isDisabled === true || group.isDisabled === true,
  ),
]

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  resolvedItem: ResolvedToolbarItem,
): ToolbarItemAttributes<Message> => {
  const kind = itemKind(resolvedItem.item)
  const isDisabled = isItemDisabled(config, resolvedItem)

  return {
    kind,
    item: resolvedItem.item,
    root: [
      ...kindAttributes(h, kind, resolvedItem.item),
      h.Tabindex(itemTabIndex(config, resolvedItem.item)),
      ...optionalAttribute<Message>(resolvedItem.item.id, value => h.Id(value)),
      ...disabledAttributes(h, kind, resolvedItem.item, isDisabled),
      h.DataAttribute('orientation', config.orientation ?? defaultOrientation),
      ...focusableAttributes(h, kind, resolvedItem.item),
      ...eventAttributes(h, config, resolvedItem.item, isDisabled),
    ],
  }
}

const childAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  child: ToolbarChildDescriptor,
): ToolbarChildAttributes<Message> => {
  if (childKind(child) === 'group') {
    return {
      _tag: 'Group',
      group: {
        group: child,
        root: groupAttributes(h, config, child),
        items: (child.items ?? []).map(item =>
          itemAttributes(h, config, { group: child, item }),
        ),
      },
    }
  }

  return {
    _tag: 'Item',
    item: itemAttributes(h, config, { item: child }),
  }
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()

  return config.toView({
    root: rootAttributes(h, config),
    children: config.children.map(child => childAttributes(h, config, child)),
  })
}

import { Effect, Option, Predicate, Schema as S } from 'effect'
import { Mount } from 'foldkit'
import * as Command from 'foldkit/command'
import * as Dom from 'foldkit/dom'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'
import { m } from 'foldkit/message'

import {
  anchorPlacement,
  PositionAnchoredSurface,
} from '../utils/anchor-positioning'
import type { AnchorPositioningConfig } from '../utils/anchor-positioning'

// MODEL

export const TooltipSide = S.Union([
  S.Literal('bottom'),
  S.Literal('top'),
  S.Literal('right'),
  S.Literal('left'),
  S.Literal('inline-start'),
  S.Literal('inline-end'),
])
export type TooltipSide = typeof TooltipSide.Type

export const TooltipAlign = S.Union([
  S.Literal('start'),
  S.Literal('center'),
  S.Literal('end'),
])
export type TooltipAlign = typeof TooltipAlign.Type

export const TooltipTransitionStatus = S.Union([
  S.Literal('idle'),
  S.Literal('starting'),
  S.Literal('ending'),
])
export type TooltipTransitionStatus = typeof TooltipTransitionStatus.Type

export const TooltipInstant = S.Union([
  S.Literal('delay'),
  S.Literal('dismiss'),
  S.Literal('focus'),
  S.Literal('tracking-cursor'),
])
export type TooltipInstant = typeof TooltipInstant.Type

export const TooltipTrackCursorAxis = S.Union([
  S.Literal('none'),
  S.Literal('x'),
  S.Literal('y'),
  S.Literal('both'),
])
export type TooltipTrackCursorAxis = typeof TooltipTrackCursorAxis.Type

export const TooltipChangeReason = S.Union([
  S.Literal('trigger-hover'),
  S.Literal('trigger-focus'),
  S.Literal('trigger-press'),
  S.Literal('outside-press'),
  S.Literal('escape-key'),
  S.Literal('disabled'),
  S.Literal('imperative-action'),
  S.Literal('none'),
])
export type TooltipChangeReason = typeof TooltipChangeReason.Type

export const TooltipOpenChange = S.Struct({
  open: S.Boolean,
  reason: TooltipChangeReason,
  activeTriggerId: S.optional(S.String),
})
export type TooltipOpenChange = typeof TooltipOpenChange.Type

export const TooltipOptions = S.Struct({
  id: S.String,
  open: S.Boolean,
  activeTriggerId: S.optional(S.String),
  triggerId: S.optional(S.String),
  triggerSelector: S.optional(S.String),
  isDisabled: S.optional(S.Boolean),
  forceMount: S.optional(S.Boolean),
  transitionStatus: S.optional(TooltipTransitionStatus),
  instant: S.optional(TooltipInstant),
  side: S.optional(TooltipSide),
  align: S.optional(TooltipAlign),
  sideOffset: S.optional(S.Number),
  alignOffset: S.optional(S.Number),
  collisionAvoidance: S.optional(S.Boolean),
  collisionPadding: S.optional(S.Number),
  arrowPadding: S.optional(S.Number),
  arrowWidth: S.optional(S.Number),
  arrowHeight: S.optional(S.Number),
  isAnchorHidden: S.optional(S.Boolean),
  isArrowUncentered: S.optional(S.Boolean),
  delay: S.optional(S.Number),
  closeDelay: S.optional(S.Number),
  closeOnClick: S.optional(S.Boolean),
  disableHoverablePopup: S.optional(S.Boolean),
  trackCursorAxis: S.optional(TooltipTrackCursorAxis),
  providerDelay: S.optional(S.Number),
  providerCloseDelay: S.optional(S.Number),
  providerTimeout: S.optional(S.Number),
  viewportActivationDirection: S.optional(S.String),
  isViewportTransitioning: S.optional(S.Boolean),
})
export type TooltipOptions = typeof TooltipOptions.Type

// MESSAGE

export const CompletedFocusTooltip = m('CompletedFocusTooltip')
export const CompletedRestoreTooltipFocus = m('CompletedRestoreTooltipFocus')

export const CommandMessage = S.Union([
  CompletedFocusTooltip,
  CompletedRestoreTooltipFocus,
])
export type CommandMessage = typeof CommandMessage.Type

// UPDATE

const defaultSide: TooltipSide = 'top'
const defaultAlign: TooltipAlign = 'center'
const defaultSideOffset = 0
const defaultAlignOffset = 0
const defaultCollisionAvoidance = true
const defaultCollisionPadding = 5
const defaultArrowPadding = 5
const defaultArrowWidth = 10
const defaultArrowHeight = 5
const defaultDelay = 600
const defaultCloseDelay = 0
const defaultProviderTimeout = 400
const defaultCloseOnClick = true
const defaultTrackCursorAxis: TooltipTrackCursorAxis = 'none'

export const popupId = (config: Pick<TooltipOptions, 'id'>): string =>
  `${config.id}-popup`

export const positionerId = (config: Pick<TooltipOptions, 'id'>): string =>
  `${config.id}-positioner`

export const arrowId = (config: Pick<TooltipOptions, 'id'>): string =>
  `${config.id}-arrow`

export const viewportId = (config: Pick<TooltipOptions, 'id'>): string =>
  `${config.id}-viewport`

export const tooltipSelector = (id: string): string => `#${popupId({ id })}`

export const triggerId = (
  config: Pick<TooltipOptions, 'id' | 'triggerId'>,
): string => config.triggerId ?? `${config.id}-trigger`

export const activeTriggerId = (
  config: Pick<TooltipOptions, 'activeTriggerId' | 'id' | 'triggerId'>,
): string => config.activeTriggerId ?? triggerId(config)

export const triggerSelector = (
  config: Pick<TooltipOptions, 'id' | 'triggerId' | 'triggerSelector'>,
): string => config.triggerSelector ?? `#${triggerId(config)}`

const rootAnchorName = (config: Pick<TooltipOptions, 'id'>): string =>
  `--${config.id}-anchor`

export const openChange = (
  open: boolean,
  reason: TooltipChangeReason = 'none',
  nextActiveTriggerId?: string | undefined,
): TooltipOpenChange => ({
  open,
  reason,
  ...(nextActiveTriggerId === undefined
    ? {}
    : { activeTriggerId: nextActiveTriggerId }),
})

export const hoverOpenChange = (
  nextActiveTriggerId?: string | undefined,
): TooltipOpenChange => openChange(true, 'trigger-hover', nextActiveTriggerId)

export const focusOpenChange = (
  nextActiveTriggerId?: string | undefined,
): TooltipOpenChange => openChange(true, 'trigger-focus', nextActiveTriggerId)

export const pressOpenChange = (
  nextActiveTriggerId?: string | undefined,
): TooltipOpenChange => openChange(true, 'trigger-press', nextActiveTriggerId)

export const hoverCloseChange = (
  nextActiveTriggerId?: string | undefined,
): TooltipOpenChange => openChange(false, 'trigger-hover', nextActiveTriggerId)

export const focusCloseChange = (
  nextActiveTriggerId?: string | undefined,
): TooltipOpenChange => openChange(false, 'trigger-focus', nextActiveTriggerId)

export const pressCloseChange = (
  nextActiveTriggerId?: string | undefined,
): TooltipOpenChange => openChange(false, 'trigger-press', nextActiveTriggerId)

export const outsideOpenChange = (): TooltipOpenChange =>
  openChange(false, 'outside-press')

export const escapeOpenChange = (): TooltipOpenChange =>
  openChange(false, 'escape-key')

export const disabledOpenChange = (): TooltipOpenChange =>
  openChange(false, 'disabled')

export const imperativeOpenChange = (): TooltipOpenChange =>
  openChange(false, 'imperative-action')

export const FocusTooltip = Command.define(
  'FocusTooltip',
  { selector: S.String },
  CompletedFocusTooltip,
)(({ selector }) =>
  Dom.focus(selector, { makeFocusable: true }).pipe(
    Effect.ignore,
    Effect.catchCause(() => Effect.void),
    Effect.as(CompletedFocusTooltip()),
  ),
)

export const RestoreTooltipFocus = Command.define(
  'RestoreTooltipFocus',
  { selector: S.String },
  CompletedRestoreTooltipFocus,
)(({ selector }) =>
  Dom.focus(selector).pipe(
    Effect.ignore,
    Effect.catchCause(() => Effect.void),
    Effect.as(CompletedRestoreTooltipFocus()),
  ),
)

export const commandForOpenChange = (
  config: Pick<TooltipOptions, 'id' | 'triggerId' | 'triggerSelector'>,
  change: TooltipOpenChange,
): Command.Command<CommandMessage> =>
  change.open
    ? FocusTooltip({ selector: tooltipSelector(config.id) })
    : RestoreTooltipFocus({ selector: triggerSelector(config) })

// VIEW

export type TooltipAttributes<Message> = Readonly<{
  provider: ReadonlyArray<Attribute<Message>>
  root: ReadonlyArray<Attribute<Message>>
  trigger: ReadonlyArray<Attribute<Message>>
  portal: ReadonlyArray<Attribute<Message>>
  positioner: TooltipPartAttributes<Message>
  popup: TooltipPartAttributes<Message>
  viewport: TooltipPartAttributes<Message>
  arrow: TooltipPartAttributes<Message>
  isMounted: boolean
  isOpen: boolean
}>

export type TooltipPartAttributes<Message> = Readonly<{
  root: ReadonlyArray<Attribute<Message>>
  isMounted: boolean
  isOpen: boolean
}>

export type ViewConfig<Message> = TooltipOptions &
  Readonly<{
    toView: (attributes: TooltipAttributes<Message>) => Html
    onOpenChange?: (change: TooltipOpenChange) => Message
  }> &
  AnchorPositioningConfig<Message>

const resolvedSide = (config: Pick<TooltipOptions, 'side'>): TooltipSide =>
  config.side ?? defaultSide

const resolvedAlign = (config: Pick<TooltipOptions, 'align'>): TooltipAlign =>
  config.align ?? defaultAlign

const resolvedDelay = (
  config: Pick<TooltipOptions, 'delay' | 'providerDelay'>,
): number => config.delay ?? config.providerDelay ?? defaultDelay

const resolvedCloseDelay = (
  config: Pick<TooltipOptions, 'closeDelay' | 'providerCloseDelay'>,
): number => config.closeDelay ?? config.providerCloseDelay ?? defaultCloseDelay

const mounted = (
  config: Pick<TooltipOptions, 'forceMount' | 'open' | 'transitionStatus'>,
): boolean =>
  config.open ||
  config.forceMount === true ||
  config.transitionStatus === 'ending'

const booleanDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: boolean | undefined,
): ReadonlyArray<Attribute<Message>> =>
  value === true ? [h.DataAttribute(name, '')] : []

const numberDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  name: string,
  value: number,
): Attribute<Message> => h.DataAttribute(name, String(value))

const openStateDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  open: boolean,
): ReadonlyArray<Attribute<Message>> =>
  open ? [h.DataAttribute('open', '')] : [h.DataAttribute('closed', '')]

const transitionDataAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  transitionStatus: TooltipTransitionStatus | undefined,
): ReadonlyArray<Attribute<Message>> => {
  if (transitionStatus === 'starting') {
    return [h.DataAttribute('starting-style', '')]
  }

  if (transitionStatus === 'ending') {
    return [h.DataAttribute('ending-style', '')]
  }

  return []
}

const instantDataAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  instant: TooltipInstant | undefined,
): ReadonlyArray<Attribute<Message>> =>
  instant === undefined ? [] : [h.DataAttribute('instant', instant)]

const openMessage = <Message>(
  config: ViewConfig<Message>,
  change: TooltipOpenChange,
): Option.Option<Message> =>
  Predicate.isNotUndefined(config.onOpenChange)
    ? Option.some(config.onOpenChange(change))
    : Option.none()

const optionalMessageAttribute = <Message>(
  message: Option.Option<Message>,
  toAttribute: (message: Message) => Attribute<Message>,
): ReadonlyArray<Attribute<Message>> =>
  Option.match(message, {
    onNone: () => [],
    onSome: value => [toAttribute(value)],
  })

const providerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('provider', ''),
  numberDataAttribute(h, 'delay', config.providerDelay ?? defaultDelay),
  numberDataAttribute(
    h,
    'close-delay',
    config.providerCloseDelay ?? defaultCloseDelay,
  ),
  numberDataAttribute(
    h,
    'timeout',
    config.providerTimeout ?? defaultProviderTimeout,
  ),
]

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('side', resolvedSide(config)),
  h.DataAttribute('align', resolvedAlign(config)),
  h.DataAttribute(
    'track-cursor-axis',
    config.trackCursorAxis ?? defaultTrackCursorAxis,
  ),
  ...booleanDataAttribute(h, 'disabled', config.isDisabled),
  ...booleanDataAttribute(
    h,
    'disable-hoverable-popup',
    config.disableHoverablePopup,
  ),
]

const triggerOpenChangeForClick = <Message>(
  config: ViewConfig<Message>,
): Option.Option<Message> => {
  const shouldClose = config.open && config.closeOnClick !== false
  const change = shouldClose
    ? pressCloseChange(activeTriggerId(config))
    : pressOpenChange(activeTriggerId(config))

  return openMessage(config, change)
}

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.Id(triggerId(config)),
  h.Type('button'),
  h.Attribute('aria-describedby', popupId(config)),
  h.DataAttribute('delay', String(resolvedDelay(config))),
  h.DataAttribute('close-delay', String(resolvedCloseDelay(config))),
  h.DataAttribute(
    'close-on-click',
    String(config.closeOnClick ?? defaultCloseOnClick),
  ),
  h.Style({ anchorName: rootAnchorName(config) }),
  ...(config.open ? [h.DataAttribute('popup-open', '')] : []),
  ...(config.isDisabled === true
    ? [h.AriaDisabled(true), h.DataAttribute('trigger-disabled', '')]
    : [h.DataAttribute('base-ui-tooltip-trigger', '')]),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, hoverOpenChange(activeTriggerId(config))),
    message => h.OnMouseEnter(message),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, hoverCloseChange(activeTriggerId(config))),
    message => h.OnMouseLeave(message),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, focusOpenChange(activeTriggerId(config))),
    message => h.OnFocus(message),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : openMessage(config, focusCloseChange(activeTriggerId(config))),
    message => h.OnBlur(message),
  ),
  ...optionalMessageAttribute(
    config.isDisabled === true
      ? Option.none()
      : triggerOpenChangeForClick(config),
    message => h.OnClick(message),
  ),
]

const portalAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
): ReadonlyArray<Attribute<Message>> => [h.DataAttribute('portal', '')]

const placementAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('side', resolvedSide(config)),
  h.DataAttribute('align', resolvedAlign(config)),
  numberDataAttribute(h, 'side-offset', config.sideOffset ?? defaultSideOffset),
  numberDataAttribute(
    h,
    'align-offset',
    config.alignOffset ?? defaultAlignOffset,
  ),
  h.DataAttribute(
    'collision-avoidance',
    String(config.collisionAvoidance ?? defaultCollisionAvoidance),
  ),
  numberDataAttribute(
    h,
    'collision-padding',
    config.collisionPadding ?? defaultCollisionPadding,
  ),
  numberDataAttribute(
    h,
    'arrow-padding',
    config.arrowPadding ?? defaultArrowPadding,
  ),
]

const positionArea = (
  config: Pick<TooltipOptions, 'align' | 'side'>,
): string => {
  const align = resolvedAlign(config)
  const side = resolvedSide(config)
  const inlineAlignments = {
    start: 'span-inline-start',
    center: 'center',
    end: 'span-inline-end',
  }
  const blockAlignments = {
    start: 'span-block-start',
    center: 'center',
    end: 'span-block-end',
  }

  if (side === 'top') {
    return `block-start ${inlineAlignments[align]}`
  }
  if (side === 'bottom') {
    return `block-end ${inlineAlignments[align]}`
  }
  if (side === 'left' || side === 'inline-start') {
    return `inline-start ${blockAlignments[align]}`
  }
  return `inline-end ${blockAlignments[align]}`
}

const positionerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): TooltipPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(positionerId(config)),
        ...(config.open ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, config.open),
        ...booleanDataAttribute(h, 'anchor-hidden', config.isAnchorHidden),
        ...instantDataAttribute(h, config.instant),
        ...placementAttributes(h, config),
        h.Style({
          position: 'absolute',
          positionAnchor: rootAnchorName(config),
          inset: 'auto',
          margin: '0',
        }),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const popupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): TooltipPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Key(`${popupId(config)}-${config.open ? 'open' : 'closed'}`),
        h.Id(popupId(config)),
        h.Role('tooltip'),
        ...(config.open ? [] : [h.Hidden(true)]),
        ...openStateDataAttributes(h, config.open),
        ...transitionDataAttributes(h, config.transitionStatus),
        ...instantDataAttribute(h, config.instant),
        ...placementAttributes(h, config),
        ...(config.open && config.onPositioned !== undefined
          ? [
              h.OnMount(
                Mount.mapMessage(
                  PositionAnchoredSurface({
                    id: popupId(config),
                    anchorId: activeTriggerId(config),
                    placement: anchorPlacement(
                      resolvedSide(config),
                      resolvedAlign(config),
                    ),
                    gap: config.sideOffset ?? defaultSideOffset,
                    offset: config.alignOffset ?? defaultAlignOffset,
                    padding: config.collisionPadding ?? defaultCollisionPadding,
                    collisionAvoidance:
                      config.collisionAvoidance ?? defaultCollisionAvoidance,
                  }),
                  config.onPositioned,
                ),
              ),
            ]
          : []),
        h.Style({
          position: config.onPositioned === undefined ? 'fixed' : 'absolute',
          ...(config.onPositioned === undefined
            ? {
                positionAnchor: rootAnchorName(config),
                positionArea: positionArea(config),
              }
            : { inset: 'auto' }),
          margin: '0',
          ...(config.onPositioned === undefined &&
          (config.collisionAvoidance ?? defaultCollisionAvoidance)
            ? { positionTryFallbacks: 'flip-inline, flip-block' }
            : {}),
        }),
        ...optionalMessageAttribute(
          openMessage(config, escapeOpenChange()),
          message =>
            h.OnKeyDownPreventDefault(key =>
              key === 'Escape' ? Option.some(message) : Option.none(),
            ),
        ),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const viewportAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): TooltipPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(viewportId(config)),
        ...instantDataAttribute(h, config.instant),
        ...(config.viewportActivationDirection === undefined
          ? []
          : [
              h.DataAttribute(
                'activation-direction',
                config.viewportActivationDirection,
              ),
            ]),
        ...booleanDataAttribute(
          h,
          'transitioning',
          config.isViewportTransitioning,
        ),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

const arrowAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isMounted: boolean,
): TooltipPartAttributes<Message> => ({
  root: isMounted
    ? [
        h.Id(arrowId(config)),
        h.AriaHidden(true),
        ...openStateDataAttributes(h, config.open),
        ...booleanDataAttribute(h, 'uncentered', config.isArrowUncentered),
        ...instantDataAttribute(h, config.instant),
        ...placementAttributes(h, config),
        h.Style({
          width: `${config.arrowWidth ?? defaultArrowWidth}px`,
          height: `${config.arrowHeight ?? defaultArrowHeight}px`,
        }),
      ]
    : [],
  isMounted,
  isOpen: config.open,
})

export const view = <Message>(config: ViewConfig<Message>): Html => {
  if (
    config.onOpenChange !== undefined &&
    config.onPositioned === undefined &&
    config.positioning !== 'static'
  ) {
    throw new Error(
      'Interactive Tooltip positioning requires an onPositioned Message mapper.',
    )
  }

  const h = html<Message>()
  const isMounted = mounted(config)

  return config.toView({
    provider: providerAttributes(h, config),
    root: rootAttributes(h, config),
    trigger: triggerAttributes(h, config),
    portal: portalAttributes(h),
    positioner: positionerAttributes(h, config, isMounted),
    popup: popupAttributes(h, config, isMounted),
    viewport: viewportAttributes(h, config, isMounted),
    arrow: arrowAttributes(h, config, isMounted),
    isMounted,
    isOpen: config.open,
  })
}

import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { cn } from '../utils/cn'
import * as BaseAccordion from '../base-ui/accordion'

// MODEL

export type AccordionChangeReason = BaseAccordion.AccordionChangeReason
export type AccordionItemDescriptor = BaseAccordion.AccordionItemDescriptor
export type AccordionOrientation = BaseAccordion.AccordionOrientation
export type AccordionPanelDescriptor = BaseAccordion.AccordionPanelDescriptor
export type AccordionPanelGeometry = BaseAccordion.AccordionPanelGeometry
export type AccordionTransitionStatus = BaseAccordion.AccordionTransitionStatus
export type AccordionValueChange = BaseAccordion.AccordionValueChange

export const AccordionStyleOptions = S.Struct({
  className: S.optional(S.String),
  itemClassName: S.optional(S.String),
  headerClassName: S.optional(S.String),
  triggerClassName: S.optional(S.String),
  contentClassName: S.optional(S.String),
  contentInnerClassName: S.optional(S.String),
  triggerIconClassName: S.optional(S.String),
})
export type AccordionStyleOptions = typeof AccordionStyleOptions.Type

// UPDATE

export const { isOpen, panelId, toggleValue, triggerId, valueChange } =
  BaseAccordion

// VIEW

export type AccordionAttributes<Message> =
  BaseAccordion.AccordionAttributes<Message>
export type AccordionItemAttributes<Message> =
  BaseAccordion.AccordionItemAttributes<Message>
export type AccordionPanelAttributes<Message> =
  BaseAccordion.AccordionPanelAttributes<Message>

export type ViewConfig<Message> = Omit<
  BaseAccordion.ViewConfig<Message>,
  'toView'
> &
  AccordionStyleOptions &
  Readonly<{
    toView?: (attributes: AccordionAttributes<Message>) => Html
  }>

export const accordionBaseClassName = 'flex w-full flex-col'

export const accordionItemBaseClassName = 'not-last:border-b'

export const accordionHeaderBaseClassName = 'flex'

export const accordionTriggerBaseClassName =
  'group/accordion-trigger relative flex flex-1 items-start justify-between rounded-lg border border-transparent py-2.5 text-left text-sm font-medium transition-all outline-none hover:underline focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 focus-visible:after:border-ring aria-disabled:pointer-events-none aria-disabled:opacity-50 **:data-[slot=accordion-trigger-icon]:ml-auto **:data-[slot=accordion-trigger-icon]:size-4 **:data-[slot=accordion-trigger-icon]:text-muted-foreground'

export const accordionContentBaseClassName =
  'overflow-hidden text-sm data-open:animate-accordion-down data-closed:animate-accordion-up'

export const accordionContentInnerBaseClassName =
  'h-(--accordion-panel-height) pt-0 pb-2.5 data-ending-style:h-0 data-starting-style:h-0 [&_a]:underline [&_a]:underline-offset-3 [&_a]:hover:text-foreground [&_p:not(:last-child)]:mb-4'

export const accordionTriggerIconBaseClassName = 'pointer-events-none'

export const accordionTriggerClosedIconClassName =
  'shrink-0 group-aria-expanded/accordion-trigger:hidden'

export const accordionTriggerOpenIconClassName =
  'hidden shrink-0 group-aria-expanded/accordion-trigger:inline'

export const accordionClassName = ({
  className,
}: Pick<AccordionStyleOptions, 'className'> = {}): string =>
  cn(accordionBaseClassName, className)

export const accordionItemClassName = ({
  className,
}: Readonly<{ className?: string | undefined }> = {}): string =>
  cn(accordionItemBaseClassName, className)

export const accordionHeaderClassName = ({
  className,
}: Readonly<{ className?: string | undefined }> = {}): string =>
  cn(accordionHeaderBaseClassName, className)

export const accordionTriggerClassName = ({
  className,
}: Readonly<{ className?: string | undefined }> = {}): string =>
  cn(accordionTriggerBaseClassName, className)

export const accordionContentClassName = ({
  className,
}: Readonly<{ className?: string | undefined }> = {}): string =>
  cn(accordionContentBaseClassName, className)

export const accordionContentInnerClassName = ({
  className,
}: Readonly<{ className?: string | undefined }> = {}): string =>
  cn(accordionContentInnerBaseClassName, className)

export const accordionTriggerIconClassName = ({
  className,
  isOpen: iconIsOpen,
}: Readonly<{
  className?: string | undefined
  isOpen: boolean
}>): string =>
  cn(
    accordionTriggerIconBaseClassName,
    iconIsOpen
      ? accordionTriggerOpenIconClassName
      : accordionTriggerClosedIconClassName,
    className,
  )

const rootAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'className' | 'dir'>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'accordion'),
  h.Class(accordionClassName({ className: config.className })),
  ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
]

const itemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'itemClassName'>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'accordion-item'),
  h.Class(accordionItemClassName({ className: config.itemClassName })),
]

const headerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'headerClassName'>,
): ReadonlyArray<Attribute<Message>> => [
  h.Class(accordionHeaderClassName({ className: config.headerClassName })),
]

const triggerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'triggerClassName'>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'accordion-trigger'),
  h.Class(accordionTriggerClassName({ className: config.triggerClassName })),
]

const contentAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'contentClassName'>,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'accordion-content'),
  h.Class(accordionContentClassName({ className: config.contentClassName })),
]

export const contentInnerAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'contentInnerClassName'>,
): ReadonlyArray<Attribute<Message>> => [
  h.Class(
    accordionContentInnerClassName({
      className: config.contentInnerClassName,
    }),
  ),
]

export const triggerIconAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: Pick<ViewConfig<Message>, 'triggerIconClassName'>,
  isOpenValue: boolean,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'accordion-trigger-icon'),
  h.Class(
    accordionTriggerIconClassName({
      className: config.triggerIconClassName,
      isOpen: isOpenValue,
    }),
  ),
]

const shadcnAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: AccordionAttributes<Message>,
): AccordionAttributes<Message> => ({
  root: [...attributes.root, ...rootAttributes(h, config)],
  items: attributes.items.map(item => ({
    ...item,
    root: [...item.root, ...itemAttributes(h, config)],
    header: [...item.header, ...headerAttributes(h, config)],
    trigger: [...item.trigger, ...triggerAttributes(h, config)],
    panel: {
      ...item.panel,
      root:
        item.panel.root.length > 0
          ? [...item.panel.root, ...contentAttributes(h, config)]
          : item.panel.root,
    },
  })),
})

const accordionIcon = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  isOpenValue: boolean,
): Html => h.span([...triggerIconAttributes(h, config, isOpenValue)], [])

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { toView, ...baseConfig } = config

  return BaseAccordion.view<Message>({
    ...baseConfig,
    toView: attributes => {
      const accordionAttributes = shadcnAttributes(h, config, attributes)

      if (toView !== undefined) {
        return toView(accordionAttributes)
      }

      return h.div(
        [...accordionAttributes.root],
        accordionAttributes.items.map(item =>
          h.div(
            [...item.root],
            [
              h.h3(
                [...item.header],
                [
                  h.button(
                    [...item.trigger],
                    [
                      item.item.label ?? item.item.value,
                      accordionIcon(h, config, false),
                      accordionIcon(h, config, true),
                    ],
                  ),
                ],
              ),
              item.panel.isMounted
                ? h.keyed('div')(
                    item.panel.isOpen ? 'open' : 'closed',
                    [...item.panel.root],
                    [
                      h.div(
                        [...contentInnerAttributes(h, config)],
                        [item.panel.panel.label ?? item.item.value],
                      ),
                    ],
                  )
                : h.empty,
            ],
          ),
        ),
      )
    },
  })
}

import { Schema as S } from 'effect'
