export type CommandDialogConfig<Message> = Omit<
  Dialog.ViewConfig<Message>,
  'toView' | 'showCloseButton' | 'contentClassName'
> &
  Readonly<{
    children?: ReadonlyArray<Child>
    contentClassName?: string
    title?: string
    description?: string
