const optionalClassAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  className: string,
): ReadonlyArray<Attribute<Message>> =>
  className === '' ? [] : [h.Class(className)]

const slotAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  slot: string,
  className: string,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', slot),
  ...optionalClassAttribute(h, className),
]

const itemClassName = <Message>(
  config: ViewConfig<Message>,
  item: MenuItemDescriptor,
): string => {
  if (BaseContextMenu.itemKind(item) === 'submenu-trigger') {
    return contextMenuSubTriggerClassName({
      className: config.subTriggerClassName,
    })
  }

  if (
    BaseContextMenu.itemKind(item) === 'checkbox' ||
    BaseContextMenu.itemKind(item) === 'radio'
  ) {
    return contextMenuCheckedItemClassName({
      className:
        BaseContextMenu.itemKind(item) === 'checkbox'
          ? config.checkboxItemClassName
          : config.radioItemClassName,
    })
  }

  return contextMenuItemClassName({ className: config.itemClassName })
}

const itemSlot = (item: MenuItemDescriptor): string => {
  if (BaseContextMenu.itemKind(item) === 'checkbox') {
    return 'context-menu-checkbox-item'
  }

  if (BaseContextMenu.itemKind(item) === 'radio') {
    return 'context-menu-radio-item'
  }

  if (BaseContextMenu.itemKind(item) === 'submenu-trigger') {
    return 'context-menu-sub-trigger'
  }

  return 'context-menu-item'
}

const shadcnItemAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  itemAttributes: BaseContextMenu.MenuItemAttributes<Message>,
): MenuItemAttributes<Message> => ({
  ...itemAttributes,
  root: [
    ...itemAttributes.root,
    ...(config.inset === true ? [h.DataAttribute('inset', 'true')] : []),
    h.DataAttribute('variant', config.variant ?? 'default'),
    ...slotAttributes(
      h,
      itemSlot(itemAttributes.item),
      itemClassName(config, itemAttributes.item),
    ),
    ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
  ],
  indicator: [
    ...itemAttributes.indicator,
    ...slotAttributes(
      h,
      BaseContextMenu.itemKind(itemAttributes.item) === 'checkbox'
        ? 'context-menu-checkbox-item-indicator'
        : 'context-menu-radio-item-indicator',
      contextMenuItemIndicatorClassName({
        className: config.itemIndicatorClassName,
      }),
    ),
  ],
  submenuIndicator: [
    ...itemAttributes.submenuIndicator,
    ...slotAttributes(h, 'context-menu-sub-indicator', 'cn-rtl-flip ml-auto'),
  ],
  shortcut: slotAttributes(
    h,
    'context-menu-shortcut',
    contextMenuShortcutClassName({ className: config.shortcutClassName }),
  ),
})

const shadcnPopupAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  popup: BaseContextMenu.MenuPopupAttributes<Message>,
): MenuPopupAttributes<Message> => ({
  ...popup,
  positioner: {
    ...popup.positioner,
    root:
      popup.positioner.root.length > 0
        ? [
            ...popup.positioner.root,
            ...optionalClassAttribute(
              h,
              contextMenuPositionerClassName({
                className: config.positionerClassName,
              }),
            ),
          ]
        : popup.positioner.root,
  },
  popup: {
    ...popup.popup,
    root:
      popup.popup.root.length > 0
        ? [
            ...popup.popup.root,
            ...slotAttributes(
              h,
              popup.parentValue === undefined
                ? 'context-menu-content'
                : 'context-menu-sub-content',
              popup.parentValue === undefined
                ? contextMenuContentClassName({
                    className: config.contentClassName,
                  })
                : contextMenuSubContentClassName({
                    className: config.subContentClassName,
                  }),
            ),
            ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
          ]
        : popup.popup.root,
  },
  group: [
    ...popup.group,
    ...slotAttributes(h, 'context-menu-group', cn(config.groupClassName)),
  ],
  groupLabel: [
    ...popup.groupLabel,
    ...(config.inset === true ? [h.DataAttribute('inset', 'true')] : []),
    ...slotAttributes(
      h,
      'context-menu-label',
      contextMenuLabelClassName({ className: config.labelClassName }),
    ),
  ],
  separator: [
    ...popup.separator,
    ...slotAttributes(
      h,
      'context-menu-separator',
      contextMenuSeparatorClassName({
        className: config.separatorClassName,
      }),
    ),
  ],
  items: popup.items.map(itemAttributes =>
    shadcnItemAttributes(h, config, itemAttributes),
  ),
})

const shadcnAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: BaseContextMenu.MenuAttributes<Message>,
): MenuAttributes<Message> => ({
  ...attributes,
  root: [
    ...attributes.root,
    ...slotAttributes(h, 'context-menu', contextMenuClassName(config)),
    ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
  ],
  trigger: [
    ...attributes.trigger,
    ...slotAttributes(
      h,
      'context-menu-trigger',
      contextMenuTriggerClassName({ className: config.triggerClassName }),
    ),
  ],
  portal: [
    ...attributes.portal,
    h.DataAttribute('slot', 'context-menu-portal'),
    ...optionalClassAttribute(h, cn(config.portalClassName)),
  ],
  popup: shadcnPopupAttributes(h, config, attributes.popup),
  submenus: attributes.submenus.map(popup =>
    shadcnPopupAttributes(h, config, popup),
  ),
})

export const checkIcon = <Message>(
  attributes: ReadonlyArray<Attribute<Message>>,
): Html => {
  const h = html<Message>()

  return h.svg(
    [
      h.Xmlns('http://www.w3.org/2000/svg'),
      h.Width('24'),
      h.Height('24'),
      h.ViewBox('0 0 24 24'),
      h.Fill('none'),
      h.Stroke('currentColor'),
      h.StrokeWidth('2'),
      h.StrokeLinecap('round'),
      h.StrokeLinejoin('round'),
      ...attributes,
    ],
    [h.path([h.D('m20 6-11 11-5-5')], [])],
  )
}

export const chevronRightIcon = <Message>(
  attributes: ReadonlyArray<Attribute<Message>>,
): Html => {
  const h = html<Message>()

  return h.svg(
    [
      h.Xmlns('http://www.w3.org/2000/svg'),
      h.Width('24'),
      h.Height('24'),
      h.ViewBox('0 0 24 24'),
      h.Fill('none'),
      h.Stroke('currentColor'),
      h.StrokeWidth('2'),
      h.StrokeLinecap('round'),
      h.StrokeLinejoin('round'),
      ...attributes,
    ],
    [h.path([h.D('m9 18 6-6-6-6')], [])],
  )
}

const defaultItemContent = <Message>(
  itemAttributes: MenuItemAttributes<Message>,
): ReadonlyArray<Html> => {
  const h = html<Message>()
  const kind = BaseContextMenu.itemKind(itemAttributes.item)
  const indicator =
    kind === 'checkbox' || kind === 'radio'
      ? h.span([...itemAttributes.indicator], [checkIcon([])])
      : h.span([], [])
  const submenuIndicator =
    kind === 'submenu-trigger'
      ? chevronRightIcon(itemAttributes.submenuIndicator)
      : h.span([], [])

  return [
    indicator,
    h.span([...itemAttributes.label], [itemAttributes.item.label]),
    submenuIndicator,
  ]
}

const popupView = <Message>(
  popup: MenuPopupAttributes<Message>,
  submenus: ReadonlyArray<MenuPopupAttributes<Message>> = [],
): ReadonlyArray<Html> => {
  const h = html<Message>()

  if (!popup.isMounted) {
    return []
  }

  return [
    ...(popup.parentValue === undefined
      ? [h.div([...popup.backdrop.root], [])]
      : []),
    h.div(
      [...popup.positioner.root],
      [
        h.div(
          [...popup.popup.root],
          [
            h.div([...popup.arrow.root], []),
            h.div(
              [...popup.group],
              [
                h.div([...popup.groupLabel], ['Menu']),
                ...popup.items.map(itemAttributes =>
                  h.div(
                    [...itemAttributes.root],
                    defaultItemContent(itemAttributes),
                  ),
                ),
              ],
            ),
            ...submenus.flatMap(submenu => popupView(submenu)),
          ],
        ),
      ],
    ),
  ]
}

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { toView, ...baseConfig } = config

  return BaseContextMenu.view<Message>({
    ...baseConfig,
    align: config.align ?? 'start',
    alignOffset: config.alignOffset ?? 4,
    side: config.side ?? 'right',
    sideOffset: config.sideOffset ?? 0,
    toView: attributes => {
      const menuAttributes = shadcnAttributes(h, config, attributes)

      if (toView !== undefined) {
        return toView(menuAttributes)
      }

      return h.div(
        [...menuAttributes.root],
        [
          h.div([...menuAttributes.trigger], ['Right click here']),
          h.div(
            [...menuAttributes.portal],
            [...popupView(menuAttributes.popup, menuAttributes.submenus)],
          ),
        ],
      )
    },
  })
}

import {
  Array as EffectArray,
  Option,
  Order,
  pipe,
  Record as EffectRecord,
  Schema as S,
  String as EffectString,
} from 'effect'
import type { Html } from 'foldkit/html'
import { evo } from 'foldkit/struct'

import { cn } from '../utils/cn'

// MODEL

export const DataTableSortDirection = S.Union([
  S.Literal('asc'),
  S.Literal('desc'),
])
export type DataTableSortDirection = typeof DataTableSortDirection.Type

export const DataTableSort = S.Struct({
  columnId: S.String,
  direction: DataTableSortDirection,
})
export type DataTableSort = typeof DataTableSort.Type

export const DataTableState = S.Struct({
  sorting: S.Array(DataTableSort),
  filters: S.Record(S.String, S.String),
  hiddenColumnIds: S.Array(S.String),
  selectedRowIds: S.Record(S.String, S.Boolean),
  pageIndex: S.Number,
  pageSize: S.Number,
})
export type DataTableState = typeof DataTableState.Type

export type DataTableColumn<Row> = Readonly<{
  id: string
  header: string
  isHideable?: boolean
  isSortable?: boolean
  isFilterable?: boolean
  valueText: (row: Row) => string
  sortValue?: (row: Row) => string | number
  filterValue?: (row: Row) => string
  cell: (row: Row) => Html
}>

export type DataTableRowModel<Row> = Readonly<{
  visibleColumns: ReadonlyArray<DataTableColumn<Row>>
  filteredRows: ReadonlyArray<Row>
  sortedRows: ReadonlyArray<Row>
  paginatedRows: ReadonlyArray<Row>
  filteredRowCount: number
  selectedFilteredRowCount: number
  selectedPageRowCount: number
  totalPageCount: number
  canPreviousPage: boolean
  canNextPage: boolean
}>

export const DataTableLayoutStyleOptions = S.Struct({
  className: S.optional(S.String),
})
export type DataTableLayoutStyleOptions =
  typeof DataTableLayoutStyleOptions.Type

// UPDATE

const normalizeFilterValue = (value: string): string =>
  EffectString.trim(value).toLocaleLowerCase()

const comparableValue = <Row>(
  column: DataTableColumn<Row>,
  row: Row,
): string | number => column.sortValue?.(row) ?? column.valueText(row)

const columnById = <Row>(
  columns: ReadonlyArray<DataTableColumn<Row>>,
  columnId: string,
): Option.Option<DataTableColumn<Row>> =>
  EffectArray.findFirst(columns, column => column.id === columnId)

const maxPageIndex = (pageCount: number): number => Math.max(pageCount - 1, 0)

const pageCountFor = (rowCount: number, pageSize: number): number =>
  Math.max(1, Math.ceil(rowCount / Math.max(pageSize, 1)))

const clampedPageIndex = (pageIndex: number, pageCount: number): number =>
  Math.min(Math.max(pageIndex, 0), maxPageIndex(pageCount))

const compareValues = (left: string | number, right: string | number): number =>
  typeof left === 'number' && typeof right === 'number'
    ? left - right
    : String(left).localeCompare(String(right))

const orderingFor = (
  left: string | number,
  right: string | number,
): -1 | 0 | 1 => {
  const value = compareValues(left, right)

  if (value < 0) {
    return -1
  }

  if (value > 0) {
    return 1
  }

  return 0
}

const selectedRowCount = <Row>(
  rows: ReadonlyArray<Row>,
  rowId: (row: Row) => string,
  state: DataTableState,
): number =>
  rows.filter(row => state.selectedRowIds[rowId(row)] === true).length

const normalizedState = (
  state: DataTableState,
  pageCount: number = pageCountFor(0, state.pageSize),
): DataTableState =>
  evo(state, {
    pageIndex: () => clampedPageIndex(state.pageIndex, pageCount),
    pageSize: value => Math.max(value, 1),
  })

const hiddenColumnIds = (
  state: DataTableState,
  columnId: string,
  isVisible: boolean,
): ReadonlyArray<string> => {
  if (isVisible) {
    return state.hiddenColumnIds.filter(id => id !== columnId)
  }

  return state.hiddenColumnIds.includes(columnId)
    ? state.hiddenColumnIds
    : [...state.hiddenColumnIds, columnId]
}

export const initialState = ({
  pageSize,
}: Readonly<{ pageSize: number }>): DataTableState =>
  normalizedState({
    sorting: [],
    filters: {},
    hiddenColumnIds: [],
    selectedRowIds: {},
    pageIndex: 0,
    pageSize,
  })

export const visibleColumns = <Row>(
  columns: ReadonlyArray<DataTableColumn<Row>>,
  state: DataTableState,
): ReadonlyArray<DataTableColumn<Row>> =>
  columns.filter(column => !state.hiddenColumnIds.includes(column.id))

export const filteredRows = <Row>(
  rows: ReadonlyArray<Row>,
  columns: ReadonlyArray<DataTableColumn<Row>>,
  state: DataTableState,
): ReadonlyArray<Row> => {
  const activeFilters = Object.entries(state.filters).filter(
    ([, value]) => EffectString.trim(value) !== '',
  )

  if (activeFilters.length === 0) {
    return rows
  }

  return rows.filter(row =>
    activeFilters.every(([columnId, value]) =>
      pipe(
        columnById(columns, columnId),
        Option.filter(column => column.isFilterable === true),
        Option.match({
          onNone: () => true,
          onSome: column =>
            (column.filterValue?.(row) ?? column.valueText(row))
              .toLocaleLowerCase()
              .includes(normalizeFilterValue(value)),
        }),
      ),
    ),
  )
}

export const sortedRows = <Row>(
  rows: ReadonlyArray<Row>,
  columns: ReadonlyArray<DataTableColumn<Row>>,
  state: DataTableState,
): ReadonlyArray<Row> =>
  state.sorting.reduceRight(
    (currentRows, sort) =>
      pipe(
        columnById(columns, sort.columnId),
        Option.filter(column => column.isSortable !== false),
        Option.match({
          onNone: () => currentRows,
          onSome: column => {
            const order = Order.mapInput(
              Order.make<Row>((left, right) =>
                orderingFor(
                  comparableValue(column, left),
                  comparableValue(column, right),
                ),
              ),
              (row: Row) => row,
            )

            return EffectArray.sort(
              currentRows,
              sort.direction === 'asc' ? order : Order.flip(order),
            )
          },
        }),
      ),
    rows,
  )

export const paginatedRows = <Row>(
  rows: ReadonlyArray<Row>,
  state: DataTableState,
): ReadonlyArray<Row> => {
  const startIndex = state.pageIndex * state.pageSize

  return rows.slice(startIndex, startIndex + state.pageSize)
}

export const rowModel = <Row>({
  rows,
  columns,
  state,
  rowId,
}: Readonly<{
  rows: ReadonlyArray<Row>
  columns: ReadonlyArray<DataTableColumn<Row>>
  state: DataTableState
  rowId: (row: Row) => string
}>): DataTableRowModel<Row> => {
  const visible = visibleColumns(columns, state)
  const filtered = filteredRows(rows, columns, state)
  const sorted = sortedRows(filtered, columns, state)
  const totalPageCount = pageCountFor(sorted.length, state.pageSize)
  const nextState = normalizedState(state, totalPageCount)
  const paginated = paginatedRows(sorted, nextState)

  return {
    visibleColumns: visible,
    filteredRows: filtered,
    sortedRows: sorted,
    paginatedRows: paginated,
    filteredRowCount: filtered.length,
    selectedFilteredRowCount: selectedRowCount(filtered, rowId, state),
    selectedPageRowCount: selectedRowCount(paginated, rowId, state),
    totalPageCount,
    canPreviousPage: nextState.pageIndex > 0,
    canNextPage: nextState.pageIndex < totalPageCount - 1,
  }
}

export const toggleSort = (
  state: DataTableState,
  columnId: string,
): DataTableState =>
  pipe(
    EffectArray.get(state.sorting, 0),
    Option.match({
      onNone: () =>
        evo(state, {
          sorting: () => [{ columnId, direction: 'asc' }],
          pageIndex: () => 0,
        }),
      onSome: sort =>
        sort.columnId === columnId
          ? evo(state, {
              sorting: () => [
                {
                  columnId,
                  direction: sort.direction === 'asc' ? 'desc' : 'asc',
                },
              ],
              pageIndex: () => 0,
            })
          : evo(state, {
              sorting: () => [{ columnId, direction: 'asc' }],
              pageIndex: () => 0,
            }),
    }),
  )

export const setFilter = (
  state: DataTableState,
  columnId: string,
  value: string,
): DataTableState =>
  evo(state, {
    filters: currentFilters => {
      const trimmedValue = EffectString.trim(value)

      return trimmedValue === ''
        ? EffectRecord.remove(currentFilters, columnId)
        : EffectRecord.set(currentFilters, columnId, value)
    },
    pageIndex: () => 0,
  })

export const clearFilters = (state: DataTableState): DataTableState =>
  evo(state, {
    filters: () => ({}),
    pageIndex: () => 0,
  })

export const toggleColumnVisibility = (
  state: DataTableState,
  columnId: string,
  isVisible: boolean,
): DataTableState =>
  evo(state, {
    hiddenColumnIds: () => hiddenColumnIds(state, columnId, isVisible),
  })

export const toggleRowSelection = (
  state: DataTableState,
  rowId: string,
): DataTableState =>
  evo(state, {
    selectedRowIds: currentSelection =>
      currentSelection[rowId] === true
        ? EffectRecord.remove(currentSelection, rowId)
        : EffectRecord.set(currentSelection, rowId, true),
  })

export const toggleAllPageRowsSelection = (
  state: DataTableState,
  rowIds: ReadonlyArray<string>,
): DataTableState => {
  const shouldSelect = rowIds.some(
    rowId => state.selectedRowIds[rowId] !== true,
  )

  return evo(state, {
    selectedRowIds: currentSelection =>
      rowIds.reduce(
        (selection, rowId) =>
          shouldSelect
            ? EffectRecord.set(selection, rowId, true)
            : EffectRecord.remove(selection, rowId),
        currentSelection,
      ),
  })
}

export const setPageIndex = (
  state: DataTableState,
  pageIndex: number,
  pageCount?: number,
): DataTableState =>
  normalizedState(
    evo(state, {
      pageIndex: () => Math.max(pageIndex, 0),
    }),
    pageCount,
  )

export const setPageSize = (
  state: DataTableState,
  pageSize: number,
): DataTableState =>
  normalizedState(
    evo(state, {
      pageSize: () => Math.max(pageSize, 1),
      pageIndex: () => 0,
    }),
  )

export const nextPage = (
  state: DataTableState,
  pageCount: number,
): DataTableState => setPageIndex(state, state.pageIndex + 1, pageCount)

export const previousPage = (state: DataTableState): DataTableState =>
  setPageIndex(state, state.pageIndex - 1)

export const firstPage = (state: DataTableState): DataTableState =>
  setPageIndex(state, 0)

export const lastPage = (
  state: DataTableState,
  pageCount: number,
): DataTableState => setPageIndex(state, maxPageIndex(pageCount), pageCount)

