  'items' | 'toView'
> &
  NavigationMenuStyleOptions &
  Readonly<{
    items: ReadonlyArray<NavigationMenuItemDescriptor>
    toView?: (attributes: NavigationMenuAttributes<Message>) => Html
  }>

