}

export const moreHorizontalIcon = <Message>(
  attributes: ReadonlyArray<Attribute<Message>> = [],
): Html => {
  const h = html<Message>()

  return icon('lucide lucide-ellipsis', attributes, [
    h.circle([h.Cx('12'), h.Cy('12'), h.R('1')], []),
